INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Setting `"dynamic": "strict"` at the mapping level means:$tv2$, $tv2$[{"id":"a","text":"Indexing a document with an unmapped field is rejected with an error"},{"id":"b","text":"Unknown fields are stored but not indexed"},{"id":"c","text":"Unknown fields are dynamically mapped"},{"id":"d","text":"All fields become keyword"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`dynamic: strict` rejects documents containing fields not in the mapping. `dynamic: false` keeps them in `_source` unindexed; the default `dynamic: true` auto-creates mappings.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Setting `"dynamic": "strict"` at the mapping level means:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which field type stores an array of objects so that each object's sub-fields keep their per-element relationship for querying?$tv2$, $tv2$[{"id":"a","text":"nested"},{"id":"b","text":"object"},{"id":"c","text":"flattened"},{"id":"d","text":"join"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `nested` type indexes each object as a hidden sub-document, preserving which sub-field values belong together. The default `object` type flattens arrays, losing element correlation. `flattened` indexes the whole object as keywords.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which field type stores an array of objects so that each object's sub-fields keep their per-element relationship for querying?$tv2$);
