INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Administration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Before a rolling upgrade/restart, disabling shard allocation prevents unnecessary rebalancing. The correct setting is:$tv2$, $tv2$[{"id":"a","text":"cluster.routing.allocation.enable: \"primaries\" (or \"none\")"},{"id":"b","text":"index.blocks.write: true"},{"id":"c","text":"discovery.type: single-node"},{"id":"d","text":"cluster.routing.rebalance.enable: \"always\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Setting `cluster.routing.allocation.enable` to `none`/`primaries` during a rolling restart stops replica reallocation churn while a node is briefly down. A write block stops indexing, not allocation.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-allocation-explain.html","label":"Elasticsearch Reference — Cluster allocation explain API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Before a rolling upgrade/restart, disabling shard allocation prevents unnecessary rebalancing. The correct setting is:$tv2$);
