INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which file configures the logging behavior of an Elasticsearch node?$tv2$, $tv2$[{"id":"a","text":"log4j2.properties"},{"id":"b","text":"elasticsearch.yml"},{"id":"c","text":"jvm.options"},{"id":"d","text":"logging.json"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Elasticsearch uses Log4j2; `log4j2.properties` in the config directory defines appenders/levels. `elasticsearch.yml` is cluster/node config and `jvm.options` is JVM tuning.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which file configures the logging behavior of an Elasticsearch node?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In `node.roles`, which combination yields a node that holds data AND can run ingest pipelines but is NOT master-eligible?$tv2$, $tv2$[{"id":"a","text":"node.roles: [ data, ingest ]"},{"id":"b","text":"node.roles: [ master, data, ingest ]"},{"id":"c","text":"node.roles: []"},{"id":"d","text":"node.roles: [ master ]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`[ data, ingest ]` gives data storage + pipeline execution while omitting `master`, so the node cannot be elected master. An empty list is coordinating-only; including `master` makes it master-eligible.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `node.roles`, which combination yields a node that holds data AND can run ingest pipelines but is NOT master-eligible?$tv2$);
