INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$For a production node bound to a routable IP, which bootstrap check commonly fails if the OS limit is too low?$tv2$, $tv2$[{"id":"a","text":"The vm.max_map_count check (must be >= 262144)"},{"id":"b","text":"The cluster.name presence check"},{"id":"c","text":"The path.logs writable check only"},{"id":"d","text":"The number_of_replicas check"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`vm.max_map_count` must be at least 262144 or the production bootstrap check fails and the node refuses to start. `number_of_replicas` is an index setting, not a bootstrap check.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$For a production node bound to a routable IP, which bootstrap check commonly fails if the OS limit is too low?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which setting identifies an individual node (shown in cluster APIs and logs)?$tv2$, $tv2$[{"id":"a","text":"node.name"},{"id":"b","text":"cluster.name"},{"id":"c","text":"node.attr.rack"},{"id":"d","text":"node.id"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`node.name` is the human-readable node identifier (defaults to the hostname). `cluster.name` groups nodes; `node.attr.*` are custom allocation attributes; `node.id` is auto-generated, not user-set.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which setting identifies an individual node (shown in cluster APIs and logs)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want shard allocation awareness so replicas avoid the same rack as their primary. The first step is to set:$tv2$, $tv2$[{"id":"a","text":"A custom node attribute (node.attr.rack_id) plus cluster.routing.allocation.awareness.attributes"},{"id":"b","text":"discovery.seed_hosts per rack"},{"id":"c","text":"index.number_of_replicas: 0"},{"id":"d","text":"node.roles: [ data_warm ]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Allocation awareness uses a custom node attribute (e.g. `node.attr.rack_id`) plus `cluster.routing.allocation.awareness.attributes: rack_id` so Elasticsearch spreads primaries/replicas across racks. The other options are unrelated.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want shard allocation awareness so replicas avoid the same rack as their primary. The first step is to set:$tv2$);
