INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Queries$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To boost recent documents' relevance using a decay over a `date` field, which query do you use?$tv2$, $tv2$[{"id":"a","text":"function_score with a gauss/exp/linear decay function"},{"id":"b","text":"constant_score"},{"id":"c","text":"match_all with sort by date"},{"id":"d","text":"range query with boost"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`function_score` with a decay function (`gauss`, `exp`, `linear`) smoothly adjusts `_score` based on distance from an origin (e.g. now) — ideal for recency boosting. `constant_score` flattens scoring; sorting by date is not relevance boosting.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl.html","label":"Elasticsearch Reference — Query DSL"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To boost recent documents' relevance using a decay over a `date` field, which query do you use?$tv2$);
