INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Queries$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$The `multi_match` type `cross_fields` is appropriate when:$tv2$, $tv2$[{"id":"a","text":"Terms of a single concept (e.g. a person's name) are spread across multiple fields and should be treated as one combined field"},{"id":"b","text":"You want the single best-scoring field only"},{"id":"c","text":"You need phrase matching"},{"id":"d","text":"You want to query a nested object"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`cross_fields` treats matched fields as one big field, useful when query terms span fields (first_name/last_name). `best_fields` uses the top field score; phrase is a different type; nested needs a `nested` query.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The `multi_match` type `cross_fields` is appropriate when:$tv2$);
