INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The `standard` analyzer applied to "The Quick-Brown FOX!" produces approximately:$tv2$, $tv2$[{"id":"a","text":"[the, quick, brown, fox]"},{"id":"b","text":"[The, Quick-Brown, FOX!]"},{"id":"c","text":"[the quick-brown fox!]"},{"id":"d","text":"[t, h, e, q, ...]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `standard` analyzer (standard tokenizer + lowercase) splits on word boundaries (the hyphen separates quick/brown) and lowercases, yielding `the, quick, brown, fox`. It does not keep the whole string or split into characters.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The `standard` analyzer applied to "The Quick-Brown FOX!" produces approximately:$tv2$);
