INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which analyzer lowercases and splits on non-letter characters (dropping numbers)?$tv2$, $tv2$[{"id":"a","text":"simple analyzer"},{"id":"b","text":"standard analyzer"},{"id":"c","text":"keyword analyzer"},{"id":"d","text":"pattern analyzer with \\d+"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `simple` analyzer uses the lowercase tokenizer: it breaks on non-letters and lowercases, discarding digits. `standard` keeps numbers; `keyword` emits one token; the pattern option is a different configurable analyzer.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which analyzer lowercases and splits on non-letter characters (dropping numbers)?$tv2$);
