INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a dedicated ingest node that runs ingest pipelines but holds no shards. The correct `node.roles` is:$tv2$, $tv2$[{"id":"a","text":"node.roles: [ ingest ]"},{"id":"b","text":"node.roles: [ data, ingest ]"},{"id":"c","text":"node.roles: [ master ]"},{"id":"d","text":"node.ingest: only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`node.roles: [ ingest ]` makes the node ingest-only (runs pipelines, holds no data). Including `data` would also store shards; `master` is unrelated; `node.ingest: only` is not valid syntax.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a dedicated ingest node that runs ingest pipelines but holds no shards. The correct `node.roles` is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After 8.x security auto-configuration, how does a NEW node typically join the existing secured cluster?$tv2$, $tv2$[{"id":"a","text":"By copying the elasticsearch.yml verbatim"},{"id":"b","text":"By starting with an enrollment token generated on an existing node (elasticsearch-create-enrollment-token)"},{"id":"c","text":"By disabling TLS first"},{"id":"d","text":"By manually editing the keystore on every node"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$An enrollment token (from `bin/elasticsearch-create-enrollment-token -s node`) lets a new node automatically obtain the CA/TLS material and join the secured cluster. Copying yml or disabling TLS is incorrect/insecure.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After 8.x security auto-configuration, how does a NEW node typically join the existing secured cluster?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid Elasticsearch node roles that can appear in `node.roles`.$tv2$, $tv2$[{"id":"a","text":"master"},{"id":"b","text":"data"},{"id":"c","text":"ingest"},{"id":"d","text":"coordinator"}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$`master`, `data` (and data tiers like data_hot/data_warm), and `ingest` are valid roles, along with ml, transform, remote_cluster_client. There is no explicit `coordinator` role — a coordinating-only node uses an empty roles list.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid Elasticsearch node roles that can appear in `node.roles`.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Indexing Data$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A document is indexed but does not appear in search results immediately. The most likely reason is:$tv2$, $tv2$[{"id":"a","text":"It is lost permanently."},{"id":"b","text":"It is not yet refreshed/searchable — by default the index refreshes about every 1 second."},{"id":"c","text":"The cluster is red."},{"id":"d","text":"The mapping rejected it silently."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Newly indexed documents become searchable only after a refresh (default `index.refresh_interval` ~1s), unless you force `?refresh=true`/`wait_for`. The document is durably written to the translog regardless.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A document is indexed but does not appear in search results immediately. The most likely reason is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Indexing Data$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want an ILM-managed time-series data stream to start writing to a new backing index when the current one reaches 50 GB or 30 days. Which ILM action achieves this?$tv2$, $tv2$[{"id":"a","text":"The `rollover` action in the hot phase"},{"id":"b","text":"The `shrink` action"},{"id":"c","text":"The `freeze` action"},{"id":"d","text":"The `delete` action"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `rollover` action (hot phase) creates a new backing index when size/age/doc conditions are met. `shrink` reduces shards, `delete` removes the index, `freeze` is deprecated/cold-related.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want an ILM-managed time-series data stream to start writing to a new backing index when the current one reaches 50 GB or 30 days. Which ILM action achieves this?$tv2$);
