INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Indexing Data$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A `_reindex` request needs to copy only documents where `region:"eu"`. How is this expressed?$tv2$, $tv2$[{"id":"a","text":"Add a `query` under `source` in the reindex body"},{"id":"b","text":"Reindex everything then delete the rest"},{"id":"c","text":"Use a `filter` at the top level of the reindex body"},{"id":"d","text":"It is not possible to filter a reindex"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `_reindex` body accepts `source.query` (a standard Query DSL query) to copy only matching documents. Filtering at reindex time is supported and preferred over copy-then-delete.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `_reindex` request needs to copy only documents where `region:"eu"`. How is this expressed?$tv2$);
