INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Indexing Data$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Which `_split` precondition must hold to split an index from 2 primary shards to 6?$tv2$, $tv2$[{"id":"a","text":"The index must be read-only and the target shard count must be a multiple of the source count"},{"id":"b","text":"The index must be empty"},{"id":"c","text":"Replicas must be set to 0 permanently"},{"id":"d","text":"The source must first be force-merged to one segment"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`_split` requires the source index to be read-only and the target primary count to be a multiple of the original (2 → 6 is 3×). Force-merge and emptiness are not requirements; replicas need not be permanently zero.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `_split` precondition must hold to split an index from 2 primary shards to 6?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Indexing Data$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which API rolls over a write alias / data stream to a new backing index when a condition is met?$tv2$, $tv2$[{"id":"a","text":"POST <alias>/_rollover with conditions (max_age, max_size, max_docs)"},{"id":"b","text":"POST <index>/_split"},{"id":"c","text":"PUT <index>/_settings"},{"id":"d","text":"POST <index>/_clone"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Rollover API creates a new index and points the write alias/data stream at it when `max_age`/`max_primary_shard_size`/`max_docs` conditions are satisfied (ILM automates this). Split/clone/settings do not roll over.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which API rolls over a write alias / data stream to a new backing index when a condition is met?$tv2$);
