INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Queries$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `terms` query with 200 values is generally preferable to 200 `should` `term` clauses because:$tv2$, $tv2$[{"id":"a","text":"It is more concise and efficient for matching any of many exact values"},{"id":"b","text":"It analyzes the input"},{"id":"c","text":"It contributes more to scoring"},{"id":"d","text":"It supports phrase matching"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A single `terms` query expresses "match any of these exact values" concisely and efficiently. Like `term`, it does not analyze input and is typically used in filter context; it is not a phrase/scoring construct.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/term-level-queries.html","label":"Elasticsearch Reference — Term-level queries"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `terms` query with 200 values is generally preferable to 200 `should` `term` clauses because:$tv2$);
