INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why are `text` fields generally NOT directly usable in a `terms` aggregation?$tv2$, $tv2$[{"id":"a","text":"Aggregating on analyzed text requires fielddata (heap-heavy) which is disabled by default; use a `.keyword` sub-field instead"},{"id":"b","text":"text fields are not indexed"},{"id":"c","text":"Aggregations only work on numbers"},{"id":"d","text":"text fields have no doc values and cannot be aggregated at all under any circumstance"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Aggregating analyzed `text` needs in-heap fielddata (default disabled to protect the heap). The idiomatic fix is to aggregate on the `keyword` multi-field, which uses doc values. (Fielddata can be enabled but is discouraged.)$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why are `text` fields generally NOT directly usable in a `terms` aggregation?$tv2$);
