INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Mappings and Text Analysis$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The `lowercase` token filter is applied:$tv2$, $tv2$[{"id":"a","text":"After the tokenizer, lowercasing each token"},{"id":"b","text":"Before the tokenizer, on raw characters"},{"id":"c","text":"As the tokenizer itself"},{"id":"d","text":"Only at query time"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`lowercase` is a token filter operating on tokens produced by the tokenizer. Lowercasing raw characters before tokenization would be a char filter; the `lowercase` tokenizer is a separate component.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The `lowercase` token filter is applied:$tv2$);
