INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Administration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A searchable snapshot allows you to:$tv2$, $tv2$[{"id":"a","text":"Mount snapshot data as a (cold/frozen) index and search it without fully restoring it to local disk"},{"id":"b","text":"Search while taking the snapshot"},{"id":"c","text":"Convert a snapshot into an ingest pipeline"},{"id":"d","text":"Replicate a snapshot to another cluster automatically"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Searchable snapshots mount snapshot-backed indices (cold/frozen tiers) so data is queryable while residing primarily in the repository, cutting local storage cost. It is not about taking snapshots concurrently or CCR.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","label":"Elasticsearch Reference — Snapshot and restore"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A searchable snapshot allows you to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Administration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The ILM `allocate` action is commonly used to:$tv2$, $tv2$[{"id":"a","text":"Move an index to a different data tier/node attribute and/or change its replica count as it ages"},{"id":"b","text":"Delete the index"},{"id":"c","text":"Roll over to a new index"},{"id":"d","text":"Force-merge segments"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `allocate` action reassigns shards (e.g. to warm/cold nodes via allocation attributes) and can change `number_of_replicas`. Deletion is `delete`, rollover is `rollover`, segment merge is `forcemerge`.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The ILM `allocate` action is commonly used to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Administration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which ILM action in the warm/cold phase reduces the number of primary shards of an index?$tv2$, $tv2$[{"id":"a","text":"shrink"},{"id":"b","text":"rollover"},{"id":"c","text":"allocate"},{"id":"d","text":"set_priority"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `shrink` action reduces primary shard count for older indices. `rollover` (hot) starts a new index, `allocate` moves/changes replicas/tiering, `set_priority` orders recovery.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which ILM action in the warm/cold phase reduces the number of primary shards of an index?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Data Processing and Aggregations$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which aggregation buckets numeric values into fixed-width intervals (e.g. every 10 units)?$tv2$, $tv2$[{"id":"a","text":"histogram"},{"id":"b","text":"terms"},{"id":"c","text":"avg"},{"id":"d","text":"cardinality"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `histogram` bucket aggregation groups numeric values into fixed `interval`-width buckets (`date_histogram` is its time variant). `terms` buckets by distinct value; `avg`/`cardinality` are metrics.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which aggregation buckets numeric values into fixed-width intervals (e.g. every 10 units)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Data Processing and Aggregations$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `filters` (plural) aggregation lets you:$tv2$, $tv2$[{"id":"a","text":"Define multiple named buckets, each based on its own query/filter"},{"id":"b","text":"Filter the query before searching"},{"id":"c","text":"Remove a field"},{"id":"d","text":"Compute an average"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `filters` aggregation creates one bucket per supplied named filter (plus an optional "other" bucket) — handy for categorizing docs by arbitrary conditions. It is not a query-level filter or a metric.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `filters` (plural) aggregation lets you:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Data Processing and Aggregations$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which ingest processor conditionally runs another processor only when a script/condition is true?$tv2$, $tv2$[{"id":"a","text":"Using the `if` parameter on a processor (painless condition)"},{"id":"b","text":"The `terms` aggregation"},{"id":"c","text":"The `bool` query"},{"id":"d","text":"The `reindex` API"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Any ingest processor can take an `if` condition (a Painless expression) so it executes only when the condition holds. Aggregations/queries are search-time; reindex is a bulk copy, not conditional logic.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which ingest processor conditionally runs another processor only when a script/condition is true?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Data Processing and Aggregations$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The `script` ingest processor is used to:$tv2$, $tv2$[{"id":"a","text":"Run a Painless script to compute or transform fields during ingest"},{"id":"b","text":"Run a search-time aggregation"},{"id":"c","text":"Define an analyzer"},{"id":"d","text":"Schedule a snapshot"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `script` processor executes Painless against the document at ingest time (e.g. derive fields). It is not a search aggregation, analyzer, or snapshot mechanism.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The `script` ingest processor is used to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Data Processing and Aggregations$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `significant_terms` aggregation surfaces:$tv2$, $tv2$[{"id":"a","text":"Terms that are unusually frequent in the query result set compared to the background corpus"},{"id":"b","text":"The most frequent terms overall only"},{"id":"c","text":"A moving average"},{"id":"d","text":"Distinct value counts"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`significant_terms` finds terms over-represented in the foreground (matching) set relative to the background, highlighting "interesting" terms. Plain `terms` shows raw frequency; cardinality counts distinct values.$tv2$, $tv2$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:elastic-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$elastic-certified-engineer-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `significant_terms` aggregation surfaces:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Helm command renders a chart locally to YAML (without installing it) so you can inspect or commit the manifests?$tv2$, $tv2$[{"id":"a","text":"helm install --dry-run --debug"},{"id":"b","text":"helm template <release> <chart>"},{"id":"c","text":"helm render <release> <chart>"},{"id":"d","text":"helm get manifest <release>"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`helm template` renders the chart to stdout without contacting a cluster. `helm install --dry-run` simulates an install but still requires a kubeconfig and release name; `helm get manifest` reads back an installed release.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Helm command renders a chart locally to YAML (without installing it) so you can inspect or commit the manifests?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To install argo-cd 7.7.3 with the CRDs already managed separately, which value should be passed?$tv2$, $tv2$[{"id":"a","text":"--set crds.install=false"},{"id":"b","text":"--skip-crds"},{"id":"c","text":"--no-hooks"},{"id":"d","text":"--set createNamespace=false"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The argo-cd chart exposes `crds.install` to decouple CRD lifecycle from the release. `--skip-crds` is a Helm-level flag that does not exist on `template`/`install` for arbitrary charts in the same way; the chart-specific value is the documented path.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To install argo-cd 7.7.3 with the CRDs already managed separately, which value should be passed?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to extract every CustomResourceDefinition installed by cert-manager into a single YAML file. Which command works?$tv2$, $tv2$[{"id":"a","text":"kubectl get crd cert-manager -o yaml > resources.yaml"},{"id":"b","text":"kubectl get crd | grep cert-manager | awk '{print $1}' | xargs -I{} kubectl get crd {} -o yaml >> resources.yaml"},{"id":"c","text":"kubectl explain crd --recursive > resources.yaml"},{"id":"d","text":"kubectl describe crd > resources.yaml"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The filter-and-xargs pipeline lists every CRD whose name contains `cert-manager` and exports each as YAML. `kubectl describe` is human-formatted, not re-applicable; `kubectl explain` documents schema, not instances.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/api-extension/custom-resources/","label":"Kubernetes Docs — Custom Resources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to extract every CustomResourceDefinition installed by cert-manager into a single YAML file. Which command works?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You are migrating worker nodes from containerd to cri-dockerd (Mirantis). After installing the `cri-dockerd` package, which command persists the kernel-module/sysctl prerequisites across reboots?$tv2$, $tv2$[{"id":"a","text":"echo 'net.ipv4.ip_forward=1' > /etc/sysctl.conf"},{"id":"b","text":"Create /etc/sysctl.d/cka.conf with the needed entries and run `sudo sysctl --system`"},{"id":"c","text":"kubeadm config images pull"},{"id":"d","text":"systemctl edit kubelet to add `--ip-forward=1`"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Drop-in files under `/etc/sysctl.d/` are reloaded by `sysctl --system`, persisting `net.bridge.bridge-nf-call-iptables`, `net.ipv4.ip_forward`, etc. Editing `/etc/sysctl.conf` works but is discouraged; the others are unrelated.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You are migrating worker nodes from containerd to cri-dockerd (Mirantis). After installing the `cri-dockerd` package, which command persists the kernel-module/sysctl prerequisites across reboots?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about the Kubernetes control plane.$tv2$, $tv2$[{"id":"a","text":"kube-apiserver is the only component that talks directly to etcd in a default kubeadm install."},{"id":"b","text":"kube-scheduler watches for unscheduled Pods and assigns them to nodes via the apiserver."},{"id":"c","text":"kube-controller-manager runs as a Deployment in kube-system."},{"id":"d","text":"etcd is the cluster's single source of truth for object state."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$On kubeadm clusters, control-plane components run as **static Pods** managed by the kubelet from `/etc/kubernetes/manifests/`, NOT as Deployments. The other three statements are correct.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about the Kubernetes control plane.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment must have a sidecar that tails a log file the main container writes. Which volume type lets both containers share the file inside the Pod?$tv2$, $tv2$[{"id":"a","text":"hostPath"},{"id":"b","text":"emptyDir"},{"id":"c","text":"configMap"},{"id":"d","text":"persistentVolumeClaim (RWO)"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`emptyDir` is created when the Pod is bound to a node and is shared by every container in the Pod — the standard pattern for sidecar log tailing. hostPath ties to the node filesystem; PVC RWO is unnecessary overhead for ephemeral logs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment must have a sidecar that tails a log file the main container writes. Which volume type lets both containers share the file inside the Pod?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You taint `node01` with `IT=Kiddie:NoSchedule`. Which toleration on a Pod is necessary and sufficient for it to schedule there?$tv2$, $tv2$[{"id":"a","text":"`{ key: \"IT\", operator: \"Exists\", effect: \"NoExecute\" }`"},{"id":"b","text":"`{ key: \"IT\", operator: \"Equal\", value: \"Kiddie\", effect: \"NoSchedule\" }`"},{"id":"c","text":"`{ key: \"Kiddie\", operator: \"Equal\", value: \"IT\", effect: \"NoSchedule\" }`"},{"id":"d","text":"No toleration is needed; taints affect only existing Pods."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A toleration must match the taint exactly on key/value/effect (or use the Exists operator with matching key + effect). NoSchedule blocks new scheduling; NoExecute additionally evicts running Pods.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You taint `node01` with `IT=Kiddie:NoSchedule`. Which toleration on a Pod is necessary and sufficient for it to schedule there?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You create a PriorityClass `high-priority` with value 9_999_999 and patch Deployment `busybox-logger` to use it. The Pods are not preempting lower-priority Pods. What is the MOST likely cause?$tv2$, $tv2$[{"id":"a","text":"You need to set `preemptionPolicy: Never`."},{"id":"b","text":"The Deployment's existing ReplicaSet still references the old template — restart the rollout (e.g. `kubectl rollout restart deploy busybox-logger`)."},{"id":"c","text":"PriorityClasses below 1_000_000_000 are ignored."},{"id":"d","text":"PriorityClass only affects DaemonSets."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Patching the Deployment spec updates the template but the running Pods belong to the previous ReplicaSet; a `rollout restart` (or any change that creates a new RS) is needed to roll the Pods over with the new priority. Priority is honored on scheduling/preemption.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/pod-priority-preemption/","label":"Kubernetes Docs — Pod Priority and Preemption"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You create a PriorityClass `high-priority` with value 9_999_999 and patch Deployment `busybox-logger` to use it. The Pods are not preempting lower-priority Pods. What is the MOST likely cause?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command exposes Deployment `frontend` on a port reachable on every node's IP at a high (30000–32767) port?$tv2$, $tv2$[{"id":"a","text":"kubectl expose deploy frontend --type=ClusterIP --port=80"},{"id":"b","text":"kubectl expose deploy frontend --type=NodePort --port=80"},{"id":"c","text":"kubectl expose deploy frontend --type=ExternalName --port=80"},{"id":"d","text":"kubectl expose deploy frontend --type=Headless --port=80"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$NodePort allocates a port from `--service-node-port-range` (default 30000–32767) on every node. ClusterIP is internal-only; ExternalName is a CNAME alias; "Headless" is `clusterIP: None`, not a type.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command exposes Deployment `frontend` on a port reachable on every node's IP at a high (30000–32767) port?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress for the nginx-ingress controller routes `/echo` on host `example.org` to Service `echoserver-service:8080`. From outside the cluster on a NodePort install, the correct test command is:$tv2$, $tv2$[{"id":"a","text":"curl http://example.org:80/echo"},{"id":"b","text":"curl -H \"Host: example.org\" http://<node-ip>:<ingress-nodeport>/echo"},{"id":"c","text":"curl http://<service-cluster-ip>:8080/echo"},{"id":"d","text":"curl --resolve example.org:80:127.0.0.1 http://example.org/echo"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Without DNS, you must hit the ingress-nginx controller's NodePort on any node IP and pass `Host: example.org` so the Ingress host rule matches. Hitting the backend Service cluster IP bypasses the Ingress and ignores the path rule.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress for the nginx-ingress controller routes `/echo` on host `example.org` to Service `echoserver-service:8080`. From outside the cluster on a NodePort install, the correct test command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to terminate TLS at the cluster edge using the Gateway API and the nginx-gateway-fabric controller. Which Gateway listener config is correct?$tv2$, $tv2$[{"id":"a","text":"protocol: HTTPS, port: 443, tls.mode: Passthrough, certificateRefs omitted"},{"id":"b","text":"protocol: HTTPS, port: 443, tls.mode: Terminate, certificateRefs: [{ kind: Secret, name: web-tls }]"},{"id":"c","text":"protocol: TLS, port: 443, tls.mode: Terminate, certificateRefs omitted"},{"id":"d","text":"protocol: HTTP, port: 443, tls.mode: Terminate"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$TLS termination requires `tls.mode: Terminate` plus a Secret of type `kubernetes.io/tls` via `certificateRefs`. Passthrough forwards the TLS connection unmodified. Listener protocol must be HTTPS for HTTPRoute attachment.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to terminate TLS at the cluster edge using the Gateway API and the nginx-gateway-fabric controller. Which Gateway listener config is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$A NetworkPolicy in namespace `backend` selects pods labelled `app=backend` and allows ingress from pods labelled `app=frontend` in namespace `frontend`. Select ALL true statements.$tv2$, $tv2$[{"id":"a","text":"The `from` list must combine a namespaceSelector and a podSelector inside a single peer object (AND), not as separate items (OR)."},{"id":"b","text":"Two separate peer items {namespaceSelector}, {podSelector} mean \"any pod from that namespace OR any pod in this namespace with that label\"."},{"id":"c","text":"A CNI implementing NetworkPolicy (e.g. Calico, Cilium) must be installed."},{"id":"d","text":"The policy implicitly allows all egress from the backend pods."}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are true. Combining selectors inside one `from` peer object is AND; separate items are OR. Egress is only restricted if the policy lists `policyTypes: [Egress]`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy in namespace `backend` selects pods labelled `app=backend` and allows ingress from pods labelled `app=frontend` in namespace `frontend`. Select ALL true statements.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which annotation marks a StorageClass as the cluster default?$tv2$, $tv2$[{"id":"a","text":"storageclass.kubernetes.io/is-default-class: \"true\""},{"id":"b","text":"storage.k8s.io/default: \"yes\""},{"id":"c","text":"kubernetes.io/default-sc: \"true\""},{"id":"d","text":"volume.beta.kubernetes.io/default: \"true\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The default StorageClass is identified by the annotation `storageclass.kubernetes.io/is-default-class: "true"`. At most one default should be set at a time; PVCs without `storageClassName` use it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which annotation marks a StorageClass as the cluster default?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PersistentVolume is `Released` with reclaimPolicy `Retain` and a stale `claimRef`. A new PVC matches it on size and storageClassName but binding fails. What MUST you do to allow rebind?$tv2$, $tv2$[{"id":"a","text":"Delete the PV."},{"id":"b","text":"Edit the PV and remove the `spec.claimRef` block."},{"id":"c","text":"Change reclaim policy to `Delete`."},{"id":"d","text":"Scale the workload to zero and back."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A Retained PV keeps its `claimRef` even after the original PVC is gone, blocking new bindings. Remove `claimRef` (and any obsolete `pv.kubernetes.io/bind-completed` annotation) so the PV returns to `Available`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PersistentVolume is `Released` with reclaimPolicy `Retain` and a stale `claimRef`. A new PVC matches it on size and storageClassName but binding fails. What MUST you do to allow rebind?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$On a kubeadm control-plane node, the apiserver static Pod manifest lives at:$tv2$, $tv2$[{"id":"a","text":"/etc/kubernetes/manifests/kube-apiserver.yaml"},{"id":"b","text":"/etc/kubernetes/static/kube-apiserver.yaml"},{"id":"c","text":"/var/lib/kubelet/config/kube-apiserver.yaml"},{"id":"d","text":"/etc/systemd/system/kube-apiserver.service"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$kubeadm places control-plane static Pod manifests in `/etc/kubernetes/manifests/`. The kubelet watches this directory and (re)starts the corresponding Pods as files change.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a kubeadm control-plane node, the apiserver static Pod manifest lives at:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The apiserver is down because `--etcd-servers=https://127.0.0.1:2380` was set in the static Pod manifest. Which is the correct fix?$tv2$, $tv2$[{"id":"a","text":"Set `--etcd-servers=https://127.0.0.1:2379` (etcd client port) in /etc/kubernetes/manifests/kube-apiserver.yaml"},{"id":"b","text":"Restart docker"},{"id":"c","text":"Run `kubeadm reset`"},{"id":"d","text":"Add `--insecure-port=8080` to the manifest"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$etcd serves clients on **2379** and peer traffic on **2380**. The apiserver must connect to the client port. After saving the manifest the kubelet recreates the static Pod automatically.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"},{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The apiserver is down because `--etcd-servers=https://127.0.0.1:2380` was set in the static Pod manifest. Which is the correct fix?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A pod is in `Pending` with the event "0/3 nodes are available: 3 node(s) had untolerated taint {node-role.kubernetes.io/control-plane: }". The fix that is MOST appropriate for a normal workload is:$tv2$, $tv2$[{"id":"a","text":"Add a toleration for the control-plane taint to the Pod."},{"id":"b","text":"Schedule the Pod on a worker node by removing the nodeSelector or adding a worker label."},{"id":"c","text":"Remove the control-plane taint from all nodes."},{"id":"d","text":"Set `spec.hostNetwork: true`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The control-plane taint exists to keep general workloads off the control plane. Either add a worker to the cluster or remove the targeting constraint that forces it onto control plane. Removing the taint cluster-wide is bad practice for production.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A pod is in `Pending` with the event "0/3 nodes are available: 3 node(s) had untolerated taint {node-role.kubernetes.io/control-plane: }". The fix that is MOST appropriate for a normal workload is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$`kubectl logs <pod>` returns "Error from server (BadRequest): previous terminated container ... not found". The container has only ever started once and is currently Running. Which flag explains the error?$tv2$, $tv2$[{"id":"a","text":"--follow"},{"id":"b","text":"--previous"},{"id":"c","text":"--tail=0"},{"id":"d","text":"--all-containers"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--previous` asks the kubelet for the prior instance's logs, which only exist after at least one restart. The fix is to drop `--previous` (or wait for a restart).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl logs <pod>` returns "Error from server (BadRequest): previous terminated container ... not found". The container has only ever started once and is currently Running. Which flag explains the error?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A node is `NotReady`. You SSH in and check `systemctl status kubelet` — it is failing to start with "open /var/lib/kubelet/config.yaml: no such file". The MOST likely root cause is:$tv2$, $tv2$[{"id":"a","text":"The container runtime is not installed."},{"id":"b","text":"The node was never bootstrapped via `kubeadm join` (or its config was deleted)."},{"id":"c","text":"kube-proxy is crashing."},{"id":"d","text":"CoreDNS is misconfigured."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubeadm join` writes `/var/lib/kubelet/config.yaml` from the cluster's kubelet-config ConfigMap. If absent, the node has not been joined or its files were removed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A node is `NotReady`. You SSH in and check `systemctl status kubelet` — it is failing to start with "open /var/lib/kubelet/config.yaml: no such file". The MOST likely root cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A pod has `requests.memory: 200Mi, limits.memory: 256Mi`. It restarts with `OOMKilled` under load. Which is the safest first remediation?$tv2$, $tv2$[{"id":"a","text":"Increase the memory LIMIT after profiling."},{"id":"b","text":"Increase the memory REQUEST only."},{"id":"c","text":"Add `--oom-score-adj=-1000` to the kubelet."},{"id":"d","text":"Disable the liveness probe."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$OOMKilled means the container exceeded its `limits.memory`. Profile actual usage and raise the limit. Increasing only the request changes scheduling but not the cgroup memory cap.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A pod has `requests.memory: 200Mi, limits.memory: 256Mi`. It restarts with `OOMKilled` under load. Which is the safest first remediation?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Before running `kubeadm init`, swap must be disabled. Which command disables it for the current boot?$tv2$, $tv2$[{"id":"a","text":"swapoff -a"},{"id":"b","text":"systemctl disable swap"},{"id":"c","text":"kubeadm config swap off"},{"id":"d","text":"sysctl -w vm.swappiness=0"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`swapoff -a` disables all swap immediately. To persist across reboots you also comment the swap entry in `/etc/fstab`. `vm.swappiness=0` only discourages swapping; it does not disable it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Before running `kubeadm init`, swap must be disabled. Which command disables it for the current boot?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command prints the join command (with token and CA hash) for adding a new worker to an existing kubeadm cluster?$tv2$, $tv2$[{"id":"a","text":"kubeadm token create --print-join-command"},{"id":"b","text":"kubeadm join --generate"},{"id":"c","text":"kubectl get token -n kube-system"},{"id":"d","text":"kubeadm init phase bootstrap-token"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubeadm token create --print-join-command` mints a fresh bootstrap token and prints the full `kubeadm join` line including `--discovery-token-ca-cert-hash`. Tokens default to a 24h TTL.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command prints the join command (with token and CA hash) for adding a new worker to an existing kubeadm cluster?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You must give ServiceAccount `ci` in namespace `build` permission to create Jobs in that namespace only. The correct binding subject is:$tv2$, $tv2$[{"id":"a","text":"kind: User, name: ci"},{"id":"b","text":"kind: ServiceAccount, name: ci, namespace: build"},{"id":"c","text":"kind: Group, name: system:serviceaccounts"},{"id":"d","text":"kind: ServiceAccount, name: system:ci"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A RoleBinding subject for a ServiceAccount uses `kind: ServiceAccount` with the `name` and `namespace`. Binding to the broad `system:serviceaccounts` group would over-grant to every SA.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You must give ServiceAccount `ci` in namespace `build` permission to create Jobs in that namespace only. The correct binding subject is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After editing `/etc/kubernetes/manifests/kube-apiserver.yaml`, how does the change take effect?$tv2$, $tv2$[{"id":"a","text":"Run `systemctl restart kube-apiserver`."},{"id":"b","text":"The kubelet detects the file change and recreates the static Pod automatically."},{"id":"c","text":"Run `kubectl rollout restart -n kube-system deploy/kube-apiserver`."},{"id":"d","text":"Run `kubeadm upgrade apply`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The kubelet watches `/etc/kubernetes/manifests/` and restarts the corresponding static Pod whenever the manifest changes. There is no systemd unit or Deployment for control-plane components on kubeadm clusters.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After editing `/etc/kubernetes/manifests/kube-apiserver.yaml`, how does the change take effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which etcdctl invocation correctly takes a snapshot when etcd uses client TLS certificates?$tv2$, $tv2$[{"id":"a","text":"ETCDCTL_API=3 etcdctl snapshot save /backup/snap.db --endpoints=https://127.0.0.1:2379 --cacert=/etc/kubernetes/pki/etcd/ca.crt --cert=/etc/kubernetes/pki/etcd/server.crt --key=/etc/kubernetes/pki/etcd/server.key"},{"id":"b","text":"etcdctl backup --data-dir /var/lib/etcd"},{"id":"c","text":"kubectl exec etcd -- snapshot save"},{"id":"d","text":"ETCDCTL_API=2 etcdctl snapshot save /backup/snap.db"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$API v3 snapshots require `--endpoints` plus the CA, client cert, and key. The legacy `etcdctl backup` and API v2 do not produce a v3 snapshot usable by `snapshot restore`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which etcdctl invocation correctly takes a snapshot when etcd uses client TLS certificates?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to cordon `node01` so the scheduler stops placing NEW Pods there but existing Pods keep running. The command is:$tv2$, $tv2$[{"id":"a","text":"kubectl drain node01"},{"id":"b","text":"kubectl cordon node01"},{"id":"c","text":"kubectl taint node node01 key=val:NoExecute"},{"id":"d","text":"kubectl delete node node01"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl cordon` marks the node `SchedulingDisabled` without evicting Pods. `drain` additionally evicts Pods; a NoExecute taint would evict non-tolerating Pods.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to cordon `node01` so the scheduler stops placing NEW Pods there but existing Pods keep running. The command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You must restore an etcd snapshot to recover a cluster. Before pointing the etcd static Pod at the restored data directory, you should:$tv2$, $tv2$[{"id":"a","text":"Leave the apiserver running so it can replay the WAL."},{"id":"b","text":"Stop the kube-apiserver (move its manifest out of /etc/kubernetes/manifests) so it does not write during the restore."},{"id":"c","text":"Delete /var/lib/kubelet."},{"id":"d","text":"Run `kubeadm reset` first."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$During an etcd restore the apiserver must not be writing to etcd. Moving the apiserver (and etcd) static-Pod manifests out, performing the restore, then restoring the manifests is the safe sequence.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You must restore an etcd snapshot to recover a cluster. Before pointing the etcd static Pod at the restored data directory, you should:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$On the first control-plane node you run `kubeadm upgrade apply v1.32.1`. To upgrade an additional control-plane node you then run:$tv2$, $tv2$[{"id":"a","text":"kubeadm upgrade apply v1.32.1 again"},{"id":"b","text":"kubeadm upgrade node"},{"id":"c","text":"kubeadm init --upgrade"},{"id":"d","text":"kubeadm join --upgrade"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Only the first control-plane node runs `kubeadm upgrade apply`. Every other control-plane and worker node runs `kubeadm upgrade node`, then upgrades the kubelet/kubectl packages.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/kubeadm/kubeadm-upgrade/","label":"Kubernetes Docs — Upgrading kubeadm clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On the first control-plane node you run `kubeadm upgrade apply v1.32.1`. To upgrade an additional control-plane node you then run:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows whether control-plane component certificates managed by kubeadm are close to expiring?$tv2$, $tv2$[{"id":"a","text":"kubeadm certs check-expiration"},{"id":"b","text":"kubectl get certificates -A"},{"id":"c","text":"openssl verify /etc/kubernetes/admin.conf"},{"id":"d","text":"kubeadm config view"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubeadm certs check-expiration` lists every kubeadm-managed certificate and its expiry. `kubeadm certs renew` renews them. `kubectl get certificates` lists cert-manager CRs, not control-plane PKI.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows whether control-plane component certificates managed by kubeadm are close to expiring?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about kubeconfig files.$tv2$, $tv2$[{"id":"a","text":"A context binds a cluster, a user, and an optional namespace."},{"id":"b","text":"`kubectl config use-context <name>` switches the active context."},{"id":"c","text":"Client certificate data can be embedded base64 or referenced by file path."},{"id":"d","text":"The KUBECONFIG env var can merge multiple kubeconfig files."}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are correct. A context ties cluster+user(+namespace); `use-context` switches; credentials may be inline (`*-data`) or file paths; `KUBECONFIG=a:b:c` merges files at load time.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about kubeconfig files.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$On a default kubeadm cluster, kube-scheduler and kube-controller-manager run as Deployments in the kube-system namespace.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. They run as static Pods managed by the kubelet from `/etc/kubernetes/manifests/`, not as Deployments. Only add-ons like CoreDNS run as Deployments.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a default kubeadm cluster, kube-scheduler and kube-controller-manager run as Deployments in the kube-system namespace.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command scales Deployment `web` to 5 replicas imperatively?$tv2$, $tv2$[{"id":"a","text":"kubectl scale deploy web --replicas=5"},{"id":"b","text":"kubectl edit deploy web --replicas=5"},{"id":"c","text":"kubectl set replicas deploy/web 5"},{"id":"d","text":"kubectl patch deploy web --replicas 5"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl scale deploy web --replicas=5` directly updates the replica count. `kubectl set` has no `replicas` subcommand and `patch` needs a JSON/strategic merge body.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command scales Deployment `web` to 5 replicas imperatively?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must only schedule on nodes labelled `disktype=ssd`. The simplest spec field is:$tv2$, $tv2$[{"id":"a","text":"spec.nodeName: ssd"},{"id":"b","text":"spec.nodeSelector: { disktype: ssd }"},{"id":"c","text":"spec.tolerations"},{"id":"d","text":"spec.priorityClassName: ssd"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`nodeSelector` is the simplest hard node-constraint, matching node labels exactly. `nodeName` pins to one specific node by name; tolerations relate to taints, not labels.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must only schedule on nodes labelled `disktype=ssd`. The simplest spec field is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A CronJob should run every 5 minutes. The correct `schedule` value is:$tv2$, $tv2$[{"id":"a","text":"\"*/5 * * * *\""},{"id":"b","text":"\"5 * * * *\""},{"id":"c","text":"\"@every5m\""},{"id":"d","text":"\"0/5 0 0 0 0\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CronJob uses standard cron syntax: `*/5 * * * *` means "every 5th minute". `5 * * * *` runs once per hour at minute 5.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A CronJob should run every 5 minutes. The correct `schedule` value is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to roll back Deployment `api` to its previous revision after a bad image. The command is:$tv2$, $tv2$[{"id":"a","text":"kubectl rollout undo deploy/api"},{"id":"b","text":"kubectl rollout pause deploy/api"},{"id":"c","text":"kubectl delete deploy api && kubectl apply -f api.yaml"},{"id":"d","text":"kubectl set image deploy/api api=previous"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl rollout undo deploy/api` reverts to the prior ReplicaSet revision. Add `--to-revision=N` for a specific revision (see `kubectl rollout history`).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to roll back Deployment `api` to its previous revision after a bad image. The command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about static Pods.$tv2$, $tv2$[{"id":"a","text":"They are defined by manifest files in the kubelet `staticPodPath` (default /etc/kubernetes/manifests)."},{"id":"b","text":"The apiserver creates a read-only mirror Pod so they appear in `kubectl get pods`."},{"id":"c","text":"You can delete a static Pod with `kubectl delete pod` permanently."},{"id":"d","text":"They are managed directly by the kubelet, not by a controller."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Deleting the mirror Pod via kubectl does NOT remove a static Pod — the kubelet recreates it; you must remove the manifest file. The other statements are correct.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about static Pods.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment uses `strategy.type: Recreate`. During an image update, the rollout behavior is:$tv2$, $tv2$[{"id":"a","text":"New Pods come up before old Pods are terminated."},{"id":"b","text":"All old Pods are terminated first, then new Pods are created (brief downtime)."},{"id":"c","text":"One Pod at a time is replaced."},{"id":"d","text":"The update is rejected — Recreate is invalid for Deployments."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `Recreate` strategy kills all existing Pods before creating new ones, causing a short outage. `RollingUpdate` is the default that avoids downtime via surge/unavailable controls.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment uses `strategy.type: Recreate`. During an image update, the rollout behavior is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A Job with `completions: 5` and `parallelism: 2` runs at most 2 Pods at a time until 5 succeed.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. `parallelism` caps concurrent Pods; `completions` is the total number of successful Pod runs required before the Job is complete.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Job with `completions: 5` and `parallelism: 2` runs at most 2 Pods at a time until 5 succeed.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A Service of type ClusterIP is reachable:$tv2$, $tv2$[{"id":"a","text":"only from within the cluster"},{"id":"b","text":"from any external client on the node IP"},{"id":"c","text":"only from the control-plane nodes"},{"id":"d","text":"from the internet via the cloud load balancer"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$ClusterIP is the default type and is reachable only from inside the cluster (Pods/Nodes). External exposure requires NodePort, LoadBalancer, or an Ingress/Gateway.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service of type ClusterIP is reachable:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$CoreDNS runs in kube-system. To verify in-cluster DNS, you exec a debug Pod and run:$tv2$, $tv2$[{"id":"a","text":"nslookup kubernetes.default.svc.cluster.local"},{"id":"b","text":"ping coredns"},{"id":"c","text":"curl http://kube-dns:53"},{"id":"d","text":"kubectl dns test"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Resolving `kubernetes.default.svc.cluster.local` from a Pod confirms CoreDNS and the kube-dns Service work. ICMP/HTTP against DNS does not validate name resolution.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$CoreDNS runs in kube-system. To verify in-cluster DNS, you exec a debug Pod and run:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A ClusterIP Service has a selector `app=web` but no endpoints appear. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"No running Pods carry the label `app=web` (or they are not Ready)."},{"id":"b","text":"kube-proxy is not installed."},{"id":"c","text":"The Service needs a NodePort."},{"id":"d","text":"CoreDNS is down."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Endpoints (EndpointSlices) are populated from Ready Pods matching the selector. A label mismatch or unready Pods yields an empty endpoint list and connection failures.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A ClusterIP Service has a selector `app=web` but no endpoints appear. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress resource exists but returns nothing. `kubectl get ingress` shows an empty ADDRESS column. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"No Ingress controller is installed/running to satisfy the Ingress."},{"id":"b","text":"The Service is ClusterIP."},{"id":"c","text":"TLS is not configured."},{"id":"d","text":"The path type is Prefix."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$An Ingress object is inert without a controller (ingress-nginx, etc.) watching and programming it. No controller means no ADDRESS and no routing.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress resource exists but returns nothing. `kubectl get ingress` shows an empty ADDRESS column. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need an Ingress path that matches `/app` and any sub-path like `/app/x`. The pathType should be:$tv2$, $tv2$[{"id":"a","text":"Exact"},{"id":"b","text":"Prefix"},{"id":"c","text":"ImplementationSpecific only"},{"id":"d","text":"Regex"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`Prefix` matches the path element prefix, so `/app` also matches `/app/x`. `Exact` requires an exact string match; `Regex` is not a valid pathType value.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need an Ingress path that matches `/app` and any sub-path like `/app/x`. The pathType should be:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy should allow ingress to `app=db` Pods ONLY on TCP 5432. The rule includes:$tv2$, $tv2$[{"id":"a","text":"ports: [{ protocol: TCP, port: 5432 }] under an ingress rule"},{"id":"b","text":"egress: [{ ports: [{ port: 5432 }] }]"},{"id":"c","text":"policyTypes: [Egress] only"},{"id":"d","text":"a Service annotation `allow-port: 5432`"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Port restrictions are declared in the `ports` list of an ingress (or egress) rule. Combined with a `from` peer this allows only matching sources on TCP 5432.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy should allow ingress to `app=db` Pods ONLY on TCP 5432. The rule includes:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Service type creates a DNS CNAME to an external hostname with no proxying?$tv2$, $tv2$[{"id":"a","text":"ClusterIP"},{"id":"b","text":"NodePort"},{"id":"c","text":"ExternalName"},{"id":"d","text":"LoadBalancer"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$`ExternalName` returns a CNAME record to the configured `externalName` hostname; kube-proxy does not proxy traffic and no cluster IP is allocated.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Service type creates a DNS CNAME to an external hostname with no proxying?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about kube-proxy.$tv2$, $tv2$[{"id":"a","text":"It programs iptables (or IPVS) rules to implement Service virtual IPs."},{"id":"b","text":"It typically runs as a DaemonSet on every node."},{"id":"c","text":"It resolves Service DNS names."},{"id":"d","text":"In IPVS mode it provides additional load-balancing algorithms."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$DNS resolution is CoreDNS, not kube-proxy. kube-proxy implements Service VIP routing via iptables/IPVS and runs as a per-node DaemonSet; IPVS adds algorithms like rr/lc.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about kube-proxy.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A headless Service is created by setting `spec.clusterIP: None`.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. With `clusterIP: None` and a selector, DNS returns the individual Pod A records instead of a single virtual IP — the basis for StatefulSet stable Pod DNS.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A headless Service is created by setting `spec.clusterIP: None`.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A PVC stays `Pending` and `kubectl describe pvc` shows "no persistent volumes available for this claim and no storage class is set". The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"No matching PV exists and no (default) StorageClass can dynamically provision one."},{"id":"b","text":"The Pod is not scheduled."},{"id":"c","text":"reclaimPolicy is Retain."},{"id":"d","text":"The PVC requested ReadWriteMany."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Without a matching pre-provisioned PV and with no StorageClass (or default) for dynamic provisioning, the PVC cannot bind and stays Pending.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC stays `Pending` and `kubectl describe pvc` shows "no persistent volumes available for this claim and no storage class is set". The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PV has `persistentVolumeReclaimPolicy: Delete`. When its bound PVC is deleted:$tv2$, $tv2$[{"id":"a","text":"The PV becomes Available for reuse."},{"id":"b","text":"The PV and the underlying storage asset are deleted."},{"id":"c","text":"The PV becomes Released and is retained."},{"id":"d","text":"Nothing happens until the node reboots."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$With `Delete`, removing the PVC also deletes the PV object and the backing volume (for dynamically provisioned volumes). `Retain` keeps both for manual reclamation.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PV has `persistentVolumeReclaimPolicy: Delete`. When its bound PVC is deleted:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Multiple Pods across different nodes must write to the same volume simultaneously. The PVC accessMode must be:$tv2$, $tv2$[{"id":"a","text":"ReadWriteOnce"},{"id":"b","text":"ReadWriteMany"},{"id":"c","text":"ReadOnlyMany"},{"id":"d","text":"ReadWriteOncePod"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$ReadWriteMany allows multiple nodes to mount the volume read-write (e.g. NFS/CephFS). ReadWriteOnce is single-node; ReadWriteOncePod restricts to a single Pod.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Multiple Pods across different nodes must write to the same volume simultaneously. The PVC accessMode must be:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To mount a ConfigMap key `app.conf` as a file at `/etc/app/app.conf`, you use:$tv2$, $tv2$[{"id":"a","text":"a configMap volume with an items[] mapping plus a volumeMount"},{"id":"b","text":"an emptyDir volume"},{"id":"c","text":"env.valueFrom.configMapKeyRef"},{"id":"d","text":"a hostPath volume"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A `configMap` volume (optionally with `items` to map specific keys to paths) mounted via `volumeMounts` projects the data as files. `configMapKeyRef` injects it as an env var, not a file.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To mount a ConfigMap key `app.conf` as a file at `/etc/app/app.conf`, you use:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A PVC with accessMode ReadWriteOnce can be mounted read-write by Pods on only one node at a time.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. ReadWriteOnce permits read-write mounting by one node; multiple Pods on that same node may share it. Cross-node concurrent write needs ReadWriteMany.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC with accessMode ReadWriteOnce can be mounted read-write by Pods on only one node at a time.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows recent cluster events sorted by time to triage a failing Pod?$tv2$, $tv2$[{"id":"a","text":"kubectl get events --sort-by=.metadata.creationTimestamp"},{"id":"b","text":"kubectl logs events"},{"id":"c","text":"kubectl top events"},{"id":"d","text":"journalctl -u events"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get events --sort-by=.metadata.creationTimestamp` lists events chronologically. `kubectl describe pod` shows events scoped to one object.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows recent cluster events sorted by time to triage a failing Pod?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod is `CrashLoopBackOff`. The single most useful command to see why the container exits is:$tv2$, $tv2$[{"id":"a","text":"kubectl logs <pod> --previous"},{"id":"b","text":"kubectl get pod <pod> -o wide"},{"id":"c","text":"kubectl top pod <pod>"},{"id":"d","text":"kubectl edit pod <pod>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CrashLoopBackOff means the container repeatedly exits; `kubectl logs --previous` shows the last terminated container's output (the actual error), since the current instance may not be running.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is `CrashLoopBackOff`. The single most useful command to see why the container exits is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A node shows `MemoryPressure=True` and Pods are being evicted. The first investigative command on the node is:$tv2$, $tv2$[{"id":"a","text":"kubectl describe node <node> (review conditions and allocatable)"},{"id":"b","text":"kubectl delete node <node>"},{"id":"c","text":"systemctl restart docker"},{"id":"d","text":"kubeadm reset"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe node` reveals the conditions, allocatable resources, and eviction events so you can identify memory exhaustion before taking action.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A node shows `MemoryPressure=True` and Pods are being evicted. The first investigative command on the node is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod is stuck `Terminating` for a long time after deletion. A common safe cause to check first is:$tv2$, $tv2$[{"id":"a","text":"A finalizer on the Pod (or the node is unreachable so the kubelet cannot confirm deletion)."},{"id":"b","text":"The apiserver is down."},{"id":"c","text":"etcd is corrupted."},{"id":"d","text":"kube-proxy crashed."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Pods stuck Terminating are usually waiting on a finalizer or a NotReady/unreachable node where the kubelet cannot confirm container shutdown. `--force --grace-period=0` is the last-resort removal.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is stuck `Terminating` for a long time after deletion. A common safe cause to check first is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to run an interactive shell in a running Pod's container to debug. The command is:$tv2$, $tv2$[{"id":"a","text":"kubectl exec -it <pod> -- /bin/sh"},{"id":"b","text":"kubectl attach <pod>"},{"id":"c","text":"kubectl run <pod> -- sh"},{"id":"d","text":"kubectl debug <pod> --shell"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl exec -it <pod> -- /bin/sh` opens an interactive TTY in the container. `attach` connects to the existing process stdio; `kubectl debug` creates an ephemeral debug container (different use).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to run an interactive shell in a running Pod's container to debug. The command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod stays `Pending` and describe shows "Insufficient cpu". The remediation is:$tv2$, $tv2$[{"id":"a","text":"Lower the Pod CPU requests or add a node with more allocatable CPU."},{"id":"b","text":"Increase the Pod CPU limit."},{"id":"c","text":"Restart kube-scheduler."},{"id":"d","text":"Add a toleration."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$"Insufficient cpu" means no node has enough allocatable CPU to satisfy the Pod's requests. Reduce requests or add capacity. Limits do not affect scheduling feasibility.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod stays `Pending` and describe shows "Insufficient cpu". The remediation is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After `kubectl apply`, a container is `RunContainerError` with "exec: \"./start.sh\": permission denied". The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"The entrypoint script is not executable / wrong command in the image or spec."},{"id":"b","text":"NetworkPolicy blocks startup."},{"id":"c","text":"The node is NotReady."},{"id":"d","text":"The Service selector is wrong."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$RunContainerError with a permission/exec message points to a bad command, missing executable bit, or wrong path in the image or `command`/`args`. Fix the image or the Pod command.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After `kubectl apply`, a container is `RunContainerError` with "exec: \"./start.sh\": permission denied". The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$kubelet on a worker is healthy but the node is `NotReady` and `kubectl describe node` shows `NetworkUnavailable=True`. The likely cause is:$tv2$, $tv2$[{"id":"a","text":"The CNI plugin is not installed or its Pods are failing on that node."},{"id":"b","text":"The apiserver cert expired."},{"id":"c","text":"Swap is enabled."},{"id":"d","text":"kubectl is the wrong version."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`NetworkUnavailable=True` indicates the node network (CNI) is not set up. Check the CNI DaemonSet Pods (Calico/Flannel/etc.) on that node and their logs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$kubelet on a worker is healthy but the node is `NotReady` and `kubectl describe node` shows `NetworkUnavailable=True`. The likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$The kube-apiserver static Pod keeps restarting. Which log source should you check directly on the control-plane node?$tv2$, $tv2$[{"id":"a","text":"crictl logs of the apiserver container (or /var/log/pods/...)"},{"id":"b","text":"kubectl logs -n kube-system deploy/kube-apiserver"},{"id":"c","text":"systemctl status kube-apiserver"},{"id":"d","text":"kubectl get events only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When the apiserver is down, kubectl cannot reach it, so inspect the container directly via `crictl ps -a` / `crictl logs` or `/var/log/pods`. There is no apiserver Deployment or systemd unit.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The kube-apiserver static Pod keeps restarting. Which log source should you check directly on the control-plane node?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A liveness probe is restarting a healthy container repeatedly. The MOST likely misconfiguration is:$tv2$, $tv2$[{"id":"a","text":"initialDelaySeconds is too small / probe path or port is wrong."},{"id":"b","text":"The container has no readiness probe."},{"id":"c","text":"The Service is ClusterIP."},{"id":"d","text":"The image is too large."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A liveness probe firing before the app is ready (low initialDelaySeconds) or pointed at the wrong path/port causes endless restarts. Tune the delay/threshold or fix the probe target.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A liveness probe is restarting a healthy container repeatedly. The MOST likely misconfiguration is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You must collect metrics with `kubectl top nodes` but it returns "Metrics API not available". The fix is:$tv2$, $tv2$[{"id":"a","text":"Install/repair the metrics-server in the cluster."},{"id":"b","text":"Restart kube-proxy."},{"id":"c","text":"Enable the dashboard."},{"id":"d","text":"Set --enable-metrics on kubectl."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl top` depends on the metrics-server serving the metrics.k8s.io API. If it is not installed or unhealthy, `top` fails. Deploy/fix metrics-server.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You must collect metrics with `kubectl top nodes` but it returns "Metrics API not available". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$A worker node is NotReady. Select ALL valid first-step checks.$tv2$, $tv2$[{"id":"a","text":"`systemctl status kubelet` and `journalctl -u kubelet` on the node."},{"id":"b","text":"`kubectl describe node <node>` for conditions and events."},{"id":"c","text":"Verify the container runtime (`crictl info` / `systemctl status containerd`)."},{"id":"d","text":"Immediately run `kubeadm reset` on the node."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Inspect the kubelet, node conditions, and the runtime first. `kubeadm reset` destroys node state and is never an appropriate first diagnostic step.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"},{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A worker node is NotReady. Select ALL valid first-step checks.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$When the kube-apiserver is unreachable, `kubectl logs` can still retrieve container logs.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. `kubectl logs` proxies through the apiserver to the kubelet. If the apiserver is down you must read logs on the node via `crictl logs` or `/var/log/pods`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$When the kube-apiserver is unreachable, `kubectl logs` can still retrieve container logs.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$On a kubeadm cluster, what is the recommended order to upgrade the control plane minor version?$tv2$, $tv2$[{"id":"a","text":"kubelet → kubeadm → kubectl → apply"},{"id":"b","text":"kubeadm upgrade plan → kubeadm upgrade apply <ver> → upgrade kubelet & kubectl"},{"id":"c","text":"kubectl drain → kubeadm reset → kubeadm init"},{"id":"d","text":"helm upgrade kubernetes"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Always run `kubeadm upgrade plan` first to confirm the target version, then `kubeadm upgrade apply` on the first control-plane node, then upgrade kubelet/kubectl. Workers follow afterwards with `kubeadm upgrade node`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/kubeadm/kubeadm-upgrade/","label":"Kubernetes Docs — Upgrading kubeadm clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a kubeadm cluster, what is the recommended order to upgrade the control plane minor version?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You back up etcd with `ETCDCTL_API=3 etcdctl snapshot save /backup/snap.db`. To restore on a new control plane you should:$tv2$, $tv2$[{"id":"a","text":"Copy snap.db into /var/lib/etcd and restart etcd."},{"id":"b","text":"Run `etcdctl snapshot restore /backup/snap.db --data-dir=/var/lib/etcd-from-backup` then point the etcd static pod at the new data-dir."},{"id":"c","text":"kubectl apply -f snap.db"},{"id":"d","text":"systemctl restart etcd — it auto-detects snapshots"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Restore writes a brand-new data directory; you then update the etcd static Pod's `--data-dir` (and hostPath volume) to that directory. Simply copying the snapshot file is not a valid restore.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You back up etcd with `ETCDCTL_API=3 etcdctl snapshot save /backup/snap.db`. To restore on a new control plane you should:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Role permits read-only access to ConfigMaps in one namespace?$tv2$, $tv2$[{"id":"a","text":"apiGroups: [\"\"], resources: [\"configmaps\"], verbs: [\"get\",\"list\",\"watch\"]"},{"id":"b","text":"apiGroups: [\"*\"], resources: [\"*\"], verbs: [\"*\"]"},{"id":"c","text":"apiGroups: [\"rbac.authorization.k8s.io\"], resources: [\"configmaps\"], verbs: [\"read\"]"},{"id":"d","text":"apiGroups: [\"core/v1\"], resources: [\"configmap\"], verbs: [\"view\"]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$ConfigMaps are in the core API group (the empty string). Read-only verbs are `get`, `list`, `watch`. Roles vs ClusterRoles differ in scope; this would be a Role for one namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Role permits read-only access to ConfigMaps in one namespace?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command installs Calico via its tigera-operator manifest?$tv2$, $tv2$[{"id":"a","text":"kubectl create -f https://raw.githubusercontent.com/projectcalico/calico/v3.29.2/manifests/tigera-operator.yaml"},{"id":"b","text":"kubeadm init --pod-network-cni=calico"},{"id":"c","text":"helm install calico stable/calico"},{"id":"d","text":"kubectl plugin install calico"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Modern Calico installs in two steps: apply `tigera-operator.yaml`, then `custom-resources.yaml` for the operator to roll out the dataplane. There is no `kubectl plugin install calico` command.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command installs Calico via its tigera-operator manifest?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Across a cluster the kubelet must be configured to set `--cluster-dns=10.96.0.10`. On a kubeadm cluster the canonical place to change this is:$tv2$, $tv2$[{"id":"a","text":"Edit /var/lib/kubelet/config.yaml on each node manually."},{"id":"b","text":"Edit the `kubelet-config` ConfigMap in kube-system; nodes pick it up after a kubelet restart (or `kubeadm upgrade node`)."},{"id":"c","text":"Edit /etc/systemd/system/kubelet.service.d/10-kubeadm.conf"},{"id":"d","text":"Run `kubectl set cluster-dns 10.96.0.10`"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$kubeadm centralizes kubelet config in the `kubelet-config` ConfigMap; `kubeadm upgrade node` regenerates the on-node config from it. Hand-editing per-node config drifts and is overwritten on the next upgrade.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Across a cluster the kubelet must be configured to set `--cluster-dns=10.96.0.10`. On a kubeadm cluster the canonical place to change this is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A wordpress Deployment in namespace `relative-fawn` must request 247m CPU and 5417Mi memory per container. The cleanest way to add resource requests to a running Deployment is:$tv2$, $tv2$[{"id":"a","text":"kubectl scale deploy wordpress --replicas=0; edit the Deployment to add `resources.requests`; scale back up."},{"id":"b","text":"kubectl patch pod ..."},{"id":"c","text":"Delete the namespace and re-apply."},{"id":"d","text":"Use a LimitRange — Deployment spec does not support resources."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Editing `spec.template.spec.containers[].resources.requests` on the Deployment is the right pattern; scaling to 0 first avoids partial rollout churn. Patching individual Pods is ignored — they belong to a ReplicaSet.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A wordpress Deployment in namespace `relative-fawn` must request 247m CPU and 5417Mi memory per container. The cleanest way to add resource requests to a running Deployment is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An HPA targets a Deployment with `minReplicas: 1, maxReplicas: 4, averageUtilization: 50% CPU` and `behavior.scaleDown.stabilizationWindowSeconds: 30`. What does the stabilization window do?$tv2$, $tv2$[{"id":"a","text":"Waits 30s of sustained low load before each scale-down to dampen flapping."},{"id":"b","text":"Caps scale-down to 30s total."},{"id":"c","text":"Disables scaling for the first 30s."},{"id":"d","text":"Waits 30s between Pod terminations."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The stabilization window is the look-back used to pick the highest recommended replicas — for scale-down a longer window dampens reactions to brief utilization dips.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale/","label":"Kubernetes Docs — Horizontal Pod Autoscaling"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An HPA targets a Deployment with `minReplicas: 1, maxReplicas: 4, averageUtilization: 50% CPU` and `behavior.scaleDown.stabilizationWindowSeconds: 30`. What does the stabilization window do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about DaemonSets.$tv2$, $tv2$[{"id":"a","text":"A DaemonSet ensures one (or some) Pod runs on every matching node."},{"id":"b","text":"DaemonSet Pods bypass the default scheduler; the kubelet binds them directly."},{"id":"c","text":"Adding a node automatically creates a Pod from the DaemonSet on that node."},{"id":"d","text":"A DaemonSet works well for node-level agents (CNI, log collectors, monitoring)."}]$tv2$::jsonb, $tv2$["a","c","d"]$tv2$::jsonb, $tv2$Since k8s 1.17 the default scheduler IS used for DaemonSet Pods (controller adds NodeAffinity); they are no longer scheduled directly by the kubelet. The other three are textbook DaemonSet properties.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/","label":"Kubernetes Docs — DaemonSet"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about DaemonSets.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Service `db` in namespace `production` is addressed by Pods in namespace `web` as:$tv2$, $tv2$[{"id":"a","text":"db"},{"id":"b","text":"db.web.svc.cluster.local"},{"id":"c","text":"db.production.svc.cluster.local"},{"id":"d","text":"production.db.cluster.local"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Cross-namespace DNS uses `<svc>.<ns>.svc.cluster.local`. Same-namespace short names (`db`) resolve via the DNS search list.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Service `db` in namespace `production` is addressed by Pods in namespace `web` as:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You replace an Ingress with a Gateway+HTTPRoute. The HTTPRoute must select an existing Gateway. Which field links them?$tv2$, $tv2$[{"id":"a","text":"spec.gatewayName"},{"id":"b","text":"spec.parentRefs"},{"id":"c","text":"metadata.ownerReferences"},{"id":"d","text":"spec.controller"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$HTTPRoute uses `spec.parentRefs` (a list of objects) to attach to one or more Gateways/listeners. There is no `gatewayName` field on HTTPRoute.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You replace an Ingress with a Gateway+HTTPRoute. The HTTPRoute must select an existing Gateway. Which field links them?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A LoadBalancer Service stays `Pending`. The cluster is bare-metal. The MOST appropriate fix is:$tv2$, $tv2$[{"id":"a","text":"Wait — kube-controller-manager will create the load balancer eventually."},{"id":"b","text":"Install a bare-metal LB provider such as MetalLB or kube-vip."},{"id":"c","text":"Switch the Service to ExternalName."},{"id":"d","text":"Set `externalTrafficPolicy: Local`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Cloud LoadBalancers are reconciled by a cloud-controller. On bare metal you need MetalLB / kube-vip / similar to allocate external IPs. `externalTrafficPolicy` only affects packet routing, not allocation.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A LoadBalancer Service stays `Pending`. The cluster is bare-metal. The MOST appropriate fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$CoreDNS pods are CrashLoopBackOff with "Loop (127.0.0.1:53 -> :53) detected for zone .". The fix is:$tv2$, $tv2$[{"id":"a","text":"Delete CoreDNS Pods — the issue is transient."},{"id":"b","text":"In the CoreDNS Corefile, replace the upstream `forward . /etc/resolv.conf` with explicit upstream resolvers (e.g. 8.8.8.8) so it does not forward to itself."},{"id":"c","text":"Disable kube-proxy."},{"id":"d","text":"Set Pod DNS policy to `None`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A loop occurs when the node's /etc/resolv.conf points to a local resolver that itself forwards to CoreDNS. Replace the forward target with the actual upstream DNS or fix the host resolv.conf.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$CoreDNS pods are CrashLoopBackOff with "Loop (127.0.0.1:53 -> :53) detected for zone .". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Create a new StorageClass `low-latency` using the local-path provisioner that defers binding until a Pod needs the volume. Which `volumeBindingMode` is correct?$tv2$, $tv2$[{"id":"a","text":"Immediate"},{"id":"b","text":"WaitForFirstConsumer"},{"id":"c","text":"OnDemand"},{"id":"d","text":"Deferred"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`WaitForFirstConsumer` postpones PV provisioning and binding until a Pod using the PVC is scheduled — essential for topology-aware (e.g. local) volumes. `OnDemand`/`Deferred` are not valid values.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Create a new StorageClass `low-latency` using the local-path provisioner that defers binding until a Pod needs the volume. Which `volumeBindingMode` is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PVC requests 250Mi but the matching pre-provisioned PV is 1Gi. The binding behavior is:$tv2$, $tv2$[{"id":"a","text":"Fails — sizes must match exactly."},{"id":"b","text":"Succeeds — the PVC binds to a PV whose capacity is ≥ requested."},{"id":"c","text":"Succeeds — but the Pod sees only 250Mi."},{"id":"d","text":"Fails — capacity downscaling is not allowed."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$PV binding requires capacity ≥ requested. The Pod sees the full PV capacity; the PVC field is a *minimum* request, not a quota.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC requests 250Mi but the matching pre-provisioned PV is 1Gi. The binding behavior is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists running containers on a node using the CRI directly (independent of kubectl)?$tv2$, $tv2$[{"id":"a","text":"docker ps"},{"id":"b","text":"crictl ps"},{"id":"c","text":"kubeadm ps"},{"id":"d","text":"systemctl list-containers"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`crictl` is the standard CLI for CRI-compatible runtimes (containerd, cri-o, cri-dockerd) and is what the CKA exam expects on modern clusters. `docker ps` only works if a Docker runtime is installed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists running containers on a node using the CRI directly (independent of kubectl)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod has `ImagePullBackOff` and `kubectl describe pod` shows "pull access denied for private/repo:v1". The fix is:$tv2$, $tv2$[{"id":"a","text":"Create a `kubernetes.io/dockerconfigjson` Secret and reference it via `spec.imagePullSecrets`."},{"id":"b","text":"Restart the kubelet."},{"id":"c","text":"Set `imagePullPolicy: Never`."},{"id":"d","text":"Use a NodePort Service for the registry."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Authenticated pulls require an `imagePullSecrets` reference on the Pod (or ServiceAccount) containing a `dockerconfigjson` Secret with the registry credentials.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod has `ImagePullBackOff` and `kubectl describe pod` shows "pull access denied for private/repo:v1". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two containers in a Pod must communicate over a NEW TLS-1.3-only nginx config exposed via a ConfigMap. After editing the ConfigMap, the new TLS settings are not active. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"ConfigMaps mounted as a volume update lazily — restart the Deployment so the new file is read at startup, or use a sidecar that watches for changes."},{"id":"b","text":"TLS 1.3 is not supported in Kubernetes."},{"id":"c","text":"The kube-proxy must be restarted."},{"id":"d","text":"NetworkPolicy is dropping the connection."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$ConfigMap volume mounts are eventually consistent, but the consuming process (nginx) only re-reads on reload. `kubectl rollout restart deploy` or sending a SIGHUP via a sidecar applies the new config.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two containers in a Pod must communicate over a NEW TLS-1.3-only nginx config exposed via a ConfigMap. After editing the ConfigMap, the new TLS settings are not active. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Inspecting `journalctl -u kubelet -f` reveals "Failed to start ContainerManager: failed to initialise top-level QOS containers: ... cgroupfs vs systemd". The fix is:$tv2$, $tv2$[{"id":"a","text":"Set the kubelet `cgroupDriver` to match the container runtime (typically `systemd` on modern installs)."},{"id":"b","text":"Disable swap."},{"id":"c","text":"Reinstall the OS."},{"id":"d","text":"Upgrade kubectl."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$kubelet and CRI must agree on the cgroup driver. On systemd-based hosts both should use `systemd`. Mismatched drivers prevent the kubelet from starting.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Inspecting `journalctl -u kubelet -f` reveals "Failed to start ContainerManager: failed to initialise top-level QOS containers: ... cgroupfs vs systemd". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$`kubectl get nodes` returns "Unable to connect to the server: x509: certificate signed by unknown authority". The MOST likely root cause for a working operator is:$tv2$, $tv2$[{"id":"a","text":"The cluster is down."},{"id":"b","text":"Your kubeconfig points to a stale CA — refresh the kubeconfig (e.g. `kubeadm kubeconfig user --client-name=admin` or pull a fresh one)."},{"id":"c","text":"CoreDNS is broken."},{"id":"d","text":"kube-proxy is in iptables mode."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$TLS verification failure against the API server's cert almost always means the kubeconfig CA does not match — rotate or regenerate the kubeconfig.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl get nodes` returns "Unable to connect to the server: x509: certificate signed by unknown authority". The MOST likely root cause for a working operator is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A control-plane Pod (e.g. kube-scheduler) is missing from `kubectl get pods -n kube-system`. The kubelet logs show it is "not running". The first place to look is:$tv2$, $tv2$[{"id":"a","text":"/var/log/syslog"},{"id":"b","text":"/etc/kubernetes/manifests/kube-scheduler.yaml — confirm the static-Pod file exists and is syntactically valid."},{"id":"c","text":"systemctl status kube-scheduler"},{"id":"d","text":"kubectl describe deploy kube-scheduler -n kube-system"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$On kubeadm clusters scheduler/controller-manager/apiserver run as static Pods from `/etc/kubernetes/manifests/`. A missing or broken manifest is the typical cause. There is no Deployment or systemd unit for them.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A control-plane Pod (e.g. kube-scheduler) is missing from `kubectl get pods -n kube-system`. The kubelet logs show it is "not running". The first place to look is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which kernel module and sysctl are required for kube-proxy/CNI iptables traffic to work on a kubeadm node?$tv2$, $tv2$[{"id":"a","text":"br_netfilter module + net.bridge.bridge-nf-call-iptables=1"},{"id":"b","text":"overlay module only"},{"id":"c","text":"ip_vs module + net.ipv4.tcp_syncookies=0"},{"id":"d","text":"nf_conntrack module + vm.max_map_count=262144"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Loading `br_netfilter` and setting `net.bridge.bridge-nf-call-iptables=1` (plus `net.ipv4.ip_forward=1`) lets bridged traffic traverse iptables so Service/Pod networking functions.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which kernel module and sysctl are required for kube-proxy/CNI iptables traffic to work on a kubeadm node?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To create a ClusterRole that allows reading Pods and a ClusterRoleBinding to group `developers` imperatively, you run:$tv2$, $tv2$[{"id":"a","text":"kubectl create clusterrole pod-reader --verb=get,list,watch --resource=pods && kubectl create clusterrolebinding dev-read --clusterrole=pod-reader --group=developers"},{"id":"b","text":"kubectl create role pod-reader --verb=* --resource=pods"},{"id":"c","text":"kubectl create rolebinding dev-read --role=pod-reader --user=developers"},{"id":"d","text":"kubectl auth grant developers pods"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A cluster-wide read needs a ClusterRole bound by a ClusterRoleBinding; binding to a `--group` grants every member. A Role/RoleBinding would only scope to one namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To create a ClusterRole that allows reading Pods and a ClusterRoleBinding to group `developers` imperatively, you run:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command verifies whether ServiceAccount `build:ci` may create deployments in namespace `build`?$tv2$, $tv2$[{"id":"a","text":"kubectl auth can-i create deployments --as=system:serviceaccount:build:ci -n build"},{"id":"b","text":"kubectl get rolebinding ci -n build"},{"id":"c","text":"kubectl describe sa ci -n build"},{"id":"d","text":"kubectl auth whoami --sa ci"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl auth can-i ... --as=system:serviceaccount:<ns>:<name>` impersonates the SA and reports whether RBAC permits the action — the canonical RBAC verification command.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command verifies whether ServiceAccount `build:ci` may create deployments in namespace `build`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$During `kubeadm upgrade`, before draining a control-plane node you should verify the plan with:$tv2$, $tv2$[{"id":"a","text":"kubeadm upgrade plan"},{"id":"b","text":"kubeadm config images list"},{"id":"c","text":"kubeadm token list"},{"id":"d","text":"kubeadm certs check-expiration"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubeadm upgrade plan` shows the current versions, the available target versions, and component upgrade actions — always run before `kubeadm upgrade apply`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/kubeadm/kubeadm-upgrade/","label":"Kubernetes Docs — Upgrading kubeadm clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$During `kubeadm upgrade`, before draining a control-plane node you should verify the plan with:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After restoring etcd to `/var/lib/etcd-restore`, what must be updated in the etcd static Pod manifest?$tv2$, $tv2$[{"id":"a","text":"The `--data-dir` flag and the corresponding hostPath volume must point to /var/lib/etcd-restore."},{"id":"b","text":"Only the container image tag."},{"id":"c","text":"The `--listen-peer-urls` to 2379."},{"id":"d","text":"Nothing — etcd auto-discovers the restored data."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A restore creates a new data directory; the etcd static Pod must reference it via `--data-dir` and its hostPath volume so the kubelet starts etcd from the restored data.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After restoring etcd to `/var/lib/etcd-restore`, what must be updated in the etcd static Pod manifest?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which file does `kubeadm init` write that you copy to `$HOME/.kube/config` for cluster-admin access?$tv2$, $tv2$[{"id":"a","text":"/etc/kubernetes/admin.conf"},{"id":"b","text":"/etc/kubernetes/kubelet.conf"},{"id":"c","text":"/etc/kubernetes/scheduler.conf"},{"id":"d","text":"/var/lib/kubelet/config.yaml"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/etc/kubernetes/admin.conf` is the cluster-admin kubeconfig generated by kubeadm. `kubelet.conf`/`scheduler.conf` are component kubeconfigs with scoped identities.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which file does `kubeadm init` write that you copy to `$HOME/.kube/config` for cluster-admin access?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You add a second control-plane node. The join command must include which extra flag beyond a worker join?$tv2$, $tv2$[{"id":"a","text":"--control-plane (with an uploaded certificate key)"},{"id":"b","text":"--node-role=master"},{"id":"c","text":"--etcd-only"},{"id":"d","text":"--skip-phases=addon"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Joining a control-plane node uses `kubeadm join --control-plane` plus `--certificate-key` (from `kubeadm init phase upload-certs` / `--upload-certs`) so the new node receives the control-plane PKI.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You add a second control-plane node. The join command must include which extra flag beyond a worker join?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$kubeadm-managed certificates are expiring. The command to renew all of them is:$tv2$, $tv2$[{"id":"a","text":"kubeadm certs renew all"},{"id":"b","text":"kubeadm init --renew-certs"},{"id":"c","text":"kubectl certificate approve --all"},{"id":"d","text":"openssl req -renew -in admin.conf"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubeadm certs renew all` renews every kubeadm-managed control-plane certificate. The control-plane static Pods then need a restart to pick up the new certs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$kubeadm-managed certificates are expiring. The command to renew all of them is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command sets the default namespace for the current kubeconfig context?$tv2$, $tv2$[{"id":"a","text":"kubectl config set-context --current --namespace=dev"},{"id":"b","text":"kubectl set namespace dev"},{"id":"c","text":"kubectl config use-namespace dev"},{"id":"d","text":"kubectl namespace dev --default"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl config set-context --current --namespace=dev` patches the active context so subsequent commands default to namespace `dev`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command sets the default namespace for the current kubeconfig context?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid steps when upgrading a kubeadm WORKER node.$tv2$, $tv2$[{"id":"a","text":"`kubectl drain <node> --ignore-daemonsets` from a control plane."},{"id":"b","text":"`kubeadm upgrade node` on the worker."},{"id":"c","text":"Upgrade the kubelet/kubectl packages and restart the kubelet."},{"id":"d","text":"`kubectl uncordon <node>` afterwards."}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are part of the documented worker upgrade: drain, `kubeadm upgrade node`, upgrade kubelet/kubectl + restart, then uncordon to resume scheduling.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/kubeadm/kubeadm-upgrade/","label":"Kubernetes Docs — Upgrading kubeadm clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid steps when upgrading a kubeadm WORKER node.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A bootstrap token created by `kubeadm token create` expires after 24 hours by default.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Bootstrap tokens default to a 24h TTL; use `--ttl 0` for a non-expiring token (not recommended) or create a new one with `--print-join-command` when needed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A bootstrap token created by `kubeadm token create` expires after 24 hours by default.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command generates Pod YAML without creating the object?$tv2$, $tv2$[{"id":"a","text":"kubectl run nginx --image=nginx --dry-run=client -o yaml"},{"id":"b","text":"kubectl create pod nginx --yaml"},{"id":"c","text":"kubectl get pod nginx -o template"},{"id":"d","text":"kubectl apply --preview"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--dry-run=client -o yaml` renders the manifest locally without contacting the apiserver — the standard exam shortcut to scaffold and then edit YAML.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command generates Pod YAML without creating the object?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must tolerate a node tainted `gpu=true:NoSchedule` AND only land on GPU nodes labelled `gpu=true`. You need:$tv2$, $tv2$[{"id":"a","text":"a matching toleration plus a nodeSelector/affinity for the label"},{"id":"b","text":"only a toleration"},{"id":"c","text":"only a nodeSelector"},{"id":"d","text":"a PriorityClass"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A toleration only permits scheduling onto the tainted node; it does not attract the Pod there. Add a nodeSelector or nodeAffinity on `gpu=true` to also require placement on GPU nodes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must tolerate a node tainted `gpu=true:NoSchedule` AND only land on GPU nodes labelled `gpu=true`. You need:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment should keep at most 5 old ReplicaSets for rollback history. The field is:$tv2$, $tv2$[{"id":"a","text":"spec.revisionHistoryLimit: 5"},{"id":"b","text":"spec.strategy.maxHistory: 5"},{"id":"c","text":"spec.rollback.limit: 5"},{"id":"d","text":"metadata.annotations.history: 5"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`spec.revisionHistoryLimit` controls how many old ReplicaSets are retained for `kubectl rollout undo`. The default is 10; setting 0 disables rollback history.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment should keep at most 5 old ReplicaSets for rollback history. The field is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An initContainer must complete before the app container starts. If the initContainer exits non-zero, the Pod:$tv2$, $tv2$[{"id":"a","text":"restarts the initContainer per the Pod restartPolicy until it succeeds"},{"id":"b","text":"starts the app container anyway"},{"id":"c","text":"is deleted immediately"},{"id":"d","text":"skips the failed initContainer"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Init containers run sequentially and must succeed; on failure the kubelet restarts the Pod (subject to restartPolicy) until the init container exits 0. The app container never starts until all init containers succeed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An initContainer must complete before the app container starts. If the initContainer exits non-zero, the Pod:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about node affinity.$tv2$, $tv2$[{"id":"a","text":"requiredDuringSchedulingIgnoredDuringExecution is a hard rule."},{"id":"b","text":"preferredDuringScheduling... is a soft (weighted) preference."},{"id":"c","text":"Affinity rules are re-evaluated and Pods evicted if labels change later."},{"id":"d","text":"It can express richer set-based label matching than nodeSelector."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$`IgnoredDuringExecution` means running Pods are NOT evicted when node labels change. Required is hard, preferred is soft/weighted, and affinity supports operators like In/NotIn/Exists.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about node affinity.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Topology spread constraints with `maxSkew: 1` and `topologyKey: zone` aim to:$tv2$, $tv2$[{"id":"a","text":"distribute Pods so the count difference between zones is at most 1"},{"id":"b","text":"allow at most 1 Pod per zone"},{"id":"c","text":"place all Pods in one zone"},{"id":"d","text":"evict Pods when zones become unbalanced"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`maxSkew` bounds the permitted imbalance of matching Pods across topology domains (zones), spreading them evenly. It is a scheduling constraint, not a runtime eviction mechanism.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Topology spread constraints with `maxSkew: 1` and `topologyKey: zone` aim to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$Setting `spec.nodeName` directly on a Pod bypasses the scheduler and binds the Pod to that node.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. A Pod with `nodeName` set is assigned to that node without scheduler involvement; it will fail if that node lacks capacity or does not exist.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Setting `spec.nodeName` directly on a Pod bypasses the scheduler and binds the Pod to that node.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command imperatively creates a ClusterIP Service for Deployment `api` on port 80?$tv2$, $tv2$[{"id":"a","text":"kubectl expose deploy api --port=80"},{"id":"b","text":"kubectl create svc api --port 80"},{"id":"c","text":"kubectl run svc api --port=80"},{"id":"d","text":"kubectl service create api 80"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl expose deploy api --port=80` creates a Service (ClusterIP by default) selecting the Deployment's Pods. `--target-port` sets the container port if it differs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command imperatively creates a ClusterIP Service for Deployment `api` on port 80?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NodePort Service is created. Which port range will Kubernetes allocate by default?$tv2$, $tv2$[{"id":"a","text":"30000–32767"},{"id":"b","text":"1–1024"},{"id":"c","text":"8080–8443"},{"id":"d","text":"40000–49999"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The default `--service-node-port-range` is 30000–32767. A specific `nodePort` can be requested within that range; conflicts are rejected.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NodePort Service is created. Which port range will Kubernetes allocate by default?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two Pods in different namespaces cannot communicate after you add a default-deny NetworkPolicy. To allow cross-namespace traffic you must:$tv2$, $tv2$[{"id":"a","text":"add an ingress rule with a namespaceSelector matching the source namespace labels"},{"id":"b","text":"delete kube-proxy"},{"id":"c","text":"switch the Service to NodePort"},{"id":"d","text":"set hostNetwork: true"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$With a default-deny policy in place you must explicitly allow the source via a `from` peer using a `namespaceSelector` (and optionally `podSelector`) matching the other namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two Pods in different namespaces cannot communicate after you add a default-deny NetworkPolicy. To allow cross-namespace traffic you must:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress with TLS needs a certificate. The secret it references must be of type:$tv2$, $tv2$[{"id":"a","text":"kubernetes.io/tls"},{"id":"b","text":"Opaque"},{"id":"c","text":"kubernetes.io/dockerconfigjson"},{"id":"d","text":"bootstrap.kubernetes.io/token"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Ingress `spec.tls[].secretName` must reference a `kubernetes.io/tls` Secret containing `tls.crt` and `tls.key`. Opaque secrets are not recognized for TLS termination.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress with TLS needs a certificate. The secret it references must be of type:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want client source IP preserved at the backend for a NodePort/LoadBalancer Service. Set:$tv2$, $tv2$[{"id":"a","text":"externalTrafficPolicy: Local"},{"id":"b","text":"internalTrafficPolicy: Cluster"},{"id":"c","text":"sessionAffinity: ClientIP"},{"id":"d","text":"publishNotReadyAddresses: true"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`externalTrafficPolicy: Local` stops the second hop SNAT so the original client IP reaches the Pod, at the cost of only routing to nodes that host a backend Pod.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want client source IP preserved at the backend for a NodePort/LoadBalancer Service. Set:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Gateway API HTTPRoute splits 80/20 between two backend Services. The weights are configured under:$tv2$, $tv2$[{"id":"a","text":"spec.rules[].backendRefs[].weight"},{"id":"b","text":"spec.rules[].split"},{"id":"c","text":"spec.parentRefs[].weight"},{"id":"d","text":"metadata.annotations.traffic-split"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$HTTPRoute supports weighted traffic splitting by assigning `weight` to each entry in `backendRefs` within a rule. There is no `split` or `parentRefs.weight` field.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Gateway API HTTPRoute splits 80/20 between two backend Services. The weights are configured under:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$CoreDNS configuration is stored in which Kubernetes object?$tv2$, $tv2$[{"id":"a","text":"a ConfigMap named coredns in kube-system"},{"id":"b","text":"a Secret named coredns"},{"id":"c","text":"a CRD named Corefile"},{"id":"d","text":"the kube-dns Service annotations"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CoreDNS reads its `Corefile` from the `coredns` ConfigMap in `kube-system`. Editing that ConfigMap (then restarting CoreDNS) changes DNS behavior.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$CoreDNS configuration is stored in which Kubernetes object?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about NetworkPolicy default behavior.$tv2$, $tv2$[{"id":"a","text":"With no policies, all Pod traffic is allowed."},{"id":"b","text":"A policy selecting a Pod for Ingress makes that Pod default-deny for non-matching ingress."},{"id":"c","text":"NetworkPolicy requires a CNI that implements it."},{"id":"d","text":"Egress is restricted only if policyTypes includes Egress."}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are correct. Pods are non-isolated until a policy selects them; once selected for a direction, only explicitly allowed traffic in that direction is permitted, and enforcement depends on the CNI.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about NetworkPolicy default behavior.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A Service named `web` in namespace `prod` is resolvable from another namespace as `web.prod.svc.cluster.local`.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. The fully qualified Service DNS name is `<service>.<namespace>.svc.cluster.local`, which resolves from any namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service named `web` in namespace `prod` is resolvable from another namespace as `web.prod.svc.cluster.local`.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all PersistentVolumes and their bound claims/status?$tv2$, $tv2$[{"id":"a","text":"kubectl get pv"},{"id":"b","text":"kubectl get volumes"},{"id":"c","text":"kubectl describe storage"},{"id":"d","text":"kubectl get pvc -A --show-pv"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get pv` shows each PV with capacity, access modes, reclaim policy, status, and the bound claim. `kubectl get pvc` shows the claim side.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all PersistentVolumes and their bound claims/status?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A StatefulSet `db` has 3 replicas with a volumeClaimTemplate. The PVCs created are named:$tv2$, $tv2$[{"id":"a","text":"data-db-0, data-db-1, data-db-2"},{"id":"b","text":"db-pvc-1, db-pvc-2, db-pvc-3"},{"id":"c","text":"db-data (one shared PVC)"},{"id":"d","text":"pvc-<uuid> randomly"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$StatefulSet PVCs from a volumeClaimTemplate are named `<template-name>-<statefulset-name>-<ordinal>`, giving each Pod its own stable PVC.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A StatefulSet `db` has 3 replicas with a volumeClaimTemplate. The PVCs created are named:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You expand a PVC by editing `spec.resources.requests.storage` but the new size is not reflected. The MOST likely reason is:$tv2$, $tv2$[{"id":"a","text":"allowVolumeExpansion is not true on the StorageClass."},{"id":"b","text":"The PVC is ReadWriteOnce."},{"id":"c","text":"The Pod is not labelled."},{"id":"d","text":"reclaimPolicy is Retain."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Online expansion requires `allowVolumeExpansion: true` on the StorageClass; without it the larger request is rejected/ignored by the provisioner.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You expand a PVC by editing `spec.resources.requests.storage` but the new size is not reflected. The MOST likely reason is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must read a Secret as files at `/etc/creds`. The correct volume type is:$tv2$, $tv2$[{"id":"a","text":"a secret volume mounted at /etc/creds"},{"id":"b","text":"an emptyDir volume"},{"id":"c","text":"a hostPath volume"},{"id":"d","text":"a downwardAPI volume"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A `secret` volume projects each Secret key as a file under the mount path. `downwardAPI` exposes Pod metadata, not Secret data; emptyDir/hostPath do not source Secret contents.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must read a Secret as files at `/etc/creds`. The correct volume type is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A PVC can bind to a PV only if the PV capacity is greater than or equal to the requested size and the access modes are compatible.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Binding requires the PV capacity ≥ the PVC request and the requested access mode to be among the PV access modes (StorageClass must also match if specified).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC can bind to a PV only if the PV capacity is greater than or equal to the requested size and the access modes are compatible.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the node a Pod is scheduled on plus its Pod IP?$tv2$, $tv2$[{"id":"a","text":"kubectl get pod <pod> -o wide"},{"id":"b","text":"kubectl logs <pod>"},{"id":"c","text":"kubectl top pod <pod>"},{"id":"d","text":"kubectl get pod <pod> --short"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get pod -o wide` adds NODE, IP, and NOMINATED NODE columns — the quickest way to see placement during triage.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the node a Pod is scheduled on plus its Pod IP?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod is `Pending` and describe shows "node(s) didn't match Pod's node affinity/selector". The fix is:$tv2$, $tv2$[{"id":"a","text":"Correct the nodeSelector/affinity or label a node to match."},{"id":"b","text":"Increase Pod CPU limits."},{"id":"c","text":"Restart the scheduler."},{"id":"d","text":"Add an imagePullSecret."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$No node satisfies the Pod's node affinity/selector. Either relax/fix the constraint or add the required label to a suitable node so the scheduler can place the Pod.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is `Pending` and describe shows "node(s) didn't match Pod's node affinity/selector". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container is `CreateContainerConfigError`. `kubectl describe pod` shows "secret \"db-cred\" not found". The remediation is:$tv2$, $tv2$[{"id":"a","text":"Create the missing Secret `db-cred` in the Pod namespace."},{"id":"b","text":"Restart the kubelet."},{"id":"c","text":"Recreate the node."},{"id":"d","text":"Add a liveness probe."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CreateContainerConfigError commonly means a referenced ConfigMap/Secret is missing. Create `db-cred` in the same namespace; the kubelet then starts the container.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container is `CreateContainerConfigError`. `kubectl describe pod` shows "secret \"db-cred\" not found". The remediation is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to test connectivity from inside the cluster to a Service. The quickest approach is:$tv2$, $tv2$[{"id":"a","text":"kubectl run tmp --rm -it --image=busybox -- wget -qO- http://<svc>:<port>"},{"id":"b","text":"curl from your laptop directly to the ClusterIP"},{"id":"c","text":"kubectl get svc -o yaml"},{"id":"d","text":"ping the Service DNS from the control-plane host"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A throwaway Pod (`kubectl run --rm -it`) tests Service reachability from within the cluster network — ClusterIPs are not routable from outside or from the host.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to test connectivity from inside the cluster to a Service. The quickest approach is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The scheduler Pod is healthy but no Pods are being scheduled cluster-wide. A likely cause to check is:$tv2$, $tv2$[{"id":"a","text":"All nodes are cordoned/NotReady or tainted so no node is feasible."},{"id":"b","text":"CoreDNS is down."},{"id":"c","text":"kubectl is outdated."},{"id":"d","text":"The dashboard is disabled."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$If every node is cordoned, NotReady, or carries a NoSchedule taint, the scheduler has no feasible node. Check `kubectl get nodes` and node taints/conditions.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The scheduler Pod is healthy but no Pods are being scheduled cluster-wide. A likely cause to check is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A node's kubelet logs show "failed to run Kubelet: misconfiguration: kubelet cgroup driver: cgroupfs is different from runtime cgroup driver: systemd". The fix is:$tv2$, $tv2$[{"id":"a","text":"Align kubelet and runtime cgroup drivers (set both to systemd)."},{"id":"b","text":"Disable the firewall."},{"id":"c","text":"Reinstall kubectl."},{"id":"d","text":"Delete /var/lib/etcd."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The kubelet and container runtime must use the same cgroup driver. Set `cgroupDriver: systemd` in the kubelet config and ensure containerd uses `SystemdCgroup = true`, then restart both.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A node's kubelet logs show "failed to run Kubelet: misconfiguration: kubelet cgroup driver: cgroupfs is different from runtime cgroup driver: systemd". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment shows the desired replicas but 0 available, and Pods are `0/1 Running`. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"The readiness probe is failing so Pods are Running but not Ready."},{"id":"b","text":"The image cannot be pulled."},{"id":"c","text":"etcd is down."},{"id":"d","text":"The Service has no selector."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`0/1 Running` means the container runs but the readiness probe fails, so the Pod is not Ready and not counted as available. Inspect/fix the readiness probe or the app.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment shows the desired replicas but 0 available, and Pods are `0/1 Running`. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After a node reboot, its Pods are not rescheduled and the node stays `NotReady`. The first thing to check is:$tv2$, $tv2$[{"id":"a","text":"Whether the kubelet and container runtime services started on boot (systemctl is-enabled)."},{"id":"b","text":"Whether CoreDNS scaled down."},{"id":"c","text":"Whether the Service is ClusterIP."},{"id":"d","text":"Whether kubectl is configured."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$After reboot a NotReady node usually means kubelet/containerd did not start. Verify they are enabled and running (`systemctl status/enable kubelet containerd`).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After a node reboot, its Pods are not rescheduled and the node stays `NotReady`. The first thing to check is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$kube-controller-manager is CrashLoopBackOff after editing its static Pod manifest. The fastest way to see the parse/flag error is:$tv2$, $tv2$[{"id":"a","text":"crictl logs of the controller-manager container on the control-plane node"},{"id":"b","text":"kubectl logs -n kube-system deploy/kube-controller-manager"},{"id":"c","text":"systemctl status kube-controller-manager"},{"id":"d","text":"kubectl rollout status"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$It is a static Pod, so use `crictl ps -a` + `crictl logs` (or `/var/log/pods`) on the node. A bad flag/YAML in the manifest is the usual culprit; fix the manifest and the kubelet restarts it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$kube-controller-manager is CrashLoopBackOff after editing its static Pod manifest. The fastest way to see the parse/flag error is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod cannot resolve external domains but resolves cluster Services fine. The likely cause is:$tv2$, $tv2$[{"id":"a","text":"CoreDNS upstream forwarders (or node /etc/resolv.conf) are misconfigured."},{"id":"b","text":"The Pod has no Service."},{"id":"c","text":"kube-proxy is in IPVS mode."},{"id":"d","text":"The image lacks curl."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Cluster names resolving but external names failing points to CoreDNS upstream forwarding (the `forward` plugin / node resolv.conf) being broken. Fix the upstream resolver configuration.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod cannot resolve external domains but resolves cluster Services fine. The likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You must capture a failing Pod's describe output and recent events for a ticket. The single best command is:$tv2$, $tv2$[{"id":"a","text":"kubectl describe pod <pod> -n <ns>"},{"id":"b","text":"kubectl get pod <pod> -o name"},{"id":"c","text":"kubectl logs <pod> --tail=1"},{"id":"d","text":"kubectl top pod <pod>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe pod` consolidates spec status, container states, conditions, and the associated events — the primary first-look troubleshooting command.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You must capture a failing Pod's describe output and recent events for a ticket. The single best command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$A Pod is stuck in `ImagePullBackOff`. Select ALL valid causes.$tv2$, $tv2$[{"id":"a","text":"The image name or tag is wrong / does not exist."},{"id":"b","text":"The registry requires auth and no imagePullSecret is set."},{"id":"c","text":"The node cannot reach the registry network."},{"id":"d","text":"The Service selector does not match the Pod."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$ImagePullBackOff is purely about pulling the image: wrong name/tag, missing registry credentials, or no network path to the registry. A Service selector mismatch is unrelated to image pulls.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is stuck in `ImagePullBackOff`. Select ALL valid causes.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$`kubectl get events -n <ns>` is useful for diagnosing why a Pod failed to schedule or pull its image.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Scheduling failures, image pull errors, and probe failures are recorded as Events; listing them (sorted by time) is a core triage step alongside `kubectl describe`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl get events -n <ns>` is useful for diagnosing why a Pod failed to schedule or pull its image.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A user `dev1` must be able to list and get Pods cluster-wide but mutate nothing. The MINIMUM RBAC binding required is:$tv2$, $tv2$[{"id":"a","text":"A Role + RoleBinding in every namespace."},{"id":"b","text":"A ClusterRole with `verbs: [get,list,watch]` on `pods` + a ClusterRoleBinding to user `dev1`."},{"id":"c","text":"A ClusterRole with `verbs: [\"*\"]` + ClusterRoleBinding."},{"id":"d","text":"A Role with `verbs: [\"*\"]` + RoleBinding to the default namespace."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Cluster-wide read of a core resource is a ClusterRole bound via ClusterRoleBinding. A Role is namespace-scoped; wildcard verbs over-privilege.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A user `dev1` must be able to list and get Pods cluster-wide but mutate nothing. The MINIMUM RBAC binding required is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command renders the spec of an installed CRD field so you can author a CR against it?$tv2$, $tv2$[{"id":"a","text":"kubectl describe crd <name>"},{"id":"b","text":"kubectl explain <kind>.<path> (e.g. certificates.spec.subject)"},{"id":"c","text":"kubectl api-versions"},{"id":"d","text":"kubectl proxy --crd"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl explain` reads the openAPI schema from the apiserver, including CRD schemas. It supports dotted paths for nested fields.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/api-extension/custom-resources/","label":"Kubernetes Docs — Custom Resources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command renders the spec of an installed CRD field so you can author a CR against it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After `kubeadm init`, the message instructs you to run `kubectl ... --kubeconfig=/etc/kubernetes/admin.conf` or copy that file to `$HOME/.kube/config`. Which is INCORRECT about that file?$tv2$, $tv2$[{"id":"a","text":"It contains an admin client cert/key."},{"id":"b","text":"It is safe to share with developers as-is."},{"id":"c","text":"Its CA cert matches the apiserver's cert."},{"id":"d","text":"Its server URL is the apiserver advertise address."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`admin.conf` is cluster-admin; never hand it to developers. Generate per-user kubeconfigs (e.g. via `kubeadm kubeconfig user`) with scoped RBAC.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After `kubeadm init`, the message instructs you to run `kubectl ... --kubeconfig=/etc/kubernetes/admin.conf` or copy that file to `$HOME/.kube/config`. Which is INCORRECT about that file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$On a fresh single-node cluster, after `kubeadm init` the apiserver is healthy but `kubectl get nodes` shows the node `NotReady`. The MOST likely remaining step is:$tv2$, $tv2$[{"id":"a","text":"Apply a CNI manifest (e.g. Calico / Flannel) so the node Ready condition can transition."},{"id":"b","text":"Restart the kubelet."},{"id":"c","text":"Set `--allow-privileged=true` on the apiserver."},{"id":"d","text":"Disable swap (kubeadm already does this)."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Node Ready requires a working network plugin. Without a CNI the kubelet reports `NetworkUnavailable` and the node stays NotReady.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a fresh single-node cluster, after `kubeadm init` the apiserver is healthy but `kubectl get nodes` shows the node `NotReady`. The MOST likely remaining step is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid placements for cri-dockerd in a CKA exam context.$tv2$, $tv2$[{"id":"a","text":"cri-dockerd is required if you keep Docker as the runtime past k8s 1.24."},{"id":"b","text":"cri-dockerd is a CRI shim that lets the kubelet talk to dockerd."},{"id":"c","text":"cri-dockerd is a CNI plugin."},{"id":"d","text":"Default kubeadm clusters typically use containerd, not cri-dockerd."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$cri-dockerd is a runtime shim, not a CNI plugin. It exists because the in-tree dockershim was removed in 1.24. Modern kubeadm clusters default to containerd.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid placements for cri-dockerd in a CKA exam context.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two Pods MUST run on different nodes. Which scheduling primitive expresses this?$tv2$, $tv2$[{"id":"a","text":"podAffinity with `topologyKey: kubernetes.io/hostname`"},{"id":"b","text":"podAntiAffinity with `topologyKey: kubernetes.io/hostname`"},{"id":"c","text":"nodeSelector: { distinct: \"true\" }"},{"id":"d","text":"PriorityClass preemption"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$PodAntiAffinity with hostname topology rejects nodes that already run a matching Pod, achieving spread-by-host.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two Pods MUST run on different nodes. Which scheduling primitive expresses this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need a sidecar that runs FOR THE LIFETIME of the main container and shares a log volume. In recent Kubernetes versions, the recommended way is:$tv2$, $tv2$[{"id":"a","text":"Add it as a second container under `spec.containers[]` sharing an emptyDir volume."},{"id":"b","text":"Add it as an initContainer."},{"id":"c","text":"Run it as a separate Deployment."},{"id":"d","text":"Use a Job."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Classic sidecars are simply additional containers in the Pod sharing volumes. The native "sidecar initContainer" (`restartPolicy: Always` on an initContainer) is a newer beta pattern for sidecars whose startup must precede the main container.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a sidecar that runs FOR THE LIFETIME of the main container and shares a log volume. In recent Kubernetes versions, the recommended way is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment has 3 replicas and `maxSurge: 1, maxUnavailable: 0`. During rollout, how many Pods total can exist simultaneously?$tv2$, $tv2$[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"6"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`maxSurge: 1` allows one extra Pod above desired (3 → up to 4). `maxUnavailable: 0` blocks dropping below desired Ready count.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment has 3 replicas and `maxSurge: 1, maxUnavailable: 0`. During rollout, how many Pods total can exist simultaneously?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want headless DNS so clients can resolve INDIVIDUAL Pod IPs of a StatefulSet. The Service config is:$tv2$, $tv2$[{"id":"a","text":"type: ClusterIP, clusterIP: None, selector: { app: db }"},{"id":"b","text":"type: NodePort, headless: true"},{"id":"c","text":"type: ExternalName, externalName: db"},{"id":"d","text":"type: ClusterIP with externalTrafficPolicy: Local"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Setting `clusterIP: None` (with a selector) makes the Service headless. CoreDNS returns A records for each backing Pod's IP — required for StatefulSet stable per-Pod DNS.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"},{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want headless DNS so clients can resolve INDIVIDUAL Pod IPs of a StatefulSet. The Service config is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy applied to `podSelector: {}` with `policyTypes: [Ingress, Egress]` and no `ingress`/`egress` rules has what effect on Pods in that namespace?$tv2$, $tv2$[{"id":"a","text":"Allow all ingress and egress."},{"id":"b","text":"Default-deny all ingress AND all egress."},{"id":"c","text":"No effect."},{"id":"d","text":"Default-deny only intra-namespace traffic."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$An empty selector matches every Pod; declaring both policyTypes with empty rule lists denies all traffic of those types. This is the classic "default deny" pattern.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy applied to `podSelector: {}` with `policyTypes: [Ingress, Egress]` and no `ingress`/`egress` rules has what effect on Pods in that namespace?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In the `gateway.networking.k8s.io/v1` API, which resource declares the controller implementation (e.g. nginx) that processes Gateways?$tv2$, $tv2$[{"id":"a","text":"GatewayClass"},{"id":"b","text":"Gateway"},{"id":"c","text":"HTTPRoute"},{"id":"d","text":"ReferenceGrant"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`GatewayClass` is the cluster-scoped resource that names the controller (e.g. `nginx`). A Gateway selects a GatewayClass; HTTPRoute attaches to a Gateway.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In the `gateway.networking.k8s.io/v1` API, which resource declares the controller implementation (e.g. nginx) that processes Gateways?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress route 80→8080 stops working after migrating from ingress-nginx Ingress to a Gateway+HTTPRoute. Both resources exist temporarily. The CORRECT cleanup is:$tv2$, $tv2$[{"id":"a","text":"Delete the old Ingress with `kubectl delete ingress <name> -n <ns>`."},{"id":"b","text":"Leave both — they coexist."},{"id":"c","text":"Delete the GatewayClass."},{"id":"d","text":"Set the Ingress annotation `disabled: true`."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Once HTTPRoute is verified working, delete the Ingress to avoid double-routing and resource churn. There is no `disabled: true` annotation in the Ingress API.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"},{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress route 80→8080 stops working after migrating from ingress-nginx Ingress to a Gateway+HTTPRoute. Both resources exist temporarily. The CORRECT cleanup is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need a StatefulSet whose Pods each get their own PVC sized 1Gi. The mechanism is:$tv2$, $tv2$[{"id":"a","text":"spec.volumeClaimTemplates on the StatefulSet"},{"id":"b","text":"spec.template.spec.volumes (one PVC reused)"},{"id":"c","text":"A Deployment with `replicas: N` and a shared PVC"},{"id":"d","text":"PriorityClass with `volumeQuota`"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`volumeClaimTemplates` materializes a fresh PVC per ordinal Pod, satisfying per-Pod persistence in StatefulSets. A single PVC referenced via `volumes` would be shared — not what you want.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a StatefulSet whose Pods each get their own PVC sized 1Gi. The mechanism is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PVC of size 1Gi must be expanded to 5Gi online. The PRE-REQUISITE on the StorageClass is:$tv2$, $tv2$[{"id":"a","text":"reclaimPolicy: Retain"},{"id":"b","text":"allowVolumeExpansion: true"},{"id":"c","text":"volumeBindingMode: Immediate"},{"id":"d","text":"parameters.fsType: ext4"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`allowVolumeExpansion: true` on the StorageClass is required; then editing the PVC `resources.requests.storage` triggers an online resize (provisioner-dependent).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC of size 1Gi must be expanded to 5Gi online. The PRE-REQUISITE on the StorageClass is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod's containerPort `80` is declared but the Service's `targetPort` is `8080`. Symptom?$tv2$, $tv2$[{"id":"a","text":"503 / connection refused — Service forwards to a port the Pod is not listening on."},{"id":"b","text":"Pods crash on startup."},{"id":"c","text":"NetworkPolicy blocks the traffic."},{"id":"d","text":"Ingress returns 404."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Service `targetPort` is the Pod port the kube-proxy DNATs to. A mismatch with the actually-listening port produces refused/timeout — not a Pod crash.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod's containerPort `80` is declared but the Service's `targetPort` is `8080`. Symptom?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You suspect the scheduler is wedged. Which command surfaces "FailedScheduling" reasons for a specific Pod?$tv2$, $tv2$[{"id":"a","text":"kubectl get events --field-selector involvedObject.name=<pod>"},{"id":"b","text":"kubectl logs deploy/kube-scheduler -n kube-system"},{"id":"c","text":"kubectl describe deploy <pod>"},{"id":"d","text":"kubectl proxy --debug"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe pod <pod>` also surfaces the same events. Filtering via field-selector is a more programmatic equivalent. Scheduler logs help too but require deeper access.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You suspect the scheduler is wedged. Which command surfaces "FailedScheduling" reasons for a specific Pod?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$kube-proxy is logging "can't open iptables lock". The fix is:$tv2$, $tv2$[{"id":"a","text":"Run kube-proxy with hostNetwork (it already does)."},{"id":"b","text":"Add the privileged securityContext or required capabilities; ensure xtables-lock is mounted from /run/xtables.lock."},{"id":"c","text":"Disable iptables and use ipvs without configuration."},{"id":"d","text":"Restart the apiserver."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$kube-proxy manipulates iptables on the host and needs the host's xtables lock and capabilities (NET_ADMIN, SYS_MODULE). The canonical DaemonSet manifest mounts `/run/xtables.lock`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$kube-proxy is logging "can't open iptables lock". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Pods on `node02` are stuck in `ContainerCreating`. `kubectl describe pod` shows "NetworkPlugin cni failed to set up pod ... no IP addresses available in range set". The MOST likely root cause is:$tv2$, $tv2$[{"id":"a","text":"PodCIDR allocated to the node is exhausted — investigate via the CNI and free / expand the range."},{"id":"b","text":"kube-proxy is down."},{"id":"c","text":"CoreDNS is broken."},{"id":"d","text":"NodePort range is full."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Each node gets a slice of the cluster Pod CIDR. When that range is exhausted, the CNI IPAM returns "no IP available". Solutions: increase per-node range or scale out nodes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Pods on `node02` are stuck in `ContainerCreating`. `kubectl describe pod` shows "NetworkPlugin cni failed to set up pod ... no IP addresses available in range set". The MOST likely root cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$`kubectl drain node01 --ignore-daemonsets --delete-emptydir-data` hangs on a PodDisruptionBudget. The CORRECT next step is:$tv2$, $tv2$[{"id":"a","text":"Wait for capacity to free up so the eviction can complete."},{"id":"b","text":"Use --force --grace-period=0 to delete the Pods (last resort — bypasses graceful termination)."},{"id":"c","text":"Delete the PDB without consideration."},{"id":"d","text":"kubeadm reset node01"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A PDB respecting eviction will block until enough replicas can be moved while satisfying minAvailable. Scaling out (or rescheduling other Pods) typically unblocks the drain. `--force` is the destructive escape hatch.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl drain node01 --ignore-daemonsets --delete-emptydir-data` hangs on a PodDisruptionBudget. The CORRECT next step is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$`kubectl exec` returns "error: unable to upgrade connection: container not found ("XYZ")" yet the Pod is Running. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"Pod has multiple containers and you must pass `-c <name>` for the right one."},{"id":"b","text":"apiserver is down."},{"id":"c","text":"kubelet TLS cert has expired."},{"id":"d","text":"NetworkPolicy blocks exec."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When the pod has multiple containers, omitting `-c` selects the default, which may not exist by the name kubectl is logging in the error. Specify the container explicitly.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl exec` returns "error: unable to upgrade connection: container not found ("XYZ")" yet the Pod is Running. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which kubeadm phase command pre-pulls the container images required for the control plane?$tv2$, $tv2$[{"id":"a","text":"kubeadm config images pull"},{"id":"b","text":"kubeadm init --pull-images"},{"id":"c","text":"crictl pull kubeadm"},{"id":"d","text":"kubectl get images -A"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubeadm config images pull` downloads the apiserver, controller-manager, scheduler, etcd, and pause images ahead of `kubeadm init` to speed up and de-risk the bootstrap.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which kubeadm phase command pre-pulls the container images required for the control plane?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A ClusterRole aggregation should automatically include rules from labelled ClusterRoles. The mechanism is:$tv2$, $tv2$[{"id":"a","text":"spec.aggregationRule.clusterRoleSelectors on the aggregate ClusterRole"},{"id":"b","text":"metadata.ownerReferences"},{"id":"c","text":"a RoleBinding with `aggregate: true`"},{"id":"d","text":"the `rbac.authorization.k8s.io/aggregate` Service annotation"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$An aggregated ClusterRole uses `aggregationRule.clusterRoleSelectors`; the controller merges rules from any ClusterRole whose labels match. The aggregate role's own `rules` are managed by the controller.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A ClusterRole aggregation should automatically include rules from labelled ClusterRoles. The mechanism is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To rotate a leaked bootstrap token, you should:$tv2$, $tv2$[{"id":"a","text":"kubeadm token delete <token-id> and create a new one when needed"},{"id":"b","text":"restart the apiserver"},{"id":"c","text":"rotate the etcd snapshot"},{"id":"d","text":"kubectl delete secret kube-proxy"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Bootstrap tokens live as Secrets in kube-system; `kubeadm token delete` revokes a leaked token immediately. Generate a fresh one with `kubeadm token create --print-join-command` only when joining nodes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To rotate a leaked bootstrap token, you should:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You must change the cluster's API server `--audit-log-path`. On a kubeadm cluster you edit:$tv2$, $tv2$[{"id":"a","text":"/etc/kubernetes/manifests/kube-apiserver.yaml (static Pod manifest)"},{"id":"b","text":"/etc/systemd/system/kube-apiserver.service"},{"id":"c","text":"the kube-apiserver ConfigMap in kube-system"},{"id":"d","text":"kubectl edit deploy kube-apiserver"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$apiserver flags are set as container args in its static Pod manifest. After saving, the kubelet recreates the Pod with the new flag. No systemd unit/Deployment/ConfigMap drives it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You must change the cluster's API server `--audit-log-path`. On a kubeadm cluster you edit:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which etcdctl command verifies the integrity/metadata of a saved snapshot file?$tv2$, $tv2$[{"id":"a","text":"ETCDCTL_API=3 etcdctl snapshot status /backup/snap.db"},{"id":"b","text":"etcdctl verify snapshot /backup/snap.db"},{"id":"c","text":"etcdctl snapshot check"},{"id":"d","text":"kubectl get etcd snapshot"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`etcdctl snapshot status <file>` prints the snapshot's hash, revision, and total keys, confirming it is a valid v3 snapshot before relying on it for restore.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which etcdctl command verifies the integrity/metadata of a saved snapshot file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes a node cleanly from the cluster after draining it?$tv2$, $tv2$[{"id":"a","text":"kubectl delete node <node> (then `kubeadm reset` on the node)"},{"id":"b","text":"kubectl cordon <node>"},{"id":"c","text":"kubeadm token delete <node>"},{"id":"d","text":"systemctl stop kubelet only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$After `kubectl drain`, remove the node object with `kubectl delete node`, then run `kubeadm reset` on the host to clean its cluster state and config files.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes a node cleanly from the cluster after draining it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A kubeadm `kubeadm join` fails with "couldn't validate the identity of the API Server: cluster CA hash ... does not match". The cause is:$tv2$, $tv2$[{"id":"a","text":"A stale/incorrect --discovery-token-ca-cert-hash on the join command."},{"id":"b","text":"The worker has swap enabled."},{"id":"c","text":"CoreDNS is down."},{"id":"d","text":"The worker kubelet is too new."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The CA cert hash pins the API server identity during discovery. A mismatched/old hash (e.g. CA rotated) fails validation. Regenerate the join command with `kubeadm token create --print-join-command`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A kubeadm `kubeadm join` fails with "couldn't validate the identity of the API Server: cluster CA hash ... does not match". The cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a Role that allows only `get` and `list` on Secrets in namespace `app`. The apiGroup for Secrets is:$tv2$, $tv2$[{"id":"a","text":"\"\" (core/v1, the empty string)"},{"id":"b","text":"rbac.authorization.k8s.io"},{"id":"c","text":"apps"},{"id":"d","text":"policy"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Secrets, ConfigMaps, Pods, and Services are in the core API group, denoted by the empty string `""` in RBAC `apiGroups`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a Role that allows only `get` and `list` on Secrets in namespace `app`. The apiGroup for Secrets is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command displays the cluster API server endpoint kubectl is currently configured to use?$tv2$, $tv2$[{"id":"a","text":"kubectl cluster-info"},{"id":"b","text":"kubectl get apiserver"},{"id":"c","text":"kubectl config endpoint"},{"id":"d","text":"kubectl version --server-url"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl cluster-info` prints the control-plane (API server) URL and core add-on endpoints, useful for confirming the active context targets the right cluster.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command displays the cluster API server endpoint kubectl is currently configured to use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL files/dirs kubeadm uses for control-plane state on a control-plane node.$tv2$, $tv2$[{"id":"a","text":"/etc/kubernetes/manifests (static Pod manifests)"},{"id":"b","text":"/etc/kubernetes/pki (cluster certificates)"},{"id":"c","text":"/var/lib/etcd (etcd data dir)"},{"id":"d","text":"/etc/kubernetes/admin.conf (admin kubeconfig)"}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are kubeadm-managed: static Pod manifests, the PKI directory, the etcd data directory, and the admin kubeconfig. Knowing these paths is essential for backup/restore and troubleshooting.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL files/dirs kubeadm uses for control-plane state on a control-plane node.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Cluster Architecture, Installation and Configuration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$On a kubeadm cluster, etcd serves client requests on port 2379 and peer (replication) traffic on port 2380.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. 2379 is the etcd client port (used by the apiserver); 2380 is the peer port for inter-member replication. The apiserver must point at 2379.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a kubeadm cluster, etcd serves client requests on port 2379 and peer (replication) traffic on port 2380.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command updates the image of container `app` in Deployment `web` imperatively?$tv2$, $tv2$[{"id":"a","text":"kubectl set image deploy/web app=nginx:1.27"},{"id":"b","text":"kubectl update deploy web --image=nginx:1.27"},{"id":"c","text":"kubectl patch image deploy web"},{"id":"d","text":"kubectl rollout image web nginx:1.27"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl set image deploy/web app=nginx:1.27` triggers a rolling update by changing the container image; `kubectl rollout undo` can revert it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command updates the image of container `app` in Deployment `web` imperatively?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A node is tainted `node.kubernetes.io/unschedulable:NoSchedule` after `kubectl cordon`. To resume scheduling you run:$tv2$, $tv2$[{"id":"a","text":"kubectl uncordon <node>"},{"id":"b","text":"kubectl taint node <node> node.kubernetes.io/unschedulable-"},{"id":"c","text":"kubectl drain <node>"},{"id":"d","text":"systemctl restart kubelet"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl uncordon` clears the `Unschedulable` mark so the scheduler can place new Pods again. It is the inverse of `cordon`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A node is tainted `node.kubernetes.io/unschedulable:NoSchedule` after `kubectl cordon`. To resume scheduling you run:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod with `restartPolicy: OnFailure` in a Job exits with code 1. The behavior is:$tv2$, $tv2$[{"id":"a","text":"The container is restarted in place until it succeeds or backoffLimit is reached."},{"id":"b","text":"The Pod is deleted immediately."},{"id":"c","text":"The Job is marked Complete."},{"id":"d","text":"A new node is provisioned."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$With `OnFailure`, the kubelet restarts the failing container in the same Pod. The Job's `backoffLimit` caps total retries before the Job is marked Failed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod with `restartPolicy: OnFailure` in a Job exits with code 1. The behavior is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a DaemonSet Pod to also run on control-plane nodes. You must add:$tv2$, $tv2$[{"id":"a","text":"a toleration for the node-role.kubernetes.io/control-plane:NoSchedule taint"},{"id":"b","text":"a nodeSelector for control-plane"},{"id":"c","text":"hostNetwork: true"},{"id":"d","text":"a PriorityClass"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Control-plane nodes carry a NoSchedule taint. A DaemonSet that must cover them needs a matching toleration; the controller still places one Pod per matching node.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/","label":"Kubernetes Docs — DaemonSet"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a DaemonSet Pod to also run on control-plane nodes. You must add:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about resource requests and limits.$tv2$, $tv2$[{"id":"a","text":"Requests influence scheduling (node must have enough allocatable)."},{"id":"b","text":"Exceeding a memory limit causes an OOMKill."},{"id":"c","text":"Exceeding a CPU limit throttles the container (not killed)."},{"id":"d","text":"A Pod with no requests is rejected by the apiserver."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$A Pod without requests/limits is allowed (it becomes BestEffort QoS). Requests drive scheduling, memory-over-limit is OOMKilled, and CPU-over-limit is throttled rather than killed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about resource requests and limits.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A higher-priority Pod cannot schedule due to capacity. With default preemption, the scheduler will:$tv2$, $tv2$[{"id":"a","text":"evict (preempt) lower-priority Pods on a node to make room"},{"id":"b","text":"wait indefinitely"},{"id":"c","text":"scale the node group automatically"},{"id":"d","text":"reject the Pod permanently"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Preemption lets the scheduler evict lower-priority Pods so a pending higher-priority Pod can be scheduled. Setting `preemptionPolicy: Never` disables this for that PriorityClass.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/pod-priority-preemption/","label":"Kubernetes Docs — Pod Priority and Preemption"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A higher-priority Pod cannot schedule due to capacity. With default preemption, the scheduler will:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Workloads and Scheduling$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A DaemonSet automatically schedules a Pod on every node added to the cluster that matches its selector.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. The DaemonSet controller ensures one matching Pod per eligible node and creates a Pod automatically when a new matching node joins.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/","label":"Kubernetes Docs — DaemonSet"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A DaemonSet automatically schedules a Pod on every node added to the cluster that matches its selector.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which object backs a Service's list of ready Pod IPs in modern Kubernetes?$tv2$, $tv2$[{"id":"a","text":"EndpointSlice"},{"id":"b","text":"NetworkPolicy"},{"id":"c","text":"IngressClass"},{"id":"d","text":"ConfigMap"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$EndpointSlices (the scalable successor to Endpoints) hold the ready backend addresses for a Service; kube-proxy programs routing from them.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which object backs a Service's list of ready Pod IPs in modern Kubernetes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need pods to reach a Service by short name `redis` within the same namespace. This works because:$tv2$, $tv2$[{"id":"a","text":"the Pod's DNS search list includes <namespace>.svc.cluster.local"},{"id":"b","text":"kube-proxy resolves names"},{"id":"c","text":"the Service has an ExternalName"},{"id":"d","text":"CoreDNS rewrites all queries to localhost"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Pods get a `search` list (e.g. `ns.svc.cluster.local svc.cluster.local cluster.local`) so the unqualified name `redis` resolves to the same-namespace Service.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need pods to reach a Service by short name `redis` within the same namespace. This works because:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy must allow DNS so Pods can still resolve names under a default-deny egress policy. You should allow egress to:$tv2$, $tv2$[{"id":"a","text":"kube-system CoreDNS Pods on UDP/TCP 53"},{"id":"b","text":"the apiserver on 6443"},{"id":"c","text":"all egress on port 80"},{"id":"d","text":"the node IP on 10250"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Under default-deny egress you must explicitly permit egress to the CoreDNS Pods (kube-dns) on port 53 UDP/TCP, otherwise name resolution breaks for selected Pods.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy must allow DNS so Pods can still resolve names under a default-deny egress policy. You should allow egress to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress uses host `shop.example.com`. Two Services must be reached at `/` and `/api`. The correct Ingress structure is:$tv2$, $tv2$[{"id":"a","text":"one rule with host shop.example.com and two paths (/ and /api) each with its backend"},{"id":"b","text":"two Ingress objects with the same host but different IngressClass"},{"id":"c","text":"a Service of type ExternalName"},{"id":"d","text":"a Gateway with no listeners"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A single Ingress rule can host multiple `paths`, each mapping a path to a backend Service/port — the standard fan-out (path-based) routing pattern.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress uses host `shop.example.com`. Two Services must be reached at `/` and `/api`. The correct Ingress structure is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which field selects which Ingress controller implements a given Ingress object?$tv2$, $tv2$[{"id":"a","text":"spec.ingressClassName"},{"id":"b","text":"metadata.namespace"},{"id":"c","text":"spec.rules[].host"},{"id":"d","text":"spec.backend.service.name"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`spec.ingressClassName` (referencing an IngressClass) tells which controller should program the Ingress. A default IngressClass is used if the field is omitted and one is marked default.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which field selects which Ingress controller implements a given Ingress object?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Gateway listener uses `allowedRoutes.namespaces.from: Selector`. This means:$tv2$, $tv2$[{"id":"a","text":"only Routes in namespaces matching the label selector may attach"},{"id":"b","text":"all namespaces may attach"},{"id":"c","text":"only the Gateway's own namespace may attach"},{"id":"d","text":"no Routes may attach"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`from: Selector` restricts route attachment to namespaces whose labels match the listener's `namespaces.selector`. `Same` limits to the Gateway namespace; `All` allows any.$tv2$, $tv2$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Gateway listener uses `allowedRoutes.namespaces.from: Selector`. This means:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the EndpointSlices (backends) for Service `web`?$tv2$, $tv2$[{"id":"a","text":"kubectl get endpointslices -l kubernetes.io/service-name=web"},{"id":"b","text":"kubectl get pods --svc web"},{"id":"c","text":"kubectl describe networkpolicy web"},{"id":"d","text":"kubectl get ingress web -o endpoints"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$EndpointSlices are labelled with `kubernetes.io/service-name`. Filtering by that label lists the slices (and thus the backend IPs) for a Service — handy when a Service has no working endpoints.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the EndpointSlices (backends) for Service `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about ClusterIP vs NodePort vs LoadBalancer Services.$tv2$, $tv2$[{"id":"a","text":"NodePort builds on ClusterIP and additionally opens a port on every node."},{"id":"b","text":"LoadBalancer builds on NodePort and provisions an external LB (cloud) or needs MetalLB on bare metal."},{"id":"c","text":"ClusterIP is the default and is internal-only."},{"id":"d","text":"LoadBalancer works out of the box on bare metal with no extra components."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$LoadBalancer requires a cloud controller or a bare-metal implementation (MetalLB/kube-vip); it is not automatic on bare metal. The layered ClusterIP→NodePort→LoadBalancer model is otherwise correct.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about ClusterIP vs NodePort vs LoadBalancer Services.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$An Ingress resource has no effect unless an Ingress controller is deployed and running in the cluster.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. The Ingress API only declares routing intent; an Ingress controller (ingress-nginx, etc.) must watch and program it for traffic to flow.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress resource has no effect unless an Ingress controller is deployed and running in the cluster.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows why a PVC is stuck Pending?$tv2$, $tv2$[{"id":"a","text":"kubectl describe pvc <name>"},{"id":"b","text":"kubectl logs pvc <name>"},{"id":"c","text":"kubectl top pvc <name>"},{"id":"d","text":"kubectl get sc --pvc <name>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe pvc` surfaces events such as "no persistent volumes available" or provisioning failures — the first step in diagnosing a Pending claim.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows why a PVC is stuck Pending?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must use a volume whose lifecycle is tied to the Pod (deleted when the Pod is removed). Use:$tv2$, $tv2$[{"id":"a","text":"an emptyDir volume"},{"id":"b","text":"a PVC with reclaimPolicy Retain"},{"id":"c","text":"a hostPath volume"},{"id":"d","text":"a static PV"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`emptyDir` is created when the Pod is assigned to a node and deleted when the Pod is removed — ephemeral, Pod-scoped storage (e.g. scratch space, sidecar log sharing).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must use a volume whose lifecycle is tied to the Pod (deleted when the Pod is removed). Use:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You set a StorageClass as cluster default but PVCs still fail to provision dynamically. A likely cause is:$tv2$, $tv2$[{"id":"a","text":"No provisioner/CSI driver is installed for that StorageClass."},{"id":"b","text":"The PVC requested ReadOnlyMany."},{"id":"c","text":"The Pod has no nodeSelector."},{"id":"d","text":"reclaimPolicy is Delete."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Dynamic provisioning needs a working provisioner (CSI driver/controller) matching the StorageClass `provisioner`. Without it, even a default StorageClass cannot create PVs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You set a StorageClass as cluster default but PVCs still fail to provision dynamically. A likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PV is `Released` (Retain) and you want to reuse the underlying disk for a fresh PVC. The cleanest approach is:$tv2$, $tv2$[{"id":"a","text":"Delete the PV object and recreate a new PV pointing at the same disk, then bind a new PVC."},{"id":"b","text":"Change the StorageClass."},{"id":"c","text":"Reboot the node."},{"id":"d","text":"Set the PVC to ReadOnlyMany."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A Retain PV stays Released with a stale claimRef. Either clear the claimRef to make it Available, or delete and recreate the PV referencing the same backing storage, then bind a new PVC.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PV is `Released` (Retain) and you want to reuse the underlying disk for a fresh PVC. The cleanest approach is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A StorageClass with `volumeBindingMode: WaitForFirstConsumer` delays PV provisioning until a Pod using the PVC is scheduled.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. WaitForFirstConsumer defers binding/provisioning until a consuming Pod is scheduled, enabling topology-aware placement (e.g. for local or zonal volumes).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A StorageClass with `volumeBindingMode: WaitForFirstConsumer` delays PV provisioning until a Pod using the PVC is scheduled.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all Pods across all namespaces with their status?$tv2$, $tv2$[{"id":"a","text":"kubectl get pods -A"},{"id":"b","text":"kubectl get pods --cluster"},{"id":"c","text":"kubectl describe pods --all"},{"id":"d","text":"kubectl pods list"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get pods -A` (or `--all-namespaces`) lists every Pod and its phase, the quickest cluster-wide health snapshot during triage.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all Pods across all namespaces with their status?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod is `Evicted` with reason "The node was low on resource: ephemeral-storage". The remediation is:$tv2$, $tv2$[{"id":"a","text":"Reduce the Pod's disk usage / add ephemeral-storage limits, or free node disk."},{"id":"b","text":"Increase the memory request."},{"id":"c","text":"Restart kube-proxy."},{"id":"d","text":"Add a toleration."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Ephemeral-storage eviction means node disk pressure. Clean node disk, set sensible ephemeral-storage requests/limits, or move logs/scratch to a volume.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is `Evicted` with reason "The node was low on resource: ephemeral-storage". The remediation is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$kube-apiserver logs show "etcdserver: request timed out". The MOST likely root cause is:$tv2$, $tv2$[{"id":"a","text":"etcd is unhealthy/slow or unreachable from the apiserver."},{"id":"b","text":"kubectl is misconfigured."},{"id":"c","text":"A NetworkPolicy blocks Pods."},{"id":"d","text":"The Service has no endpoints."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The apiserver depends on etcd; request timeouts point to etcd being down, slow (disk I/O), or network-unreachable. Check the etcd static Pod, disk latency, and `etcdctl endpoint health`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$kube-apiserver logs show "etcdserver: request timed out". The MOST likely root cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod cannot reach a Service although endpoints exist. Curling the Pod IP directly works. The likely cause is:$tv2$, $tv2$[{"id":"a","text":"kube-proxy is not programming Service rules on that node (check its DaemonSet)."},{"id":"b","text":"The image is wrong."},{"id":"c","text":"The PVC is Pending."},{"id":"d","text":"CoreDNS scaled to zero."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Direct Pod IP works but the Service VIP does not → Service routing (iptables/IPVS) is not programmed, typically a kube-proxy failure on that node. Inspect the kube-proxy DaemonSet/logs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod cannot reach a Service although endpoints exist. Curling the Pod IP directly works. The likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need the last 50 log lines for container `app` in a multi-container Pod. The command is:$tv2$, $tv2$[{"id":"a","text":"kubectl logs <pod> -c app --tail=50"},{"id":"b","text":"kubectl logs <pod> --all-containers --head=50"},{"id":"c","text":"kubectl logs <pod> --previous"},{"id":"d","text":"kubectl describe pod <pod> | tail -50"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$In a multi-container Pod you must select the container with `-c`; `--tail=50` limits the output to the most recent 50 lines.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need the last 50 log lines for container `app` in a multi-container Pod. The command is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A new Pod stays `Pending` and `kubectl describe` shows "untolerated taint" for a DEDICATED workload node. The intended fix is:$tv2$, $tv2$[{"id":"a","text":"Add a matching toleration to the Pod so it can land on the dedicated node."},{"id":"b","text":"Remove all taints cluster-wide."},{"id":"c","text":"Restart the scheduler."},{"id":"d","text":"Use hostNetwork."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$For a deliberately tainted dedicated node, the correct fix is to add the matching toleration to Pods that should run there — not to strip the taint, which would defeat node isolation.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A new Pod stays `Pending` and `kubectl describe` shows "untolerated taint" for a DEDICATED workload node. The intended fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A worker shows `Ready` but Pods scheduled there never start (stuck ContainerCreating). `crictl ps` is empty. Check first:$tv2$, $tv2$[{"id":"a","text":"The container runtime and CNI on that node (crictl info, CNI Pod logs)."},{"id":"b","text":"The apiserver audit log."},{"id":"c","text":"kubectl version skew."},{"id":"d","text":"The Ingress controller."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$ContainerCreating with no containers usually means the runtime or CNI cannot set up the sandbox. Inspect `crictl info`, containerd status, and the CNI plugin logs on that node.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A worker shows `Ready` but Pods scheduled there never start (stuck ContainerCreating). `crictl ps` is empty. Check first:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After `kubectl apply`, a Deployment is unchanged and kubectl prints "unchanged". You expected a rollout. The likely reason is:$tv2$, $tv2$[{"id":"a","text":"The applied manifest is identical to the live spec (no diff to trigger a rollout)."},{"id":"b","text":"The apiserver is down."},{"id":"c","text":"RBAC denied the apply."},{"id":"d","text":"The namespace is terminating."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A rollout only happens when the Pod template changes. If `apply` reports "unchanged", the manifest matched the live object; use `kubectl rollout restart` to force a new rollout.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After `kubectl apply`, a Deployment is unchanged and kubectl prints "unchanged". You expected a rollout. The likely reason is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$etcd is up but `kubectl` commands are very slow cluster-wide. A common root cause to investigate is:$tv2$, $tv2$[{"id":"a","text":"etcd disk latency / fsync performance (slow storage backing /var/lib/etcd)."},{"id":"b","text":"kubectl binary version."},{"id":"c","text":"A missing Service selector."},{"id":"d","text":"The Ingress class."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$etcd is highly sensitive to disk fsync latency. Slow disks cause apiserver/etcd latency that manifests as cluster-wide kubectl slowness. Check etcd metrics and move it to faster storage.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$etcd is up but `kubectl` commands are very slow cluster-wide. A common root cause to investigate is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Job never completes and its Pod is stuck `Pending` with "0/3 nodes are available: insufficient memory". The fix is:$tv2$, $tv2$[{"id":"a","text":"Lower the Job Pod memory request or add node capacity."},{"id":"b","text":"Increase backoffLimit."},{"id":"c","text":"Set restartPolicy: Always."},{"id":"d","text":"Delete CoreDNS."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$"insufficient memory" is a scheduling feasibility problem driven by the Pod's memory request vs node allocatable. Reduce the request or add memory capacity.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Job never completes and its Pod is stuck `Pending` with "0/3 nodes are available: insufficient memory". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You suspect a control-plane node's kubelet client cert expired. The symptom that fits is:$tv2$, $tv2$[{"id":"a","text":"The node goes NotReady and kubelet logs show TLS/certificate errors talking to the apiserver."},{"id":"b","text":"Pods get more CPU."},{"id":"c","text":"Services lose their cluster IP."},{"id":"d","text":"CoreDNS returns NXDOMAIN for everything."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$An expired kubelet client cert breaks the kubelet→apiserver mTLS, so the node stops heartbeating and goes NotReady with cert errors. Rotate the kubelet cert / re-issue its kubeconfig.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You suspect a control-plane node's kubelet client cert expired. The symptom that fits is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To create an ephemeral debug container in a running Pod (e.g. to get a shell with tools), use:$tv2$, $tv2$[{"id":"a","text":"kubectl debug -it <pod> --image=busybox --target=<container>"},{"id":"b","text":"kubectl exec -it <pod> --add-tools"},{"id":"c","text":"kubectl run debug --attach"},{"id":"d","text":"kubectl cp tools <pod>:/"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl debug` injects an ephemeral container sharing the target Pod's namespaces, useful when the app image lacks a shell or debugging tools. It does not restart the Pod.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To create an ephemeral debug container in a running Pod (e.g. to get a shell with tools), use:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Troubleshooting$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A Pod in `CrashLoopBackOff` is repeatedly starting and exiting; the back-off delay between restarts grows over time.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. The kubelet applies an exponential back-off (capped) between restarts of a repeatedly failing container, which is why the state is named CrashLoopBackOff.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:cka-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-cka-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod in `CrashLoopBackOff` is repeatedly starting and exiting; the back-off delay between restarts grows over time.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which `kubectl` command imperatively creates a Pod named `mypod` running the `nginx:1.25` image and exposes container port 80, without creating a Deployment?$tv2$, $tv2$[{"id":"a","text":"kubectl create pod mypod --image=nginx:1.25 --port=80"},{"id":"b","text":"kubectl run mypod --image=nginx:1.25 --restart=Never --port=80"},{"id":"c","text":"kubectl apply pod mypod --image=nginx:1.25 --port=80"},{"id":"d","text":"kubectl deploy mypod --image=nginx:1.25 --port=80"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl run` with `--restart=Never` creates a bare Pod (not a Deployment or Job). `--port` records the containerPort. `kubectl create pod` is not a valid subcommand, and `kubectl apply` requires a manifest.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `kubectl` command imperatively creates a Pod named `mypod` running the `nginx:1.25` image and exposes container port 80, without creating a Deployment?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must run a one-off database migration to completion before the main application container starts and serves traffic. Which Pod construct is the correct fit?$tv2$, $tv2$[{"id":"a","text":"A sidecar container in the same Pod"},{"id":"b","text":"An initContainer that runs the migration"},{"id":"c","text":"A separate Deployment running the migration script"},{"id":"d","text":"A liveness probe that triggers the migration"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Init containers run to completion sequentially before any app containers start. Sidecars run alongside app containers (not before), and probes do not run workloads.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must run a one-off database migration to completion before the main application container starts and serves traffic. Which Pod construct is the correct fit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$You need a workload that runs to completion on a schedule every night at 02:00. Select ALL true statements about Kubernetes CronJobs.$tv2$, $tv2$[{"id":"a","text":"CronJob.spec.schedule uses standard cron syntax (e.g. \"0 2 * * *\")."},{"id":"b","text":"A CronJob creates a Job object for each scheduled run."},{"id":"c","text":"CronJobs run forever; like Deployments they restart Pods on completion."},{"id":"d","text":"spec.concurrencyPolicy can be Allow, Forbid, or Replace."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$CronJobs spawn a Job per schedule fire. Jobs run to completion — CronJobs do NOT restart finished Pods like Deployments. `concurrencyPolicy` controls overlapping runs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"},{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a workload that runs to completion on a schedule every night at 02:00. Select ALL true statements about Kubernetes CronJobs.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You build a container image and the running container exits immediately. The Dockerfile ends with `CMD ["./app"]` but a `kubectl logs` shows "exec: ./app: not found". The most likely cause is:$tv2$, $tv2$[{"id":"a","text":"The image uses a scratch base and the binary is dynamically linked against glibc that is not present."},{"id":"b","text":"The Pod has no readiness probe configured."},{"id":"c","text":"The Service selector does not match the Pod labels."},{"id":"d","text":"A NetworkPolicy is blocking the container from starting."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A dynamically linked binary placed in a scratch image fails to exec because the dynamic loader/glibc is absent. Probes, Services, and NetworkPolicies are unrelated to container startup exec failures.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You build a container image and the running container exits immediately. The Dockerfile ends with `CMD ["./app"]` but a `kubectl logs` shows "exec: ./app: not found". The most likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You need to update the image of Deployment `web` to `nginx:1.27` while preserving rollout history. Which command does this idiomatically?$tv2$, $tv2$[{"id":"a","text":"kubectl edit deployment web (and save the file)"},{"id":"b","text":"kubectl set image deployment/web nginx=nginx:1.27"},{"id":"c","text":"kubectl replace deployment/web --image=nginx:1.27"},{"id":"d","text":"kubectl patch pod web --image=nginx:1.27"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl set image` is the canonical, recorded way to update a container image on a Deployment and triggers a rolling update with a revision recorded in the rollout history.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to update the image of Deployment `web` to `nginx:1.27` while preserving rollout history. Which command does this idiomatically?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A bad image was rolled out to Deployment `api`. Which command rolls back to the previous revision?$tv2$, $tv2$[{"id":"a","text":"kubectl undo deployment api"},{"id":"b","text":"kubectl rollout undo deployment/api"},{"id":"c","text":"kubectl rollback deployment api --to-revision=previous"},{"id":"d","text":"kubectl rollout revert deployment/api"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl rollout undo deployment/<name>` reverts to the prior revision. Use `--to-revision=N` to target a specific one.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A bad image was rolled out to Deployment `api`. Which command rolls back to the previous revision?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a Deployment's RollingUpdate strategy, `maxSurge: 25%` and `maxUnavailable: 0` for a 4-replica Deployment means:$tv2$, $tv2$[{"id":"a","text":"At most 1 extra Pod above 4 may exist during rollout; never fewer than 4 ready."},{"id":"b","text":"Up to 25% of Pods may be unavailable at any time."},{"id":"c","text":"Pods are upgraded one at a time, terminating the old first."},{"id":"d","text":"The Deployment is paused until all Pods are ready."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`maxSurge` is how many Pods above desired may be created during rollout. `maxUnavailable: 0` means the ready count never drops below desired — useful for zero-downtime updates.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Deployment's RollingUpdate strategy, `maxSurge: 25%` and `maxUnavailable: 0` for a 4-replica Deployment means:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which tool packages Kubernetes manifests as versioned, templatable units called "charts" with values overrides?$tv2$, $tv2$[{"id":"a","text":"Kustomize"},{"id":"b","text":"Helm"},{"id":"c","text":"Skaffold"},{"id":"d","text":"kubectl apply -k"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Helm uses charts and a `values.yaml` template system. Kustomize composes overlays from base manifests without templating.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which tool packages Kubernetes manifests as versioned, templatable units called "charts" with values overrides?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Your app boots in 45 seconds before its `/healthz` endpoint becomes responsive. The kubelet keeps killing the Pod with "Liveness probe failed". The MOST appropriate fix is:$tv2$, $tv2$[{"id":"a","text":"Remove the liveness probe entirely."},{"id":"b","text":"Add a startupProbe so the liveness probe is suppressed until the container has finished starting."},{"id":"c","text":"Replace the liveness probe with a readiness probe."},{"id":"d","text":"Increase the Pod's memory limit."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$startupProbe lets slow-starting containers boot without being killed by liveness. Replacing liveness with readiness leaves the Pod running but never marked ready, hurting traffic. Removing liveness entirely is not recommended for long-lived processes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Your app boots in 45 seconds before its `/healthz` endpoint becomes responsive. The kubelet keeps killing the Pod with "Liveness probe failed". The MOST appropriate fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Pod `web-7d8` is in a `CrashLoopBackOff`. Which sequence is the BEST first-step diagnosis?$tv2$, $tv2$[{"id":"a","text":"kubectl delete pod web-7d8 and let it be recreated."},{"id":"b","text":"kubectl logs web-7d8 --previous; kubectl describe pod web-7d8"},{"id":"c","text":"kubectl exec -it web-7d8 -- /bin/sh"},{"id":"d","text":"kubectl scale deployment web --replicas=0 then back up."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`logs --previous` shows stdout of the crashed container before restart; `describe` shows Events and exit codes. Exec only works on a running container.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Pod `web-7d8` is in a `CrashLoopBackOff`. Which sequence is the BEST first-step diagnosis?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about probes in Kubernetes.$tv2$, $tv2$[{"id":"a","text":"A failing readinessProbe removes the Pod's IP from Service endpoints but does NOT restart the container."},{"id":"b","text":"A failing livenessProbe causes the kubelet to restart the container."},{"id":"c","text":"A startupProbe runs continuously throughout the Pod's lifetime."},{"id":"d","text":"Probes can be httpGet, exec, tcpSocket, or grpc actions."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$startupProbe runs ONLY during startup, then liveness/readiness take over. Readiness gates traffic without restart; liveness triggers restart. Probe actions are httpGet/exec/tcpSocket/grpc.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about probes in Kubernetes.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a ConfigMap named `app-config` containing a single key `LOG_LEVEL=debug` imperatively?$tv2$, $tv2$[{"id":"a","text":"kubectl create configmap app-config --from-literal=LOG_LEVEL=debug"},{"id":"b","text":"kubectl set configmap app-config LOG_LEVEL=debug"},{"id":"c","text":"kubectl run configmap app-config --env=LOG_LEVEL=debug"},{"id":"d","text":"kubectl apply configmap app-config --data=LOG_LEVEL=debug"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--from-literal=KEY=VALUE` is the standard way to inject literal key/value pairs into a ConfigMap. `--from-file=` loads file contents instead.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a ConfigMap named `app-config` containing a single key `LOG_LEVEL=debug` imperatively?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need a Pod that runs as a NON-root user with UID 1000 and rejects privilege escalation. Which `securityContext` fragment achieves this?$tv2$, $tv2$[{"id":"a","text":"spec.securityContext: { runAsUser: 1000, allowPrivilegeEscalation: false }"},{"id":"b","text":"spec.securityContext: { runAsUser: 1000 } and spec.containers[].securityContext: { allowPrivilegeEscalation: false }"},{"id":"c","text":"spec.containers[].env: { USER: \"1000\", PRIV_ESCAL: \"false\" }"},{"id":"d","text":"spec.serviceAccountName: non-root"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`runAsUser` is valid at Pod or container level. `allowPrivilegeEscalation` is a CONTAINER-level field only and must be set in the container's securityContext.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a Pod that runs as a NON-root user with UID 1000 and rejects privilege escalation. Which `securityContext` fragment achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How are Secret values stored in etcd by default in a managed Kubernetes cluster with default settings?$tv2$, $tv2$[{"id":"a","text":"AES-256 encrypted at rest with a customer-managed key."},{"id":"b","text":"Base64-encoded (NOT encrypted) unless an EncryptionConfiguration is configured."},{"id":"c","text":"Hashed with bcrypt."},{"id":"d","text":"Stored only on the kubelet node, never in etcd."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$By default, Kubernetes Secrets are base64-encoded in etcd — encoding, NOT encryption. Encryption-at-rest requires `EncryptionConfiguration` on the API server.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How are Secret values stored in etcd by default in a managed Kubernetes cluster with default settings?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod needs to call the Kubernetes API to list Pods in its namespace. Which is the correct approach?$tv2$, $tv2$[{"id":"a","text":"Hard-code an admin kubeconfig as a Secret in the Pod."},{"id":"b","text":"Create a ServiceAccount with a Role granting `get,list pods`, bind it via RoleBinding, and set `spec.serviceAccountName` on the Pod."},{"id":"c","text":"Set `spec.privileged: true` on the container."},{"id":"d","text":"Disable RBAC for the namespace."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The correct pattern is a dedicated ServiceAccount bound to a least-privilege Role via a RoleBinding. The Pod uses that SA via `spec.serviceAccountName`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod needs to call the Kubernetes API to list Pods in its namespace. Which is the correct approach?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A container requests 100m CPU and limits 500m CPU. The node has free capacity. During traffic spikes the container is throttled at ~500m even though there is idle CPU. Why?$tv2$, $tv2$[{"id":"a","text":"The request, not the limit, caps usage."},{"id":"b","text":"The CPU LIMIT enforces a hard cap via CFS quota — usage above 500m is throttled regardless of node capacity."},{"id":"c","text":"The kubelet evicts the Pod above 500m CPU."},{"id":"d","text":"Throttling occurs only when memory pressure exists."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$CPU `limits` are enforced as hard CFS quotas — a container is throttled at the limit even when the node is idle. `requests` only affect scheduling.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container requests 100m CPU and limits 500m CPU. The node has free capacity. During traffic spikes the container is throttled at ~500m even though there is idle CPU. Why?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Service type exposes a Pod set on a stable cluster-internal IP only?$tv2$, $tv2$[{"id":"a","text":"NodePort"},{"id":"b","text":"LoadBalancer"},{"id":"c","text":"ClusterIP"},{"id":"d","text":"ExternalName"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$ClusterIP (the default) is internal-only. NodePort opens a port on every node; LoadBalancer provisions an external LB; ExternalName is a DNS alias.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Service type exposes a Pod set on a stable cluster-internal IP only?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service `db.production` is reached from a Pod in the `production` namespace via which fully qualified DNS name?$tv2$, $tv2$[{"id":"a","text":"db"},{"id":"b","text":"db.svc.production"},{"id":"c","text":"db.production.svc.cluster.local"},{"id":"d","text":"production.db.cluster.local"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Service DNS is `<svc>.<ns>.svc.cluster.local`. Within the same namespace `db` alone resolves; the FQDN is `db.production.svc.cluster.local`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service `db.production` is reached from a Pod in the `production` namespace via which fully qualified DNS name?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$About Kubernetes NetworkPolicies, select ALL true statements.$tv2$, $tv2$[{"id":"a","text":"A NetworkPolicy needs a CNI plugin that implements policy enforcement (e.g. Calico, Cilium) to take effect."},{"id":"b","text":"In a namespace with NO NetworkPolicy, all Pod-to-Pod traffic is allowed by default."},{"id":"c","text":"A NetworkPolicy selecting Pods with no `ingress` rules denies ALL ingress to those Pods."},{"id":"d","text":"NetworkPolicies can filter by destination port AND by source Pod labels."}]$tv2$::jsonb, $tv2$["a","b","c","d"]$tv2$::jsonb, $tv2$All four are true. The default cluster posture is allow-all until a NetworkPolicy targets a Pod; once targeted, traffic must match an explicit allow rule.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$About Kubernetes NetworkPolicies, select ALL true statements.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to expose HTTP path `/api/*` of Service `api` and `/web/*` of Service `web` on the same external hostname. The correct resource is:$tv2$, $tv2$[{"id":"a","text":"Two LoadBalancer Services on the same external IP"},{"id":"b","text":"An Ingress with two path rules pointing to the two Services"},{"id":"c","text":"A NodePort Service with multiple ports"},{"id":"d","text":"A NetworkPolicy with two egress rules"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Ingress provides HTTP host- and path-based routing to multiple backend Services through a single ingress controller.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to expose HTTP path `/api/*` of Service `api` and `/web/*` of Service `web` on the same external hostname. The correct resource is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command generates a Pod manifest to stdout WITHOUT creating the Pod, useful for editing before applying?$tv2$, $tv2$[{"id":"a","text":"kubectl run nginx --image=nginx --dry-run=client -o yaml"},{"id":"b","text":"kubectl create pod nginx --image=nginx --no-apply"},{"id":"c","text":"kubectl generate pod nginx --image=nginx"},{"id":"d","text":"kubectl run nginx --image=nginx --export"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--dry-run=client -o yaml` renders the manifest locally without contacting the server, the standard recipe for scaffolding a YAML to edit. `--export` was removed and `kubectl generate` does not exist.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command generates a Pod manifest to stdout WITHOUT creating the Pod, useful for editing before applying?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod uses the ambassador pattern. What does the ambassador container do?$tv2$, $tv2$[{"id":"a","text":"Runs the migration before the app starts."},{"id":"b","text":"Proxies outbound network connections (e.g. to a sharded database) so the main container talks only to localhost."},{"id":"c","text":"Transforms the app's log format for an external monitoring system."},{"id":"d","text":"Holds the Pod's shared volume open."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The ambassador pattern places a proxy sidecar that brokers connections to external services, letting the main container use a simple localhost endpoint while the ambassador handles discovery/sharding/TLS.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod uses the ambassador pattern. What does the ambassador container do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A Job with `restartPolicy: Always` is valid in its Pod template.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Job Pod templates must use `restartPolicy: OnFailure` or `Never`. `Always` is rejected because a Job must be able to reach a terminal completed state.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Job with `restartPolicy: Always` is valid in its Pod template.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a Job whose Pods are cleaned up automatically 100 seconds after the Job finishes. Which field do you set?$tv2$, $tv2$[{"id":"a","text":"spec.ttlSecondsAfterFinished: 100"},{"id":"b","text":"spec.activeDeadlineSeconds: 100"},{"id":"c","text":"spec.backoffLimit: 100"},{"id":"d","text":"spec.completions: 100"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`ttlSecondsAfterFinished` lets the TTL controller delete a finished Job (and its Pods) after the given seconds. `activeDeadlineSeconds` caps runtime, not cleanup.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a Job whose Pods are cleaned up automatically 100 seconds after the Job finishes. Which field do you set?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A multi-stage Dockerfile copies a compiled binary from a `builder` stage into a minimal final image. The primary benefit is:$tv2$, $tv2$[{"id":"a","text":"Faster CPU at runtime."},{"id":"b","text":"A smaller final image with no build toolchain, reducing attack surface and pull time."},{"id":"c","text":"Automatic horizontal scaling."},{"id":"d","text":"Built-in liveness probing."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Multi-stage builds discard compilers and intermediate artifacts, shipping only the runtime artifact. This shrinks the image and removes unneeded tools from the attack surface.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A multi-stage Dockerfile copies a compiled binary from a `builder` stage into a minimal final image. The primary benefit is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Pod field guarantees an init container completes before a sidecar (native sidecar) and the main app start?$tv2$, $tv2$[{"id":"a","text":"A regular initContainer entry (without restartPolicy) listed before the native sidecar."},{"id":"b","text":"A container in spec.containers with a higher priority."},{"id":"c","text":"spec.terminationGracePeriodSeconds."},{"id":"d","text":"An emptyDir volume."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Ordinary init containers (no `restartPolicy: Always`) run to completion sequentially before any sidecar or app container starts. Native sidecars are init containers WITH `restartPolicy: Always` and stay running.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Pod field guarantees an init container completes before a sidecar (native sidecar) and the main app start?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid reasons to put two containers in the SAME Pod rather than two Pods.$tv2$, $tv2$[{"id":"a","text":"They must share the same network namespace (localhost) and lifecycle."},{"id":"b","text":"They need to share an emptyDir volume tightly coupled to the app."},{"id":"c","text":"They should scale independently of each other."},{"id":"d","text":"One adapts/proxies for the other (sidecar/adapter/ambassador)."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Co-locating is right for tightly coupled helpers sharing network/volumes/lifecycle. If two components must scale independently, they belong in separate Pods/Deployments.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid reasons to put two containers in the SAME Pod rather than two Pods.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a CronJob that runs `date` every 5 minutes using the busybox image?$tv2$, $tv2$[{"id":"a","text":"kubectl create cronjob now --image=busybox --schedule=\"*/5 * * * *\" -- date"},{"id":"b","text":"kubectl run cronjob now --image=busybox --every=5m -- date"},{"id":"c","text":"kubectl create job now --cron=\"*/5 * * * *\" --image=busybox -- date"},{"id":"d","text":"kubectl schedule cronjob now --image=busybox -- date"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl create cronjob <name> --image= --schedule="<cron>" -- <cmd>` is the imperative form. The command after `--` becomes the container args.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a CronJob that runs `date` every 5 minutes using the busybox image?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container should declare it listens on TCP 8080. Which Pod spec field documents this (and is used by some tooling/probes)?$tv2$, $tv2$[{"id":"a","text":"spec.containers[].ports: [{ containerPort: 8080 }]"},{"id":"b","text":"spec.ports: [{ port: 8080 }]"},{"id":"c","text":"spec.containers[].expose: 8080"},{"id":"d","text":"metadata.annotations.port: \"8080\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`containers[].ports[].containerPort` declares the port the container listens on. It is informational/used by tooling; it does not by itself publish the port externally.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container should declare it listens on TCP 8080. Which Pod spec field documents this (and is used by some tooling/probes)?$tv2$);
