INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A Deployment with `progressDeadlineSeconds: 600` will report a `ProgressDeadlineExceeded` condition if the rollout makes no progress within 600 seconds.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`progressDeadlineSeconds` bounds how long a rollout may stall; exceeding it sets the Deployment's `Progressing` condition to `False` with reason `ProgressDeadlineExceeded`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment with `progressDeadlineSeconds: 600` will report a `ProgressDeadlineExceeded` condition if the rollout makes no progress within 600 seconds.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You change a Deployment's `spec.template` annotation only (no image change). What happens?$tv2$, $tv2$[{"id":"a","text":"Nothing — only image changes trigger rollouts."},{"id":"b","text":"A new ReplicaSet is created and a rolling update occurs because the Pod template hash changed."},{"id":"c","text":"The Deployment is rejected."},{"id":"d","text":"Existing Pods are patched in place without restart."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Any change to `spec.template` (including labels/annotations on the Pod template) changes the template hash, creating a new ReplicaSet and triggering a rolling update.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You change a Deployment's `spec.template` annotation only (no image change). What happens?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command applies all YAML manifests in a directory recursively?$tv2$, $tv2$[{"id":"a","text":"kubectl apply -f ./manifests/ -R"},{"id":"b","text":"kubectl apply --dir ./manifests/"},{"id":"c","text":"kubectl create -r ./manifests/"},{"id":"d","text":"kubectl apply -f ./manifests/ --all"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl apply -f <dir> -R` (or `--recursive`) walks subdirectories applying every manifest found.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command applies all YAML manifests in a directory recursively?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment has `minReadySeconds: 20`. During a rolling update, a new Pod becomes Ready. When is it counted as available?$tv2$, $tv2$[{"id":"a","text":"Immediately when Ready."},{"id":"b","text":"Only after it has been Ready for 20 continuous seconds."},{"id":"c","text":"After 20 seconds regardless of Ready state."},{"id":"d","text":"Never — minReadySeconds blocks the rollout."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`minReadySeconds` requires a Pod to stay Ready for that duration before it is considered available, slowing rollouts so flapping Pods are not counted as healthy.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment has `minReadySeconds: 20`. During a rolling update, a new Pod becomes Ready. When is it counted as available?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Helm: which command upgrades a release `myapp` with a new chart version and overridden value `replicaCount=4`?$tv2$, $tv2$[{"id":"a","text":"helm upgrade myapp ./chart --set replicaCount=4"},{"id":"b","text":"helm update myapp --replicas=4"},{"id":"c","text":"helm install myapp ./chart --upgrade --replicaCount 4"},{"id":"d","text":"helm patch myapp replicaCount=4"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`helm upgrade <release> <chart> --set key=value` upgrades an existing release with overrides. `--set` overrides values inline; `-f` supplies a values file.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Helm: which command upgrades a release `myapp` with a new chart version and overridden value `replicaCount=4`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Kustomize: which kubectl command applies a kustomization in the current directory?$tv2$, $tv2$[{"id":"a","text":"kubectl apply -k ."},{"id":"b","text":"kubectl kustomize apply ."},{"id":"c","text":"kubectl apply --kustomize-build ."},{"id":"d","text":"kubectl apply -f kustomization.yaml"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl apply -k <dir>` builds the kustomization (base + overlays/patches) and applies the result. `kubectl kustomize <dir>` only renders to stdout.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Kustomize: which kubectl command applies a kustomization in the current directory?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which probe should you use to delay traffic to a Pod until it has loaded its cache, WITHOUT restarting the container if loading is slow?$tv2$, $tv2$[{"id":"a","text":"livenessProbe"},{"id":"b","text":"readinessProbe"},{"id":"c","text":"startupProbe"},{"id":"d","text":"A preStop hook"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Readiness gates Service traffic without restarting the container. Liveness restarts on failure; startupProbe protects slow boots from liveness but does not itself gate Service endpoints the way readiness does.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which probe should you use to delay traffic to a Pod until it has loaded its cache, WITHOUT restarting the container if loading is slow?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A probe has `initialDelaySeconds: 10`. What does this configure?$tv2$, $tv2$[{"id":"a","text":"How long the kubelet waits after container start before the FIRST probe."},{"id":"b","text":"The interval between probes."},{"id":"c","text":"How long to wait for a probe response before timing out."},{"id":"d","text":"Number of failures before action."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`initialDelaySeconds` delays the first probe after the container starts. `periodSeconds` is the interval, `timeoutSeconds` the per-probe timeout, `failureThreshold` the failure count.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A probe has `initialDelaySeconds: 10`. What does this configure?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container is OOMKilled. Where is this most directly visible?$tv2$, $tv2$[{"id":"a","text":"kubectl describe pod — the last state shows Terminated with reason OOMKilled."},{"id":"b","text":"kubectl get svc"},{"id":"c","text":"kubectl top nodes only"},{"id":"d","text":"It is never reported anywhere."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe pod` shows the container's Last State as `Terminated` with reason `OOMKilled` and exit code 137 when the kernel OOM killer reaped it for exceeding its memory limit.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container is OOMKilled. Where is this most directly visible?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command opens an interactive shell in a running Pod's `app` container?$tv2$, $tv2$[{"id":"a","text":"kubectl exec -it <pod> -c app -- /bin/sh"},{"id":"b","text":"kubectl shell <pod>/app"},{"id":"c","text":"kubectl run -it <pod> -c app -- sh"},{"id":"d","text":"kubectl attach <pod> -c app --tty"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl exec -it <pod> -c <container> -- <shell>` runs a command in an existing container. `kubectl attach` attaches to the main process's stdio, not a new shell.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command opens an interactive shell in a running Pod's `app` container?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A distroless container has no shell, so `kubectl exec -- sh` fails. Which feature lets you attach a debugging container to the running Pod?$tv2$, $tv2$[{"id":"a","text":"kubectl debug <pod> --image=busybox --target=app (ephemeral container)"},{"id":"b","text":"kubectl exec --force <pod>"},{"id":"c","text":"kubectl cp a shell into the Pod"},{"id":"d","text":"kubectl logs --debug <pod>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl debug` injects an ephemeral container sharing the target container's namespaces, letting you troubleshoot images that lack a shell or tools.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A distroless container has no shell, so `kubectl exec -- sh` fails. Which feature lets you attach a debugging container to the running Pod?$tv2$);
