INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Secret should be mounted so each key becomes a file under `/etc/creds`. Which volume mount is correct?$tv2$, $tv2$[{"id":"a","text":"A volume of type `secret` referencing the Secret, mounted at /etc/creds."},{"id":"b","text":"envFrom.secretRef pointed at /etc/creds."},{"id":"c","text":"A configMap volume."},{"id":"d","text":"hostPath: /etc/creds."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A `secret` volume projects each Secret key as a file under the mountPath. `envFrom`/`secretKeyRef` inject env vars, not files.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Secret should be mounted so each key becomes a file under `/etc/creds`. Which volume mount is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A container sets `securityContext.readOnlyRootFilesystem: true` and the app needs to write temp files. The correct fix is:$tv2$, $tv2$[{"id":"a","text":"Set readOnlyRootFilesystem: false (defeats the hardening)."},{"id":"b","text":"Mount an emptyDir volume at the app's temp/writable path."},{"id":"c","text":"Run the container as root."},{"id":"d","text":"Add a livenessProbe."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Keep the root filesystem read-only for hardening and provide writable scratch space by mounting a writable volume (e.g. emptyDir) at the path the app writes to.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container sets `securityContext.readOnlyRootFilesystem: true` and the app needs to write temp files. The correct fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `securityContext` setting drops all Linux capabilities and adds back only `NET_BIND_SERVICE`?$tv2$, $tv2$[{"id":"a","text":"capabilities: { drop: [\"ALL\"], add: [\"NET_BIND_SERVICE\"] }"},{"id":"b","text":"privileged: false, netBind: true"},{"id":"c","text":"capabilities: { remove: \"*\", grant: \"NET_BIND_SERVICE\" }"},{"id":"d","text":"runAsUser: 0, capAdd: NET_BIND_SERVICE"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Container `securityContext.capabilities` uses `drop` and `add` lists. Dropping `ALL` then adding only what is needed follows least-privilege.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `securityContext` setting drops all Linux capabilities and adds back only `NET_BIND_SERVICE`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$Setting `automountServiceAccountToken: false` on a Pod or ServiceAccount prevents the API token from being mounted into the Pod.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Disabling automount stops the default ServiceAccount token projection, reducing the blast radius for Pods that never call the Kubernetes API.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Setting `automountServiceAccountToken: false` on a Pod or ServiceAccount prevents the API token from being mounted into the Pod.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container needs the Pod's own name available as an env var. Which mechanism provides this?$tv2$, $tv2$[{"id":"a","text":"The Downward API via fieldRef: metadata.name"},{"id":"b","text":"A ConfigMap auto-created per Pod"},{"id":"c","text":"A Secret named after the Pod"},{"id":"d","text":"spec.hostname only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Downward API exposes Pod metadata (name, namespace, labels, resource limits) to containers via `env[].valueFrom.fieldRef` or a downwardAPI volume.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container needs the Pod's own name available as an env var. Which mechanism provides this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a TLS Secret from cert and key files?$tv2$, $tv2$[{"id":"a","text":"kubectl create secret tls my-tls --cert=tls.crt --key=tls.key"},{"id":"b","text":"kubectl create secret generic my-tls --tls --cert tls.crt"},{"id":"c","text":"kubectl create tls my-tls tls.crt tls.key"},{"id":"d","text":"kubectl create secret my-tls --type=tls"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl create secret tls <name> --cert= --key=` produces a `kubernetes.io/tls` Secret containing `tls.crt` and `tls.key`, suitable for Ingress TLS.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a TLS Secret from cert and key files?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about resource requests and limits.$tv2$, $tv2$[{"id":"a","text":"Scheduling decisions are based on requests, not limits."},{"id":"b","text":"A container exceeding its memory limit is OOMKilled."},{"id":"c","text":"A container exceeding its CPU limit is OOMKilled."},{"id":"d","text":"If requests == limits for all resources, the Pod gets the Guaranteed QoS class."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$CPU is compressible: exceeding the CPU limit causes throttling, NOT OOMKill. Memory is incompressible: exceeding the memory limit triggers OOMKill. Requests drive scheduling and QoS classification.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about resource requests and limits.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod needs an emptyDir that lives in RAM (tmpfs) for fast scratch I/O. Which spec achieves this?$tv2$, $tv2$[{"id":"a","text":"volumes: [{ name: cache, emptyDir: { medium: Memory } }]"},{"id":"b","text":"volumes: [{ name: cache, emptyDir: { type: tmpfs } }]"},{"id":"c","text":"volumes: [{ name: cache, ramDisk: {} }]"},{"id":"d","text":"volumes: [{ name: cache, hostPath: { path: /dev/shm } }]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`emptyDir.medium: Memory` backs the volume with tmpfs (RAM). It counts against the container's memory limit and is cleared when the Pod is removed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod needs an emptyDir that lives in RAM (tmpfs) for fast scratch I/O. Which spec achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a PVC of 5Gi that is dynamically provisioned by the `fast-ssd` StorageClass. Which fields are required on the PVC?$tv2$, $tv2$[{"id":"a","text":"spec.storageClassName: fast-ssd, spec.accessModes, spec.resources.requests.storage: 5Gi"},{"id":"b","text":"spec.volumeName: fast-ssd only"},{"id":"c","text":"spec.capacity.storage: 5Gi only"},{"id":"d","text":"spec.provisioner: fast-ssd"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A dynamically provisioned PVC needs a `storageClassName`, `accessModes`, and a storage request. `provisioner` is a StorageClass field, and `capacity` is a PV field.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a PVC of 5Gi that is dynamically provisioned by the `fast-ssd` StorageClass. Which fields are required on the PVC?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command exposes Deployment `web` as a ClusterIP Service on port 80 targeting container port 8080?$tv2$, $tv2$[{"id":"a","text":"kubectl expose deployment web --port=80 --target-port=8080"},{"id":"b","text":"kubectl service create web --port=80 --container=8080"},{"id":"c","text":"kubectl expose deployment web --listen=80 --forward=8080"},{"id":"d","text":"kubectl create svc web 80:8080"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl expose deployment <name> --port= --target-port=` creates a Service (ClusterIP by default) whose `port` is the Service port and `targetPort` the container port.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command exposes Deployment `web` as a ClusterIP Service on port 80 targeting container port 8080?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A headless Service has `clusterIP: None`. What is its effect for a backing StatefulSet?$tv2$, $tv2$[{"id":"a","text":"It load-balances over a single virtual IP."},{"id":"b","text":"DNS returns the individual Pod IPs (and per-Pod DNS names) instead of one virtual IP."},{"id":"c","text":"It blocks all traffic."},{"id":"d","text":"It exposes the Service on every node."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A headless Service (`clusterIP: None`) skips the virtual IP; DNS returns the Pod A records directly, enabling per-Pod addressing for StatefulSets.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A headless Service has `clusterIP: None`. What is its effect for a backing StatefulSet?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service maps `port: 80` to `targetPort: http`. What must the Pod define for this to resolve?$tv2$, $tv2$[{"id":"a","text":"A named container port `http` in containers[].ports."},{"id":"b","text":"An env var named http."},{"id":"c","text":"A label http=true."},{"id":"d","text":"An annotation port/http."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A string `targetPort` references a container port by its `name`. The Pod must declare `ports: [{ name: http, containerPort: <n> }]` so the Service can resolve it.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service maps `port: 80` to `targetPort: http`. What must the Pod define for this to resolve?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A NetworkPolicy that specifies an `egress` rule restricts only outbound traffic from the selected Pods and does not by itself affect inbound traffic.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Ingress and egress are independent in a NetworkPolicy. Declaring `policyTypes: [Egress]` with egress rules constrains outbound traffic only; ingress remains governed by other policies (or default-allow).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy that specifies an `egress` rule restricts only outbound traffic from the selected Pods and does not by itself affect inbound traffic.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Two NetworkPolicies select the same Pod: one allows ingress from `app=a`, another from `app=b`. The effective ingress allow set is:$tv2$, $tv2$[{"id":"a","text":"Only app=a (first policy wins)."},{"id":"b","text":"The UNION — traffic from app=a OR app=b is allowed."},{"id":"c","text":"The intersection — only Pods that are both app=a and app=b."},{"id":"d","text":"Nothing — conflicting policies deny all."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$NetworkPolicies are additive. When multiple policies select a Pod, the allowed traffic is the union of all their rules; there is no deny rule and no precedence.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two NetworkPolicies select the same Pod: one allows ingress from `app=a`, another from `app=b`. The effective ingress allow set is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress needs path `/v2` to route to `api-v2:80`. Which `pathType` matches `/v2` and `/v2/users` but NOT `/v20`?$tv2$, $tv2$[{"id":"a","text":"Exact"},{"id":"b","text":"Prefix"},{"id":"c","text":"ImplementationSpecific"},{"id":"d","text":"Regex"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`pathType: Prefix` matches by URL path SEGMENTS, so `/v2` matches `/v2` and `/v2/users` but not `/v20`. `Exact` matches only `/v2` literally.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress needs path `/v2` to route to `api-v2:80`. Which `pathType` matches `/v2` and `/v2/users` but NOT `/v20`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A client Pod cannot resolve `web.default.svc.cluster.local`. Which component is responsible for in-cluster Service DNS?$tv2$, $tv2$[{"id":"a","text":"CoreDNS (the cluster DNS add-on)"},{"id":"b","text":"kube-proxy"},{"id":"c","text":"The Ingress controller"},{"id":"d","text":"etcd"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CoreDNS serves cluster DNS, resolving Service and Pod names. kube-proxy programs the data path (iptables/IPVS) but does not answer DNS queries.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A client Pod cannot resolve `web.default.svc.cluster.local`. Which component is responsible for in-cluster Service DNS?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service of type LoadBalancer in a cloud cluster also implicitly allocates which other Service primitives?$tv2$, $tv2$[{"id":"a","text":"A ClusterIP and a NodePort, in addition to the external LB."},{"id":"b","text":"Only an ExternalName."},{"id":"c","text":"Nothing else; just the LB."},{"id":"d","text":"An Ingress object."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A LoadBalancer Service is layered on top of NodePort and ClusterIP: it gets a ClusterIP, a NodePort on each node, and the cloud LB forwards to the NodePort.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service of type LoadBalancer in a cloud cluster also implicitly allocates which other Service primitives?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Services and selectors.$tv2$, $tv2$[{"id":"a","text":"A Service with no selector will not auto-populate Endpoints; you can manage Endpoints/EndpointSlices manually."},{"id":"b","text":"sessionAffinity: ClientIP pins a client to the same backend Pod."},{"id":"c","text":"A Service selector must match the Deployment's name."},{"id":"d","text":"Removing the only Ready Pod leaves the Service with zero endpoints, so connections fail."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Selectors match Pod LABELS, not Deployment names. Selector-less Services support manual Endpoints. `sessionAffinity: ClientIP` provides client stickiness. No Ready Pods means no endpoints and failed connections.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Services and selectors.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod has one main container plus a small companion container that ships its stdout logs to an external aggregator. This is which multi-container pattern?$tv2$, $tv2$[{"id":"a","text":"Init container"},{"id":"b","text":"Sidecar"},{"id":"c","text":"Ambassador"},{"id":"d","text":"Adapter"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A sidecar augments the main container (logging, metrics, sync) sharing the same Pod's lifecycle and volumes. Ambassador proxies network calls; adapter normalizes output for external consumption.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod has one main container plus a small companion container that ships its stdout logs to an external aggregator. This is which multi-container pattern?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a Job that runs 5 Pods in parallel until 10 successful completions are reached. Which Job fields achieve this?$tv2$, $tv2$[{"id":"a","text":"completions: 10, parallelism: 5"},{"id":"b","text":"replicas: 10, parallelism: 5"},{"id":"c","text":"completions: 5, parallelism: 10"},{"id":"d","text":"backoffLimit: 10, parallelism: 5"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`completions` is total successes needed; `parallelism` caps concurrent Pods. `backoffLimit` only governs retry attempts on failure.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a Job that runs 5 Pods in parallel until 10 successful completions are reached. Which Job fields achieve this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A CronJob has `concurrencyPolicy: Forbid` and `startingDeadlineSeconds: 30`. The previous run is still active when the next schedule fires 30s late. What happens to that fire?$tv2$, $tv2$[{"id":"a","text":"A second Job is started in parallel."},{"id":"b","text":"The fire is skipped because the previous run is active AND the deadline has passed."},{"id":"c","text":"The previous Job is killed and replaced."},{"id":"d","text":"The CronJob is suspended automatically."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`Forbid` prevents concurrency, and missing the startingDeadline marks the fire as missed/skipped (recorded in status).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A CronJob has `concurrencyPolicy: Forbid` and `startingDeadlineSeconds: 30`. The previous run is still active when the next schedule fires 30s late. What happens to that fire?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a Dockerfile, which instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT and is preferred over `RUN cd /app`?$tv2$, $tv2$[{"id":"a","text":"CHDIR /app"},{"id":"b","text":"WORKDIR /app"},{"id":"c","text":"PWD /app"},{"id":"d","text":"CD /app"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`WORKDIR` is the only Dockerfile instruction that persists the working directory across layers. `RUN cd` only affects the single layer.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Dockerfile, which instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT and is preferred over `RUN cd /app`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command scales Deployment `api` to 6 replicas?$tv2$, $tv2$[{"id":"a","text":"kubectl scale deployment/api --replicas=6"},{"id":"b","text":"kubectl resize deployment api 6"},{"id":"c","text":"kubectl set replicas deployment/api 6"},{"id":"d","text":"kubectl deploy api --scale=6"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl scale` is the canonical command for adjusting replicas on Deployments, ReplicaSets, ReplicationControllers, and StatefulSets.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command scales Deployment `api` to 6 replicas?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You apply a Deployment with `strategy.type: Recreate`. What is the practical effect during an update?$tv2$, $tv2$[{"id":"a","text":"New Pods are gradually scaled up while old ones scale down."},{"id":"b","text":"All old Pods are terminated FIRST; then new Pods are created — service downtime is expected."},{"id":"c","text":"Only one Pod is updated at a time."},{"id":"d","text":"The rollout is paused until manual approval."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Recreate fully drains the old Pods before launching the new ones. It is appropriate for workloads incompatible with running two versions simultaneously (e.g. some PVC-bound singletons).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You apply a Deployment with `strategy.type: Recreate`. What is the practical effect during an update?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A canary release strategy on Kubernetes typically:$tv2$, $tv2$[{"id":"a","text":"Replaces all Pods with the new version at once."},{"id":"b","text":"Routes a small share of traffic to a small subset of new-version Pods, expanding as confidence grows."},{"id":"c","text":"Requires the kube-apiserver to be restarted."},{"id":"d","text":"Is only possible with a service mesh."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Canary = gradual exposure of the new version to a subset of users. Achievable natively via two Deployments behind one Service or with finer-grained traffic split via Ingress/Service mesh.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A canary release strategy on Kubernetes typically:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Kustomize's primary value proposition relative to Helm is:$tv2$, $tv2$[{"id":"a","text":"Built-in template language with conditionals and loops."},{"id":"b","text":"Pure-YAML overlays that patch a common \"base\" — no templating language needed."},{"id":"c","text":"A chart registry for versioned releases."},{"id":"d","text":"It replaces kubectl entirely."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Kustomize composes overlays over a base via strategic-merge or JSON patches — there is no template language. Helm offers templating + a chart registry; the two tools are complementary.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Kustomize's primary value proposition relative to Helm is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command tails (streams) logs of all Pods of Deployment `web`?$tv2$, $tv2$[{"id":"a","text":"kubectl logs -f -l app=web"},{"id":"b","text":"kubectl tail deployment/web"},{"id":"c","text":"kubectl logs deployment/web --stream"},{"id":"d","text":"kubectl stream deployment web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`-l` filters by label and `-f` follows logs. `kubectl logs deployment/web -f` works too but only streams from one Pod selected by the controller.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command tails (streams) logs of all Pods of Deployment `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$An exec liveness probe `cat /tmp/healthy` runs every 10s with failureThreshold 3. The file disappears at t=0. Approximately when will the kubelet restart the container?$tv2$, $tv2$[{"id":"a","text":"Immediately at t=0"},{"id":"b","text":"Around t=10s (1 failure)"},{"id":"c","text":"Around t=30s (3 consecutive failures × 10s period)"},{"id":"d","text":"Never — exec probes do not trigger restarts"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Liveness probes mark a container failed only after `failureThreshold` consecutive failures. With period 10s × 3 failures ≈ 30s before restart.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An exec liveness probe `cat /tmp/healthy` runs every 10s with failureThreshold 3. The file disappears at t=0. Approximately when will the kubelet restart the container?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows recent cluster events, ordered by timestamp, namespace-scoped?$tv2$, $tv2$[{"id":"a","text":"kubectl get events --sort-by=.lastTimestamp"},{"id":"b","text":"kubectl describe events"},{"id":"c","text":"kubectl event log"},{"id":"d","text":"kubectl logs events"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get events --sort-by=.lastTimestamp` is the standard debugging recipe. `describe pod` also surfaces the events for a specific Pod.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows recent cluster events, ordered by timestamp, namespace-scoped?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You mount a ConfigMap `app-cfg` as a volume at `/etc/app`. The ConfigMap is then updated with `kubectl apply`. What does the running Pod see?$tv2$, $tv2$[{"id":"a","text":"The file in /etc/app is updated automatically after the kubelet sync (eventually consistent; typically within ~1 minute)."},{"id":"b","text":"The Pod is restarted automatically on the next sync."},{"id":"c","text":"Nothing changes until the Pod is manually deleted/recreated."},{"id":"d","text":"The Pod immediately enters CrashLoopBackOff."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$ConfigMaps and Secrets mounted as volumes propagate updates to the in-Pod filesystem on the next kubelet sync (period configurable, default ~60s). Env-var injections, by contrast, are baked in at Pod start.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You mount a ConfigMap `app-cfg` as a volume at `/etc/app`. The ConfigMap is then updated with `kubectl apply`. What does the running Pod see?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A Secret of type `kubernetes.io/dockerconfigjson` is referenced by a Pod via `spec.imagePullSecrets`. Its purpose is:$tv2$, $tv2$[{"id":"a","text":"Encrypting traffic between Pods."},{"id":"b","text":"Providing credentials to pull images from a private registry."},{"id":"c","text":"Encrypting volumes at rest."},{"id":"d","text":"Authenticating the Pod to the API server."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`dockerconfigjson` secrets carry registry credentials; referenced via `imagePullSecrets`, they let the kubelet pull from private registries.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Secret of type `kubernetes.io/dockerconfigjson` is referenced by a Pod via `spec.imagePullSecrets`. Its purpose is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A namespace has a `ResourceQuota` of `requests.cpu: 1` and `limits.cpu: 2`. You apply a Pod requesting 600m CPU and limiting 1500m. The cluster has free capacity. What happens?$tv2$, $tv2$[{"id":"a","text":"The Pod is accepted because the cluster has free CPU."},{"id":"b","text":"The Pod is REJECTED at admission because limits.cpu (1500m) added to existing usage may exceed 2 (depends on existing usage); but the request also pushes near the 1 CPU ceiling — admission rejects when the quota is exceeded."},{"id":"c","text":"The Pod is accepted but throttled to 100m."},{"id":"d","text":"The kubelet evicts an existing Pod to make room."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$ResourceQuotas are enforced at admission. New Pods are rejected if their request/limit pushes the namespace totals above the quota.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A namespace has a `ResourceQuota` of `requests.cpu: 1` and `limits.cpu: 2`. You apply a Pod requesting 600m CPU and limiting 1500m. The cluster has free capacity. What happens?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod with no resource requests is scheduled. Then memory pressure builds on the node and the kubelet must evict Pods. Which Pod is evicted FIRST under standard QoS rules?$tv2$, $tv2$[{"id":"a","text":"Guaranteed Pods (requests == limits)"},{"id":"b","text":"Burstable Pods (requests < limits)"},{"id":"c","text":"BestEffort Pods (no requests or limits)"},{"id":"d","text":"Pods marked critical via priorityClass"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Eviction order under node pressure is BestEffort → Burstable → Guaranteed. BestEffort Pods (no requests/limits) are sacrificed first.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod with no resource requests is scheduled. Then memory pressure builds on the node and the kubelet must evict Pods. Which Pod is evicted FIRST under standard QoS rules?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PersistentVolumeClaim with `accessModes: [ReadWriteOnce]` can be:$tv2$, $tv2$[{"id":"a","text":"Mounted read-write by exactly one node at a time."},{"id":"b","text":"Mounted read-write by every Pod in the namespace concurrently."},{"id":"c","text":"Mounted read-only by many nodes but not read-write."},{"id":"d","text":"Mounted read-write only by Pods in the same Pod."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$RWO permits read-write by ONE node (not Pod). Multiple Pods on that same node can mount it. RWX permits multi-node read-write.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PersistentVolumeClaim with `accessModes: [ReadWriteOnce]` can be:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service `api` of type ClusterIP selects Pods with label `app=api`. You scale the Deployment up by 2 Pods. What must you do for the new Pods to receive traffic?$tv2$, $tv2$[{"id":"a","text":"Update the Service's `targetPort` to the new Pod count."},{"id":"b","text":"Nothing — the EndpointSlice controller updates endpoints automatically as Pods become Ready."},{"id":"c","text":"Delete and recreate the Service."},{"id":"d","text":"Restart kube-proxy on every node."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The EndpointSlice / Endpoints controller continuously reconciles Service backends to match Ready Pods of the selector. No manual action is needed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service `api` of type ClusterIP selects Pods with label `app=api`. You scale the Deployment up by 2 Pods. What must you do for the new Pods to receive traffic?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy in namespace `prod` has `podSelector: {}` and `policyTypes: [Ingress]` with no `ingress` rules. The effect is:$tv2$, $tv2$[{"id":"a","text":"Allow all ingress to all Pods in prod."},{"id":"b","text":"Deny all ingress to all Pods in prod."},{"id":"c","text":"Deny all egress from all Pods in prod."},{"id":"d","text":"No effect (empty policy is ignored)."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$An empty `podSelector: {}` matches every Pod in the namespace; declaring `policyTypes: [Ingress]` with no `ingress` rules denies all ingress to those Pods.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy in namespace `prod` has `podSelector: {}` and `policyTypes: [Ingress]` with no `ingress` rules. The effect is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A NodePort Service has `spec.ports[0].nodePort: 31000`. From OUTSIDE the cluster, the Service is reachable via:$tv2$, $tv2$[{"id":"a","text":"http://<any-node-ip>:31000"},{"id":"b","text":"http://<service-cluster-ip>:31000"},{"id":"c","text":"http://<pod-ip>:31000"},{"id":"d","text":"http://<kube-apiserver>:31000"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$NodePort opens the same port on every node. Reach the Service at any node's IP on that port; kube-proxy forwards into the cluster.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NodePort Service has `spec.ports[0].nodePort: 31000`. From OUTSIDE the cluster, the Service is reachable via:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need a stable DNS-based alias for the external hostname `db.example.com` inside the cluster. Which Service type fits?$tv2$, $tv2$[{"id":"a","text":"ClusterIP"},{"id":"b","text":"NodePort"},{"id":"c","text":"LoadBalancer"},{"id":"d","text":"ExternalName"}]$tv2$::jsonb, $tv2$["d"]$tv2$::jsonb, $tv2$ExternalName Services return a CNAME to an external host in cluster DNS — no proxying, no IP allocation.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a stable DNS-based alias for the external hostname `db.example.com` inside the cluster. Which Service type fits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command runs a one-off Pod that prints text and is removed automatically when it exits?$tv2$, $tv2$[{"id":"a","text":"kubectl run tmp --image=busybox --restart=Never --rm -it -- echo hi"},{"id":"b","text":"kubectl create pod tmp --image=busybox --once"},{"id":"c","text":"kubectl run tmp --image=busybox --ephemeral -- echo hi"},{"id":"d","text":"kubectl exec tmp --image=busybox -- echo hi"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl run ... --restart=Never --rm -it -- <cmd>` runs a throwaway Pod attached to your terminal and deletes it on exit, ideal for quick checks.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command runs a one-off Pod that prints text and is removed automatically when it exits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$The adapter multi-container pattern is best described as:$tv2$, $tv2$[{"id":"a","text":"A container that runs before the app to set up state."},{"id":"b","text":"A sidecar that transforms the main container's output into a standardized format for external consumers (e.g. metrics)."},{"id":"c","text":"A proxy for outbound connections."},{"id":"d","text":"A container that holds a shared volume."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The adapter normalizes/translates the main container's output (logs, metrics) into a format an external system expects, without modifying the app.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$The adapter multi-container pattern is best described as:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A native sidecar is defined as an init container with `restartPolicy: Always` and keeps running alongside the main app containers.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Native sidecars (stable since Kubernetes 1.29) are init containers with `restartPolicy: Always`; they start before app containers and continue running for the Pod's lifetime.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A native sidecar is defined as an init container with `restartPolicy: Always` and keeps running alongside the main app containers.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Job must abort if it runs longer than 5 minutes regardless of retries. Which field enforces this?$tv2$, $tv2$[{"id":"a","text":"spec.activeDeadlineSeconds: 300"},{"id":"b","text":"spec.backoffLimit: 300"},{"id":"c","text":"spec.ttlSecondsAfterFinished: 300"},{"id":"d","text":"spec.completions: 300"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`activeDeadlineSeconds` is a hard wall-clock cap on the Job; once exceeded the Job is terminated and marked failed, overriding remaining retries.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Job must abort if it runs longer than 5 minutes regardless of retries. Which field enforces this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In a Pod spec, which field sets the command run by the container, overriding the image's ENTRYPOINT?$tv2$, $tv2$[{"id":"a","text":"spec.containers[].command"},{"id":"b","text":"spec.containers[].entrypoint"},{"id":"c","text":"spec.command"},{"id":"d","text":"spec.containers[].run"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$In Kubernetes, `containers[].command` overrides the image ENTRYPOINT and `containers[].args` overrides CMD.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Pod spec, which field sets the command run by the container, overriding the image's ENTRYPOINT?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An indexed Job (`completionMode: Indexed`) with `completions: 3` gives each Pod:$tv2$, $tv2$[{"id":"a","text":"A unique completion index (0,1,2) via the JOB_COMPLETION_INDEX env var."},{"id":"b","text":"The same index 0."},{"id":"c","text":"A random UUID only."},{"id":"d","text":"No way to distinguish Pods."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Indexed Jobs assign each Pod a unique index 0..completions-1, exposed via `JOB_COMPLETION_INDEX`, enabling static work partitioning.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An indexed Job (`completionMode: Indexed`) with `completions: 3` gives each Pod:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about init containers vs sidecars.$tv2$, $tv2$[{"id":"a","text":"A plain init container must finish before the next container starts."},{"id":"b","text":"A native sidecar starts before app containers but does not block them by needing to complete."},{"id":"c","text":"Init containers and app containers always start at the same time."},{"id":"d","text":"Init containers can use a different image than the app container."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Plain init containers run to completion sequentially; native sidecars (restartPolicy Always) start early but stay running. App containers do NOT start simultaneously with init containers. Each container can use any image.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about init containers vs sidecars.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction declares a default command that is easily overridden by `docker run <img> <args>`?$tv2$, $tv2$[{"id":"a","text":"CMD"},{"id":"b","text":"ENTRYPOINT (exec form)"},{"id":"c","text":"RUN"},{"id":"d","text":"LABEL"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`CMD` provides default arguments that are replaced entirely when the user passes a command to `docker run`. `ENTRYPOINT` is harder to override (requires `--entrypoint`).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction declares a default command that is easily overridden by `docker run <img> <args>`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod's init container writes a config file to a shared emptyDir; the app container reads it. If the init container fails repeatedly, the app container:$tv2$, $tv2$[{"id":"a","text":"Starts anyway and reads a stale file."},{"id":"b","text":"Never starts — the Pod stays in Init:Error/CrashLoopBackOff until the init container succeeds."},{"id":"c","text":"Is scheduled to another node."},{"id":"d","text":"Is converted into a Job."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$App containers do not start until ALL init containers succeed. A persistently failing init container keeps the Pod in an Init phase and the app never runs.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod's init container writes a config file to a shared emptyDir; the app container reads it. If the init container fails repeatedly, the app container:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command records the previous and current config for a Deployment so you can diff before applying?$tv2$, $tv2$[{"id":"a","text":"kubectl diff -f deployment.yaml"},{"id":"b","text":"kubectl apply --preview -f deployment.yaml"},{"id":"c","text":"kubectl compare deployment.yaml"},{"id":"d","text":"kubectl rollout diff deployment/web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl diff -f <file>` shows what `kubectl apply` would change by comparing the manifest against the live cluster state.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command records the previous and current config for a Deployment so you can diff before applying?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment selector is `matchLabels: {app: web}` but the Pod template labels are `{app: api}`. What happens on apply?$tv2$, $tv2$[{"id":"a","text":"It works; labels are advisory."},{"id":"b","text":"The Deployment is rejected/invalid because the selector must match the template labels."},{"id":"c","text":"A Service is auto-created."},{"id":"d","text":"It silently scales to zero."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A Deployment's `spec.selector` must match the Pod template labels; a mismatch is a validation error and the object is rejected.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment selector is `matchLabels: {app: web}` but the Pod template labels are `{app: api}`. What happens on apply?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You ran `kubectl rollout undo deployment/web` but need to go to revision 2 specifically. Which command?$tv2$, $tv2$[{"id":"a","text":"kubectl rollout undo deployment/web --to-revision=2"},{"id":"b","text":"kubectl rollout undo deployment/web -r 2"},{"id":"c","text":"kubectl rollback deployment/web 2"},{"id":"d","text":"kubectl set revision deployment/web 2"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl rollout undo deployment/<name> --to-revision=N` rolls back to a specific revision listed by `kubectl rollout history`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You ran `kubectl rollout undo deployment/web` but need to go to revision 2 specifically. Which command?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$Scaling a Deployment with `kubectl scale` creates a new ReplicaSet revision.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Scaling only changes the replica count on the existing ReplicaSet; it does NOT alter the Pod template, so no new revision is created. Only `spec.template` changes create revisions.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Scaling a Deployment with `kubectl scale` creates a new ReplicaSet revision.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment is stuck: new Pods are `Pending` due to insufficient memory and old Pods still serve traffic. With `maxUnavailable: 0`, the rollout:$tv2$, $tv2$[{"id":"a","text":"Forces old Pods down to make room."},{"id":"b","text":"Stalls — old Pods stay up (no downtime) until new Pods can be scheduled or the progress deadline triggers."},{"id":"c","text":"Deletes the Deployment."},{"id":"d","text":"Switches to Recreate automatically."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$With `maxUnavailable: 0`, the controller will not remove old Pods until replacements are Ready. If new Pods cannot schedule, the rollout stalls safely and may report ProgressDeadlineExceeded.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment is stuck: new Pods are `Pending` due to insufficient memory and old Pods still serve traffic. With `maxUnavailable: 0`, the rollout:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command edits a live Deployment in your default editor and applies on save?$tv2$, $tv2$[{"id":"a","text":"kubectl edit deployment/web"},{"id":"b","text":"kubectl modify deployment web"},{"id":"c","text":"kubectl patch deployment web --editor"},{"id":"d","text":"kubectl update deployment web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl edit <resource>/<name>` opens the live object in `$EDITOR`; saving applies the change via a patch.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command edits a live Deployment in your default editor and applies on save?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment owns ReplicaSet `web-abc` (current) and `web-def` (old, 0 replicas). You delete ReplicaSet `web-abc` directly. What happens?$tv2$, $tv2$[{"id":"a","text":"The Deployment recreates a matching ReplicaSet and its Pods to reconcile desired state."},{"id":"b","text":"The Deployment is deleted too."},{"id":"c","text":"Nothing — the Pods keep running orphaned."},{"id":"d","text":"The old ReplicaSet web-def is promoted with the new image."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Deployment controller continuously reconciles; deleting its active ReplicaSet causes it to create a new ReplicaSet from the current template and restore the desired Pods.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment owns ReplicaSet `web-abc` (current) and `web-def` (old, 0 replicas). You delete ReplicaSet `web-abc` directly. What happens?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Helm: which command lists the currently installed releases in a namespace?$tv2$, $tv2$[{"id":"a","text":"helm list -n <namespace>"},{"id":"b","text":"helm get releases"},{"id":"c","text":"helm ps -n <namespace>"},{"id":"d","text":"helm show releases"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`helm list` (alias `helm ls`) shows installed releases; `-n` scopes to a namespace, `-A` lists across all namespaces.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Helm: which command lists the currently installed releases in a namespace?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Helm: which command renders a chart's templates locally without installing, to inspect the resulting manifests?$tv2$, $tv2$[{"id":"a","text":"helm template ./mychart"},{"id":"b","text":"helm render ./mychart"},{"id":"c","text":"helm install ./mychart --dry-only"},{"id":"d","text":"helm build ./mychart"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`helm template <chart>` renders manifests to stdout with values substituted, without touching the cluster. `helm install --dry-run` requires a cluster connection.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Helm: which command renders a chart's templates locally without installing, to inspect the resulting manifests?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows a Pod's recent Events plus container statuses for troubleshooting?$tv2$, $tv2$[{"id":"a","text":"kubectl describe pod <pod>"},{"id":"b","text":"kubectl logs <pod> --events"},{"id":"c","text":"kubectl get pod <pod> -o events"},{"id":"d","text":"kubectl inspect pod <pod>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl describe pod` shows container state, restart counts, conditions, and the Events section — the first stop for diagnosing scheduling/start failures.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows a Pod's recent Events plus container statuses for troubleshooting?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A readiness probe uses `periodSeconds: 5`, `successThreshold: 1`, `failureThreshold: 3`. After the Pod becomes unready, how many consecutive successful probes return it to Ready?$tv2$, $tv2$[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"5"},{"id":"d","text":"It never returns automatically."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`successThreshold` for readiness defaults to 1; a single success flips the Pod back to Ready. `failureThreshold` (3) is how many failures mark it unready.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A readiness probe uses `periodSeconds: 5`, `successThreshold: 1`, `failureThreshold: 3`. After the Pod becomes unready, how many consecutive successful probes return it to Ready?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An exec probe command returns exit code 0. The probe is considered:$tv2$, $tv2$[{"id":"a","text":"Successful"},{"id":"b","text":"Failed"},{"id":"c","text":"Unknown"},{"id":"d","text":"Timed out"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$An exec probe succeeds when the command exits 0; any non-zero exit is a failure. httpGet succeeds on 2xx/3xx; tcpSocket succeeds if the connection opens.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An exec probe command returns exit code 0. The probe is considered:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A container restarts every ~40s. `kubectl describe pod` shows Last State Terminated, Reason Error, Exit Code 1, and a livenessProbe with periodSeconds 10 failureThreshold 3. The MOST likely root cause to investigate first is:$tv2$, $tv2$[{"id":"a","text":"The Service selector."},{"id":"b","text":"The application itself exiting/crashing (exit code 1) or failing its liveness endpoint — check kubectl logs --previous."},{"id":"c","text":"A NetworkPolicy."},{"id":"d","text":"The node's disk pressure."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Reason `Error` with exit code 1 plus a ~30s liveness window points to the app crashing or failing its health endpoint. `kubectl logs --previous` reveals the crash output.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container restarts every ~40s. `kubectl describe pod` shows Last State Terminated, Reason Error, Exit Code 1, and a livenessProbe with periodSeconds 10 failureThreshold 3. The MOST likely root cause to investigate first is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A failing readiness probe causes the kubelet to restart the container.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Readiness only removes the Pod from Service endpoints; it never restarts the container. Liveness probe failures are what trigger restarts.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A failing readiness probe causes the kubelet to restart the container.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command streams logs from the last 1 hour for a Pod and keeps following new lines?$tv2$, $tv2$[{"id":"a","text":"kubectl logs <pod> --since=1h -f"},{"id":"b","text":"kubectl logs <pod> --last=1h --stream"},{"id":"c","text":"kubectl logs <pod> -t 1h"},{"id":"d","text":"kubectl logs <pod> --range=1h --watch"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--since=1h` limits to the last hour and `-f` follows. `--tail=N` instead limits to the last N lines.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command streams logs from the last 1 hour for a Pod and keeps following new lines?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod is stuck `Pending`. `kubectl describe pod` shows a FailedScheduling event "0/3 nodes available: insufficient cpu". The fix that does NOT require new nodes is:$tv2$, $tv2$[{"id":"a","text":"Lower the Pod's CPU request so it fits an existing node."},{"id":"b","text":"Add a livenessProbe."},{"id":"c","text":"Change the Service type."},{"id":"d","text":"Increase replicas."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Insufficient CPU at scheduling means the Pod's CPU REQUEST exceeds any node's allocatable. Reducing the request (or freeing capacity) lets the scheduler place it without adding nodes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod is stuck `Pending`. `kubectl describe pod` shows a FailedScheduling event "0/3 nodes available: insufficient cpu". The fix that does NOT require new nodes is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Secret's value should be consumed as an env var WITHOUT the value appearing in the Pod manifest. Which is correct?$tv2$, $tv2$[{"id":"a","text":"env: [{ name: PW, valueFrom: { secretKeyRef: { name: db, key: password } } }]"},{"id":"b","text":"env: [{ name: PW, value: \"{{secret:db.password}}\" }]"},{"id":"c","text":"env: [{ name: PW, configMapKeyRef: { name: db, key: password } }]"},{"id":"d","text":"envFrom: [{ value: db/password }]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`env[].valueFrom.secretKeyRef` references a Secret key by name; the literal value stays in the Secret, not the Pod spec.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Secret's value should be consumed as an env var WITHOUT the value appearing in the Pod manifest. Which is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must run with supplemental group 3000 added to its processes for shared-volume access. Which field?$tv2$, $tv2$[{"id":"a","text":"spec.securityContext.fsGroup or supplementalGroups"},{"id":"b","text":"spec.containers[].user"},{"id":"c","text":"spec.serviceAccountName"},{"id":"d","text":"metadata.labels.group"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Pod-level `securityContext.fsGroup` sets a supplemental group that owns mounted volumes; `supplementalGroups` adds extra GIDs to the container processes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must run with supplemental group 3000 added to its processes for shared-volume access. Which field?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a docker-registry pull Secret?$tv2$, $tv2$[{"id":"a","text":"kubectl create secret docker-registry regcred --docker-server=... --docker-username=... --docker-password=..."},{"id":"b","text":"kubectl create secret generic regcred --type=docker"},{"id":"c","text":"kubectl create registry-secret regcred"},{"id":"d","text":"kubectl create secret tls regcred --registry"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl create secret docker-registry` produces a `kubernetes.io/dockerconfigjson` Secret for pulling from private registries via `imagePullSecrets`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a docker-registry pull Secret?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod sets `runAsNonRoot: true` but the image's default user is root (UID 0) and no `runAsUser` is set. What happens at start?$tv2$, $tv2$[{"id":"a","text":"The container starts as root anyway."},{"id":"b","text":"The kubelet refuses to start the container (CreateContainerConfigError) because it would run as root."},{"id":"c","text":"Kubernetes auto-assigns UID 1000."},{"id":"d","text":"The Pod is OOMKilled."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`runAsNonRoot: true` makes the kubelet validate the effective user is non-root at start. If the image would run as UID 0, container creation fails rather than running privileged.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod sets `runAsNonRoot: true` but the image's default user is root (UID 0) and no `runAsUser` is set. What happens at start?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command attaches an existing ConfigMap's keys to a Deployment's Pods as env vars via imperative patch is impractical; instead the recommended approach is:$tv2$, $tv2$[{"id":"a","text":"Add `envFrom: [{ configMapRef: { name: <cm> } }]` to the Deployment's container spec and apply."},{"id":"b","text":"Set the keys as Pod annotations."},{"id":"c","text":"Create a Service pointing at the ConfigMap."},{"id":"d","text":"Mount the ConfigMap as a Secret."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Declaratively adding `envFrom.configMapRef` to the container projects every ConfigMap key as an env var; editing the Deployment template triggers a rollout so Pods pick it up.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command attaches an existing ConfigMap's keys to a Deployment's Pods as env vars via imperative patch is impractical; instead the recommended approach is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$Environment variables injected from a ConfigMap update automatically in a running container when the ConfigMap changes.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Env vars are evaluated only at container start. ConfigMap/Secret changes reflect live ONLY for volume mounts; env-var consumers need a Pod restart.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Environment variables injected from a ConfigMap update automatically in a running container when the ConfigMap changes.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod needs its memory limit exposed to the app as an env var. Which Downward API ref is correct?$tv2$, $tv2$[{"id":"a","text":"valueFrom: { resourceFieldRef: { containerName: app, resource: limits.memory } }"},{"id":"b","text":"valueFrom: { fieldRef: { fieldPath: spec.memory } }"},{"id":"c","text":"valueFrom: { configMapKeyRef: { name: limits } }"},{"id":"d","text":"value: $(MEMORY_LIMIT)"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Downward API exposes resource requests/limits via `resourceFieldRef` (e.g. `limits.memory`, `requests.cpu`), letting apps self-tune (e.g. JVM heap).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod needs its memory limit exposed to the app as an env var. Which Downward API ref is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A ServiceAccount `reader` needs read access to ConfigMaps in namespace `app`. Minimal RBAC is:$tv2$, $tv2$[{"id":"a","text":"A Role with rules [verbs: get,list,watch; resources: configmaps] plus a RoleBinding to the SA."},{"id":"b","text":"A ClusterRoleBinding granting cluster-admin."},{"id":"c","text":"Add the SA to the system:masters group."},{"id":"d","text":"Set the Pod privileged."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Least privilege: a namespaced Role limited to `get/list/watch` on `configmaps`, bound to the SA via a RoleBinding in that namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A ServiceAccount `reader` needs read access to ConfigMaps in namespace `app`. Minimal RBAC is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about ConfigMaps and Secrets.$tv2$, $tv2$[{"id":"a","text":"Both can be mounted as volumes or injected as env vars."},{"id":"b","text":"A Secret's data values are base64-encoded in the manifest."},{"id":"c","text":"A ConfigMap can store binary data via the binaryData field."},{"id":"d","text":"Secrets are encrypted at rest by default without any extra configuration."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$ConfigMaps/Secrets both support volume and env consumption; Secret `data` is base64; ConfigMaps support `binaryData`. Encryption at rest requires explicit EncryptionConfiguration — it is NOT on by default.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"},{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about ConfigMaps and Secrets.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PVC is `Pending` with event "no persistent volumes available for this claim and no storage class is set". The fix is:$tv2$, $tv2$[{"id":"a","text":"Set a valid storageClassName (or create a matching PV) so the claim can bind/provision."},{"id":"b","text":"Increase the Pod's CPU limit."},{"id":"c","text":"Add a readiness probe."},{"id":"d","text":"Recreate the Service."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A PVC with no StorageClass and no matching static PV cannot bind. Specifying a StorageClass enables dynamic provisioning, or an admin must create a matching PV.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC is `Pending` with event "no persistent volumes available for this claim and no storage class is set". The fix is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container should NOT be able to gain more privileges than its parent process. Which setting enforces this?$tv2$, $tv2$[{"id":"a","text":"securityContext.allowPrivilegeEscalation: false"},{"id":"b","text":"securityContext.privileged: true"},{"id":"c","text":"securityContext.runAsUser: 0"},{"id":"d","text":"hostPID: true"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`allowPrivilegeEscalation: false` sets the no_new_privs flag so setuid binaries cannot elevate privileges beyond the container process.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container should NOT be able to gain more privileges than its parent process. Which setting enforces this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$From a Pod in namespace `team-a`, what is the shortest name that resolves Service `cache` in the SAME namespace?$tv2$, $tv2$[{"id":"a","text":"cache"},{"id":"b","text":"cache.team-a"},{"id":"c","text":"cache.svc"},{"id":"d","text":"cache.cluster.local"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Within the same namespace the bare Service name `cache` resolves via the search domain. The FQDN is `cache.team-a.svc.cluster.local`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$From a Pod in namespace `team-a`, what is the shortest name that resolves Service `cache` in the SAME namespace?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service uses `externalTrafficPolicy: Local` on a NodePort. The effect is:$tv2$, $tv2$[{"id":"a","text":"Traffic is only routed to Pods on the node that received it, preserving the client source IP."},{"id":"b","text":"All traffic is dropped."},{"id":"c","text":"Traffic is duplicated to every Pod."},{"id":"d","text":"The Service becomes ClusterIP."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`externalTrafficPolicy: Local` avoids the extra SNAT hop, preserving the client source IP but only forwarding to local Pods (nodes without a Pod return no endpoints).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service uses `externalTrafficPolicy: Local` on a NodePort. The effect is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy allows DNS egress. Which rule typically permits Pods to resolve names?$tv2$, $tv2$[{"id":"a","text":"egress to kube-system namespace / kube-dns Pods on UDP and TCP port 53"},{"id":"b","text":"egress to 0.0.0.0/0 port 443"},{"id":"c","text":"ingress from port 53"},{"id":"d","text":"egress to the API server on 6443"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When a default-deny egress policy is in place, you must explicitly allow egress to the cluster DNS (CoreDNS/kube-dns) on port 53 (UDP and TCP) or name resolution breaks.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy allows DNS egress. Which rule typically permits Pods to resolve names?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$An Ingress resource requires a running Ingress controller to actually route traffic.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Ingress object only declares routing intent; an Ingress controller (e.g. ingress-nginx) must be deployed to watch Ingress objects and implement the routing.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress resource requires a running Ingress controller to actually route traffic.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Service's `targetPort` is omitted entirely. What value does Kubernetes use?$tv2$, $tv2$[{"id":"a","text":"It defaults to the same value as `port`."},{"id":"b","text":"It defaults to 0 and the Service fails."},{"id":"c","text":"It defaults to 80."},{"id":"d","text":"The Service is rejected."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When `targetPort` is not specified it defaults to the value of `port`; the Service forwards Service-port traffic to the same numeric container port.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service's `targetPort` is omitted entirely. What value does Kubernetes use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need pod-to-pod traffic blocked by default in namespace `secure`, allowing only explicitly permitted flows. The baseline policy is:$tv2$, $tv2$[{"id":"a","text":"A NetworkPolicy with podSelector: {} and policyTypes: [Ingress, Egress] with no rules (default-deny), then add allow policies."},{"id":"b","text":"A LoadBalancer Service."},{"id":"c","text":"Set hostNetwork: true on all Pods."},{"id":"d","text":"Delete CoreDNS."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A default-deny policy selecting all Pods with empty Ingress/Egress rule sets establishes a deny baseline; additive allow policies then open required paths (including DNS).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need pod-to-pod traffic blocked by default in namespace `secure`, allowing only explicitly permitted flows. The baseline policy is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress has `spec.ingressClassName: nginx`. Its purpose is:$tv2$, $tv2$[{"id":"a","text":"To select which Ingress controller handles this Ingress."},{"id":"b","text":"To set the TLS cipher suite."},{"id":"c","text":"To name the backend Service."},{"id":"d","text":"To define the URL path."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`ingressClassName` binds the Ingress to a specific IngressClass/controller, important in clusters running multiple Ingress controllers.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress has `spec.ingressClassName: nginx`. Its purpose is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service `web` has endpoints but `curl web` from another Pod times out, while `curl <podIP>` works. The MOST likely cause is:$tv2$, $tv2$[{"id":"a","text":"A NetworkPolicy or DNS issue (the Service name/IP path is blocked or unresolved), not the Pods themselves."},{"id":"b","text":"The Pods are down."},{"id":"c","text":"The image is wrong."},{"id":"d","text":"The Deployment has zero replicas."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Direct Pod IP working but Service name failing isolates the problem to DNS resolution or a NetworkPolicy blocking the ClusterIP/DNS path — the Pods are healthy.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service `web` has endpoints but `curl web` from another Pod times out, while `curl <podIP>` works. The MOST likely cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Ingress.$tv2$, $tv2$[{"id":"a","text":"A single Ingress can fan out multiple hostnames to different Services."},{"id":"b","text":"TLS termination can be configured via spec.tls with a kubernetes.io/tls Secret."},{"id":"c","text":"Ingress natively load-balances raw TCP/UDP for arbitrary protocols."},{"id":"d","text":"pathType Prefix matches by path segments."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Ingress is HTTP/HTTPS layer-7 routing — it does not natively handle arbitrary TCP/UDP (use a Service of type LoadBalancer/NodePort for that). It supports host fan-out, TLS termination, and prefix path matching.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Ingress.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Docker layer is rebuilt FIRST when only the application source code (added last in the Dockerfile) changes?$tv2$, $tv2$[{"id":"a","text":"The base image FROM layer."},{"id":"b","text":"The layer added immediately after the changed source line, and everything below."},{"id":"c","text":"The COPY/ADD layer containing the changed source and every layer AFTER it."},{"id":"d","text":"The entire image is rebuilt from scratch every time."}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Docker cache is invalidated at the first changed layer and every subsequent layer. Placing rarely-changing instructions early (e.g. dependency install) maximises cache reuse.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Docker layer is rebuilt FIRST when only the application source code (added last in the Dockerfile) changes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two containers in one Pod need to share a directory. Which volume type is appropriate?$tv2$, $tv2$[{"id":"a","text":"emptyDir"},{"id":"b","text":"hostPath"},{"id":"c","text":"persistentVolumeClaim"},{"id":"d","text":"configMap"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`emptyDir` is created when the Pod is assigned to a node and shared among the Pod's containers. It is removed when the Pod terminates. hostPath ties to a specific node; PVC is typically for cross-Pod persistence.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two containers in one Pod need to share a directory. Which volume type is appropriate?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about init containers.$tv2$, $tv2$[{"id":"a","text":"Init containers run to completion BEFORE app containers start."},{"id":"b","text":"Init containers can have their own resource requests/limits and securityContext."},{"id":"c","text":"Init containers run in parallel with app containers."},{"id":"d","text":"If an init container fails, the Pod is restarted (by default)."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Init containers run sequentially before app containers — not in parallel. They have their own resources/securityContext. Default restartPolicy is Always, so an init failure triggers Pod restart.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about init containers.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Job has `backoffLimit: 4`. What does this mean?$tv2$, $tv2$[{"id":"a","text":"The Job retries up to 4 times before being marked failed."},{"id":"b","text":"The Job runs at most 4 Pods in parallel."},{"id":"c","text":"The Job times out after 4 minutes."},{"id":"d","text":"The Job retains 4 completed Pods after success."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`backoffLimit` caps the number of retries on failure. After that many attempts, the Job reports Failed status.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Job has `backoffLimit: 4`. What does this mean?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command pauses an in-progress rollout of Deployment `api`?$tv2$, $tv2$[{"id":"a","text":"kubectl rollout pause deployment/api"},{"id":"b","text":"kubectl rollout halt deployment/api"},{"id":"c","text":"kubectl scale deployment/api --pause"},{"id":"d","text":"kubectl deploy api --pause"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl rollout pause/resume deployment/<name>` pauses and resumes a rollout. Useful for canary-style staged updates.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command pauses an in-progress rollout of Deployment `api`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which kubectl subcommand creates resources from a manifest in a declarative, idempotent way?$tv2$, $tv2$[{"id":"a","text":"kubectl create -f manifest.yaml"},{"id":"b","text":"kubectl apply -f manifest.yaml"},{"id":"c","text":"kubectl run -f manifest.yaml"},{"id":"d","text":"kubectl replace -f manifest.yaml"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`kubectl apply` is the declarative command — it creates resources that do not exist and patches existing ones based on the manifest, tracking changes via the last-applied annotation.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which kubectl subcommand creates resources from a manifest in a declarative, idempotent way?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment's revisionHistoryLimit defaults to 10. What does it control?$tv2$, $tv2$[{"id":"a","text":"Maximum simultaneous rolling Pods."},{"id":"b","text":"Maximum number of OLD ReplicaSets retained for rollback."},{"id":"c","text":"Maximum age in days before a ReplicaSet is pruned."},{"id":"d","text":"Maximum number of replicas."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`revisionHistoryLimit` keeps the last N old ReplicaSets so `kubectl rollout undo --to-revision=N` can target them. Older ones are garbage-collected.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment's revisionHistoryLimit defaults to 10. What does it control?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A blue/green deployment strategy on Kubernetes is typically implemented by:$tv2$, $tv2$[{"id":"a","text":"Running two Deployments (blue, green) behind one Service, switching the Service selector between them at cutover."},{"id":"b","text":"Using `strategy.type: Recreate` on a single Deployment."},{"id":"c","text":"Setting `maxUnavailable: 50%`."},{"id":"d","text":"Disabling the readiness probe during cutover."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Blue/green keeps two complete environments and flips the selector (or Ingress backend) atomically. Recreate is single-Deployment downtime updates, not blue/green.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A blue/green deployment strategy on Kubernetes is typically implemented by:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod has two containers `app` and `proxy`. How do you retrieve only the `app` container's logs?$tv2$, $tv2$[{"id":"a","text":"kubectl logs <pod> --container=app"},{"id":"b","text":"kubectl logs <pod>/app"},{"id":"c","text":"kubectl logs --filter=app <pod>"},{"id":"d","text":"kubectl exec <pod> -- logs app"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Use `-c`/`--container` to disambiguate containers when a Pod has more than one.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod has two containers `app` and `proxy`. How do you retrieve only the `app` container's logs?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You add a readinessProbe to a fronting Pod. During slow startup the Pod reports Ready=False. What is the user-visible effect?$tv2$, $tv2$[{"id":"a","text":"The Pod is killed and restarted by the kubelet."},{"id":"b","text":"The Pod's IP is REMOVED from any backing Service's endpoints, so traffic is not routed to it."},{"id":"c","text":"The Pod is moved to another node."},{"id":"d","text":"The Deployment fails the rollout immediately."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Readiness gates Service endpoint membership but does NOT restart Pods. A rollout pauses if too few Pods become Ready (per maxUnavailable).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You add a readinessProbe to a fronting Pod. During slow startup the Pod reports Ready=False. What is the user-visible effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command prints CPU and memory usage of every Pod in the current namespace (requires metrics-server)?$tv2$, $tv2$[{"id":"a","text":"kubectl top pods"},{"id":"b","text":"kubectl get pods --metrics"},{"id":"c","text":"kubectl resources pods"},{"id":"d","text":"kubectl describe metrics"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl top` reads from the Metrics API served by metrics-server (or equivalent). `kubectl top nodes` shows node-level metrics.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command prints CPU and memory usage of every Pod in the current namespace (requires metrics-server)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a generic Secret named `db-cred` with key `password=s3cret!`?$tv2$, $tv2$[{"id":"a","text":"kubectl create secret generic db-cred --from-literal=password=s3cret!"},{"id":"b","text":"kubectl create secret db-cred --password=s3cret!"},{"id":"c","text":"kubectl set secret db-cred password=s3cret!"},{"id":"d","text":"kubectl secret generic db-cred password=s3cret!"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl create secret generic ... --from-literal` is the imperative form. There are also `tls` and `docker-registry` subtypes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a generic Secret named `db-cred` with key `password=s3cret!`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container needs the entire ConfigMap `app-cfg` exposed as environment variables. Which spec snippet does this?$tv2$, $tv2$[{"id":"a","text":"envFrom: [{ configMapRef: { name: app-cfg } }]"},{"id":"b","text":"env: [{ valueFrom: { configMap: app-cfg } }]"},{"id":"c","text":"volumeMounts: [{ name: app-cfg, mountPath: /env }]"},{"id":"d","text":"configMap: app-cfg"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`envFrom.configMapRef` projects every key in the ConfigMap as an env var. `env[].valueFrom.configMapKeyRef` is for one key at a time.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container needs the entire ConfigMap `app-cfg` exposed as environment variables. Which spec snippet does this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A namespace has a `LimitRange` with default container CPU request 200m / limit 500m. You apply a Pod with NO resources specified. What happens?$tv2$, $tv2$[{"id":"a","text":"The Pod is rejected at admission."},{"id":"b","text":"The Pod is created with request 200m / limit 500m applied by the LimitRange admission controller."},{"id":"c","text":"The Pod runs with no requests/limits (LimitRange is advisory)."},{"id":"d","text":"The Pod runs but is marked Failed."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$LimitRange admission injects the namespace defaults into Pods that omit them. It can also enforce min/max bounds, rejecting Pods that violate them.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A namespace has a `LimitRange` with default container CPU request 200m / limit 500m. You apply a Pod with NO resources specified. What happens?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need a Pod to use a non-default ServiceAccount `ci-bot`. Which Pod spec field sets this?$tv2$, $tv2$[{"id":"a","text":"spec.serviceAccount: ci-bot"},{"id":"b","text":"spec.serviceAccountName: ci-bot"},{"id":"c","text":"spec.containers[].serviceAccount: ci-bot"},{"id":"d","text":"metadata.serviceAccount: ci-bot"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`spec.serviceAccountName` is the correct field. `spec.serviceAccount` is deprecated and `containers[].serviceAccount` does not exist.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need a Pod to use a non-default ServiceAccount `ci-bot`. Which Pod spec field sets this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about PersistentVolumes and PersistentVolumeClaims.$tv2$, $tv2$[{"id":"a","text":"A PVC binds to one PV at a time; the binding is exclusive."},{"id":"b","text":"StorageClasses enable dynamic provisioning — a matching PV is created on demand when the PVC is created."},{"id":"c","text":"A PVC can be expanded online if the StorageClass has `allowVolumeExpansion: true`."},{"id":"d","text":"Deleting a PVC always deletes the underlying PV regardless of reclaim policy."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$PV reclaim policy controls deletion: `Delete` removes the PV; `Retain` keeps it. So deletion of a PVC does NOT always delete the PV — depends on policy.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about PersistentVolumes and PersistentVolumeClaims.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service `web` selects Pods with `app=web`. Two Pods have that label — one Ready, one NotReady. Endpoints for the Service contain:$tv2$, $tv2$[{"id":"a","text":"Both Pod IPs."},{"id":"b","text":"Only the Ready Pod's IP; the NotReady Pod is in `notReadyAddresses`."},{"id":"c","text":"Only the NotReady Pod's IP."},{"id":"d","text":"No endpoints until both are Ready."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$EndpointSlices place Ready Pods in `addresses` and not-Ready Pods in `notReadyAddresses`. Only Ready endpoints receive traffic.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service `web` selects Pods with `app=web`. Two Pods have that label — one Ready, one NotReady. Endpoints for the Service contain:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Service field selects which Pods back the Service?$tv2$, $tv2$[{"id":"a","text":"spec.selector"},{"id":"b","text":"spec.podSelector"},{"id":"c","text":"spec.targetSelector"},{"id":"d","text":"metadata.labels"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`spec.selector` on a Service matches Pods by label and populates Endpoints. `podSelector` is a NetworkPolicy field; `metadata.labels` are the Service's own labels.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Service field selects which Pods back the Service?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress routes `host: shop.example.com` to Service `shop:80`. TLS is enabled via `spec.tls[0].secretName: shop-tls`. The Secret type must be:$tv2$, $tv2$[{"id":"a","text":"Opaque"},{"id":"b","text":"kubernetes.io/tls"},{"id":"c","text":"kubernetes.io/dockerconfigjson"},{"id":"d","text":"bootstrap.kubernetes.io/token"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Ingress TLS requires a `kubernetes.io/tls` Secret carrying `tls.crt` and `tls.key`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"},{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress routes `host: shop.example.com` to Service `shop:80`. TLS is enabled via `spec.tls[0].secretName: shop-tls`. The Secret type must be:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy in namespace `prod` allows ingress from Pods labelled `role=frontend` in namespace `web`. Which selector pair is correct?$tv2$, $tv2$[{"id":"a","text":"ingress.from: [{ podSelector: { matchLabels: { role: frontend } } }]"},{"id":"b","text":"ingress.from: [{ namespaceSelector: { matchLabels: { kubernetes.io/metadata.name: web } }, podSelector: { matchLabels: { role: frontend } } }]"},{"id":"c","text":"ingress.from: [{ namespaceSelector: { matchLabels: { role: frontend } } }]"},{"id":"d","text":"ingress.from: [{ ipBlock: { cidr: 0.0.0.0/0 } }]"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Cross-namespace selection requires BOTH a namespaceSelector (to match the source namespace) AND a podSelector (to match the source Pods). Option A would match only Pods in the same namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy in namespace `prod` allows ingress from Pods labelled `role=frontend` in namespace `web`. Which selector pair is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command adds a label `tier=backend` to an existing Pod `api`?$tv2$, $tv2$[{"id":"a","text":"kubectl label pod api tier=backend"},{"id":"b","text":"kubectl set label pod/api tier=backend"},{"id":"c","text":"kubectl annotate pod api tier=backend"},{"id":"d","text":"kubectl edit pod api --label tier=backend"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl label <resource> <name> key=value` adds/updates a label. Use `key-` to remove a label and `--overwrite` to change an existing one.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command adds a label `tier=backend` to an existing Pod `api`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A workload needs exactly one Pod per node for a node-local agent. Which controller is designed for this?$tv2$, $tv2$[{"id":"a","text":"Deployment"},{"id":"b","text":"DaemonSet"},{"id":"c","text":"Job"},{"id":"d","text":"StatefulSet"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A DaemonSet ensures one Pod per (matching) node — used for log shippers, node exporters, and CNI agents. Deployments do not pin one Pod per node.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A workload needs exactly one Pod per node for a node-local agent. Which controller is designed for this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$Containers in the same Pod can communicate over localhost because they share the Pod's network namespace.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$All containers in a Pod share one network namespace and IP, so they reach each other via `localhost`/127.0.0.1 and must not bind the same port.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Containers in the same Pod can communicate over localhost because they share the Pod's network namespace.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A CronJob keeps too many old Jobs around. Which fields cap retained finished Jobs?$tv2$, $tv2$[{"id":"a","text":"spec.successfulJobsHistoryLimit and spec.failedJobsHistoryLimit"},{"id":"b","text":"spec.backoffLimit and spec.completions"},{"id":"c","text":"spec.ttlSeconds and spec.maxJobs"},{"id":"d","text":"spec.concurrencyPolicy only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CronJob `successfulJobsHistoryLimit` (default 3) and `failedJobsHistoryLimit` (default 1) bound how many finished Jobs are retained for inspection.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A CronJob keeps too many old Jobs around. Which fields cap retained finished Jobs?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Pod spec field passes ARGS to the container, overriding the image CMD but not the ENTRYPOINT?$tv2$, $tv2$[{"id":"a","text":"spec.containers[].args"},{"id":"b","text":"spec.containers[].command"},{"id":"c","text":"spec.args"},{"id":"d","text":"spec.containers[].cmd"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`containers[].args` overrides the image CMD (the default arguments) while leaving the ENTRYPOINT intact. `containers[].command` overrides ENTRYPOINT.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Pod spec field passes ARGS to the container, overriding the image CMD but not the ENTRYPOINT?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod has containers A and B sharing an emptyDir. A writes a ready file then exits 0; B waits for it. With `restartPolicy: Always`, what happens to A?$tv2$, $tv2$[{"id":"a","text":"A is restarted repeatedly even though it succeeded, because Always restarts on any exit."},{"id":"b","text":"A is never restarted."},{"id":"c","text":"The whole Pod is deleted."},{"id":"d","text":"A is converted to an init container."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$With `restartPolicy: Always`, the kubelet restarts a container that exits regardless of exit code. A short-lived setup step belongs in an init container, not a sidecar with Always.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod has containers A and B sharing an emptyDir. A writes a ready file then exits 0; B waits for it. With `restartPolicy: Always`, what happens to A?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Jobs.$tv2$, $tv2$[{"id":"a","text":"parallelism controls how many Pods may run at once."},{"id":"b","text":"completions sets how many successful Pods are required."},{"id":"c","text":"A Job Pod template may use restartPolicy: Always."},{"id":"d","text":"backoffLimit caps failed retries before the Job is marked Failed."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Job Pod templates must use `OnFailure` or `Never` (never `Always`). `parallelism`/`completions` shape concurrency and required successes; `backoffLimit` bounds retries.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Jobs.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction is best for declaring a writable data location decoupled from the image layers?$tv2$, $tv2$[{"id":"a","text":"VOLUME /data"},{"id":"b","text":"MOUNT /data"},{"id":"c","text":"STORAGE /data"},{"id":"d","text":"PERSIST /data"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`VOLUME` declares a mount point whose contents live outside the image's union filesystem. In Kubernetes you typically supply that path via a Pod volume (emptyDir/PVC).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction is best for declaring a writable data location decoupled from the image layers?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Design and Build$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must be scheduled only onto nodes labelled `disktype=ssd`. The simplest mechanism is:$tv2$, $tv2$[{"id":"a","text":"spec.nodeSelector: { disktype: ssd }"},{"id":"b","text":"A NetworkPolicy"},{"id":"c","text":"A readinessProbe"},{"id":"d","text":"spec.serviceAccountName"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`nodeSelector` is the simplest node-constraint: the Pod schedules only on nodes carrying all the specified labels. Affinity offers richer expressions.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must be scheduled only onto nodes labelled `disktype=ssd`. The simplest mechanism is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command outputs a Deployment manifest without creating it, to save to a file?$tv2$, $tv2$[{"id":"a","text":"kubectl create deployment web --image=nginx --dry-run=client -o yaml"},{"id":"b","text":"kubectl create deployment web --image=nginx --no-create"},{"id":"c","text":"kubectl get deployment web -o yaml --template"},{"id":"d","text":"kubectl deploy web --image=nginx --export"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--dry-run=client -o yaml` renders the manifest client-side without contacting the API server, the standard scaffold-then-edit workflow.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command outputs a Deployment manifest without creating it, to save to a file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Deployment's old ReplicaSets are piling up consuming etcd. The field to reduce retention is:$tv2$, $tv2$[{"id":"a","text":"spec.revisionHistoryLimit"},{"id":"b","text":"spec.replicas"},{"id":"c","text":"spec.minReadySeconds"},{"id":"d","text":"spec.progressDeadlineSeconds"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Lowering `revisionHistoryLimit` reduces how many old ReplicaSets are kept (default 10). Fewer revisions means less clutter but fewer rollback targets.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Deployment's old ReplicaSets are piling up consuming etcd. The field to reduce retention is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command annotates a Deployment with a change-cause so it appears in rollout history?$tv2$, $tv2$[{"id":"a","text":"kubectl annotate deployment/web kubernetes.io/change-cause=\"bump to 1.27\""},{"id":"b","text":"kubectl set cause deployment/web \"bump to 1.27\""},{"id":"c","text":"kubectl rollout cause deployment/web --msg=\"bump\""},{"id":"d","text":"kubectl label deployment/web change-cause=bump"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `kubernetes.io/change-cause` annotation populates the CHANGE-CAUSE column in `kubectl rollout history`, documenting why each revision was created.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command annotates a Deployment with a change-cause so it appears in rollout history?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$With RollingUpdate, `maxSurge` and `maxUnavailable` cannot both be 0.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$If both are 0 the rollout can neither create an extra Pod nor drop an existing one, so it could never make progress; Kubernetes rejects that combination.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$With RollingUpdate, `maxSurge` and `maxUnavailable` cannot both be 0.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You set `kubectl rollout pause deployment/web`, then change the image twice, then `kubectl rollout resume`. How many new ReplicaSets/rollouts occur?$tv2$, $tv2$[{"id":"a","text":"One — the paused state batches the changes; resuming rolls out the final template once."},{"id":"b","text":"Two — one rollout per image change."},{"id":"c","text":"Zero — pause cancels changes."},{"id":"d","text":"Three."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$While paused, the Deployment accumulates spec changes without rolling out. Resuming performs a single rollout to the latest template, enabling staged multi-edit canaries.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You set `kubectl rollout pause deployment/web`, then change the image twice, then `kubectl rollout resume`. How many new ReplicaSets/rollouts occur?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command deletes all resources defined in a manifest file?$tv2$, $tv2$[{"id":"a","text":"kubectl delete -f app.yaml"},{"id":"b","text":"kubectl remove -f app.yaml"},{"id":"c","text":"kubectl destroy -f app.yaml"},{"id":"d","text":"kubectl apply -f app.yaml --delete"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl delete -f <file>` removes every object the manifest declares, useful for tearing down a declaratively created app.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command deletes all resources defined in a manifest file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Helm: which command rolls a release back to a previous revision?$tv2$, $tv2$[{"id":"a","text":"helm rollback <release> <revision>"},{"id":"b","text":"helm undo <release>"},{"id":"c","text":"helm revert <release> --to <revision>"},{"id":"d","text":"helm upgrade <release> --rollback"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`helm rollback <release> <revision>` reverts a release to a prior revision recorded in its history (`helm history <release>` lists them).$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Helm: which command rolls a release back to a previous revision?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a Helm chart, where do default configurable parameters live?$tv2$, $tv2$[{"id":"a","text":"values.yaml"},{"id":"b","text":"Chart.yaml"},{"id":"c","text":"templates/_helpers.tpl"},{"id":"d","text":"requirements.lock"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`values.yaml` holds default values referenced by templates via `.Values`; users override them with `--set` or `-f`. `Chart.yaml` holds chart metadata.$tv2$, $tv2$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Helm chart, where do default configurable parameters live?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Deployment$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Kustomize overlay needs to change the image tag of the base for the prod environment. Which kustomization field does this cleanly?$tv2$, $tv2$[{"id":"a","text":"images: [{ name: myapp, newTag: v2 }]"},{"id":"b","text":"patchesJson6902 only"},{"id":"c","text":"configMapGenerator"},{"id":"d","text":"namePrefix"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Kustomize's `images` transformer overrides image name/tag/digest without a manual patch, a common base-vs-overlay pattern.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Kustomize overlay needs to change the image tag of the base for the prod environment. Which kustomization field does this cleanly?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows which node a Pod is running on and its Pod IP?$tv2$, $tv2$[{"id":"a","text":"kubectl get pod <pod> -o wide"},{"id":"b","text":"kubectl describe node <pod>"},{"id":"c","text":"kubectl get pod <pod> --node"},{"id":"d","text":"kubectl top pod <pod>"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl get pod -o wide` adds NODE, IP, NOMINATED NODE columns — quick context for scheduling/networking diagnosis.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows which node a Pod is running on and its Pod IP?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A liveness httpGet probe returns HTTP 500. The kubelet treats this as:$tv2$, $tv2$[{"id":"a","text":"A failure (only 2xx/3xx are success)."},{"id":"b","text":"A success (any response means alive)."},{"id":"c","text":"Unknown until timeout."},{"id":"d","text":"A readiness signal only."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$httpGet probes succeed only on status codes 200–399. A 4xx/5xx counts as a failure toward `failureThreshold`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A liveness httpGet probe returns HTTP 500. The kubelet treats this as:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You need to copy a log file out of a running Pod's container to your machine. Which command?$tv2$, $tv2$[{"id":"a","text":"kubectl cp <namespace>/<pod>:/var/log/app.log ./app.log"},{"id":"b","text":"kubectl scp <pod>:/var/log/app.log ."},{"id":"c","text":"kubectl logs <pod> > app.log only works for stdout"},{"id":"d","text":"kubectl get file <pod>:/var/log/app.log"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl cp` copies files between a container and the local filesystem (it requires `tar` in the container). It is the way to retrieve files not written to stdout.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to copy a log file out of a running Pod's container to your machine. Which command?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL correct probe-tuning statements for a slow-starting app.$tv2$, $tv2$[{"id":"a","text":"A startupProbe with a generous failureThreshold × periodSeconds protects boot from liveness kills."},{"id":"b","text":"Once the startupProbe succeeds, liveness and readiness probes begin."},{"id":"c","text":"initialDelaySeconds on liveness can also mitigate slow starts but is less precise than a startupProbe."},{"id":"d","text":"A startupProbe runs for the entire Pod lifetime."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$startupProbe runs only until it first succeeds, then hands off to liveness/readiness. A long startup budget is its purpose; `initialDelaySeconds` is a coarser alternative.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL correct probe-tuning statements for a slow-starting app.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$`kubectl top` requires a metrics provider (e.g. metrics-server) to be installed in the cluster.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl top` reads the Metrics API; without metrics-server (or an equivalent) it errors with "Metrics API not available".$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$`kubectl top` requires a metrics provider (e.g. metrics-server) to be installed in the cluster.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod shows STATUS `ImagePullBackOff`. The first command to confirm the cause is:$tv2$, $tv2$[{"id":"a","text":"kubectl describe pod <pod> (read the Events for the pull error/auth failure)"},{"id":"b","text":"kubectl logs <pod>"},{"id":"c","text":"kubectl top pod <pod>"},{"id":"d","text":"kubectl exec <pod> -- sh"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$There are no logs for a container that never started. `kubectl describe pod` Events show the exact pull error: wrong tag, missing image, or registry auth failure.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod shows STATUS `ImagePullBackOff`. The first command to confirm the cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Observability and Maintenance$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod terminated with exit code 137. This typically indicates:$tv2$, $tv2$[{"id":"a","text":"The process was killed by SIGKILL (often the OOM killer or a failed graceful shutdown)."},{"id":"b","text":"A successful completion."},{"id":"c","text":"A configuration parse error."},{"id":"d","text":"A DNS failure."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Exit code 137 = 128 + 9 (SIGKILL). Common causes are an OOMKill (memory limit exceeded) or termination after the grace period elapsed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod terminated with exit code 137. This typically indicates:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A specific Secret key `tls.key` should be projected to file path `keys/server.key` with mode 0400. Which volume config?$tv2$, $tv2$[{"id":"a","text":"secret: { secretName: s, items: [{ key: tls.key, path: keys/server.key, mode: 0400 }] }"},{"id":"b","text":"secret: { secretName: s, file: keys/server.key }"},{"id":"c","text":"configMap: { name: s, key: tls.key }"},{"id":"d","text":"secret: { secretName: s, env: tls.key }"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A secret volume's `items` lets you select specific keys, set the in-Pod relative `path`, and per-file `mode` permissions.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A specific Secret key `tls.key` should be projected to file path `keys/server.key` with mode 0400. Which volume config?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must run with seccomp profile RuntimeDefault. Which field sets this?$tv2$, $tv2$[{"id":"a","text":"spec.securityContext.seccompProfile.type: RuntimeDefault"},{"id":"b","text":"spec.containers[].seccomp: default"},{"id":"c","text":"metadata.annotations.seccomp: runtime/default"},{"id":"d","text":"spec.runtimeClassName: seccomp"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The modern field is `securityContext.seccompProfile.type` (RuntimeDefault or Localhost). The old annotation form is deprecated/removed.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must run with seccomp profile RuntimeDefault. Which field sets this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command updates an existing ConfigMap key idempotently from a manifest?$tv2$, $tv2$[{"id":"a","text":"kubectl apply -f configmap.yaml"},{"id":"b","text":"kubectl create configmap --update"},{"id":"c","text":"kubectl set configmap -f configmap.yaml"},{"id":"d","text":"kubectl patch configmap --from-file"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl apply -f` is the declarative, idempotent path: it creates the ConfigMap if absent and patches changed keys if present.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command updates an existing ConfigMap key idempotently from a manifest?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A container needs the NET_ADMIN capability but the cluster enforces the Baseline Pod Security Standard. The likely outcome is:$tv2$, $tv2$[{"id":"a","text":"The Pod is rejected/denied by the namespace's Pod Security admission because NET_ADMIN is disallowed under Baseline/Restricted."},{"id":"b","text":"It works with no restriction."},{"id":"c","text":"Kubernetes silently drops only that capability and continues."},{"id":"d","text":"It forces privileged mode automatically."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Pod Security admission Baseline/Restricted profiles forbid adding most capabilities (only a small set is allowed). A Pod requesting NET_ADMIN is rejected in an enforcing namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container needs the NET_ADMIN capability but the cluster enforces the Baseline Pod Security Standard. The likely outcome is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod should disable mounting the default ServiceAccount token. Which Pod field?$tv2$, $tv2$[{"id":"a","text":"spec.automountServiceAccountToken: false"},{"id":"b","text":"spec.serviceAccountName: none"},{"id":"c","text":"spec.containers[].mountToken: false"},{"id":"d","text":"metadata.annotations.token: disabled"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Setting `automountServiceAccountToken: false` at the Pod (or ServiceAccount) level stops projecting the API token, reducing exposure for Pods that never call the API.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod should disable mounting the default ServiceAccount token. Which Pod field?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod requests `memory: 256Mi` and limits `memory: 256Mi`, and CPU request==limit. Its QoS class is:$tv2$, $tv2$[{"id":"a","text":"Guaranteed"},{"id":"b","text":"Burstable"},{"id":"c","text":"BestEffort"},{"id":"d","text":"Critical"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When every container has requests equal to limits for both CPU and memory, the Pod is `Guaranteed` — the last to be evicted under node pressure.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod requests `memory: 256Mi` and limits `memory: 256Mi`, and CPU request==limit. Its QoS class is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A ConfigMap mounted as a volume reflects updates in the container's filesystem after the kubelet sync, but subPath mounts do NOT receive updates.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Whole-volume ConfigMap mounts update on sync, but a `subPath` mount is resolved once at start and is NOT updated when the ConfigMap changes.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A ConfigMap mounted as a volume reflects updates in the container's filesystem after the kubelet sync, but subPath mounts do NOT receive updates.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An app reads its config from `/config/app.yaml`. You want this sourced from ConfigMap key `app.yaml`. Which mount is correct?$tv2$, $tv2$[{"id":"a","text":"A configMap volume with items mapping key app.yaml → path app.yaml, mounted at /config"},{"id":"b","text":"envFrom configMapRef"},{"id":"c","text":"A secret volume"},{"id":"d","text":"hostPath /config"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Mounting the ConfigMap as a volume (optionally using `items` to control filenames) places `app.yaml` at `/config/app.yaml` for file-based config consumption.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An app reads its config from `/config/app.yaml`. You want this sourced from ConfigMap key `app.yaml`. Which mount is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about SecurityContext.$tv2$, $tv2$[{"id":"a","text":"runAsUser can be set at Pod or container level; the container value wins for that container."},{"id":"b","text":"allowPrivilegeEscalation is a container-level field."},{"id":"c","text":"fsGroup is a Pod-level field affecting volume ownership."},{"id":"d","text":"privileged: true is required to run as a non-root user."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Running as non-root needs `runAsNonRoot`/`runAsUser`, NOT privileged (privileged grants near-host access). Pod vs container precedence, container-only `allowPrivilegeEscalation`, and Pod-level `fsGroup` are all correct.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about SecurityContext.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A PVC with StorageClass `standard` and `allowVolumeExpansion: true` needs more space. The supported way to grow it is:$tv2$, $tv2$[{"id":"a","text":"Edit the PVC's spec.resources.requests.storage to a larger value and apply."},{"id":"b","text":"Delete and recreate the PVC (data loss)."},{"id":"c","text":"Edit the PV capacity directly only."},{"id":"d","text":"Scale the Deployment."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When the StorageClass allows expansion, increasing the PVC's requested storage triggers an online (or after-restart) volume resize without recreating the claim.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A PVC with StorageClass `standard` and `allowVolumeExpansion: true` needs more space. The supported way to grow it is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Application Environment, Configuration and Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod must NOT share the host's PID namespace. Which is the safe default to keep?$tv2$, $tv2$[{"id":"a","text":"spec.hostPID: false (the default)"},{"id":"b","text":"spec.hostPID: true"},{"id":"c","text":"spec.shareProcessNamespace: true with hostPID"},{"id":"d","text":"spec.hostNetwork: true"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Leaving `hostPID` false (default) isolates the Pod from host processes. Setting it true exposes/inspects host PIDs and is a security concern best avoided.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod must NOT share the host's PID namespace. Which is the safe default to keep?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a ClusterIP Service for an existing Pod labelled `app=cache` on port 6379?$tv2$, $tv2$[{"id":"a","text":"kubectl expose pod <pod> --port=6379 --name=cache"},{"id":"b","text":"kubectl create svc <pod> --port=6379"},{"id":"c","text":"kubectl service expose pod <pod> 6379"},{"id":"d","text":"kubectl run cache --expose --port=6379"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl expose pod <pod> --port=` creates a Service selecting that Pod's labels (ClusterIP by default). For Deployments use `kubectl expose deployment`.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a ClusterIP Service for an existing Pod labelled `app=cache` on port 6379?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy `ingress.from` uses only `ipBlock: { cidr: 10.0.0.0/24 }`. This allows ingress from:$tv2$, $tv2$[{"id":"a","text":"Any source whose IP falls in 10.0.0.0/24 (subject to CNI handling of pod source IPs)."},{"id":"b","text":"Only Pods with a specific label."},{"id":"c","text":"All namespaces."},{"id":"d","text":"Nothing — ipBlock is invalid for ingress."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`ipBlock` matches by CIDR. It is typically used for off-cluster sources; pod-to-pod source IPs may be obscured by SNAT depending on the CNI.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy `ingress.from` uses only `ipBlock: { cidr: 10.0.0.0/24 }`. This allows ingress from:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Service should distribute connections so a given client always hits the same Pod. Which setting?$tv2$, $tv2$[{"id":"a","text":"spec.sessionAffinity: ClientIP"},{"id":"b","text":"spec.type: LoadBalancer"},{"id":"c","text":"spec.externalTrafficPolicy: Local"},{"id":"d","text":"spec.publishNotReadyAddresses: true"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`sessionAffinity: ClientIP` makes kube-proxy route a client IP to the same backend for the affinity timeout window.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Service should distribute connections so a given client always hits the same Pod. Which setting?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$A ClusterIP Service is reachable from outside the cluster by default.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$ClusterIP is internal-only. External exposure needs NodePort, LoadBalancer, an Ingress, or port-forwarding.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A ClusterIP Service is reachable from outside the cluster by default.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A NetworkPolicy permits egress to `podSelector: {role: db}` on TCP 5432, but app Pods also fail DNS lookups. The cause is:$tv2$, $tv2$[{"id":"a","text":"A default-deny egress is in effect and DNS (UDP/TCP 53 to CoreDNS) was not explicitly allowed."},{"id":"b","text":"The db Pods are down."},{"id":"c","text":"ClusterIP is disabled."},{"id":"d","text":"The Service selector is wrong."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Once an egress policy selects the Pods, all egress not explicitly allowed is denied — including DNS. You must add an egress rule for port 53 to the cluster DNS.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A NetworkPolicy permits egress to `podSelector: {role: db}` on TCP 5432, but app Pods also fail DNS lookups. The cause is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to test a Service from your laptop without exposing it externally. Which command?$tv2$, $tv2$[{"id":"a","text":"kubectl port-forward service/web 8080:80"},{"id":"b","text":"kubectl expose service/web --external"},{"id":"c","text":"kubectl proxy service/web"},{"id":"d","text":"kubectl tunnel web 8080:80"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`kubectl port-forward service/<svc> <local>:<svcPort>` tunnels a local port to the Service through the API server — handy for ad-hoc testing without changing Service type.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to test a Service from your laptop without exposing it externally. Which command?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An Ingress with no `host` field on a rule matches:$tv2$, $tv2$[{"id":"a","text":"All inbound HTTP hosts (the rule is a default/catch-all for its paths)."},{"id":"b","text":"No traffic."},{"id":"c","text":"Only localhost."},{"id":"d","text":"Only HTTPS traffic."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A rule without `host` applies to requests for any hostname, acting as a default backend rule for the listed paths.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An Ingress with no `host` field on a rule matches:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A Pod needs to reach a Service in another namespace `data`. From namespace `app`, the correct DNS name for Service `pg` is:$tv2$, $tv2$[{"id":"a","text":"pg.data.svc.cluster.local (or short form pg.data)"},{"id":"b","text":"pg (resolves only same-namespace)"},{"id":"c","text":"data.pg.cluster.local"},{"id":"d","text":"pg.app.svc.cluster.local"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Cross-namespace access uses `<svc>.<ns>` or the FQDN `<svc>.<ns>.svc.cluster.local`. The bare name only resolves within the caller's own namespace.$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A Pod needs to reach a Service in another namespace `data`. From namespace `app`, the correct DNS name for Service `pg` is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Services and Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about NetworkPolicies.$tv2$, $tv2$[{"id":"a","text":"They are namespaced resources."},{"id":"b","text":"Without a policy selecting a Pod, the Pod allows all traffic by default."},{"id":"c","text":"Selecting a Pod with policyTypes Ingress and no ingress rules denies all ingress to it."},{"id":"d","text":"NetworkPolicies are enforced even when the CNI plugin does not support them."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$NetworkPolicies are namespaced and additive; an unselected Pod defaults to allow-all; a selected Pod with empty ingress rules is default-deny ingress. Enforcement REQUIRES a policy-capable CNI (Calico, Cilium, etc.).$tv2$, $tv2$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:ckad-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$linuxfoundation-ckad-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about NetworkPolicies.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command initializes a new swarm and turns the current node into the first manager?$tv2$, $tv2$[{"id":"a","text":"docker swarm create"},{"id":"b","text":"docker swarm init"},{"id":"c","text":"docker node promote --init"},{"id":"d","text":"docker service create --swarm"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker swarm init` bootstraps a swarm and makes the current node a manager (leader). `docker swarm create` is not a valid subcommand; `docker node promote` operates on an existing swarm; `docker service create` deploys a service into an existing swarm.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command initializes a new swarm and turns the current node into the first manager?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a swarm, you scale the `web` service to 5 replicas with `docker service scale web=5`. One worker node then goes down. What does the swarm do?$tv2$, $tv2$[{"id":"a","text":"It marks the service as failed until the node returns."},{"id":"b","text":"The orchestrator reschedules the lost replicas onto remaining healthy nodes to restore the desired count."},{"id":"c","text":"It permanently reduces the replica count to match available nodes."},{"id":"d","text":"Nothing — replicas are pinned to their original node."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Swarm continuously reconciles actual state to the declared desired state. Lost replicas on a downed node are rescheduled onto healthy nodes. Replicas are not pinned unless constraints force them.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a swarm, you scale the `web` service to 5 replicas with `docker service scale web=5`. One worker node then goes down. What does the swarm do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about swarm manager nodes and Raft.$tv2$, $tv2$[{"id":"a","text":"Manager nodes use the Raft consensus algorithm to maintain a consistent cluster state."},{"id":"b","text":"A swarm with 5 managers tolerates the loss of up to 2 managers while remaining functional."},{"id":"c","text":"Adding more managers always increases write throughput linearly."},{"id":"d","text":"An even number of managers does not improve fault tolerance over the next lower odd number."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Raft requires a quorum (majority). With N managers, fault tolerance is floor((N-1)/2) — 5 managers tolerate 2 failures. More managers increase consensus overhead, not write throughput. An even count gives no tolerance benefit over the lower odd count, so odd numbers are recommended.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about swarm manager nodes and Raft.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command deploys a multi-service application defined in `stack.yml` to a swarm as a stack named `app`?$tv2$, $tv2$[{"id":"a","text":"docker compose up -d stack.yml"},{"id":"b","text":"docker stack deploy -c stack.yml app"},{"id":"c","text":"docker service deploy --stack app stack.yml"},{"id":"d","text":"docker swarm deploy app stack.yml"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker stack deploy -c <compose-file> <stack-name>` deploys a Compose-format file to a swarm as a stack. `docker compose up` runs locally, not on a swarm; the other options are not valid commands.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command deploys a multi-service application defined in `stack.yml` to a swarm as a stack named `app`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want a service to run exactly one task on every node in the swarm, including new nodes added later. Which service mode achieves this?$tv2$, $tv2$[{"id":"a","text":"Replicated mode with replicas equal to the current node count"},{"id":"b","text":"Global mode (--mode global)"},{"id":"c","text":"Replicated-job mode"},{"id":"d","text":"Constraint mode with node.role==worker"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A global service runs exactly one task per node and automatically schedules a task onto any node that joins later. A fixed replica count does not adjust when nodes are added; replicated-job runs to completion; constraints only filter placement.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a service to run exactly one task on every node in the swarm, including new nodes added later. Which service mode achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction defines the default command run by the container, while still allowing it to be overridden on `docker run`?$tv2$, $tv2$[{"id":"a","text":"ENTRYPOINT in exec form only"},{"id":"b","text":"CMD"},{"id":"c","text":"RUN"},{"id":"d","text":"EXEC"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`CMD` sets the default command/arguments and is fully overridden by arguments passed to `docker run`. `RUN` executes at build time; `EXEC` is not a Dockerfile instruction; `ENTRYPOINT` defines the executable and is not replaced by run-time args (they are appended).$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction defines the default command run by the container, while still allowing it to be overridden on `docker run`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A multi-stage Dockerfile has a `build` stage with the Go toolchain and a final stage `FROM alpine`. What is the primary benefit?$tv2$, $tv2$[{"id":"a","text":"It builds faster because stages run in parallel by default."},{"id":"b","text":"The final image excludes build tooling and intermediate artifacts, drastically reducing image size and attack surface."},{"id":"c","text":"It allows the container to run as root automatically."},{"id":"d","text":"It removes the need for a .dockerignore file."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Multi-stage builds copy only the needed artifacts into a lean final stage, so compilers/SDKs never ship in the runtime image. Stages are not parallel by default, and multi-stage has nothing to do with the run user or .dockerignore.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A multi-stage Dockerfile has a `build` stage with the Go toolchain and a final stage `FROM alpine`. What is the primary benefit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker image layers and tags.$tv2$, $tv2$[{"id":"a","text":"Each Dockerfile instruction such as RUN, COPY, or ADD creates a new image layer."},{"id":"b","text":"A tag is an immutable, content-addressable identifier that can never be moved."},{"id":"c","text":"Image layers are cached and reused across builds when the instruction and its inputs are unchanged."},{"id":"d","text":"A digest (sha256:...) uniquely and immutably identifies a specific image content."}]$tv2$::jsonb, $tv2$["a","c","d"]$tv2$::jsonb, $tv2$RUN/COPY/ADD create layers; the build cache reuses unchanged layers. A digest is the immutable content-addressable identifier — a tag is a mutable human-readable label that can be re-pointed to a different image.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker image layers and tags.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You built `myapp:1.0` locally and want to push it to a private registry at `registry.example.com:5000`. Which sequence is correct?$tv2$, $tv2$[{"id":"a","text":"docker push myapp:1.0 registry.example.com:5000"},{"id":"b","text":"docker tag myapp:1.0 registry.example.com:5000/myapp:1.0 ; docker push registry.example.com:5000/myapp:1.0"},{"id":"c","text":"docker image export myapp:1.0 | docker registry import"},{"id":"d","text":"docker registry add myapp:1.0 ; docker push myapp:1.0"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$An image must be tagged with the registry host/repository before pushing; `docker push` then targets that fully qualified reference. The other forms are not valid Docker CLI usage.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You built `myapp:1.0` locally and want to push it to a private registry at `registry.example.com:5000`. Which sequence is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which file is the canonical location for persistent Docker daemon configuration on Linux?$tv2$, $tv2$[{"id":"a","text":"/etc/docker/daemon.json"},{"id":"b","text":"/var/lib/docker/config.yml"},{"id":"c","text":"~/.docker/config.json"},{"id":"d","text":"/etc/default/docker-cli"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/etc/docker/daemon.json` configures the daemon (`dockerd`). `~/.docker/config.json` is the *client* config (registry auth, etc.); `/var/lib/docker` is the data root, not config.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which file is the canonical location for persistent Docker daemon configuration on Linux?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You set `"log-driver": "json-file"` and `"log-opts": {"max-size": "10m", "max-file": "3"}` in daemon.json. What is the effect?$tv2$, $tv2$[{"id":"a","text":"All containers fail to start until logging is disabled."},{"id":"b","text":"New containers default to the json-file driver with log rotation capped at 3 files of 10 MB each."},{"id":"c","text":"Existing containers immediately switch drivers without restart."},{"id":"d","text":"Logs are forwarded to a remote syslog server."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Daemon-level `log-driver`/`log-opts` set the default for newly created containers, with rotation here limited to three 10 MB files. Existing containers keep their original driver until recreated; syslog would require the `syslog` driver.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You set `"log-driver": "json-file"` and `"log-opts": {"max-size": "10m", "max-file": "3"}` in daemon.json. What is the effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$After editing /etc/docker/daemon.json on a systemd Linux host, which command applies the new daemon configuration?$tv2$, $tv2$[{"id":"a","text":"docker reload"},{"id":"b","text":"systemctl restart docker"},{"id":"c","text":"docker daemon --refresh"},{"id":"d","text":"kill -1 dockerd && docker start"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Restarting the service with `systemctl restart docker` reloads daemon.json. Some options can be reloaded with `SIGHUP` to dockerd, but there is no `docker reload`/`docker daemon --refresh` command.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After editing /etc/docker/daemon.json on a systemd Linux host, which command applies the new daemon configuration?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the default network driver used when you run a container without specifying `--network`?$tv2$, $tv2$[{"id":"a","text":"host"},{"id":"b","text":"bridge"},{"id":"c","text":"overlay"},{"id":"d","text":"none"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$On a standalone Docker host, containers attach to the default `bridge` network unless `--network` specifies otherwise. `overlay` is for multi-host swarm networking; `host` shares the host stack; `none` disables networking.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the default network driver used when you run a container without specifying `--network`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two containers on a user-defined bridge network need to reach each other by name. What enables this?$tv2$, $tv2$[{"id":"a","text":"You must publish ports with -p for them to communicate."},{"id":"b","text":"Docker provides automatic DNS-based service discovery between containers on the same user-defined network."},{"id":"c","text":"They can only communicate via their IP addresses; no name resolution exists."},{"id":"d","text":"You must link them with the deprecated --link flag."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$User-defined bridge networks include an embedded DNS server so containers resolve each other by name/alias automatically. Port publishing is for host-to-container access; the legacy `--link` is not required on user-defined networks.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two containers on a user-defined bridge network need to reach each other by name. What enables this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker network drivers.$tv2$, $tv2$[{"id":"a","text":"The overlay driver connects multiple Docker daemons and is used for swarm service networking."},{"id":"b","text":"The macvlan driver assigns containers a MAC address making them appear as physical devices on the network."},{"id":"c","text":"The host driver gives a container its own isolated network namespace separate from the host."},{"id":"d","text":"Publishing a port with -p 8080:80 maps host port 8080 to container port 80."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Overlay spans hosts (swarm); macvlan exposes containers as first-class L2 devices; `-p host:container` maps ports. The host driver does the opposite of option C — it removes network isolation by sharing the host network namespace.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"},{"url":"https://docs.docker.com/engine/network/drivers/host/","label":"Docker Docs — Host network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker network drivers.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Enabling Docker Content Trust (DOCKER_CONTENT_TRUST=1) provides what guarantee?$tv2$, $tv2$[{"id":"a","text":"It encrypts all container filesystem layers at rest."},{"id":"b","text":"It ensures images are signed and verifies their integrity and publisher before pull/run."},{"id":"c","text":"It scans images for CVEs and blocks vulnerable ones."},{"id":"d","text":"It forces all containers to run as a non-root user."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Content trust uses digital signatures (Notary/TUF) so the engine only pulls/runs signed, verified images. It does not encrypt layers, scan for CVEs, or change the container user.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Enabling Docker Content Trust (DOCKER_CONTENT_TRUST=1) provides what guarantee?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag drops all Linux capabilities and then adds back only NET_BIND_SERVICE?$tv2$, $tv2$[{"id":"a","text":"--privileged --cap NET_BIND_SERVICE"},{"id":"b","text":"--cap-drop ALL --cap-add NET_BIND_SERVICE"},{"id":"c","text":"--security-opt cap=NET_BIND_SERVICE"},{"id":"d","text":"--no-caps --add-cap NET_BIND_SERVICE"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--cap-drop ALL` removes every capability and `--cap-add NET_BIND_SERVICE` re-grants only that one — a least-privilege pattern. `--privileged` does the opposite (grants everything); the other flags are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag drops all Linux capabilities and then adds back only NET_BIND_SERVICE?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You enable user namespace remapping (userns-remap) on the daemon. What is the security benefit?$tv2$, $tv2$[{"id":"a","text":"Containers can no longer use any volumes."},{"id":"b","text":"A process running as root (UID 0) inside a container is mapped to an unprivileged UID on the host."},{"id":"c","text":"It encrypts inter-container traffic automatically."},{"id":"d","text":"It disables the Docker API socket."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$userns-remap maps in-container UIDs (including root) to a non-privileged range on the host, so a container breakout does not yield host root. It does not disable volumes, encrypt traffic, or disable the API.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You enable user namespace remapping (userns-remap) on the daemon. What is the security benefit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement best distinguishes a named volume from a bind mount?$tv2$, $tv2$[{"id":"a","text":"Named volumes are managed by Docker under its data root; bind mounts map an arbitrary host path you control directly."},{"id":"b","text":"Bind mounts are stored inside the container writable layer; volumes are not."},{"id":"c","text":"Named volumes can only be used in swarm mode."},{"id":"d","text":"Bind mounts are automatically backed up by Docker; volumes are not."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Volumes live in a Docker-managed area (e.g. /var/lib/docker/volumes) and are the preferred mechanism; bind mounts attach a specific host directory/file. Neither is stored in the container writable layer, and Docker does not auto-backup either.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement best distinguishes a named volume from a bind mount?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want sensitive scratch data to exist only in memory and never be written to the container or host disk. Which mount type fits?$tv2$, $tv2$[{"id":"a","text":"A named volume"},{"id":"b","text":"A bind mount"},{"id":"c","text":"A tmpfs mount"},{"id":"d","text":"The container writable layer"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$A tmpfs mount stores data in host RAM only and is removed when the container stops — ideal for transient secrets. Volumes and bind mounts persist on disk; the writable layer also persists for the container lifetime and can be committed.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/tmpfs/","label":"Docker Docs — tmpfs mounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want sensitive scratch data to exist only in memory and never be written to the container or host disk. Which mount type fits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command promotes an existing worker node named `node-3` to a manager?$tv2$, $tv2$[{"id":"a","text":"docker node promote node-3"},{"id":"b","text":"docker swarm promote node-3"},{"id":"c","text":"docker node update --role manager node-3 --force"},{"id":"d","text":"docker manager add node-3"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker node promote <node>` (a shortcut for `docker node update --role manager`) elevates a worker to manager. `docker swarm promote` and `docker manager add` are not valid subcommands.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command promotes an existing worker node named `node-3` to a manager?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A swarm service is created with `--replicas 3`. You run `docker service ps web` and see one task in state `Shutdown` and a replacement `Running`. What happened?$tv2$, $tv2$[{"id":"a","text":"The service was scaled down to 2 replicas."},{"id":"b","text":"A task failed or its node became unavailable, so the orchestrator created a replacement to maintain the desired 3 running tasks."},{"id":"c","text":"The whole service crashed and must be redeployed."},{"id":"d","text":"Docker keeps every task ever created in the Running state."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Swarm keeps a task history; a Shutdown task plus a new Running task means the original task ended and was rescheduled to keep the declared replica count. The service itself is healthy and was not scaled down.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A swarm service is created with `--replicas 3`. You run `docker service ps web` and see one task in state `Shutdown` and a replacement `Running`. What happened?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker service create` flag publishes container port 80 on swarm port 8080 using the routing mesh?$tv2$, $tv2$[{"id":"a","text":"--expose 8080:80"},{"id":"b","text":"--publish published=8080,target=80"},{"id":"c","text":"--port 8080:80 --mesh"},{"id":"d","text":"--ingress 8080:80"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--publish published=8080,target=80` (or `-p 8080:80`) publishes the port through the swarm routing mesh by default (ingress mode). `--expose` only documents a port; the other flags are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker service create` flag publishes container port 80 on swarm port 8080 using the routing mesh?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a swarm service to publish a port but bypass the routing mesh so each node only answers when it runs a task locally. Which publish mode achieves this?$tv2$, $tv2$[{"id":"a","text":"mode=ingress"},{"id":"b","text":"mode=host"},{"id":"c","text":"mode=global"},{"id":"d","text":"mode=direct"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--publish mode=host` binds the port directly on the node running the task, skipping the routing mesh. `mode=ingress` is the default mesh behavior; `global`/`direct` are not publish modes.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a swarm service to publish a port but bypass the routing mesh so each node only answers when it runs a task locally. Which publish mode achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes a stack named `app` and all of its services, networks, and configs from the swarm?$tv2$, $tv2$[{"id":"a","text":"docker stack rm app"},{"id":"b","text":"docker stack down app"},{"id":"c","text":"docker swarm rm app"},{"id":"d","text":"docker service rm app"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker stack rm app` deletes every resource that stack created. There is no `docker stack down`; `docker service rm` only removes a single service, not the whole stack.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes a stack named `app` and all of its services, networks, and configs from the swarm?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about swarm service rollbacks and health.$tv2$, $tv2$[{"id":"a","text":"docker service rollback reverts a service to its previous specification."},{"id":"b","text":"A --update-failure-action rollback can automatically roll back an update when too many tasks fail."},{"id":"c","text":"A container HEALTHCHECK status of unhealthy can cause swarm to replace the task during an update."},{"id":"d","text":"Rollbacks are impossible once an update completes."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Swarm stores the prior service spec so `docker service rollback` and `--update-failure-action rollback` work; healthchecks feed update decisions. Rollback to the previous spec remains available after an update completes, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about swarm service rollbacks and health.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A node shows `Availability: Active` but `Status: Down` in `docker node ls`. What does this indicate?$tv2$, $tv2$[{"id":"a","text":"The node is intentionally drained."},{"id":"b","text":"The manager has lost contact with the node (it is unreachable/offline) even though it is configured to accept tasks."},{"id":"c","text":"The node has been removed from the swarm."},{"id":"d","text":"The node is paused for maintenance."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`Availability=Active` means it should accept tasks, but `Status=Down` means the manager cannot reach it, so its tasks are rescheduled elsewhere. Drain/pause are availability values, not the Down status.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A node shows `Availability: Active` but `Status: Down` in `docker node ls`. What does this indicate?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command scales the swarm service `api` to 10 replicas?$tv2$, $tv2$[{"id":"a","text":"docker service scale api=10"},{"id":"b","text":"docker scale api 10"},{"id":"c","text":"docker service replicas api 10"},{"id":"d","text":"docker swarm scale api=10"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker service scale api=10` (or `docker service update --replicas 10 api`) sets the desired replica count. The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command scales the swarm service `api` to 10 replicas?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Swarm mode is a separate product you must install in addition to the Docker Engine.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with Docker Desktop"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. Swarm mode is built into the Docker Engine; you simply run `docker swarm init` to enable it — no separate package or installation is required.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Swarm mode is a separate product you must install in addition to the Docker Engine.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want to back up the swarm so the cluster can be recovered if managers are lost. What should you back up on a manager?$tv2$, $tv2$[{"id":"a","text":"Only /var/lib/docker/volumes"},{"id":"b","text":"The /var/lib/docker/swarm directory (the Raft state/store), ideally with the daemon stopped"},{"id":"c","text":"The image cache under /var/lib/docker/overlay2"},{"id":"d","text":"The /etc/docker/daemon.json file alone"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The swarm Raft state and TLS material live under `/var/lib/docker/swarm`; backing it up (engine stopped for consistency) lets you restore the cluster. Volumes and image cache do not contain swarm cluster state.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to back up the swarm so the cluster can be recovered if managers are lost. What should you back up on a manager?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `docker stack deploy` Compose file uses the `deploy:` key with `replicas`, `placement`, and `resources`. Where are these honored?$tv2$, $tv2$[{"id":"a","text":"Only by docker compose up locally."},{"id":"b","text":"Only by swarm (docker stack deploy) — the deploy key is ignored by plain docker compose up."},{"id":"c","text":"By both, identically."},{"id":"d","text":"By the registry when pushing."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `deploy:` section is a swarm-specific directive applied by `docker stack deploy`; standalone `docker compose up` ignores it. It has nothing to do with registries.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `docker stack deploy` Compose file uses the `deploy:` key with `replicas`, `placement`, and `resources`. Where are these honored?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction sets environment variables that persist in the running container?$tv2$, $tv2$[{"id":"a","text":"ARG"},{"id":"b","text":"ENV"},{"id":"c","text":"SET"},{"id":"d","text":"EXPORT"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`ENV` defines variables available at build time and in the running container. `ARG` values are build-time only and not present at runtime; `SET`/`EXPORT` are not Dockerfile instructions.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction sets environment variables that persist in the running container?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What is the difference between `ARG` and `ENV` in a Dockerfile?$tv2$, $tv2$[{"id":"a","text":"They are identical aliases."},{"id":"b","text":"ARG defines build-time variables (passed via --build-arg) not present at runtime; ENV sets variables available both at build time and in the running container."},{"id":"c","text":"ENV is build-time only; ARG is runtime only."},{"id":"d","text":"ARG can only be used in multi-stage builds."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$ARG values are supplied with `--build-arg` and only exist during the build; ENV values persist into the image and container environment. Both can be used in any build, single- or multi-stage.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the difference between `ARG` and `ENV` in a Dockerfile?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command authenticates the Docker CLI to a registry so subsequent pushes/pulls are authorized?$tv2$, $tv2$[{"id":"a","text":"docker auth registry.example.com"},{"id":"b","text":"docker login registry.example.com"},{"id":"c","text":"docker registry login"},{"id":"d","text":"docker connect registry.example.com"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker login <registry>` stores credentials (in `~/.docker/config.json` or a credential helper) for that registry. `docker auth`/`docker connect`/`docker registry login` are not valid commands.$tv2$, $tv2$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command authenticates the Docker CLI to a registry so subsequent pushes/pulls are authorized?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to inspect the build history and layer commands of an image `myapp:1.0`. Which command shows this?$tv2$, $tv2$[{"id":"a","text":"docker image history myapp:1.0"},{"id":"b","text":"docker image layers myapp:1.0"},{"id":"c","text":"docker inspect --layers myapp:1.0"},{"id":"d","text":"docker build --show-history myapp:1.0"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker image history` (or `docker history`) lists the layers and the instruction that created each. `docker inspect` shows config/metadata but not the per-layer build commands the way history does; the others are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to inspect the build history and layer commands of an image `myapp:1.0`. Which command shows this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker registries and image references.$tv2$, $tv2$[{"id":"a","text":"An image reference has the form [registry[:port]/]repository[:tag|@digest]."},{"id":"b","text":"If no registry is specified, the Docker CLI defaults to Docker Hub (docker.io)."},{"id":"c","text":"docker push always pushes to the local daemon only."},{"id":"d","text":"An insecure (HTTP) registry must be allowed via the insecure-registries daemon setting."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$References include an optional registry and a tag or digest; an omitted registry defaults to docker.io; HTTP registries require the `insecure-registries` allowlist. `docker push` sends the image to a remote registry, not the local daemon, so C is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker registries and image references.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command saves the image `myapp:1.0` to a portable tar archive that can be loaded on an air-gapped host?$tv2$, $tv2$[{"id":"a","text":"docker export myapp:1.0 > myapp.tar"},{"id":"b","text":"docker save -o myapp.tar myapp:1.0"},{"id":"c","text":"docker commit myapp:1.0 myapp.tar"},{"id":"d","text":"docker image archive myapp:1.0"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker save` writes one or more images (with all layers/metadata) to a tar that `docker load` can import. `docker export` dumps a container filesystem (not an image with history); `docker commit` creates an image from a container.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command saves the image `myapp:1.0` to a portable tar archive that can be loaded on an air-gapped host?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A HEALTHCHECK instruction in a Dockerfile primarily lets Docker:$tv2$, $tv2$[{"id":"a","text":"Sign the image so only trusted versions run."},{"id":"b","text":"Periodically run a command inside the container to report its health (healthy/unhealthy) so orchestrators can act on it."},{"id":"c","text":"Scan the image for CVEs at build time."},{"id":"d","text":"Reduce the number of layers in the image."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$HEALTHCHECK defines a probe whose exit status sets the container health state, which swarm and tooling use for replacement/routing. It does not sign, scan, or change layering.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A HEALTHCHECK instruction in a Dockerfile primarily lets Docker:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Running `docker image prune` (without -a) removes all unused images, including tagged ones not used by any container.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --volumes"},{"id":"d","text":"Only in swarm mode"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. `docker image prune` removes only dangling images (untagged, no repository). You must add `-a`/`--all` to also remove unused but tagged images.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Running `docker image prune` (without -a) removes all unused images, including tagged ones not used by any container.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You build for both linux/amd64 and linux/arm64 and want a single tag clients can pull on either architecture. What Docker feature provides this?$tv2$, $tv2$[{"id":"a","text":"A manifest list / multi-architecture image built with docker buildx"},{"id":"b","text":"A multi-stage build"},{"id":"c","text":"The .dockerignore file"},{"id":"d","text":"Docker Content Trust"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A manifest list (multi-arch image), typically produced with `docker buildx build --platform`, lets one tag resolve to the right per-architecture image automatically. Multi-stage builds, .dockerignore, and content trust solve unrelated problems.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You build for both linux/amd64 and linux/arm64 and want a single tag clients can pull on either architecture. What Docker feature provides this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json key sets the default cgroup/OCI runtime, and what is the conventional default runtime name?$tv2$, $tv2$[{"id":"a","text":"\"default-runtime\": \"runc\""},{"id":"b","text":"\"oci-runtime\": \"containerd\""},{"id":"c","text":"\"runtime\": \"docker\""},{"id":"d","text":"\"exec-runtime\": \"runc\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `default-runtime` key chooses which OCI runtime new containers use; the conventional default is `runc`. The other keys are not valid daemon configuration options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json key sets the default cgroup/OCI runtime, and what is the conventional default runtime name?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command displays disk usage by images, containers, volumes, and build cache?$tv2$, $tv2$[{"id":"a","text":"docker system df"},{"id":"b","text":"docker disk usage"},{"id":"c","text":"docker info --disk"},{"id":"d","text":"docker volume df"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker system df` summarizes space used (and reclaimable) by images, containers, local volumes, and build cache. The other commands are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command displays disk usage by images, containers, volumes, and build cache?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container exits immediately and you want it to restart automatically unless you explicitly stop it, surviving daemon restarts. Which restart policy fits?$tv2$, $tv2$[{"id":"a","text":"--restart no"},{"id":"b","text":"--restart on-failure:3"},{"id":"c","text":"--restart unless-stopped"},{"id":"d","text":"--restart=once"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$`unless-stopped` restarts the container automatically (including after daemon/host reboot) unless it was explicitly stopped. `on-failure:3` caps retries and only on non-zero exit; `--restart=once` is not a valid policy.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container exits immediately and you want it to restart automatically unless you explicitly stop it, surviving daemon restarts. Which restart policy fits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After adding your user to the `docker` group, why can that user run Docker without sudo, and what is the security caveat?$tv2$, $tv2$[{"id":"a","text":"It does not work; sudo is always required."},{"id":"b","text":"The docker group grants access to the Docker daemon socket, which is root-equivalent — group membership effectively grants root on the host."},{"id":"c","text":"It only allows read-only Docker commands."},{"id":"d","text":"It encrypts the Docker socket for that user."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Members of the `docker` group can talk to the daemon socket, and the Docker API is root-equivalent (mount host paths, run privileged containers). Treat docker-group membership as granting root.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After adding your user to the `docker` group, why can that user run Docker without sudo, and what is the security caveat?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command streams real-time resource usage (CPU, memory, network, block I/O) for running containers?$tv2$, $tv2$[{"id":"a","text":"docker stats"},{"id":"b","text":"docker top"},{"id":"c","text":"docker metrics"},{"id":"d","text":"docker monitor"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker stats` shows a live stream of per-container CPU/memory/network/IO usage. `docker top` lists processes inside one container; `docker metrics`/`docker monitor` are not commands.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command streams real-time resource usage (CPU, memory, network, block I/O) for running containers?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid daemon.json configuration keys.$tv2$, $tv2$[{"id":"a","text":"\"insecure-registries\""},{"id":"b","text":"\"registry-mirrors\""},{"id":"c","text":"\"default-address-pools\""},{"id":"d","text":"\"auto-prune-everything\""}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$`insecure-registries`, `registry-mirrors`, and `default-address-pools` are real daemon options (HTTP registries, pull-through mirrors, and the address ranges for new bridge/overlay networks). `auto-prune-everything` is not a Docker daemon key.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid daemon.json configuration keys.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You add `"registry-mirrors": ["https://mirror.example.com"]` to daemon.json. What is the effect?$tv2$, $tv2$[{"id":"a","text":"All pushes go to mirror.example.com."},{"id":"b","text":"Docker Hub pulls are first attempted through the configured pull-through mirror, reducing rate limits and latency."},{"id":"c","text":"It disables Docker Hub entirely."},{"id":"d","text":"It signs images automatically."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A registry mirror is a pull-through cache for Docker Hub: pulls try the mirror first. It does not affect pushes, does not disable Hub, and does not sign images.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You add `"registry-mirrors": ["https://mirror.example.com"]` to daemon.json. What is the effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all networks the Docker daemon manages?$tv2$, $tv2$[{"id":"a","text":"docker network ls"},{"id":"b","text":"docker net list"},{"id":"c","text":"docker network show"},{"id":"d","text":"docker ls networks"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker network ls` lists networks with their ID, name, driver, and scope. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all networks the Docker daemon manages?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You attach a running container to an additional user-defined network after it started. Which command does this?$tv2$, $tv2$[{"id":"a","text":"docker network connect mynet mycontainer"},{"id":"b","text":"docker network add mycontainer mynet"},{"id":"c","text":"docker container network mycontainer mynet"},{"id":"d","text":"docker attach --network mynet mycontainer"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker network connect <network> <container>` attaches a running container to another network (and `docker network disconnect` removes it). The other commands are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You attach a running container to an additional user-defined network after it started. Which command does this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container run with `--network none` has what connectivity?$tv2$, $tv2$[{"id":"a","text":"Full access to the host network."},{"id":"b","text":"Only a loopback interface — no external network connectivity at all."},{"id":"c","text":"Access to the default bridge only."},{"id":"d","text":"Access to overlay networks only."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `none` driver gives the container its own network namespace with only loopback and no external interfaces — useful for fully isolated, network-free workloads.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container run with `--network none` has what connectivity?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two containers must communicate, but you do NOT want them reachable from any other container on the host. The best approach is to:$tv2$, $tv2$[{"id":"a","text":"Put them both on the default bridge network."},{"id":"b","text":"Create a dedicated user-defined bridge network and attach only those two containers to it."},{"id":"c","text":"Use --network host for both."},{"id":"d","text":"Publish all their ports with -p."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A dedicated user-defined network isolates the two containers (with DNS by name) from containers on other networks. The shared default bridge mixes all containers; host networking removes isolation; publishing ports exposes them more widely.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two containers must communicate, but you do NOT want them reachable from any other container on the host. The best approach is to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about swarm overlay networking.$tv2$, $tv2$[{"id":"a","text":"Overlay networks let services on different swarm nodes communicate as if on one L2 network."},{"id":"b","text":"Swarm overlay control plane traffic can be encrypted with the --opt encrypted flag on the network."},{"id":"c","text":"Containers not part of a service cannot ever join a swarm overlay network."},{"id":"d","text":"The overlay driver uses VXLAN encapsulation under the hood."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Overlay spans nodes via VXLAN and supports optional data-plane encryption (`--opt encrypted`). Standalone containers CAN join an overlay if it is created `--attachable`, so C is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about swarm overlay networking.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the IP address and network attachments of a running container `web`?$tv2$, $tv2$[{"id":"a","text":"docker inspect web (look at NetworkSettings)"},{"id":"b","text":"docker network ip web"},{"id":"c","text":"docker container ip web"},{"id":"d","text":"docker ps --ip web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker inspect web` exposes `NetworkSettings`/`Networks` with the container IP, gateway, and attached networks (you can also use a `--format` template). The other commands are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the IP address and network attachments of a running container `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You publish `-p 80:80` for two different containers on the same host at the same time. What happens to the second one?$tv2$, $tv2$[{"id":"a","text":"Both share port 80 transparently via the routing mesh."},{"id":"b","text":"The second container fails to start (or the run fails) because host port 80 is already bound."},{"id":"c","text":"Docker automatically remaps the second to a random port."},{"id":"d","text":"The first container is stopped to free the port."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A published host port is exclusive on a standalone host, so binding the same port twice fails with a port-already-allocated error. Docker does not auto-remap or stop the existing container; the routing mesh applies to swarm services, not standalone `-p`.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You publish `-p 80:80` for two different containers on the same host at the same time. What happens to the second one?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag makes the container root filesystem read-only, forcing writable data into explicit volumes/tmpfs?$tv2$, $tv2$[{"id":"a","text":"--read-only"},{"id":"b","text":"--immutable"},{"id":"c","text":"--no-write"},{"id":"d","text":"--ro-rootfs"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--read-only` mounts the container filesystem read-only; you then add `--tmpfs` or volumes for paths that must be writable. The other flags do not exist.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag makes the container root filesystem read-only, forcing writable data into explicit volumes/tmpfs?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How are Docker swarm secrets exposed inside a container that the service is granted?$tv2$, $tv2$[{"id":"a","text":"As environment variables."},{"id":"b","text":"As in-memory files mounted under /run/secrets/<secret_name>."},{"id":"c","text":"Written to the image during build."},{"id":"d","text":"In the container labels."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A granted secret is mounted as a tmpfs-backed file at `/run/secrets/<name>`, never persisted to disk or the image and not placed in env vars (which can leak via inspect/logs).$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How are Docker swarm secrets exposed inside a container that the service is granted?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag prevents a process inside the container from gaining new privileges (e.g. via setuid binaries)?$tv2$, $tv2$[{"id":"a","text":"--security-opt no-new-privileges"},{"id":"b","text":"--cap-drop SETUID"},{"id":"c","text":"--privileged=false"},{"id":"d","text":"--no-setuid"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--security-opt no-new-privileges` sets the kernel `no_new_privs` bit so setuid/setgid binaries cannot escalate privileges. Dropping SETUID alone is narrower; `--privileged=false` is just the default; `--no-setuid` is not a flag.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag prevents a process inside the container from gaining new privileges (e.g. via setuid binaries)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: By default, the root user inside a container (without userns-remap) is the same root (UID 0) as on the host.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with --privileged"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Without user-namespace remapping, container UID 0 maps to host UID 0; that is exactly why running as non-root and/or enabling userns-remap is recommended to limit breakout impact.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: By default, the root user inside a container (without userns-remap) is the same root (UID 0) as on the host.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to apply a custom AppArmor profile to a container. Which flag is used?$tv2$, $tv2$[{"id":"a","text":"--security-opt apparmor=my-profile"},{"id":"b","text":"--apparmor my-profile"},{"id":"c","text":"--lsm apparmor=my-profile"},{"id":"d","text":"--profile apparmor:my-profile"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--security-opt apparmor=<profile>` selects the AppArmor profile for the container (Docker also loads a default `docker-default` profile). The other flag forms are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to apply a custom AppArmor profile to a container. Which flag is used?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker Content Trust (DCT).$tv2$, $tv2$[{"id":"a","text":"Setting DOCKER_CONTENT_TRUST=1 makes docker pull only retrieve signed images."},{"id":"b","text":"DCT uses The Update Framework (TUF) / Notary for signing and verification."},{"id":"c","text":"With DCT enabled, docker push signs the pushed image."},{"id":"d","text":"DCT scans images for vulnerabilities before allowing them to run."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$DCT (Notary/TUF) signs on push and verifies signatures on pull/run when enabled. It is an integrity/publisher control, not a vulnerability scanner — that is a separate tool like Docker Scout.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker Content Trust (DCT).$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why is mounting the host Docker socket (`-v /var/run/docker.sock:/var/run/docker.sock`) into a container a serious risk?$tv2$, $tv2$[{"id":"a","text":"It only slows the container down."},{"id":"b","text":"The container can then control the Docker daemon, which is root-equivalent, allowing full host compromise."},{"id":"c","text":"It disables container DNS."},{"id":"d","text":"It prevents the container from using volumes."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A container with the daemon socket can create privileged containers and mount host paths, effectively gaining root on the host. Grant it only to trusted tooling and prefer scoped/proxied access.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is mounting the host Docker socket (`-v /var/run/docker.sock:/var/run/docker.sock`) into a container a serious risk?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes all unused (dangling) local volumes to reclaim space?$tv2$, $tv2$[{"id":"a","text":"docker volume prune"},{"id":"b","text":"docker volume clean"},{"id":"c","text":"docker prune volumes"},{"id":"d","text":"docker volume rm --unused"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker volume prune` deletes local volumes not referenced by any container. The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes all unused (dangling) local volumes to reclaim space?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag mounts a host directory `/data` into the container at `/app/data` as a bind mount using the --mount syntax?$tv2$, $tv2$[{"id":"a","text":"--mount type=bind,source=/data,target=/app/data"},{"id":"b","text":"--mount type=volume,source=/data,target=/app/data"},{"id":"c","text":"-v bind:/data:/app/data"},{"id":"d","text":"--bind /data:/app/data"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--mount type=bind,source=/data,target=/app/data` is the explicit bind-mount form. `type=volume` would treat `/data` as a named volume; `-v bind:...` and `--bind` are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag mounts a host directory `/data` into the container at `/app/data` as a bind mount using the --mount syntax?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A volume driver/plugin (e.g. for NFS or cloud block storage) lets you:$tv2$, $tv2$[{"id":"a","text":"Only create volumes on the local disk."},{"id":"b","text":"Provision and attach volumes backed by external/remote storage systems so data survives node loss and can move between hosts."},{"id":"c","text":"Encrypt the image registry."},{"id":"d","text":"Replace the need for a Dockerfile."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Volume plugins integrate external storage backends (NFS, cloud block/file storage), enabling portable, durable data across hosts — important for stateful services in a cluster. They are unrelated to registries or Dockerfiles.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A volume driver/plugin (e.g. for NFS or cloud block storage) lets you:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You mount a named volume into a fresh container at a path that already contains files in the image. What happens on first use of an empty named volume?$tv2$, $tv2$[{"id":"a","text":"The image files at that path are deleted."},{"id":"b","text":"Docker copies the existing image content at the mount path into the new empty named volume (volume pre-population)."},{"id":"c","text":"The container fails to start."},{"id":"d","text":"The volume is ignored and the image files are used."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$For an empty named volume, Docker pre-populates it with the content already present at the mount target in the image. (This copy behavior does not apply to bind mounts or to non-empty volumes.)$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You mount a named volume into a fresh container at a path that already contains files in the image. What happens on first use of an empty named volume?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all nodes participating in a swarm (run from a manager)?$tv2$, $tv2$[{"id":"a","text":"docker swarm ls"},{"id":"b","text":"docker node ls"},{"id":"c","text":"docker service ps"},{"id":"d","text":"docker stack nodes"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker node ls` lists swarm nodes with their availability, manager status, and leader. `docker swarm ls` is not valid; `docker service ps` lists tasks of a service; there is no `docker stack nodes`.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all nodes participating in a swarm (run from a manager)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A swarm manager node is being decommissioned for maintenance. Which is the correct first step to safely move work off it without losing manager quorum?$tv2$, $tv2$[{"id":"a","text":"docker node rm <node> immediately"},{"id":"b","text":"docker node update --availability drain <node>"},{"id":"c","text":"docker swarm leave on that node while it is still the leader"},{"id":"d","text":"docker service scale all=0"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Setting availability to `drain` reschedules tasks off the node while keeping it in the swarm. Removing or leaving abruptly can break quorum; you demote and then remove managers carefully.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A swarm manager node is being decommissioned for maintenance. Which is the correct first step to safely move work off it without losing manager quorum?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How does the swarm routing mesh make a published service port reachable?$tv2$, $tv2$[{"id":"a","text":"Only the node currently running a task answers on the published port."},{"id":"b","text":"Every node in the swarm listens on the published port and routes the request to an active task, even if no task runs locally."},{"id":"c","text":"You must configure an external load balancer manually for any access."},{"id":"d","text":"The published port is reachable only from inside containers."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The routing mesh makes the published port available on every swarm node; incoming traffic is load-balanced to a healthy task wherever it runs. An external LB is optional, not required.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How does the swarm routing mesh make a published service port reachable?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You create a swarm service that needs a database password. What is the recommended way to deliver it?$tv2$, $tv2$[{"id":"a","text":"Bake it into the image with ENV in the Dockerfile"},{"id":"b","text":"Pass it via --env on docker service create"},{"id":"c","text":"Create a Docker secret and attach it with --secret so it is mounted at /run/secrets"},{"id":"d","text":"Store it in a world-readable bind mount"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Docker secrets are encrypted in the Raft log, transmitted only to nodes running the service, and exposed in-memory at /run/secrets. ENV/--env and bind mounts leak the value in image history, inspect output, or the filesystem.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You create a swarm service that needs a database password. What is the recommended way to deliver it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker swarm services and stacks.$tv2$, $tv2$[{"id":"a","text":"docker service update --image newimage:tag triggers a rolling update of the service tasks."},{"id":"b","text":"Swarm configs (docker config) are intended for non-sensitive configuration files."},{"id":"c","text":"A stack deployed with docker stack deploy can include services, networks, and volumes from a single Compose file."},{"id":"d","text":"Worker nodes can run docker service create to schedule new services."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Service updates roll out per the update config; configs hold non-secret data; stacks bundle services/networks/volumes. Only manager nodes accept orchestration commands like `service create` — workers cannot.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/configs/","label":"Docker Docs — Store configuration data using configs"},{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker swarm services and stacks.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction copies files from the build context and also supports remote URLs and automatic tar extraction?$tv2$, $tv2$[{"id":"a","text":"COPY"},{"id":"b","text":"ADD"},{"id":"c","text":"GET"},{"id":"d","text":"IMPORT"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`ADD` can fetch remote URLs and auto-extract local tar archives; `COPY` is the simpler, preferred instruction for plain file copies. `GET`/`IMPORT` are not Dockerfile instructions.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction copies files from the build context and also supports remote URLs and automatic tar extraction?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A teammate reports your image is huge because each RUN apt-get installs and then a later RUN deletes the cache. Why is the image still large?$tv2$, $tv2$[{"id":"a","text":"apt-get does not actually download anything."},{"id":"b","text":"Each RUN is a separate layer; files added in one layer still occupy space even if deleted in a later layer."},{"id":"c","text":"Docker compresses only the final layer."},{"id":"d","text":"The .dockerignore file overrides layer sizes."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Layers are additive and immutable; deleting a file in a later layer hides it but its bytes remain in the earlier layer. Combine install + cleanup in a single RUN (or use multi-stage) to keep it out of the image.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A teammate reports your image is huge because each RUN apt-get installs and then a later RUN deletes the cache. Why is the image still large?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does `docker pull nginx@sha256:abc123...` guarantee compared to `docker pull nginx:latest`?$tv2$, $tv2$[{"id":"a","text":"It always pulls the newest build of nginx."},{"id":"b","text":"It pulls the exact, immutable image content identified by that digest regardless of tag movement."},{"id":"c","text":"It runs a vulnerability scan before pulling."},{"id":"d","text":"It pulls from Docker Hub only and never a private registry."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Pinning by digest fetches the precise image content (reproducible/immutable). A tag like `latest` can be re-pointed at any time. Digest pinning does not scan images or restrict the registry.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `docker pull nginx@sha256:abc123...` guarantee compared to `docker pull nginx:latest`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You run a local Docker registry with `docker run -d -p 5000:5000 registry:2`. To push `myapp` to it you should tag the image as:$tv2$, $tv2$[{"id":"a","text":"myapp:5000"},{"id":"b","text":"localhost:5000/myapp"},{"id":"c","text":"registry:2/myapp"},{"id":"d","text":"docker.io/library/myapp"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The registry host:port must prefix the repository, e.g. `localhost:5000/myapp`, before `docker push localhost:5000/myapp`. The other forms either lack the registry host or point at Docker Hub.$tv2$, $tv2$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You run a local Docker registry with `docker run -d -p 5000:5000 registry:2`. To push `myapp` to it you should tag the image as:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json setting changes where Docker stores images, containers, and volumes on disk?$tv2$, $tv2$[{"id":"a","text":"\"data-root\": \"/mnt/docker\""},{"id":"b","text":"\"graph-path\": \"/mnt/docker\""},{"id":"c","text":"\"storage-path\": \"/mnt/docker\""},{"id":"d","text":"\"root-dir\": \"/mnt/docker\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`data-root` (formerly the deprecated `graph`) sets the Docker data directory. The other keys are not valid daemon configuration options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json setting changes where Docker stores images, containers, and volumes on disk?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows system-wide Docker information including the storage driver, logging driver, and number of containers/images?$tv2$, $tv2$[{"id":"a","text":"docker version"},{"id":"b","text":"docker info"},{"id":"c","text":"docker inspect docker"},{"id":"d","text":"docker system version"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker info` reports daemon-level details: storage/logging drivers, container and image counts, swarm status, etc. `docker version` shows client/server versions only.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows system-wide Docker information including the storage driver, logging driver, and number of containers/images?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$On Linux, which storage driver does Docker recommend and use by default on modern kernels with overlay filesystem support?$tv2$, $tv2$[{"id":"a","text":"aufs"},{"id":"b","text":"devicemapper"},{"id":"c","text":"overlay2"},{"id":"d","text":"vfs"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$`overlay2` is the recommended, default storage driver on supported Linux kernels. `aufs`/`devicemapper` are legacy; `vfs` has no copy-on-write and is used only for testing.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On Linux, which storage driver does Docker recommend and use by default on modern kernels with overlay filesystem support?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a user-defined overlay network named `appnet` for use by swarm services?$tv2$, $tv2$[{"id":"a","text":"docker network create -d overlay appnet"},{"id":"b","text":"docker network add overlay appnet"},{"id":"c","text":"docker swarm network create appnet"},{"id":"d","text":"docker overlay create appnet"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker network create -d overlay appnet` creates an attachable swarm-scoped overlay network. The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a user-defined overlay network named `appnet` for use by swarm services?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container started with `--network host` behaves how with respect to port publishing?$tv2$, $tv2$[{"id":"a","text":"It still requires -p to expose ports."},{"id":"b","text":"It shares the host network namespace; the service binds directly to host ports and -p is ignored."},{"id":"c","text":"It cannot reach the network at all."},{"id":"d","text":"It gets its own IP on the default bridge."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$With the host driver the container uses the host network stack directly, so processes bind host ports without `-p` (which is ignored). There is no separate container IP or bridge attachment.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/host/","label":"Docker Docs — Host network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container started with `--network host` behaves how with respect to port publishing?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want containers to appear as distinct physical hosts on the existing 192.168.10.0/24 LAN, each with its own LAN IP. Which network driver is designed for this?$tv2$, $tv2$[{"id":"a","text":"bridge"},{"id":"b","text":"overlay"},{"id":"c","text":"macvlan"},{"id":"d","text":"none"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$The macvlan driver attaches containers directly to the physical network with their own MAC/IP, making them appear as separate devices on the LAN. bridge NATs behind the host; overlay is multi-host swarm; none disables networking.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want containers to appear as distinct physical hosts on the existing 192.168.10.0/24 LAN, each with its own LAN IP. Which network driver is designed for this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does running a container with `--privileged` do?$tv2$, $tv2$[{"id":"a","text":"It drops all Linux capabilities for maximum isolation."},{"id":"b","text":"It grants the container nearly all host capabilities and device access, largely disabling isolation safeguards."},{"id":"c","text":"It forces the container to run as a non-root user."},{"id":"d","text":"It enables Docker Content Trust for that container."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--privileged` gives the container almost full host access (all capabilities, devices, relaxed seccomp/AppArmor). It is the opposite of least privilege and should be avoided unless strictly required.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does running a container with `--privileged` do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$By default Docker applies a seccomp profile to containers. What does this profile do?$tv2$, $tv2$[{"id":"a","text":"It encrypts the container root filesystem."},{"id":"b","text":"It restricts the set of Linux syscalls a container process may invoke, blocking dangerous ones by default."},{"id":"c","text":"It signs images on push."},{"id":"d","text":"It rotates container logs."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Seccomp filters syscalls; Docker ships a default profile that blocks a large set of dangerous calls while allowing those most apps need. It is unrelated to encryption, signing, or logging.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$By default Docker applies a seccomp profile to containers. What does this profile do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL recommended Docker security hardening practices.$tv2$, $tv2$[{"id":"a","text":"Run containers as a non-root user where possible (USER instruction or --user)."},{"id":"b","text":"Use --cap-drop ALL and add back only required capabilities."},{"id":"c","text":"Run every container with --privileged for convenience."},{"id":"d","text":"Enable Docker Content Trust to only run signed images."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Non-root users, dropping capabilities, and content trust all reduce risk. Running everything `--privileged` does the opposite — it removes isolation and is explicitly discouraged.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL recommended Docker security hardening practices.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container is removed with `docker rm`. What happens to data written into a named volume it used?$tv2$, $tv2$[{"id":"a","text":"The volume and its data are deleted along with the container."},{"id":"b","text":"The named volume and its data persist and can be reused by another container."},{"id":"c","text":"The data is moved into the image."},{"id":"d","text":"The volume becomes read-only permanently."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Named volumes have a lifecycle independent of containers; removing the container leaves the volume and its data intact (unless `docker rm -v` or `docker volume rm` is used). Anonymous volumes can be pruned, but named ones persist.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container is removed with `docker rm`. What happens to data written into a named volume it used?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a named volume called `dbdata`?$tv2$, $tv2$[{"id":"a","text":"docker volume create dbdata"},{"id":"b","text":"docker volume add dbdata"},{"id":"c","text":"docker create volume dbdata"},{"id":"d","text":"docker storage new dbdata"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker volume create <name>` creates a managed named volume. The other forms are not valid Docker CLI commands.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a named volume called `dbdata`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command makes the current manager node leave the swarm and dismantle it (last manager)?$tv2$, $tv2$[{"id":"a","text":"docker swarm leave --force"},{"id":"b","text":"docker swarm destroy"},{"id":"c","text":"docker node rm self"},{"id":"d","text":"docker swarm down"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker swarm leave --force` is required for a manager (especially the last one) to leave; without `--force` the engine refuses to avoid breaking quorum. `docker swarm destroy/down` are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command makes the current manager node leave the swarm and dismantle it (last manager)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You run `docker service logs web`. What does this show?$tv2$, $tv2$[{"id":"a","text":"Only the logs of the manager node."},{"id":"b","text":"Aggregated logs from all tasks (replicas) of the service across the swarm."},{"id":"c","text":"The swarm Raft log."},{"id":"d","text":"Only build logs of the image."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker service logs` aggregates stdout/stderr from every task of the service across nodes. It is not the Raft log or build output.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You run `docker service logs web`. What does this show?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker service create` option reserves 512 MB of memory and limits the service to 1 CPU per task?$tv2$, $tv2$[{"id":"a","text":"--reserve-mem 512m --max-cpu 1"},{"id":"b","text":"--reserve-memory 512m --limit-cpu 1"},{"id":"c","text":"--memory 512m --cpus 1"},{"id":"d","text":"--mem-reservation 512m --cpu-quota 1"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Swarm services use `--reserve-memory`/`--reserve-cpu` for scheduling reservations and `--limit-memory`/`--limit-cpu` for hard limits. `--memory`/`--cpus` are `docker run` (standalone) flags, not service flags; the others are invalid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker service create` option reserves 512 MB of memory and limits the service to 1 CPU per task?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A swarm has 4 manager nodes. How many manager failures can it tolerate while keeping quorum?$tv2$, $tv2$[{"id":"a","text":"2"},{"id":"b","text":"1"},{"id":"c","text":"3"},{"id":"d","text":"0"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Quorum needs a majority: with 4 managers a majority is 3, so only 1 failure is tolerated — the same as 3 managers. This is why odd numbers of managers are recommended.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A swarm has 4 manager nodes. How many manager failures can it tolerate while keeping quorum?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists the running tasks (and their nodes) for the service `api`?$tv2$, $tv2$[{"id":"a","text":"docker service ps api"},{"id":"b","text":"docker service tasks api"},{"id":"c","text":"docker ps --service api"},{"id":"d","text":"docker node ps api"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker service ps api` lists the service tasks, their desired/current state, and the node each runs on. `docker node ps` lists tasks on a *node*, not a service; the other forms are invalid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists the running tasks (and their nodes) for the service `api`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about swarm node availability states.$tv2$, $tv2$[{"id":"a","text":"active means the node can receive new tasks."},{"id":"b","text":"pause means existing tasks keep running but no new tasks are scheduled to the node."},{"id":"c","text":"drain means existing tasks are stopped and rescheduled elsewhere and no new tasks are placed."},{"id":"d","text":"active means the node is removed from the swarm."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$active accepts new tasks; pause keeps current tasks but blocks new ones; drain evacuates and blocks scheduling. active does not remove the node from the swarm, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about swarm node availability states.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A service deployed with `--mode replicated-job --replicas 5` behaves how?$tv2$, $tv2$[{"id":"a","text":"It keeps 5 tasks running forever."},{"id":"b","text":"It runs 5 tasks to completion (one-shot batch job) and does not restart them once they exit successfully."},{"id":"c","text":"It runs one task per node forever."},{"id":"d","text":"It is rejected — jobs are not supported in swarm."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A replicated job runs the requested number of tasks until they complete successfully (batch semantics), unlike a long-running replicated service. Global-job is the per-node variant; jobs are supported in swarm.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A service deployed with `--mode replicated-job --replicas 5` behaves how?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: You can run `docker service create` from a swarm worker node.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --force"},{"id":"d","text":"Only for global services"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. Orchestration commands such as `docker service create/scale/update` must be issued against a manager node; workers only execute tasks and cannot accept these commands.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: You can run `docker service create` from a swarm worker node.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command rotates the swarm join tokens (e.g. after a suspected leak of a worker token)?$tv2$, $tv2$[{"id":"a","text":"docker swarm join-token --rotate worker"},{"id":"b","text":"docker swarm token reset worker"},{"id":"c","text":"docker node rotate-token worker"},{"id":"d","text":"docker swarm regenerate worker"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker swarm join-token --rotate worker` (or `manager`) invalidates the old token and issues a new one. The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command rotates the swarm join tokens (e.g. after a suspected leak of a worker token)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$In a Compose/stack file, what is the effect of `deploy.placement.constraints: [node.role == manager]`?$tv2$, $tv2$[{"id":"a","text":"The service tasks may run on any node."},{"id":"b","text":"The service tasks are scheduled only onto manager nodes."},{"id":"c","text":"It promotes workers to managers."},{"id":"d","text":"It is ignored by docker stack deploy."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A placement constraint of `node.role == manager` restricts the service to manager nodes (a common pattern for cluster-aware tooling). It does not change node roles and is honored by `docker stack deploy`.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Compose/stack file, what is the effect of `deploy.placement.constraints: [node.role == manager]`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command demotes a manager node `node-2` back to a worker?$tv2$, $tv2$[{"id":"a","text":"docker node demote node-2"},{"id":"b","text":"docker swarm demote node-2"},{"id":"c","text":"docker node update --worker node-2"},{"id":"d","text":"docker manager rm node-2"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker node demote <node>` (shortcut for `docker node update --role worker`) returns a manager to worker status. The other forms are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command demotes a manager node `node-2` back to a worker?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction documents that the container listens on a given port at runtime (without actually publishing it)?$tv2$, $tv2$[{"id":"a","text":"PORT"},{"id":"b","text":"EXPOSE"},{"id":"c","text":"LISTEN"},{"id":"d","text":"PUBLISH"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`EXPOSE` documents the intended listening port (used by tooling and `-P`), but does not publish it to the host — you still need `-p`/`-P` at run time. `PORT`/`LISTEN`/`PUBLISH` are not Dockerfile instructions.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction documents that the container listens on a given port at runtime (without actually publishing it)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You build with `docker build --target builder -t app:dev .` on a multi-stage Dockerfile. What does `--target` do?$tv2$, $tv2$[{"id":"a","text":"It signs the image."},{"id":"b","text":"It stops the build at the named stage, producing an image of just that stage (useful for debugging or test images)."},{"id":"c","text":"It selects the registry to push to."},{"id":"d","text":"It sets the default CMD."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--target <stage>` builds only up to the named stage, so you can produce an intermediate (e.g. build/test) image without the final runtime stage. It has nothing to do with signing, registries, or CMD.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You build with `docker build --target builder -t app:dev .` on a multi-stage Dockerfile. What does `--target` do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all images present in the local Docker image store?$tv2$, $tv2$[{"id":"a","text":"docker images (or docker image ls)"},{"id":"b","text":"docker image list --remote"},{"id":"c","text":"docker registry ls"},{"id":"d","text":"docker ps -a --images"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker images` / `docker image ls` lists locally stored images with repository, tag, ID, and size. `docker ps` lists containers; the others are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all images present in the local Docker image store?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to retag an existing image `app:1.0` as `app:latest` without rebuilding. Which command?$tv2$, $tv2$[{"id":"a","text":"docker image tag app:1.0 app:latest"},{"id":"b","text":"docker image rename app:1.0 app:latest"},{"id":"c","text":"docker image alias app:1.0 app:latest"},{"id":"d","text":"docker tag --new app:latest app:1.0"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker image tag <source> <target>` adds an additional tag pointing at the same image ID (no rebuild). The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to retag an existing image `app:1.0` as `app:latest` without rebuilding. Which command?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL effective ways to reduce final Docker image size.$tv2$, $tv2$[{"id":"a","text":"Use a minimal base image (e.g. alpine or distroless)."},{"id":"b","text":"Use multi-stage builds to discard build tooling."},{"id":"c","text":"Combine related RUN steps and clean package caches in the same layer."},{"id":"d","text":"Add every debugging tool you might ever need to the runtime image."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Minimal bases, multi-stage builds, and cleaning caches within the same RUN all shrink images. Bundling many debug tools into the runtime image does the opposite and enlarges the attack surface.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL effective ways to reduce final Docker image size.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What is the difference between `docker save` and `docker export`?$tv2$, $tv2$[{"id":"a","text":"They are identical."},{"id":"b","text":"`docker save` archives one or more images with all layers and metadata; `docker export` flattens a single container's filesystem into a tar (no image history)."},{"id":"c","text":"`docker export` archives images; `docker save` archives containers."},{"id":"d","text":"Both only work on running containers."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker save`/`docker load` preserve full image layer history; `docker export`/`docker import` produce a flattened single-layer filesystem from a container. They are not interchangeable and save works on images regardless of run state.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the difference between `docker save` and `docker export`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT/COPY instructions?$tv2$, $tv2$[{"id":"a","text":"CD"},{"id":"b","text":"WORKDIR"},{"id":"c","text":"CHDIR"},{"id":"d","text":"PWD"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`WORKDIR` sets (and creates if needed) the directory used by following instructions and as the default at runtime. Using shell `cd` in a RUN does not persist across instructions; `CD`/`CHDIR`/`PWD` are not instructions.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT/COPY instructions?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A Dockerfile may contain multiple FROM instructions, each starting a new build stage.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with buildx"},{"id":"d","text":"Only one FROM is ever allowed"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Multiple `FROM` lines define multi-stage builds; each `FROM` begins a new stage that can be named with `AS <name>` and selectively copied from.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A Dockerfile may contain multiple FROM instructions, each starting a new build stage.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You see a build step show `---> Using cache`. What does that mean, and how can you force a clean rebuild?$tv2$, $tv2$[{"id":"a","text":"It means the build failed; rerun with sudo."},{"id":"b","text":"The layer was reused from the build cache because the instruction and inputs were unchanged; use `docker build --no-cache` to rebuild everything."},{"id":"c","text":"It means the image is signed; disable content trust."},{"id":"d","text":"It means the registry served the layer; log out to fix it."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Docker reuses a cached layer when the instruction and its inputs are unchanged; `--no-cache` disables the build cache so all steps re-execute. It is unrelated to signing or registry auth.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You see a build step show `---> Using cache`. What does that mean, and how can you force a clean rebuild?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json key enables IPv6 networking for containers?$tv2$, $tv2$[{"id":"a","text":"\"ipv6\": true"},{"id":"b","text":"\"enable-ipv6\": true"},{"id":"c","text":"\"net6\": true"},{"id":"d","text":"\"v6\": \"on\""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `"ipv6": true` key (paired with a `fixed-cidr-v6` range) enables IPv6 for the default bridge in daemon.json; older docs reference `enable-ipv6` per-network, but as a daemon option the canonical key is `ipv6`. Of the listed options only the IPv6-enabling boolean is meaningful — `net6`/`v6` are not valid keys.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json key enables IPv6 networking for containers?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the Docker client and daemon (server) version and API version?$tv2$, $tv2$[{"id":"a","text":"docker version"},{"id":"b","text":"docker info"},{"id":"c","text":"docker --release"},{"id":"d","text":"docker system version"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker version` prints client and server versions, the Go version, and the API version. `docker info` shows daemon configuration/stats but not the version layout; `docker --release`/`docker system version` are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the Docker client and daemon (server) version and API version?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want the Docker daemon to start automatically on boot of a systemd Linux host. Which command sets that up?$tv2$, $tv2$[{"id":"a","text":"systemctl enable docker"},{"id":"b","text":"docker daemon --boot"},{"id":"c","text":"systemctl autostart docker"},{"id":"d","text":"docker config startup on"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`systemctl enable docker` creates the boot-time start link (add `--now` to also start it immediately). The other commands are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want the Docker daemon to start automatically on boot of a systemd Linux host. Which command sets that up?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command tails and follows the logs of a single container `web` started without swarm?$tv2$, $tv2$[{"id":"a","text":"docker logs -f web"},{"id":"b","text":"docker service logs -f web"},{"id":"c","text":"docker tail web"},{"id":"d","text":"docker container output web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker logs -f web` follows the stdout/stderr captured by the container logging driver. `docker service logs` is for swarm services; `docker tail`/`docker container output` do not exist.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command tails and follows the logs of a single container `web` started without swarm?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which logging driver should you configure to ship container logs to a centralized syslog server?$tv2$, $tv2$[{"id":"a","text":"json-file"},{"id":"b","text":"syslog"},{"id":"c","text":"none"},{"id":"d","text":"local"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `syslog` driver forwards container logs to a syslog endpoint. `json-file`/`local` store logs on the host; `none` disables collection (and `docker logs`).$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which logging driver should you configure to ship container logs to a centralized syslog server?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker logging.$tv2$, $tv2$[{"id":"a","text":"With the json-file driver, docker logs can read container output."},{"id":"b","text":"With certain remote drivers (e.g. syslog/gelf), docker logs may not return output unless dual logging is enabled."},{"id":"c","text":"log-opts max-size and max-file configure json-file log rotation."},{"id":"d","text":"The none driver still allows docker logs to work normally."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$json-file (and local) support `docker logs`; some remote drivers do not unless dual logging is on; max-size/max-file rotate json-file logs. The `none` driver disables `docker logs`, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker logging.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command deletes a user-defined network named `appnet` (when no containers are attached)?$tv2$, $tv2$[{"id":"a","text":"docker network rm appnet"},{"id":"b","text":"docker network delete appnet"},{"id":"c","text":"docker rm network appnet"},{"id":"d","text":"docker network destroy appnet"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker network rm appnet` removes the network (it must have no attached containers). The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command deletes a user-defined network named `appnet` (when no containers are attached)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A daemon fails to start after editing daemon.json. The most likely cause and first thing to check is:$tv2$, $tv2$[{"id":"a","text":"The host has no internet."},{"id":"b","text":"Invalid JSON syntax or an unknown/duplicate key in /etc/docker/daemon.json — validate the file and check the daemon journal/logs."},{"id":"c","text":"Docker requires a reboot for every change."},{"id":"d","text":"The image cache is corrupt."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$dockerd refuses to start on malformed JSON or unrecognized options; check `journalctl -u docker` (or the daemon log) and validate `daemon.json`. Connectivity and the image cache are unrelated to a config-parse failure.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A daemon fails to start after editing daemon.json. The most likely cause and first thing to check is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$On a user-defined bridge network, container A wants to reach container B by a custom hostname `db`. How do you set that alias?$tv2$, $tv2$[{"id":"a","text":"It is impossible; only container names resolve."},{"id":"b","text":"Use --network-alias db when running container B (or networks.<net>.aliases in Compose)."},{"id":"c","text":"Edit /etc/hosts on the host."},{"id":"d","text":"Publish a port with -p db:5432."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A network alias (`--network-alias db`) registers an extra DNS name on that user-defined network so other containers resolve `db`. Editing host `/etc/hosts` or publishing a port does not create container DNS aliases.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$On a user-defined bridge network, container A wants to reach container B by a custom hostname `db`. How do you set that alias?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `-P` (capital) flag do on `docker run`?$tv2$, $tv2$[{"id":"a","text":"Publishes a specific host:container port pair."},{"id":"b","text":"Publishes all ports declared with EXPOSE to random high host ports."},{"id":"c","text":"Disables port publishing."},{"id":"d","text":"Runs the container in privileged mode."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`-P` publishes every EXPOSEd port to ephemeral host ports (see them via `docker port`). `-p` (lowercase) maps specific ports; `-P` is unrelated to privilege.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `-P` (capital) flag do on `docker run`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json setting lets you change the default subnet pools Docker uses when creating bridge/overlay networks (e.g. to avoid clashing with corporate IP ranges)?$tv2$, $tv2$[{"id":"a","text":"\"default-address-pools\""},{"id":"b","text":"\"bip-range\""},{"id":"c","text":"\"subnet-pool\""},{"id":"d","text":"\"network-cidr\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`default-address-pools` defines the base CIDR ranges and sizes from which Docker carves new network subnets, useful to avoid overlap with existing infrastructure. The other keys are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json setting lets you change the default subnet pools Docker uses when creating bridge/overlay networks (e.g. to avoid clashing with corporate IP ranges)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker DNS and service discovery.$tv2$, $tv2$[{"id":"a","text":"Containers on a user-defined network resolve each other by container name via Docker's embedded DNS."},{"id":"b","text":"In swarm, a service is reachable by its service name, which resolves to a virtual IP (VIP) load-balancing across tasks by default."},{"id":"c","text":"You can switch a swarm service to DNS round-robin (dnsrr) endpoint mode instead of VIP."},{"id":"d","text":"The legacy default bridge provides automatic name-based DNS resolution."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$User-defined networks and swarm services provide embedded DNS; swarm defaults to a VIP and supports `dnsrr` mode. The legacy default bridge does NOT provide automatic name resolution, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker DNS and service discovery.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows detailed configuration of a network, including connected containers and subnet?$tv2$, $tv2$[{"id":"a","text":"docker network inspect appnet"},{"id":"b","text":"docker network show appnet"},{"id":"c","text":"docker inspect --net appnet"},{"id":"d","text":"docker network detail appnet"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker network inspect appnet` returns the driver, subnet/gateway, options, and attached containers. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows detailed configuration of a network, including connected containers and subnet?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A macvlan network is configured with `--subnet 192.168.10.0/24 --gateway 192.168.10.1 -o parent=eth0`. A common limitation to be aware of is:$tv2$, $tv2$[{"id":"a","text":"Containers cannot get IP addresses at all."},{"id":"b","text":"By default the Docker host itself cannot communicate with the macvlan containers over that interface (macvlan host/container isolation)."},{"id":"c","text":"Macvlan only works in swarm mode."},{"id":"d","text":"Macvlan disables DNS for all containers on the host."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$With macvlan, the parent host interface generally cannot talk to its own macvlan child containers without an extra macvlan sub-interface workaround. It does work outside swarm and does not globally disable DNS.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A macvlan network is configured with `--subnet 192.168.10.0/24 --gateway 192.168.10.1 -o parent=eth0`. A common limitation to be aware of is:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag runs the container process as UID 1000 instead of root, overriding the image USER?$tv2$, $tv2$[{"id":"a","text":"--user 1000"},{"id":"b","text":"--uid 1000"},{"id":"c","text":"--as-user 1000"},{"id":"d","text":"--run-as 1000"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--user 1000` (or `--user 1000:1000`) sets the runtime UID/GID, overriding the Dockerfile `USER`. `--uid`/`--as-user`/`--run-as` are not valid flags.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag runs the container process as UID 1000 instead of root, overriding the image USER?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$When securing the Docker daemon TCP socket, which port and protection are conventional?$tv2$, $tv2$[{"id":"a","text":"Port 2375 with no TLS."},{"id":"b","text":"Port 2376 protected with TLS mutual authentication (client and server certificates)."},{"id":"c","text":"Port 22 over SSH only."},{"id":"d","text":"Port 80 with basic auth."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The convention is TLS-protected daemon access on port 2376 with mutual cert auth; port 2375 is the unencrypted (dangerous) port and should not be exposed. SSH/HTTP basic auth are not the Docker API transport.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$When securing the Docker daemon TCP socket, which port and protection are conventional?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command updates a swarm secret's usage by removing it from a service and adding a new version (since secret contents are immutable)?$tv2$, $tv2$[{"id":"a","text":"docker secret edit"},{"id":"b","text":"docker service update --secret-rm old --secret-add new"},{"id":"c","text":"docker secret rotate"},{"id":"d","text":"docker secret update --value"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Swarm secrets are immutable, so rotation is done by creating a new secret and using `docker service update --secret-rm <old> --secret-add <new>`. There is no `docker secret edit`/`rotate`/`update --value`.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command updates a swarm secret's usage by removing it from a service and adding a new version (since secret contents are immutable)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Anyone with access to the Docker daemon (Unix socket or unauthenticated TCP) can effectively obtain root on the host.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with --privileged"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. The Docker API is root-equivalent: a caller can run privileged containers and bind-mount the host filesystem, so daemon access must be tightly controlled (TLS, socket permissions).$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Anyone with access to the Docker daemon (Unix socket or unauthenticated TCP) can effectively obtain root on the host.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` option disables the default seccomp profile entirely (generally NOT recommended)?$tv2$, $tv2$[{"id":"a","text":"--security-opt seccomp=unconfined"},{"id":"b","text":"--no-seccomp"},{"id":"c","text":"--cap-drop seccomp"},{"id":"d","text":"--seccomp off"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--security-opt seccomp=unconfined` runs the container without syscall filtering; you can also point it at a custom JSON profile. It widens the attack surface and is discouraged. The other forms are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` option disables the default seccomp profile entirely (generally NOT recommended)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL controls that help limit the blast radius of a container compromise.$tv2$, $tv2$[{"id":"a","text":"Running the container as a non-root user."},{"id":"b","text":"Dropping unneeded Linux capabilities (--cap-drop)."},{"id":"c","text":"Enabling user-namespace remapping on the daemon."},{"id":"d","text":"Mounting the host Docker socket into the container."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Non-root users, dropped capabilities, and userns-remap all shrink what a compromised container can do. Mounting the Docker socket does the opposite — it grants root-equivalent host control.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL controls that help limit the blast radius of a container compromise.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all Docker-managed volumes on the host?$tv2$, $tv2$[{"id":"a","text":"docker volume ls"},{"id":"b","text":"docker volume list --all"},{"id":"c","text":"docker ls volumes"},{"id":"d","text":"docker storage ls"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker volume ls` lists volumes with their driver and name. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all Docker-managed volumes on the host?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why should images be pinned by digest (image@sha256:...) in security-sensitive deployments?$tv2$, $tv2$[{"id":"a","text":"Digests download faster than tags."},{"id":"b","text":"A digest is immutable content-addressable, so you always run exactly the verified bytes even if a tag is later re-pushed/poisoned."},{"id":"c","text":"Digests automatically scan for CVEs."},{"id":"d","text":"Digests bypass the registry login."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Tags are mutable and can be re-pointed; a digest guarantees the exact image content you reviewed/approved is what runs. It does not change download speed, scan for CVEs, or skip authentication.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why should images be pinned by digest (image@sha256:...) in security-sensitive deployments?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You append `:ro` to a volume mount, e.g. `-v data:/app/data:ro`. What does this do?$tv2$, $tv2$[{"id":"a","text":"Deletes the volume after the container stops."},{"id":"b","text":"Mounts the volume read-only inside the container so the process cannot modify it."},{"id":"c","text":"Makes the volume reside only in RAM."},{"id":"d","text":"Replicates the volume to other hosts."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `:ro` option mounts the volume read-only for that container (the default is `rw`). It does not delete, move to RAM, or replicate the volume.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You append `:ro` to a volume mount, e.g. `-v data:/app/data:ro`. What does this do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A bind mount can shadow (hide) files that exist at the same path inside the image.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for named volumes"},{"id":"d","text":"Only in swarm mode"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. A bind mount overlays the host path onto the target, hiding any image content previously at that path; unlike an empty named volume, a bind mount is never pre-populated from the image.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A bind mount can shadow (hide) files that exist at the same path inside the image.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A stateful database service in swarm uses a local named volume. When the task reschedules to a different node, the data is missing. What is the correct explanation/fix?$tv2$, $tv2$[{"id":"a","text":"Local volumes are automatically replicated; the issue must be a bug."},{"id":"b","text":"Local volumes are node-local and do not follow a rescheduled task; use a shared/clustered volume plugin (or pin the task to its node) for persistent stateful data."},{"id":"c","text":"Swarm never reschedules database tasks."},{"id":"d","text":"You must run docker volume prune to fix it."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A `local` volume only exists on the node it was created on, so a rescheduled task on another node sees an empty/new volume. Use a volume plugin backed by shared storage, or constrain the task to its node, for durable stateful workloads.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A stateful database service in swarm uses a local named volume. When the task reschedules to a different node, the data is missing. What is the correct explanation/fix?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command retrieves the worker join token needed to add a new worker node to an existing swarm?$tv2$, $tv2$[{"id":"a","text":"docker swarm join-token worker"},{"id":"b","text":"docker node token worker"},{"id":"c","text":"docker swarm token --worker"},{"id":"d","text":"docker swarm worker-token"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker swarm join-token worker` (run on a manager) prints the full `docker swarm join` command with the worker token. The other forms are not valid CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command retrieves the worker join token needed to add a new worker node to an existing swarm?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A 3-manager swarm loses 2 managers simultaneously. What is the cluster state?$tv2$, $tv2$[{"id":"a","text":"The swarm continues normally; 1 manager is enough."},{"id":"b","text":"The swarm loses quorum: existing tasks keep running but no new orchestration/scheduling decisions can be made until quorum is restored."},{"id":"c","text":"All running containers are immediately killed."},{"id":"d","text":"Worker nodes are automatically promoted to managers to restore quorum."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Quorum needs a majority (2 of 3). With only 1 manager left, the control plane is read-only for orchestration — running tasks continue, but scheduling/updates are blocked until quorum is recovered. Workers are not auto-promoted.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A 3-manager swarm loses 2 managers simultaneously. What is the cluster state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker service create` option restricts a service's tasks to run only on nodes labeled `region=eu`?$tv2$, $tv2$[{"id":"a","text":"--placement-pref region=eu"},{"id":"b","text":"--constraint node.labels.region==eu"},{"id":"c","text":"--filter region=eu"},{"id":"d","text":"--node-label region=eu"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--constraint node.labels.region==eu` is a hard placement constraint. `--placement-pref` only biases spread; the other flags are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker service create` option restricts a service's tasks to run only on nodes labeled `region=eu`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You update a swarm service image and want only one task replaced at a time, waiting 10s between batches. Which options configure this?$tv2$, $tv2$[{"id":"a","text":"--update-parallelism 1 --update-delay 10s"},{"id":"b","text":"--rolling 1 --pause 10s"},{"id":"c","text":"--batch-size 1 --batch-wait 10s"},{"id":"d","text":"--replicas 1 --delay 10s"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--update-parallelism` sets how many tasks update at once and `--update-delay` the wait between batches. The other flag names are not part of the Docker service update configuration.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You update a swarm service image and want only one task replaced at a time, waiting 10s between batches. Which options configure this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker on Kubernetes and orchestration choices.$tv2$, $tv2$[{"id":"a","text":"Docker Desktop can run a single-node Kubernetes cluster for local development."},{"id":"b","text":"A Docker Compose file can target either swarm (docker stack deploy) or be translated for other orchestrators."},{"id":"c","text":"Swarm mode is built into the Docker Engine and requires no separate installation."},{"id":"d","text":"Kubernetes and swarm cannot both be concepts you prepare for; only swarm exists in Docker."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Docker Desktop bundles an optional single-node Kubernetes; Compose files drive swarm stacks; swarm mode ships in the Engine. Option D is false — both Kubernetes and swarm orchestration are relevant.$tv2$, $tv2$[{"url":"https://docs.docker.com/desktop/features/kubernetes/","label":"Docker Docs — Deploy on Kubernetes"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"},{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker on Kubernetes and orchestration choices.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command builds an image from the current directory and tags it `myapp:2.0`?$tv2$, $tv2$[{"id":"a","text":"docker build -t myapp:2.0 ."},{"id":"b","text":"docker image new myapp:2.0 ."},{"id":"c","text":"docker create -t myapp:2.0 ."},{"id":"d","text":"docker compile myapp:2.0 ."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker build -t name:tag <context>` builds and tags an image. `docker create` makes a container from an existing image; the other commands do not exist.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command builds an image from the current directory and tags it `myapp:2.0`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What is the purpose of a `.dockerignore` file?$tv2$, $tv2$[{"id":"a","text":"It lists Dockerfile instructions to skip."},{"id":"b","text":"It excludes files/directories from the build context sent to the daemon, speeding builds and avoiding leaking secrets."},{"id":"c","text":"It marks layers as cacheable."},{"id":"d","text":"It tells the registry which tags to ignore."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`.dockerignore` prunes the build context (e.g. .git, node_modules, secrets) before it is sent to the daemon. It has nothing to do with skipping instructions, caching, or registry tags.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the purpose of a `.dockerignore` file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Dockerfile best practices.$tv2$, $tv2$[{"id":"a","text":"Order instructions so that frequently changing layers (e.g. app source) come after stable ones (e.g. dependency install) to maximize cache reuse."},{"id":"b","text":"Prefer a minimal base image to reduce size and attack surface."},{"id":"c","text":"Use multi-stage builds to keep build-only tooling out of the final image."},{"id":"d","text":"Always run the application as root for compatibility."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Layer ordering for cache, minimal bases, and multi-stage builds are recommended. Running as root is discouraged — prefer a dedicated non-root USER.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Dockerfile best practices.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Difference between `ENTRYPOINT ["app"]` and `CMD ["app"]` when the user runs `docker run image arg1`?$tv2$, $tv2$[{"id":"a","text":"Both are completely replaced by arg1."},{"id":"b","text":"With ENTRYPOINT, arg1 is appended as an argument to app; with CMD, arg1 replaces the command entirely."},{"id":"c","text":"CMD runs at build time; ENTRYPOINT at run time."},{"id":"d","text":"There is no functional difference."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Run-time arguments are appended to an exec-form ENTRYPOINT but override CMD. A common pattern is ENTRYPOINT for the binary and CMD for default args. Neither runs at build time (that is RUN).$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Difference between `ENTRYPOINT ["app"]` and `CMD ["app"]` when the user runs `docker run image arg1`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json key configures the daemon to listen on a TCP socket in addition to the default Unix socket?$tv2$, $tv2$[{"id":"a","text":"\"hosts\": [\"unix:///var/run/docker.sock\", \"tcp://0.0.0.0:2376\"]"},{"id":"b","text":"\"listen\": \"tcp://0.0.0.0:2376\""},{"id":"c","text":"\"bind\": \"0.0.0.0:2376\""},{"id":"d","text":"\"api-port\": 2376"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `hosts` array sets the sockets dockerd listens on. Exposing TCP should be paired with TLS (port 2376). The other keys are not valid daemon options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json key configures the daemon to listen on a TCP socket in addition to the default Unix socket?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command would you use to reclaim disk by removing stopped containers, unused networks, dangling images, and build cache?$tv2$, $tv2$[{"id":"a","text":"docker system prune"},{"id":"b","text":"docker clean --all"},{"id":"c","text":"docker gc"},{"id":"d","text":"docker rmi --unused"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker system prune` removes stopped containers, unused networks, dangling images, and build cache (add `-a`/`--volumes` for more). The other commands are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command would you use to reclaim disk by removing stopped containers, unused networks, dangling images, and build cache?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You set `"live-restore": true` in daemon.json. What does this enable?$tv2$, $tv2$[{"id":"a","text":"Containers keep running while the Docker daemon is down (e.g. during a daemon upgrade/restart)."},{"id":"b","text":"Automatic restart of the daemon if it crashes."},{"id":"c","text":"Live migration of containers between hosts."},{"id":"d","text":"Real-time replication of volumes."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$live-restore keeps containers running during daemon downtime/upgrades. It is not crash auto-restart, container live migration, or volume replication.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You set `"live-restore": true` in daemon.json. What does this enable?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You run `docker run -d -p 127.0.0.1:8080:80 nginx`. Who can reach the web server?$tv2$, $tv2$[{"id":"a","text":"Anyone on the network via the host's external IP on port 8080."},{"id":"b","text":"Only clients on the host itself (loopback), since the publish is bound to 127.0.0.1."},{"id":"c","text":"Only other containers on the bridge network."},{"id":"d","text":"No one — binding to 127.0.0.1 disables the port."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Specifying `127.0.0.1:8080:80` binds the published port to the host loopback only, so remote hosts cannot reach it — useful for restricting exposure. Containers on the bridge reach nginx by its container IP regardless.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You run `docker run -d -p 127.0.0.1:8080:80 nginx`. Who can reach the web server?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Containers attached to the default (legacy) bridge network get automatic DNS-based name resolution between each other just like on user-defined bridge networks.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --link"},{"id":"d","text":"Only in swarm mode"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. The default `bridge` network does NOT provide automatic container name resolution; only user-defined networks include the embedded DNS server. The legacy `--link` flag was the old workaround on the default bridge.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Containers attached to the default (legacy) bridge network get automatic DNS-based name resolution between each other just like on user-defined bridge networks.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$In swarm mode, what is the `ingress` network used for?$tv2$, $tv2$[{"id":"a","text":"It is a user-defined overlay you must create before deploying any service."},{"id":"b","text":"It is a special built-in overlay network that carries the routing-mesh traffic for services that publish ports."},{"id":"c","text":"It connects manager nodes' Raft traffic."},{"id":"d","text":"It is the default bridge each swarm node uses for local containers."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `ingress` overlay is created automatically with the swarm and handles routing-mesh load-balanced traffic for published service ports. Raft control traffic and the local default bridge are separate.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In swarm mode, what is the `ingress` network used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why is exposing the Docker daemon on an unauthenticated TCP socket (e.g. tcp://0.0.0.0:2375) dangerous?$tv2$, $tv2$[{"id":"a","text":"It only slows down image pulls."},{"id":"b","text":"Anyone who can reach the socket can run containers and effectively gain root on the host."},{"id":"c","text":"It disables container logging."},{"id":"d","text":"It prevents the use of volumes."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The Docker API is root-equivalent: full access to the daemon allows running privileged containers and mounting the host filesystem. Always require TLS/mutual auth (port 2376) or keep it on the Unix socket.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is exposing the Docker daemon on an unauthenticated TCP socket (e.g. tcp://0.0.0.0:2375) dangerous?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction helps reduce risk by ensuring the container process does not run as root?$tv2$, $tv2$[{"id":"a","text":"PRIVILEGE none"},{"id":"b","text":"USER appuser"},{"id":"c","text":"ROOT off"},{"id":"d","text":"SECURITY nonroot"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `USER` instruction sets the UID/username the container runs as, enabling least-privilege non-root execution. The other instructions do not exist.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction helps reduce risk by ensuring the container process does not run as root?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Image vulnerability scanning (e.g. docker scout) primarily helps you to:$tv2$, $tv2$[{"id":"a","text":"Sign images so only trusted ones run."},{"id":"b","text":"Identify known CVEs in the packages and base layers of an image so you can remediate them."},{"id":"c","text":"Restrict syscalls available to the container."},{"id":"d","text":"Remap container UIDs to the host."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Scanning surfaces known vulnerabilities (CVEs) in image contents so you can patch/upgrade. Signing is content trust, syscall restriction is seccomp, and UID remap is userns — different controls.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Image vulnerability scanning (e.g. docker scout) primarily helps you to:$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which docker run syntax mounts the named volume `data` at `/var/lib/app` inside the container?$tv2$, $tv2$[{"id":"a","text":"docker run -v data:/var/lib/app myimg"},{"id":"b","text":"docker run --mount /var/lib/app=data myimg"},{"id":"c","text":"docker run --volume=/data myimg"},{"id":"d","text":"docker run -p data:/var/lib/app myimg"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`-v <volumename>:<container-path>` mounts a named volume (equivalently `--mount type=volume,source=data,target=/var/lib/app`). `-p` publishes ports, not volumes; the other forms are malformed.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which docker run syntax mounts the named volume `data` at `/var/lib/app` inside the container?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A copy-on-write storage driver like overlay2 affects container write performance how?$tv2$, $tv2$[{"id":"a","text":"All writes are blocked unless a volume is attached."},{"id":"b","text":"The first modification of a file from a lower image layer triggers a copy-up into the container layer, adding overhead for write-heavy workloads."},{"id":"c","text":"Writes are faster than a bind mount in every case."},{"id":"d","text":"It stores writes directly back into the image layers."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Copy-on-write copies a file up from the image layers to the writable layer on first modification, which is costly for write-heavy or large-file workloads — hence using volumes/bind mounts for such data. Image layers themselves remain read-only.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A copy-on-write storage driver like overlay2 affects container write performance how?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command retrieves the manager join token for adding another manager to an existing swarm?$tv2$, $tv2$[{"id":"a","text":"docker swarm join-token manager"},{"id":"b","text":"docker node token manager"},{"id":"c","text":"docker swarm manager-token"},{"id":"d","text":"docker swarm token --manager"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker swarm join-token manager` (run on a manager) prints the full join command with the manager token. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command retrieves the manager join token for adding another manager to an existing swarm?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does `docker service inspect --pretty web` provide?$tv2$, $tv2$[{"id":"a","text":"Only the container logs."},{"id":"b","text":"A human-readable summary of the service spec: image, mode, replicas, networks, update config, etc."},{"id":"c","text":"The Raft store contents."},{"id":"d","text":"The Dockerfile used to build the image."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`docker service inspect --pretty` formats the service definition (image, replicas/mode, ports, update policy) for humans; without `--pretty` it returns JSON. It does not expose logs, the Raft store, or the Dockerfile.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `docker service inspect --pretty web` provide?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which option on `docker service update` adds a published port to an existing service?$tv2$, $tv2$[{"id":"a","text":"--port-add 8080:80"},{"id":"b","text":"--publish-add 8080:80"},{"id":"c","text":"--expose-add 8080:80"},{"id":"d","text":"--add-port 8080:80"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Service updates use `--publish-add`/`--publish-rm` to change published ports (mirrored by `--env-add`, `--mount-add`, etc.). `--port-add`/`--expose-add`/`--add-port` are not valid options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which option on `docker service update` adds a published port to an existing service?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want at most one replica of a service per node (spread it out) without forcing global mode. Which placement option helps?$tv2$, $tv2$[{"id":"a","text":"--replicas-max-per-node 1"},{"id":"b","text":"--placement-pref spread=node.id"},{"id":"c","text":"--constraint node.role==worker"},{"id":"d","text":"--mode global only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--replicas-max-per-node 1` caps how many tasks of the service may run on a single node, spreading replicas without using global mode. `--placement-pref spread` biases distribution but does not hard-cap per node; a role constraint just filters nodes.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want at most one replica of a service per node (spread it out) without forcing global mode. Which placement option helps?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists the stacks currently deployed to the swarm?$tv2$, $tv2$[{"id":"a","text":"docker stack ls"},{"id":"b","text":"docker stack list --all"},{"id":"c","text":"docker swarm stacks"},{"id":"d","text":"docker service stacks"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker stack ls` lists deployed stacks and their service counts. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists the stacks currently deployed to the swarm?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about swarm certificates and security.$tv2$, $tv2$[{"id":"a","text":"Swarm uses mutual TLS between nodes for control-plane communication."},{"id":"b","text":"Manager and worker join tokens differ and can be rotated independently."},{"id":"c","text":"The CA certificate expiry/rotation interval can be configured with docker swarm update --cert-expiry."},{"id":"d","text":"Swarm sends all node traffic in plaintext by default."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Swarm auto-provisions a CA and uses mutual TLS; tokens are role-specific and rotatable; `--cert-expiry` tunes certificate rotation. Control-plane traffic is encrypted by default, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about swarm certificates and security.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A swarm service uses `--restart-condition on-failure`. What does this mean for its tasks?$tv2$, $tv2$[{"id":"a","text":"Tasks are restarted only when they exit with a non-zero status."},{"id":"b","text":"Tasks never restart."},{"id":"c","text":"Tasks restart even on a clean (zero) exit."},{"id":"d","text":"Tasks restart only when the node reboots."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`on-failure` restarts a task only on non-zero exit; `any` (the default) restarts regardless of exit code, and `none` never restarts. It is independent of node reboots.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A swarm service uses `--restart-condition on-failure`. What does this mean for its tasks?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: In a swarm, manager nodes can also run service tasks (act as workers) by default.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only if drained"},{"id":"d","text":"Only single-node swarms"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. By default managers also schedule and run tasks; you can set a manager to `Drain` availability if you want it to handle orchestration only and not run workloads.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: In a swarm, manager nodes can also run service tasks (act as workers) by default.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How do swarm configs differ from swarm secrets?$tv2$, $tv2$[{"id":"a","text":"Configs are encrypted at rest in Raft and mounted at /run/secrets; secrets are plaintext."},{"id":"b","text":"Configs are for non-sensitive data and are not encrypted at rest the way secrets are; secrets are encrypted in the Raft log and intended for sensitive values."},{"id":"c","text":"They are identical features with different names."},{"id":"d","text":"Configs can only hold binary data; secrets only text."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Secrets are encrypted in the Raft store and mounted at `/run/secrets` for sensitive data; configs deliver non-sensitive configuration files and are not given the same at-rest encryption guarantees. Both can hold text or binary.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/configs/","label":"Docker Docs — Store configuration data using configs"},{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How do swarm configs differ from swarm secrets?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$After losing quorum (most managers gone) and being unable to recover them, which command can force a single surviving manager to form a new single-manager cluster from the existing Raft state?$tv2$, $tv2$[{"id":"a","text":"docker swarm init --force-new-cluster"},{"id":"b","text":"docker swarm recover"},{"id":"c","text":"docker node promote --force"},{"id":"d","text":"docker swarm join --rebuild"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker swarm init --force-new-cluster` (run on a surviving manager) reinitializes the swarm from the local Raft data with a single manager, after which you re-add managers/workers. The other commands are not valid recovery operations.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After losing quorum (most managers gone) and being unable to recover them, which command can force a single surviving manager to form a new single-manager cluster from the existing Raft state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Orchestration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes the swarm service `web` and stops all of its tasks?$tv2$, $tv2$[{"id":"a","text":"docker service rm web"},{"id":"b","text":"docker service stop web"},{"id":"c","text":"docker service delete web"},{"id":"d","text":"docker swarm rm web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker service rm web` removes the service and terminates its tasks (there is no `docker service stop`/`delete`). `docker swarm rm` is not a valid subcommand.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes the swarm service `web` and stops all of its tasks?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Dockerfile instruction adds key/value metadata (e.g. maintainer, version) to the image?$tv2$, $tv2$[{"id":"a","text":"META"},{"id":"b","text":"LABEL"},{"id":"c","text":"TAG"},{"id":"d","text":"ANNOTATE"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`LABEL key=value` attaches metadata visible via `docker inspect`/`docker image inspect`. `MAINTAINER` is deprecated in favor of LABEL; `META`/`TAG`/`ANNOTATE` are not Dockerfile instructions.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Dockerfile instruction adds key/value metadata (e.g. maintainer, version) to the image?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a build to fail if a required build argument is not provided. Which Dockerfile pattern enforces this?$tv2$, $tv2$[{"id":"a","text":"Declare ARG REQUIRED and reference ${REQUIRED:?error message} in a RUN step."},{"id":"b","text":"Use CMD to validate it."},{"id":"c","text":"Add VALIDATE ARG to the Dockerfile."},{"id":"d","text":"It is impossible; args are always optional."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Declaring the `ARG` and using a shell parameter expansion like `${REQUIRED:?msg}` in a RUN causes the build to error if it is empty/unset. CMD runs at container start, not build; `VALIDATE ARG` is not an instruction.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a build to fail if a required build argument is not provided. Which Dockerfile pattern enforces this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes the local image `myapp:1.0`?$tv2$, $tv2$[{"id":"a","text":"docker rmi myapp:1.0 (or docker image rm myapp:1.0)"},{"id":"b","text":"docker image delete myapp:1.0"},{"id":"c","text":"docker rm -i myapp:1.0"},{"id":"d","text":"docker prune myapp:1.0"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker rmi` / `docker image rm` deletes an image (use `-f` if it is tagged multiple times or in use). `docker rm` removes containers; the other forms are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes the local image `myapp:1.0`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In `COPY --from=builder /app/bin /usr/local/bin/`, what does `--from=builder` reference?$tv2$, $tv2$[{"id":"a","text":"A remote registry named builder."},{"id":"b","text":"A previous build stage named builder, so artifacts are copied from that stage into the current one."},{"id":"c","text":"A volume called builder."},{"id":"d","text":"The host filesystem path /builder."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`--from=<stage>` (or `--from=<image>`) copies files from an earlier multi-stage build stage (here `builder`) into the current stage — the core mechanism of multi-stage builds. It is not a registry, volume, or host path.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `COPY --from=builder /app/bin /usr/local/bin/`, what does `--from=builder` reference?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about image tags and the `latest` tag.$tv2$, $tv2$[{"id":"a","text":"latest is just a conventional default tag, not automatically the newest build."},{"id":"b","text":"Pulling an image without a tag defaults to the latest tag."},{"id":"c","text":"A tag can be re-pointed to a different image by tagging/pushing again."},{"id":"d","text":"latest always guarantees the most recently built version of an image."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$`latest` is only the default tag name with no recency guarantee; an untagged pull uses `:latest`; tags are mutable pointers. Therefore D is false — `latest` does not guarantee the newest build.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about image tags and the `latest` tag.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A private registry returns "no basic auth credentials" on push. What is the most likely fix?$tv2$, $tv2$[{"id":"a","text":"Rebuild the image with --no-cache."},{"id":"b","text":"Run docker login <registry> to authenticate before pushing."},{"id":"c","text":"Add the image to .dockerignore."},{"id":"d","text":"Enable Docker Content Trust."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$That error means the CLI has no stored credentials for the registry; `docker login <registry>` authenticates and stores them so the push is authorized. Rebuilding, .dockerignore, and content trust are unrelated to the auth failure.$tv2$, $tv2$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A private registry returns "no basic auth credentials" on push. What is the most likely fix?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why is the order of Dockerfile instructions important for build speed?$tv2$, $tv2$[{"id":"a","text":"Docker runs later instructions first."},{"id":"b","text":"A change to an instruction invalidates the cache for it and all subsequent layers, so put rarely changing steps (e.g. dependency install) before frequently changing ones (e.g. COPY source)."},{"id":"c","text":"Order has no effect on caching."},{"id":"d","text":"Only the FROM line affects caching."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The build cache is sequential: once a layer changes, every following layer is rebuilt. Placing stable steps early (and volatile COPY of source late) maximizes cache hits and speeds rebuilds.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is the order of Dockerfile instructions important for build speed?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: `docker commit` creates a new image from the current state of a running or stopped container.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for paused containers"},{"id":"d","text":"Only in swarm mode"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. `docker commit <container> <image>` snapshots a container's filesystem into a new image, though building from a Dockerfile is preferred for reproducibility.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: `docker commit` creates a new image from the current state of a running or stopped container.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Image Creation, Management, and Registry$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want to keep the build cache reusable across CI runners that do not share local storage. Which BuildKit feature helps?$tv2$, $tv2$[{"id":"a","text":"Registry-backed build cache via --cache-to/--cache-from with buildx."},{"id":"b","text":"The .dockerignore file."},{"id":"c","text":"Docker Content Trust."},{"id":"d","text":"The HEALTHCHECK instruction."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$BuildKit/buildx can export and import the build cache to/from a registry (`--cache-to`, `--cache-from`), letting ephemeral CI runners share cache. .dockerignore, content trust, and HEALTHCHECK do not address cache portability.$tv2$, $tv2$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to keep the build cache reusable across CI runners that do not share local storage. Which BuildKit feature helps?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which daemon.json key configures a list of DNS servers given to containers by default?$tv2$, $tv2$[{"id":"a","text":"\"dns\": [\"8.8.8.8\", \"1.1.1.1\"]"},{"id":"b","text":"\"resolvers\": [\"8.8.8.8\"]"},{"id":"c","text":"\"nameservers\": [\"8.8.8.8\"]"},{"id":"d","text":"\"dns-config\": \"8.8.8.8\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `dns` array sets the default DNS servers placed in containers' resolv.conf (overridable per-container with `--dns`). The other keys are not valid daemon options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which daemon.json key configures a list of DNS servers given to containers by default?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command removes ALL stopped containers in one step?$tv2$, $tv2$[{"id":"a","text":"docker container prune"},{"id":"b","text":"docker rm --all-stopped"},{"id":"c","text":"docker clean containers"},{"id":"d","text":"docker container gc"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker container prune` deletes all stopped containers (with a confirmation prompt unless `-f`). The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command removes ALL stopped containers in one step?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to limit a single container to 512 MB of memory and 50% of one CPU. Which docker run flags apply?$tv2$, $tv2$[{"id":"a","text":"--memory 512m --cpus 0.5"},{"id":"b","text":"--mem 512 --cpu 50"},{"id":"c","text":"--ram 512m --cpu-limit 0.5"},{"id":"d","text":"--limit-mem 512m --limit-cpu 0.5"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--memory 512m` sets the hard memory limit and `--cpus 0.5` caps CPU to half a core for a standalone container. The other flag names are not valid Docker run options.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to limit a single container to 512 MB of memory and 50% of one CPU. Which docker run flags apply?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command opens an interactive shell inside an already-running container `web`?$tv2$, $tv2$[{"id":"a","text":"docker exec -it web /bin/sh"},{"id":"b","text":"docker run -it web /bin/sh"},{"id":"c","text":"docker attach web sh"},{"id":"d","text":"docker shell web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker exec -it web /bin/sh` starts a new interactive process in the running container. `docker run` would start a *new* container; `docker attach` connects to the main process stdio, not a new shell; `docker shell` is not a command.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command opens an interactive shell inside an already-running container `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the low-level JSON configuration and state of a container `web`?$tv2$, $tv2$[{"id":"a","text":"docker inspect web"},{"id":"b","text":"docker container info web"},{"id":"c","text":"docker show web"},{"id":"d","text":"docker describe web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker inspect web` returns detailed JSON (config, mounts, networks, state). The other commands are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the low-level JSON configuration and state of a container `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker installation and the daemon on Linux.$tv2$, $tv2$[{"id":"a","text":"dockerd is the daemon and the docker CLI is a separate client that talks to it over a socket."},{"id":"b","text":"On systemd hosts the service is typically managed via systemctl (start/stop/enable docker)."},{"id":"c","text":"daemon.json changes generally require a daemon restart (or reload) to take effect."},{"id":"d","text":"The docker CLI must run on the same host as dockerd and cannot be remote."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$The CLI is a client to `dockerd` over a socket, managed by systemd, and config changes need a restart/reload. The CLI can target a remote daemon (e.g. via TLS TCP or contexts), so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker installation and the daemon on Linux.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Installation and Configuration$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want to switch the docker CLI between multiple daemons (local, remote TLS) without changing env vars each time. Which feature is intended for this?$tv2$, $tv2$[{"id":"a","text":"docker context (docker context create/use)"},{"id":"b","text":"docker profile"},{"id":"c","text":"daemon.json aliases"},{"id":"d","text":"docker daemon switch"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Docker contexts store endpoint/TLS settings per environment so `docker context use <name>` switches the active daemon target. `docker profile`/`docker daemon switch` and daemon.json aliases do not exist.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to switch the docker CLI between multiple daemons (local, remote TLS) without changing env vars each time. Which feature is intended for this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the public-facing host port mappings of a running container `web`?$tv2$, $tv2$[{"id":"a","text":"docker port web"},{"id":"b","text":"docker network port web"},{"id":"c","text":"docker inspect --ports web"},{"id":"d","text":"docker ps --ports web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker port web` lists the container-to-host port mappings. `docker ps` shows ports in a column but `docker port` is the dedicated command; the other forms are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the public-facing host port mappings of a running container `web`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Why is the default `bridge` network generally discouraged for multi-container apps in favor of a user-defined bridge?$tv2$, $tv2$[{"id":"a","text":"The default bridge is slower hardware."},{"id":"b","text":"User-defined bridges add automatic DNS-based service discovery and better isolation; the default bridge requires legacy --link and shares all containers."},{"id":"c","text":"The default bridge cannot reach the internet."},{"id":"d","text":"User-defined bridges are required for single containers."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$User-defined bridges provide embedded DNS (resolve by container name) and segment containers; the legacy default bridge lacks automatic name resolution and groups every container together. Both have internet access via NAT.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is the default `bridge` network generally discouraged for multi-container apps in favor of a user-defined bridge?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` option disconnects a container from networking entirely?$tv2$, $tv2$[{"id":"a","text":"--network none"},{"id":"b","text":"--no-net"},{"id":"c","text":"--network disabled"},{"id":"d","text":"--isolate-net"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--network none` attaches the container to the `none` network so it has only loopback. `--no-net`/`--network disabled`/`--isolate-net` are not valid options.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` option disconnects a container from networking entirely?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You created an overlay network but a standalone (non-service) container cannot attach to it. What likely needs to change?$tv2$, $tv2$[{"id":"a","text":"Overlay networks never allow containers."},{"id":"b","text":"Recreate the overlay network with the --attachable flag so standalone containers may join it."},{"id":"c","text":"Switch the container to host networking."},{"id":"d","text":"Disable the routing mesh."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$By default swarm overlay networks only accept service tasks; creating them with `--attachable` lets standalone containers connect too. Host networking and disabling the mesh do not address attachability.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You created an overlay network but a standalone (non-service) container cannot attach to it. What likely needs to change?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about publishing ports.$tv2$, $tv2$[{"id":"a","text":"-p 8080:80 maps host 8080 to container 80 on all host interfaces by default."},{"id":"b","text":"-p 127.0.0.1:8080:80 restricts the published port to the host loopback only."},{"id":"c","text":"-p 80 (single value) lets Docker pick a random host port for container port 80."},{"id":"d","text":"EXPOSE in a Dockerfile publishes the port to the host automatically."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Port publishing supports all-interface, loopback-bound, and ephemeral host-port forms. `EXPOSE` only documents the port — it does not publish it; you still need `-p`/`-P`, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about publishing ports.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In swarm, a service's default endpoint mode is `vip`. What does that mean for clients resolving the service name?$tv2$, $tv2$[{"id":"a","text":"Each task IP is returned directly in round-robin."},{"id":"b","text":"The service name resolves to a single stable virtual IP; the swarm load-balances connections across healthy tasks behind it."},{"id":"c","text":"Clients must use the node IPs directly."},{"id":"d","text":"The service is unreachable until you set dnsrr."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$In `vip` mode the service name resolves to one virtual IP and swarm internally load-balances to tasks. `dnsrr` mode instead returns the individual task IPs for client-side balancing.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In swarm, a service's default endpoint mode is `vip`. What does that mean for clients resolving the service name?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Networking$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Containers on different user-defined bridge networks on the same host cannot reach each other by default. How can you let a specific container reach both?$tv2$, $tv2$[{"id":"a","text":"It is impossible without host networking."},{"id":"b","text":"Attach that container to both networks with docker network connect (multi-homing)."},{"id":"c","text":"Delete one of the networks."},{"id":"d","text":"Publish every container port with -p."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$User-defined bridge networks are isolated from each other; connecting a container to multiple networks (`docker network connect`) lets it communicate on both. Host networking or publishing ports are broader/less precise and not required.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Containers on different user-defined bridge networks on the same host cannot reach each other by default. How can you let a specific container reach both?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which `docker run` flag adds a single Linux capability (e.g. NET_ADMIN) without granting all of them?$tv2$, $tv2$[{"id":"a","text":"--cap-add NET_ADMIN"},{"id":"b","text":"--privileged NET_ADMIN"},{"id":"c","text":"--add-capability NET_ADMIN"},{"id":"d","text":"--cap NET_ADMIN=on"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`--cap-add NET_ADMIN` grants just that capability on top of the default set (often paired with `--cap-drop ALL`). `--privileged` grants everything; the other flags are not valid.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `docker run` flag adds a single Linux capability (e.g. NET_ADMIN) without granting all of them?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement about the default Docker seccomp profile is correct?$tv2$, $tv2$[{"id":"a","text":"It blocks all syscalls, breaking most containers."},{"id":"b","text":"It allows the common syscalls applications need while blocking a set of dangerous ones (e.g. certain kernel/keyring/clock operations)."},{"id":"c","text":"It only applies to privileged containers."},{"id":"d","text":"It encrypts syscall arguments."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Docker's default seccomp profile is a permissive allowlist that still blocks roughly several dozen dangerous syscalls. It applies to normal containers (a `--privileged` container effectively runs unconfined) and does not encrypt anything.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement about the default Docker seccomp profile is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A container only needs to read configuration from a host directory. Which mount option follows least privilege?$tv2$, $tv2$[{"id":"a","text":"Mount it read-write so the app can also update it."},{"id":"b","text":"Mount it read-only, e.g. -v /etc/app:/etc/app:ro, so a compromised container cannot modify host config."},{"id":"c","text":"Use --privileged so it has full access."},{"id":"d","text":"Bake the config into the image instead of mounting."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A read-only bind mount (`:ro`) grants exactly the needed read access and prevents tampering with host files — a least-privilege choice. Read-write or `--privileged` grants more than required.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A container only needs to read configuration from a host directory. Which mount option follows least privilege?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Running a container with --privileged is recommended as a default for convenience.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for databases"},{"id":"d","text":"Only on managers"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. `--privileged` disables most isolation (all capabilities, device access, relaxed seccomp/AppArmor) and should be avoided unless a specific workload truly requires it.$tv2$, $tv2$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Running a container with --privileged is recommended as a default for convenience.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How does enabling userns-remap interact with bind mounts/volumes you previously created as host root?$tv2$, $tv2$[{"id":"a","text":"Nothing changes; permissions are irrelevant."},{"id":"b","text":"Because container UIDs are remapped to a high host UID range, existing root-owned host files may become inaccessible until ownership is adjusted for the remapped range."},{"id":"c","text":"It deletes the existing data."},{"id":"d","text":"It automatically chowns all host paths to the container user."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$userns-remap shifts in-container UIDs to a subordinate host UID range, so files owned by host root may no longer be writable/readable by the remapped container user — a known operational caveat to plan for. Docker does not auto-chown or delete data.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How does enabling userns-remap interact with bind mounts/volumes you previously created as host root?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Docker daemon attack surface.$tv2$, $tv2$[{"id":"a","text":"Exposing the daemon on tcp://0.0.0.0:2375 with no TLS allows remote root-equivalent control."},{"id":"b","text":"TLS mutual authentication should protect any TCP-exposed daemon (port 2376)."},{"id":"c","text":"Unix socket access (or docker group membership) is effectively root on the host."},{"id":"d","text":"The Docker API enforces per-command Linux user permissions automatically."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$An unauthenticated TCP daemon, socket access, and docker-group membership are all root-equivalent; TCP exposure must use mutual TLS on 2376. The API does not apply OS-user-level authorization per command, so D is false.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Docker daemon attack surface.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does `docker scout cves <image>` (or an equivalent scanner) report?$tv2$, $tv2$[{"id":"a","text":"Whether the image is digitally signed."},{"id":"b","text":"Known CVE vulnerabilities found in the image's OS packages and language dependencies, so you can remediate them."},{"id":"c","text":"The container's live syscall activity."},{"id":"d","text":"The swarm Raft health."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Image scanning enumerates known CVEs in the image contents to drive patching/upgrades. Signing is content trust, syscall monitoring is runtime tooling/seccomp, and Raft health is a swarm concern — all distinct.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `docker scout cves <image>` (or an equivalent scanner) report?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows detailed information about the volume `dbdata`, including its mountpoint on the host?$tv2$, $tv2$[{"id":"a","text":"docker volume inspect dbdata"},{"id":"b","text":"docker volume show dbdata"},{"id":"c","text":"docker inspect volume dbdata"},{"id":"d","text":"docker volume detail dbdata"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`docker volume inspect dbdata` returns the driver, labels, and host `Mountpoint`. The other forms are not valid Docker CLI syntax.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows detailed information about the volume `dbdata`, including its mountpoint on the host?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which approach reliably backs up the data in a named volume `dbdata`?$tv2$, $tv2$[{"id":"a","text":"Copy /var/lib/docker directly while the daemon runs."},{"id":"b","text":"Run a helper container that mounts the volume and tars its contents to a bind-mounted host path (docker run --rm -v dbdata:/data -v $PWD:/backup ... tar ...)."},{"id":"c","text":"Use docker commit on the volume."},{"id":"d","text":"docker volume export dbdata > backup.tar"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The supported pattern is a throwaway container that mounts the volume and the backup destination and archives the data; this works across drivers. Touching `/var/lib/docker` live is unsafe, `docker commit` snapshots containers not volumes, and `docker volume export` is not a command.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which approach reliably backs up the data in a named volume `dbdata`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Anonymous volumes (created when no name is given, e.g. -v /data) can be removed by docker volume prune once no container references them.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only named volumes can be pruned"},{"id":"d","text":"Volumes can never be pruned"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Anonymous (and unused named) volumes not referenced by any container are removed by `docker volume prune`; this is why important data should use clearly named volumes and be backed up.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Anonymous volumes (created when no name is given, e.g. -v /data) can be removed by docker volume prune once no container references them.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Storage and Volumes$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement best describes the relationship between storage drivers (overlay2) and volumes?$tv2$, $tv2$[{"id":"a","text":"Volumes use the storage driver's copy-on-write for all writes."},{"id":"b","text":"The storage driver manages the image/container layered filesystem (copy-on-write), while volumes bypass it to give better, persistent I/O for application data."},{"id":"c","text":"They are the same subsystem."},{"id":"d","text":"Volumes only work with the vfs driver."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The storage driver (e.g. overlay2) handles the layered, copy-on-write container filesystem; volumes write outside that layer for persistence and to avoid copy-up overhead — recommended for databases and write-heavy data. Volumes work regardless of the storage driver.$tv2$, $tv2$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:dca-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$docker-dca-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement best describes the relationship between storage drivers (overlay2) and volumes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which Git command creates a local copy of a remote repository, including its full history and working tree?$tv2$, $tv2$[{"id":"a","text":"git pull"},{"id":"b","text":"git clone <url>"},{"id":"c","text":"git fetch <url>"},{"id":"d","text":"git init <url>"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git clone <url>` downloads the entire repository, history, and checks out the default branch. `git pull` updates an existing clone, `git fetch` only downloads objects/refs without merging, and `git init` creates a new empty repo (it takes a directory, not a URL).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Git command creates a local copy of a remote repository, including its full history and working tree?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You modified three tracked files but want to commit only one of them. Which sequence stages just `app.py` and records the commit?$tv2$, $tv2$[{"id":"a","text":"git commit app.py -m \"fix\""},{"id":"b","text":"git add app.py && git commit -m \"fix\""},{"id":"c","text":"git stage --all && git commit -m \"fix\""},{"id":"d","text":"git commit -a -m \"fix\""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git add app.py` stages only that file, then `git commit -m` records the staged snapshot. `git commit -a` would commit all modified tracked files, and `git stage --all` stages everything.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You modified three tracked files but want to commit only one of them. Which sequence stages just `app.py` and records the commit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You have uncommitted local changes but need to switch branches quickly without committing. Which command shelves the changes for later restoration?$tv2$, $tv2$[{"id":"a","text":"git reset --hard"},{"id":"b","text":"git stash"},{"id":"c","text":"git checkout -- ."},{"id":"d","text":"git clean -fd"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git stash` saves modified tracked files and staged changes to a stack, restoring a clean working tree; `git stash pop` reapplies them. `git reset --hard` and `git checkout -- .` discard changes permanently, and `git clean -fd` deletes untracked files.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You have uncommitted local changes but need to switch branches quickly without committing. Which command shelves the changes for later restoration?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: `git rebase` rewrites commit history by reapplying commits onto a new base, which can change commit SHAs.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Rebasing replays a branch's commits onto a different base commit, producing new commit objects with new SHAs. This is why rebasing shared/published branches is discouraged — it diverges history for collaborators.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: `git rebase` rewrites commit history by reapplying commits onto a new base, which can change commit SHAs.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In GitLab Flow, what is the recommended relationship between feature branches and the main branch?$tv2$, $tv2$[{"id":"a","text":"Feature branches are created from main and merged back via merge request after review."},{"id":"b","text":"Feature branches are committed to directly on production servers."},{"id":"c","text":"Feature work is committed straight to main without branches."},{"id":"d","text":"Each developer maintains a permanent personal copy of main that is never merged."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab Flow uses short-lived feature branches branched off main, integrated back through merge requests after review and CI. Committing directly to main or to production bypasses review and pipeline validation.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In GitLab Flow, what is the recommended relationship between feature branches and the main branch?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A protected branch in GitLab, by default, prevents which action for users below the configured push role?$tv2$, $tv2$[{"id":"a","text":"Viewing the branch in the repository"},{"id":"b","text":"Pushing commits directly and force-pushing to that branch"},{"id":"c","text":"Creating issues that reference the branch"},{"id":"d","text":"Cloning the repository"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Protected branches restrict who can push and merge, and block force pushes by default, so changes must flow through merge requests. They do not affect read access, cloning, or issue creation.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A protected branch in GitLab, by default, prevents which action for users below the configured push role?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to contribute to a project where you lack push access. Which GitLab workflow lets you propose changes from your own copy?$tv2$, $tv2$[{"id":"a","text":"Clone the project and push a new branch to the original repository"},{"id":"b","text":"Fork the project, push to your fork, then open a merge request to the upstream project"},{"id":"c","text":"Open an issue and attach a patch file"},{"id":"d","text":"Request the Owner role on the upstream project"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The fork workflow creates a server-side copy you control; you push branches there and open a merge request targeting the upstream project. You cannot push branches to a repo you lack access to, and issues are not a code-contribution mechanism.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to contribute to a project where you lack push access. Which GitLab workflow lets you propose changes from your own copy?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Git command creates an annotated tag `v1.0.0` on the current commit?$tv2$, $tv2$[{"id":"a","text":"git tag v1.0.0"},{"id":"b","text":"git tag -a v1.0.0 -m \"Release 1.0.0\""},{"id":"c","text":"git branch v1.0.0"},{"id":"d","text":"git commit --tag v1.0.0"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git tag -a <name> -m <msg>` creates an annotated tag (a full object with tagger, date, and message). `git tag v1.0.0` alone creates a lightweight tag, and `git branch` creates a branch, not a tag.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Git command creates an annotated tag `v1.0.0` on the current commit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$By default, what is the file name and location GitLab looks for to define a project's CI/CD pipeline?$tv2$, $tv2$[{"id":"a","text":".gitlab-ci.yml in the repository root"},{"id":"b","text":"ci/pipeline.yaml in the repository root"},{"id":"c","text":".gitlab/config.yml in the project"},{"id":"d","text":"gitlab-pipeline.json in the repository root"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab reads the pipeline definition from `.gitlab-ci.yml` in the repository root by default (the path is configurable in project settings). The other paths are not GitLab defaults.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$By default, what is the file name and location GitLab looks for to define a project's CI/CD pipeline?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In `.gitlab-ci.yml`, jobs that belong to the same `stage` behave how relative to each other?$tv2$, $tv2$[{"id":"a","text":"They run sequentially in the order written"},{"id":"b","text":"They run in parallel, and the next stage starts only after all jobs in the current stage succeed"},{"id":"c","text":"Only the first job in the stage runs; the rest are skipped"},{"id":"d","text":"They each trigger a separate pipeline"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Jobs in the same stage run in parallel (subject to runner availability). The pipeline advances to the next stage only when every job in the current stage passes (unless `allow_failure` is set).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `.gitlab-ci.yml`, jobs that belong to the same `stage` behave how relative to each other?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about `artifacts` and `cache` in GitLab CI/CD.$tv2$, $tv2$[{"id":"a","text":"artifacts are uploaded to GitLab and can be passed to jobs in later stages and downloaded from the UI."},{"id":"b","text":"cache is intended to speed up jobs by reusing files (e.g. dependencies) between pipeline runs and is best-effort."},{"id":"c","text":"cache is guaranteed to always be available and is the correct way to pass build outputs between stages."},{"id":"d","text":"artifacts have a configurable expiry via expire_in."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Artifacts are stored by GitLab, passed downstream, downloadable, and can expire via `expire_in`. Cache is a best-effort optimization for reuse between runs and is NOT guaranteed; build outputs that must reach later stages should use artifacts, not cache.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about `artifacts` and `cache` in GitLab CI/CD.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a `deploy` job to start as soon as its `build` job finishes, without waiting for other jobs in the build stage. Which keyword expresses this dependency?$tv2$, $tv2$[{"id":"a","text":"only: [build]"},{"id":"b","text":"needs: [build]"},{"id":"c","text":"dependencies: build"},{"id":"d","text":"when: on_success"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`needs` creates a directed acyclic graph (DAG): a job runs as soon as its listed `needs` jobs complete, ignoring stage ordering. `dependencies` only controls which artifacts are downloaded; `only` controls job inclusion; `when` controls run conditions.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a `deploy` job to start as soon as its `build` job finishes, without waiting for other jobs in the build stage. Which keyword expresses this dependency?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which modern keyword should be used to control whether a job is added to a pipeline based on conditions such as branch name or changed files?$tv2$, $tv2$[{"id":"a","text":"rules"},{"id":"b","text":"tags"},{"id":"c","text":"environment"},{"id":"d","text":"services"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`rules` is the recommended mechanism to include/exclude jobs conditionally (it supersedes `only`/`except`). `tags` selects runners, `environment` declares a deployment target, and `services` attaches helper containers.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which modern keyword should be used to control whether a job is added to a pipeline based on conditions such as branch name or changed files?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job specifies `tags: [docker]`. What does this control?$tv2$, $tv2$[{"id":"a","text":"Which Git tag the job builds from"},{"id":"b","text":"That the job only runs for tagged releases"},{"id":"c","text":"That the job runs only on runners that have the matching `docker` tag"},{"id":"d","text":"The Docker image used to run the job"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Job `tags` are matched against runner tags so the job is picked up only by runners registered with those tags. Git tag pipelines use `rules`/`CI_COMMIT_TAG`; the job's container is set with `image`.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job specifies `tags: [docker]`. What does this control?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$In a merge request description or commit message, which phrase automatically closes issue #42 when the change merges to the default branch?$tv2$, $tv2$[{"id":"a","text":"See #42"},{"id":"b","text":"Closes #42"},{"id":"c","text":"Related to #42"},{"id":"d","text":"Mentions #42"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab recognizes closing keywords such as `Closes #42` (also Fixes/Resolves) in MR descriptions and commit messages; merging to the default branch closes the referenced issue. "See" / "Related to" only create cross-links.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a merge request description or commit message, which phrase automatically closes issue #42 when the change merges to the default branch?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A team wants a Kanban-style view where dragging an issue between columns changes its labels. Which GitLab feature provides this?$tv2$, $tv2$[{"id":"a","text":"Milestones"},{"id":"b","text":"Issue boards"},{"id":"c","text":"Epics"},{"id":"d","text":"Snippets"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Issue boards present issues in label/list columns; moving a card between lists updates the issue's labels. Milestones group work by time/scope, epics group issues across projects, and snippets store shareable code.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A team wants a Kanban-style view where dragging an issue between columns changes its labels. Which GitLab feature provides this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which GitLab object groups multiple related issues that may span several projects into a single higher-level deliverable?$tv2$, $tv2$[{"id":"a","text":"Label"},{"id":"b","text":"Milestone"},{"id":"c","text":"Epic"},{"id":"d","text":"Tag"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Epics (a group-level feature) collect issues across projects under one initiative. Labels categorize, milestones track a scoped/time-boxed set of work, and Git tags mark commits.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which GitLab object groups multiple related issues that may span several projects into a single higher-level deliverable?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which GitLab security scanner analyzes your source code (without executing it) to find potential vulnerabilities?$tv2$, $tv2$[{"id":"a","text":"SAST (Static Application Security Testing)"},{"id":"b","text":"Dependency Scanning"},{"id":"c","text":"Secret Detection"},{"id":"d","text":"Container Registry"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$SAST inspects source code statically for insecure patterns. Dependency Scanning checks third-party libraries for known CVEs, Secret Detection finds leaked credentials, and the Container Registry stores images (not a scanner).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which GitLab security scanner analyzes your source code (without executing it) to find potential vulnerabilities?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which GitLab default role grants the LEAST privilege — typically read-only visibility into a private project, with no ability to push code?$tv2$, $tv2$[{"id":"a","text":"Guest"},{"id":"b","text":"Developer"},{"id":"c","text":"Maintainer"},{"id":"d","text":"Owner"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The role hierarchy is Guest < Reporter < Developer < Maintainer < Owner. Guest is the lowest, with limited read access and no push rights. Developers can push to non-protected branches; Maintainers/Owners administer the project/group.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which GitLab default role grants the LEAST privilege — typically read-only visibility into a private project, with no ability to push code?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which feature records who performed sensitive actions (e.g. permission changes, settings changes) for compliance review?$tv2$, $tv2$[{"id":"a","text":"Issue boards"},{"id":"b","text":"Audit events"},{"id":"c","text":"CI/CD cache"},{"id":"d","text":"Snippets"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Audit events log security-relevant actions (membership/permission/setting changes) with actor and timestamp, supporting compliance and forensics. Boards, cache, and snippets are unrelated to audit logging.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"},{"url":"https://docs.gitlab.com/ee/administration/compliance.html","label":"GitLab Docs — Compliance"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which feature records who performed sensitive actions (e.g. permission changes, settings changes) for compliance review?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the staging area (also called the index) in Git?$tv2$, $tv2$[{"id":"a","text":"A remote server that mirrors the repository"},{"id":"b","text":"An intermediate area where changes are prepared before they become part of the next commit"},{"id":"c","text":"A backup of every previous commit"},{"id":"d","text":"A temporary branch created during a merge"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The staging area (index) holds the snapshot that will go into the next commit. `git add` moves changes into it, and `git commit` records exactly what is staged. It is local, not a remote or a backup.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the staging area (also called the index) in Git?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command discards unstaged changes in the tracked file `app.py`, restoring it to the last committed state?$tv2$, $tv2$[{"id":"a","text":"git restore app.py"},{"id":"b","text":"git rm app.py"},{"id":"c","text":"git stash drop app.py"},{"id":"d","text":"git commit --reset app.py"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git restore app.py` (or the older `git checkout -- app.py`) discards working-tree changes for that file. `git rm` deletes and stages a removal, `git stash drop` removes a stash entry, and `--reset` is not a commit flag.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command discards unstaged changes in the tracked file `app.py`, restoring it to the last committed state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `.gitignore` file do?$tv2$, $tv2$[{"id":"a","text":"Encrypts files before they are committed"},{"id":"b","text":"Specifies intentionally untracked file patterns that Git should not stage or report as untracked"},{"id":"c","text":"Lists files that must always be committed"},{"id":"d","text":"Records the commit history in a human-readable form"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`.gitignore` lists glob patterns for files Git should not track (build output, secrets, dependencies). It does not encrypt, force-include, or store history. Already-tracked files are not affected until untracked.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `.gitignore` file do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the commit history of the current branch, most recent first?$tv2$, $tv2$[{"id":"a","text":"git status"},{"id":"b","text":"git log"},{"id":"c","text":"git reflog --branches"},{"id":"d","text":"git diff HEAD"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git log` lists commits reachable from HEAD, newest first, with author, date, and message. `git status` shows working-tree state, `git diff HEAD` shows changes vs HEAD, and `git reflog` shows ref movements (not the same as branch history).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the commit history of the current branch, most recent first?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A merge produced conflicts. After manually editing the files to resolve them, what completes the merge?$tv2$, $tv2$[{"id":"a","text":"git merge --abort"},{"id":"b","text":"git add the resolved files, then git commit"},{"id":"c","text":"git reset --hard HEAD"},{"id":"d","text":"git checkout --theirs ."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$After fixing conflict markers you stage the resolved files with `git add` and then `git commit` to finalize the merge commit. `--abort` cancels the merge, `reset --hard` discards work, and `--theirs` blindly takes one side.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A merge produced conflicts. After manually editing the files to resolve them, what completes the merge?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A commit SHA in Git is a hash that uniquely identifies the content and history of that commit.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Each commit gets a SHA-1 (or SHA-256) hash computed over its tree, parent(s), author, message, etc. Changing any of those produces a different SHA, which is why rewriting history changes commit IDs.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A commit SHA in Git is a hash that uniquely identifies the content and history of that commit.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What does `git diff` (with no arguments) show by default?$tv2$, $tv2$[{"id":"a","text":"The differences between staged changes and the last commit"},{"id":"b","text":"The differences between the working tree and the staging area (unstaged changes)"},{"id":"c","text":"A list of all branches"},{"id":"d","text":"The remote URL configuration"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Plain `git diff` shows unstaged changes — working tree vs index. `git diff --cached` (or `--staged`) shows staged vs last commit. It does not list branches or show remotes.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `git diff` (with no arguments) show by default?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to undo a pushed commit on a shared branch without rewriting history. Which command is safest?$tv2$, $tv2$[{"id":"a","text":"git reset --hard HEAD~1 then force push"},{"id":"b","text":"git revert <commit>"},{"id":"c","text":"git rebase -i HEAD~1"},{"id":"d","text":"git commit --amend then force push"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git revert` creates a new commit that undoes the target commit, preserving history — safe for shared branches. The other options rewrite history and require force-pushing, which disrupts collaborators.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to undo a pushed commit on a shared branch without rewriting history. Which command is safest?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Git branches.$tv2$, $tv2$[{"id":"a","text":"A branch is a lightweight movable pointer to a commit."},{"id":"b","text":"Creating a branch copies the entire repository contents to a new directory."},{"id":"c","text":"HEAD normally points to the currently checked-out branch."},{"id":"d","text":"Deleting a merged branch removes the commits it shared with main."}]$tv2$::jsonb, $tv2$["a","c"]$tv2$::jsonb, $tv2$A branch is just a movable pointer/ref to a commit, and HEAD references the current branch. Branches are not directory copies, and deleting a branch only removes the label — shared commits reachable from other branches remain.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Git branches.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the default branch in a GitLab project typically used for?$tv2$, $tv2$[{"id":"a","text":"Storing CI/CD logs"},{"id":"b","text":"Serving as the primary, stable line of development that pipelines and merge requests target by default"},{"id":"c","text":"Holding only documentation"},{"id":"d","text":"Running runners"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The default branch (often `main`) is the primary integration branch; new MRs and many pipeline rules target it, and it is commonly protected. It is not a log store or runner.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"},{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the default branch in a GitLab project typically used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A CODEOWNERS file in a GitLab repository primarily does what?$tv2$, $tv2$[{"id":"a","text":"Defines which users/groups are responsible for specific files or paths so they can be required reviewers"},{"id":"b","text":"Lists the project members allowed to clone the repository"},{"id":"c","text":"Configures CI/CD runner tags"},{"id":"d","text":"Sets the project visibility level"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$CODEOWNERS maps file/path patterns to owners; combined with protected branches, owners can be required approvers for changes to their paths. It does not manage cloning, runners, or visibility.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A CODEOWNERS file in a GitLab repository primarily does what?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement best describes a merge request in GitLab?$tv2$, $tv2$[{"id":"a","text":"A request to delete a branch permanently"},{"id":"b","text":"A proposal to merge changes from a source branch into a target branch, with review, discussion, and CI"},{"id":"c","text":"A scheduled backup of the repository"},{"id":"d","text":"A way to fork a project"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A merge request proposes integrating a source branch into a target branch and is the hub for code review, discussion, approvals, and pipeline results. It is not a deletion, backup, or fork operation.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement best describes a merge request in GitLab?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Your MR target branch advanced and now has conflicts with your source branch. Which is a valid resolution path entirely within GitLab/Git?$tv2$, $tv2$[{"id":"a","text":"Close the MR and open a new project"},{"id":"b","text":"Rebase or merge the target branch into your source branch, resolve conflicts, and push the update"},{"id":"c","text":"Delete the target branch"},{"id":"d","text":"Force the MR to merge ignoring conflicts"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$You update the source branch by merging or rebasing the latest target into it, resolving conflicts, then pushing; the MR re-evaluates. GitLab will not merge with unresolved conflicts, and deleting the target is not a resolution.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Your MR target branch advanced and now has conflicts with your source branch. Which is a valid resolution path entirely within GitLab/Git?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid GitLab merge methods.$tv2$, $tv2$[{"id":"a","text":"Merge commit"},{"id":"b","text":"Merge commit with semi-linear history"},{"id":"c","text":"Fast-forward merge"},{"id":"d","text":"Rebase and rename"}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$GitLab supports "Merge commit", "Merge commit with semi-linear history", and "Fast-forward merge". "Rebase and rename" is not a GitLab merge method.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid GitLab merge methods.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In GitLab Flow, what triggers a deployment to an environment in the simplest model?$tv2$, $tv2$[{"id":"a","text":"Manually copying files to the server"},{"id":"b","text":"Merging into the branch associated with that environment, which runs the deployment pipeline"},{"id":"c","text":"Creating an issue labeled deploy"},{"id":"d","text":"Renaming the repository"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab Flow ties environments to branches; merging into an environment branch triggers the pipeline that deploys it. Manual file copies or issue labels are not the GitLab Flow deployment mechanism.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"},{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In GitLab Flow, what triggers a deployment to an environment in the simplest model?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which Git command integrates upstream changes into your branch by replaying your commits on top of the latest upstream tip, keeping linear history?$tv2$, $tv2$[{"id":"a","text":"git merge upstream/main"},{"id":"b","text":"git rebase upstream/main"},{"id":"c","text":"git cherry-pick upstream/main"},{"id":"d","text":"git reset upstream/main"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git rebase upstream/main` reapplies your commits onto the updated base for a linear history. `git merge` creates a merge commit instead; cherry-pick copies specific commits; reset moves the branch pointer.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Git command integrates upstream changes into your branch by replaying your commits on top of the latest upstream tip, keeping linear history?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which protected-branch setting forces all changes to go through a merge request rather than direct pushes, even for Maintainers?$tv2$, $tv2$[{"id":"a","text":"Set \"Allowed to push and merge\" to \"No one\" while allowing merge"},{"id":"b","text":"Disable the repository"},{"id":"c","text":"Make the project private"},{"id":"d","text":"Remove all members"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Setting "Allowed to push" to "No one" (while merge is still allowed for some role) forces all changes through MRs since nobody can push directly. Privacy/visibility and membership do not enforce MR-only flow.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which protected-branch setting forces all changes to go through a merge request rather than direct pushes, even for Maintainers?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: In a typical GitLab feature-branch workflow, the feature branch should be kept short-lived and merged back via a merge request after review and passing CI.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Short-lived feature branches reduce merge conflicts and integration risk; they are merged via MR once reviewed and CI is green, keeping the default branch stable.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: In a typical GitLab feature-branch workflow, the feature branch should be kept short-lived and merged back via a merge request after review and passing CI.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$In `.gitlab-ci.yml`, what does the top-level `stages` keyword define?$tv2$, $tv2$[{"id":"a","text":"The Docker images used by all jobs"},{"id":"b","text":"The ordered list of stages and the order in which groups of jobs execute"},{"id":"c","text":"The runners assigned to the project"},{"id":"d","text":"The environment variables for the pipeline"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`stages` lists the pipeline stages in execution order; jobs are assigned to a stage and stages run sequentially while jobs within a stage run in parallel. It does not set images, runners, or variables.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `.gitlab-ci.yml`, what does the top-level `stages` keyword define?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `script` keyword in a job specify?$tv2$, $tv2$[{"id":"a","text":"The runner tags"},{"id":"b","text":"The shell commands the runner executes for that job"},{"id":"c","text":"The artifacts to upload"},{"id":"d","text":"The stage name"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`script` is the required list of shell commands a job runs. `tags` selects runners, `artifacts` declares outputs, and `stage` assigns the job to a stage.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `script` keyword in a job specify?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword sets commands that run before the main `script` in a job (e.g. installing dependencies)?$tv2$, $tv2$[{"id":"a","text":"before_script"},{"id":"b","text":"pre_run"},{"id":"c","text":"setup"},{"id":"d","text":"init"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`before_script` runs prior to `script` (and `after_script` runs afterward, even on failure). `pre_run`, `setup`, and `init` are not GitLab CI keywords.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword sets commands that run before the main `script` in a job (e.g. installing dependencies)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `image` keyword specify for a job using the Docker executor?$tv2$, $tv2$[{"id":"a","text":"The Git branch to build"},{"id":"b","text":"The Docker image used as the environment in which the job runs"},{"id":"c","text":"The artifact name"},{"id":"d","text":"The runner host operating system"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`image` sets the container image the job runs inside (with the Docker executor). It is unrelated to branches, artifact naming, or directly choosing the runner host OS.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `image` keyword specify for a job using the Docker executor?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a job to run only when files under `src/` change. Which configuration expresses this?$tv2$, $tv2$[{"id":"a","text":"rules: - changes: [\"src/**/*\"]"},{"id":"b","text":"only: branches"},{"id":"c","text":"needs: [src]"},{"id":"d","text":"environment: src"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`rules:changes` includes the job only when the listed paths change. `only: branches` is unrelated to file changes, `needs` builds a DAG, and `environment` declares a deployment target.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a job to run only when files under `src/` change. Which configuration expresses this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job sets `retry: 2`. What is the effect?$tv2$, $tv2$[{"id":"a","text":"The job runs twice in parallel"},{"id":"b","text":"If the job fails, GitLab automatically retries it up to two more times"},{"id":"c","text":"The job is delayed by two minutes"},{"id":"d","text":"The pipeline retries from the first stage"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`retry: 2` makes GitLab automatically re-run a failed job up to two additional times before marking it failed. It does not parallelize, delay, or restart the whole pipeline.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job sets `retry: 2`. What is the effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `when: on_failure` on a job mean?$tv2$, $tv2$[{"id":"a","text":"The job runs only if a job in an earlier stage failed"},{"id":"b","text":"The job always runs"},{"id":"c","text":"The job never runs"},{"id":"d","text":"The job runs only on protected branches"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`when: on_failure` runs the job only when at least one job in an earlier stage failed (useful for cleanup/notifications). `on_success` (default), `always`, and `manual` are the other common values.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `when: on_failure` on a job mean?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about pipeline triggers/types in GitLab.$tv2$, $tv2$[{"id":"a","text":"A branch pipeline runs when commits are pushed to a branch."},{"id":"b","text":"A merge request pipeline can run for changes proposed in an MR."},{"id":"c","text":"A scheduled pipeline runs on a defined cron-like schedule."},{"id":"d","text":"Pipelines can only ever be started manually by an administrator."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$GitLab supports branch, merge request, scheduled, tag, and manually-triggered pipelines, among others. Pipelines are NOT restricted to admin-only manual starts.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about pipeline triggers/types in GitLab.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which predefined CI/CD variable holds the branch or tag name for which the pipeline is running?$tv2$, $tv2$[{"id":"a","text":"CI_PROJECT_DIR"},{"id":"b","text":"CI_COMMIT_REF_NAME"},{"id":"c","text":"CI_RUNNER_ID"},{"id":"d","text":"CI_JOB_STAGE"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`CI_COMMIT_REF_NAME` is the branch or tag the pipeline runs for. `CI_PROJECT_DIR` is the checkout path, `CI_JOB_STAGE` the stage name, and `CI_RUNNER_ID` the runner identifier.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which predefined CI/CD variable holds the branch or tag name for which the pipeline is running?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What is the purpose of the `cache:key` keyword?$tv2$, $tv2$[{"id":"a","text":"It encrypts the cache contents"},{"id":"b","text":"It defines a key that determines which cache is reused/stored, enabling per-branch or per-dependency caches"},{"id":"c","text":"It selects which runner stores the cache"},{"id":"d","text":"It sets the artifact expiry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`cache:key` controls cache identity (e.g. keyed by branch or a lockfile hash) so the right cache is restored/saved. It does not encrypt, choose runners, or set artifact expiry.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the purpose of the `cache:key` keyword?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A deploy job has `environment: name: production` and `when: manual`. What is the typical reason for this combination?$tv2$, $tv2$[{"id":"a","text":"To deploy automatically on every commit"},{"id":"b","text":"To require a human to explicitly trigger the production deployment (a manual gate)"},{"id":"c","text":"To disable deployments"},{"id":"d","text":"To run the job on every branch"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Combining `environment` with `when: manual` creates a tracked production deployment that a person must click to run — a deliberate release gate. It is the opposite of automatic on every commit.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A deploy job has `environment: name: production` and `when: manual`. What is the typical reason for this combination?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about GitLab Runners and executors.$tv2$, $tv2$[{"id":"a","text":"Runners can be instance-wide (shared), group, or project-specific."},{"id":"b","text":"The docker executor isolates each job in a container."},{"id":"c","text":"A runner must always use the shell executor."},{"id":"d","text":"Job tags are matched to runner tags to route jobs."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Runners can be shared/group/project-scoped, the docker executor isolates jobs per container, and job tags route work to tagged runners. A runner is NOT forced to use the shell executor — many executors exist (docker, kubernetes, shell, ssh, etc.).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"},{"url":"https://docs.gitlab.com/runner/executors/","label":"GitLab Docs — Runner executors"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about GitLab Runners and executors.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$To authenticate a CI/CD job pushing an image to the project Container Registry, which predefined variables are most relevant?$tv2$, $tv2$[{"id":"a","text":"CI_REGISTRY, CI_REGISTRY_USER, CI_REGISTRY_PASSWORD"},{"id":"b","text":"CI_PAGES_URL only"},{"id":"c","text":"CI_RUNNER_TAGS"},{"id":"d","text":"CI_DEFAULT_BRANCH"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab injects `CI_REGISTRY`, `CI_REGISTRY_USER`, and `CI_REGISTRY_PASSWORD` (and `CI_REGISTRY_IMAGE`) so jobs can `docker login` and push to the integrated registry. The others are unrelated to registry auth.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/packages/container_registry/","label":"GitLab Docs — Container Registry"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To authenticate a CI/CD job pushing an image to the project Container Registry, which predefined variables are most relevant?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is a GitLab issue primarily used for?$tv2$, $tv2$[{"id":"a","text":"Storing compiled binaries"},{"id":"b","text":"Tracking work such as bugs, feature requests, and tasks, with discussion and assignment"},{"id":"c","text":"Running CI/CD pipelines"},{"id":"d","text":"Hosting a static website"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Issues track and discuss work items (bugs, features, tasks) with assignees, labels, milestones, and threaded comments. Binaries go to artifacts/registry, pipelines run CI, and Pages hosts sites.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is a GitLab issue primarily used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which feature lets you assign an issue or merge request to a specific person responsible for it?$tv2$, $tv2$[{"id":"a","text":"Assignees"},{"id":"b","text":"Labels"},{"id":"c","text":"Tags"},{"id":"d","text":"Runners"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Assignees designate who is responsible for an issue/MR (GitLab also supports multiple assignees in some tiers). Labels categorize, Git tags mark commits, and runners execute CI.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which feature lets you assign an issue or merge request to a specific person responsible for it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does referencing `!123` in an issue comment do?$tv2$, $tv2$[{"id":"a","text":"Deletes merge request 123"},{"id":"b","text":"Creates a cross-link to merge request number 123"},{"id":"c","text":"Merges MR 123 immediately"},{"id":"d","text":"Assigns the issue to user 123"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab reference syntax: `#123` links an issue, `!123` links a merge request, `@user` mentions a user. It creates a navigable cross-reference, not a destructive action.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does referencing `!123` in an issue comment do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which feature visualizes remaining work over time for a milestone?$tv2$, $tv2$[{"id":"a","text":"Burndown chart"},{"id":"b","text":"Container registry"},{"id":"c","text":"CI/CD cache"},{"id":"d","text":"Protected branch"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A burndown (and burnup) chart on a milestone shows progress/remaining work over the milestone period. The registry, cache, and protected branches are unrelated to milestone progress visualization.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which feature visualizes remaining work over time for a milestone?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about labels in GitLab.$tv2$, $tv2$[{"id":"a","text":"Labels can be project-scoped or group-scoped."},{"id":"b","text":"Scoped labels (key::value) enforce mutual exclusivity within a scope."},{"id":"c","text":"Labels can be used to build issue board lists."},{"id":"d","text":"A label can only ever be applied to one issue at a time."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Labels can be project or group level, scoped labels (`key::value`) are mutually exclusive within their key, and board lists are built from labels. A label can be applied to many issues — it is not single-use.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"},{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about labels in GitLab.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Two issues must be done in order — issue B should not start until A is finished. Which GitLab capability models this dependency?$tv2$, $tv2$[{"id":"a","text":"Linked issues with a \"blocks/is blocked by\" relationship"},{"id":"b","text":"A shared label only"},{"id":"c","text":"A protected tag"},{"id":"d","text":"A CI/CD cache"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab linked issues support relationship types including "blocks" / "is blocked by", explicitly modeling ordering dependencies. Labels alone do not enforce a dependency, and tags/cache are unrelated.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Two issues must be done in order — issue B should not start until A is finished. Which GitLab capability models this dependency?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is a GitLab Wiki used for?$tv2$, $tv2$[{"id":"a","text":"Running CI/CD jobs"},{"id":"b","text":"Maintaining project documentation in a versioned, separate Git repository"},{"id":"c","text":"Storing Docker images"},{"id":"d","text":"Tracking commit SHAs"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A project Wiki holds documentation, backed by its own Git repository and versioned independently of the code. It does not run CI, store images, or track commit hashes.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is a GitLab Wiki used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Order the GitLab default roles from least to most privileged.$tv2$, $tv2$[{"id":"a","text":"Owner < Maintainer < Developer < Reporter < Guest"},{"id":"b","text":"Guest < Reporter < Developer < Maintainer < Owner"},{"id":"c","text":"Reporter < Guest < Maintainer < Developer < Owner"},{"id":"d","text":"Developer < Guest < Reporter < Maintainer < Owner"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The default role hierarchy is Guest < Reporter < Developer < Maintainer < Owner, with each level adding capabilities (Reporter adds read of issues/code analytics, Developer adds push, etc.).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Order the GitLab default roles from least to most privileged.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which role can typically view issues and the repository but cannot push code or create merge requests?$tv2$, $tv2$[{"id":"a","text":"Owner"},{"id":"b","text":"Maintainer"},{"id":"c","text":"Reporter"},{"id":"d","text":"Developer"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Reporter has read-oriented access (view code, issues, analytics) but no push or MR-create rights. Developers can push and open MRs; Maintainers/Owners administer the project.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which role can typically view issues and the repository but cannot push code or create merge requests?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How are GitLab SAST results most commonly surfaced to reviewers?$tv2$, $tv2$[{"id":"a","text":"As emails only"},{"id":"b","text":"In the merge request security widget and the pipeline Security tab, showing newly introduced vulnerabilities"},{"id":"c","text":"Only in the project README"},{"id":"d","text":"In the container registry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$SAST (and other scanners) report findings into the pipeline Security tab and the MR security widget, highlighting vulnerabilities introduced by the change so reviewers can act before merging.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How are GitLab SAST results most commonly surfaced to reviewers?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL GitLab application security scanning categories.$tv2$, $tv2$[{"id":"a","text":"SAST (static analysis of source code)"},{"id":"b","text":"Secret Detection (finding leaked credentials)"},{"id":"c","text":"Dependency Scanning (known CVEs in dependencies)"},{"id":"d","text":"Branch Renaming Scanning"}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$SAST, Secret Detection, and Dependency Scanning are real GitLab security scanning categories (alongside DAST, container scanning, etc.). "Branch Renaming Scanning" is not a security scanner.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"},{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL GitLab application security scanning categories.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A leaked API token was committed last week. Which scanner is designed to detect it, and what is the recommended remediation?$tv2$, $tv2$[{"id":"a","text":"Dependency Scanning; ignore it"},{"id":"b","text":"Secret Detection; revoke/rotate the token and remove it from the codebase"},{"id":"c","text":"SAST; just delete the file"},{"id":"d","text":"Container Scanning; rebuild the image only"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Secret Detection flags committed credentials. Because Git history retains the secret, the correct response is to revoke/rotate the token immediately and remove it from code/config (deleting the file alone is insufficient).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A leaked API token was committed last week. Which scanner is designed to detect it, and what is the recommended remediation?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why should secrets (passwords, tokens) be stored as masked/protected CI/CD variables rather than committed to the repository?$tv2$, $tv2$[{"id":"a","text":"It makes pipelines run faster"},{"id":"b","text":"It keeps secrets out of version history and reduces exposure in logs and to untrusted branches"},{"id":"c","text":"It is required to use any runner"},{"id":"d","text":"It automatically encrypts the whole repository"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Storing secrets as masked/protected CI/CD variables avoids persisting them in Git history, hides them in job logs, and limits exposure to protected refs — far safer than committing them. It is not a speed or runner requirement.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why should secrets (passwords, tokens) be stored as masked/protected CI/CD variables rather than committed to the repository?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Making a project "private" in GitLab restricts access so only explicitly added members can view it.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Private visibility means only project members (or group members with inherited access) can see the project. Internal is logged-in users; public is anyone.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Making a project "private" in GitLab restricts access so only explicitly added members can view it.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a new branch named `feature-x` and immediately switches to it?$tv2$, $tv2$[{"id":"a","text":"git branch feature-x"},{"id":"b","text":"git checkout -b feature-x"},{"id":"c","text":"git switch feature-x"},{"id":"d","text":"git merge feature-x"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git checkout -b feature-x` creates and checks out the branch in one step (equivalent to `git switch -c feature-x`). `git branch feature-x` creates it without switching, and `git switch feature-x` fails if the branch does not exist.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a new branch named `feature-x` and immediately switches to it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `git merge feature` do when run while `main` is checked out and the branches have diverged?$tv2$, $tv2$[{"id":"a","text":"Deletes the feature branch after copying its files"},{"id":"b","text":"Combines the histories of feature into main, creating a merge commit when needed"},{"id":"c","text":"Rewrites main's history to match feature exactly"},{"id":"d","text":"Pushes feature to the remote main branch"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Merging integrates the feature branch into main; with diverged history Git creates a merge commit with two parents. It does not delete branches, rewrite history (that is rebase), or push anything.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `git merge feature` do when run while `main` is checked out and the branches have diverged?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: `git fetch` updates your remote-tracking branches but does NOT modify your local working branch or files.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. `git fetch` downloads new objects and updates remote-tracking refs (e.g. `origin/main`) but leaves your checked-out branch untouched. `git pull` is `fetch` followed by a merge/rebase, which does change your working branch.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: `git fetch` updates your remote-tracking branches but does NOT modify your local working branch or files.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You accidentally ran `git stash` twice. Which command lists all stash entries so you can choose which to restore?$tv2$, $tv2$[{"id":"a","text":"git stash show"},{"id":"b","text":"git stash list"},{"id":"c","text":"git stash pop --all"},{"id":"d","text":"git log --stash"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git stash list` shows the stack of stash entries (stash@{0}, stash@{1}, ...). `git stash show` displays one entry's diff, and there is no `--all` flag on pop or a `--stash` option on log.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You accidentally ran `git stash` twice. Which command lists all stash entries so you can choose which to restore?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Within a GitLab group, what is a subgroup primarily used for?$tv2$, $tv2$[{"id":"a","text":"Storing CI/CD job logs separately from projects"},{"id":"b","text":"Organizing projects and members into a nested hierarchy under the parent group"},{"id":"c","text":"Replacing protected branches at the instance level"},{"id":"d","text":"Running pipelines without a runner"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Subgroups create a nested namespace hierarchy, letting you mirror team/department structure and inherit/scope membership and settings. They are not log storage, branch protection, or a runner substitute.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"},{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Within a GitLab group, what is a subgroup primarily used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about protected branches in GitLab.$tv2$, $tv2$[{"id":"a","text":"You can configure which roles are allowed to push and which are allowed to merge."},{"id":"b","text":"Force push to a protected branch is blocked by default."},{"id":"c","text":"Protected branches make the repository read-only for everyone."},{"id":"d","text":"You can require code owner approval on a protected branch."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Protected branches let you set allowed push/merge roles, block force pushes by default, and optionally require Code Owner approval. They do NOT make the whole repository read-only — only the protected branch is restricted.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about protected branches in GitLab.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$After forking a project, how do you keep your fork up to date with new commits on the original (upstream) project?$tv2$, $tv2$[{"id":"a","text":"Delete and re-fork every time upstream changes"},{"id":"b","text":"Add the original project as a remote (e.g. upstream) and fetch/merge its changes into your fork"},{"id":"c","text":"Open an issue asking maintainers to sync your fork"},{"id":"d","text":"Forks update automatically and require no action ever"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$You add the original repo as a second remote (commonly `upstream`), then fetch and merge/rebase its changes into your fork. GitLab also offers a UI "Update fork" action, but forks do not sync fully automatically.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After forking a project, how do you keep your fork up to date with new commits on the original (upstream) project?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In GitLab Flow with environment branches, how is code typically promoted from staging to production?$tv2$, $tv2$[{"id":"a","text":"By force-pushing the staging branch over production"},{"id":"b","text":"By merging the production-ready branch into the production environment branch (often via merge request)"},{"id":"c","text":"By committing directly to the production branch on the server"},{"id":"d","text":"By deleting the staging branch"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab Flow promotes changes forward by merging into downstream environment branches (e.g. main → pre-production → production), typically through merge requests so review/CI gate each promotion. Force-pushing or direct server commits bypass that flow.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In GitLab Flow with environment branches, how is code typically promoted from staging to production?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A job sets `when: manual`. What is the effect?$tv2$, $tv2$[{"id":"a","text":"The job runs automatically but with low priority"},{"id":"b","text":"The job is added to the pipeline but only runs when a user explicitly triggers (plays) it"},{"id":"c","text":"The job is skipped entirely"},{"id":"d","text":"The job runs only on manual (self-managed) runners"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`when: manual` creates a job that appears in the pipeline but stays paused until a user clicks play. It is commonly used for deployments. It is unrelated to runner type or priority.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job sets `when: manual`. What is the effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A job has `allow_failure: true` and it fails. What happens to the pipeline?$tv2$, $tv2$[{"id":"a","text":"The pipeline fails immediately"},{"id":"b","text":"The pipeline continues and is not marked as failed because of this job (it shows a warning)"},{"id":"c","text":"The job is automatically retried three times"},{"id":"d","text":"The next stage is skipped"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`allow_failure: true` lets a job fail without failing the pipeline; the pipeline proceeds and shows a warning indicator. It does not trigger retries or skip stages.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job has `allow_failure: true` and it fails. What happens to the pipeline?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to reuse a shared pipeline template stored in another repository. Which `.gitlab-ci.yml` keyword references external configuration?$tv2$, $tv2$[{"id":"a","text":"extends"},{"id":"b","text":"include"},{"id":"c","text":"needs"},{"id":"d","text":"trigger"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`include` pulls in external YAML (local file, another project, remote URL, or a template). `extends` reuses configuration defined within the same file, `needs` builds a DAG, and `trigger` starts downstream pipelines.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/includes.html","label":"GitLab Docs — include"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to reuse a shared pipeline template stored in another repository. Which `.gitlab-ci.yml` keyword references external configuration?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about CI/CD variables in GitLab.$tv2$, $tv2$[{"id":"a","text":"Project-level CI/CD variables can be marked \"masked\" so their values are hidden in job logs."},{"id":"b","text":"Variables can be marked \"protected\" so they are only available on protected branches and tags."},{"id":"c","text":"Predefined variables like CI_COMMIT_REF_NAME are provided automatically by GitLab."},{"id":"d","text":"CI/CD variables can only be defined inside the .gitlab-ci.yml file."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Variables can be masked, marked protected, and GitLab injects many predefined variables (e.g. `CI_COMMIT_REF_NAME`). They can be defined in the YAML file OR in project/group/instance settings — not only in the file.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about CI/CD variables in GitLab.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `deploy` job defines `environment: name: production, url: https://example.com`. What does declaring an environment provide?$tv2$, $tv2$[{"id":"a","text":"It encrypts all artifacts produced by the job"},{"id":"b","text":"It tracks deployments to that environment and enables features like deployment history and rollback"},{"id":"c","text":"It forces the job to run on a shared runner"},{"id":"d","text":"It disables the job's logs for security"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Declaring an `environment` lets GitLab record deployments, show deployment history, link the live URL, and support rollback/stop actions. It does not affect artifact encryption, runner selection, or log visibility.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `deploy` job defines `environment: name: production, url: https://example.com`. What does declaring an environment provide?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$Which runner executor runs each CI/CD job in its own container, giving clean isolated environments per job?$tv2$, $tv2$[{"id":"a","text":"shell"},{"id":"b","text":"docker"},{"id":"c","text":"ssh"},{"id":"d","text":"static"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `docker` executor spins up a fresh container per job, providing isolation and reproducibility. The `shell` executor runs jobs directly on the runner host (shared state), `ssh` runs them on a remote machine, and `static` is not a GitLab Runner executor.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/runner/executors/","label":"GitLab Docs — Runner executors"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which runner executor runs each CI/CD job in its own container, giving clean isolated environments per job?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the purpose of marking a merge request as a Draft (e.g. title prefixed with "Draft:")?$tv2$, $tv2$[{"id":"a","text":"It permanently deletes the source branch"},{"id":"b","text":"It signals the MR is not ready and blocks merging until the Draft flag is removed"},{"id":"c","text":"It automatically approves the merge request"},{"id":"d","text":"It converts the MR into an issue"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A Draft MR communicates work-in-progress and GitLab prevents it from being merged until the Draft status is cleared. It does not delete branches, auto-approve, or convert to an issue.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/drafts.html","label":"GitLab Docs — Draft merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the purpose of marking a merge request as a Draft (e.g. title prefixed with "Draft:")?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You want to track all issues and merge requests targeted for the "2.0 Release" with a due date. Which feature fits best?$tv2$, $tv2$[{"id":"a","text":"A label named release-2.0"},{"id":"b","text":"A milestone named 2.0 Release with a due date"},{"id":"c","text":"A protected tag"},{"id":"d","text":"A snippet"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Milestones group issues/MRs toward a deliverable and support start/due dates and progress burndown. A label only categorizes (no dates), a protected tag marks a commit, and a snippet stores code.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to track all issues and merge requests targeted for the "2.0 Release" with a due date. Which feature fits best?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a merge request, which mechanism lets reviewers formally signal that required approval criteria are met before merging?$tv2$, $tv2$[{"id":"a","text":"Adding a comment that says \"LGTM\""},{"id":"b","text":"Merge request approvals (approval rules / required approvers)"},{"id":"c","text":"Closing the related issue"},{"id":"d","text":"Adding a label named approved"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Merge request approval rules require a configured number/group of approvers to approve before the MR can merge. A comment or a label is informal and not enforced; closing an issue is unrelated.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a merge request, which mechanism lets reviewers formally signal that required approval criteria are met before merging?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which GitLab scanner specifically looks for credentials (API keys, tokens, passwords) accidentally committed to the repository?$tv2$, $tv2$[{"id":"a","text":"Secret Detection"},{"id":"b","text":"SAST"},{"id":"c","text":"Dependency Scanning"},{"id":"d","text":"GitLab Pages"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Secret Detection scans commits/history for leaked secrets like tokens and keys. SAST analyzes code logic, Dependency Scanning checks libraries for known CVEs, and GitLab Pages is static-site hosting.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which GitLab scanner specifically looks for credentials (API keys, tokens, passwords) accidentally committed to the repository?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A user must be able to push to non-protected branches and create merge requests, but should NOT manage project settings or members. Which default role is appropriate?$tv2$, $tv2$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Owner"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$The Developer role can push to non-protected branches and create MRs but cannot administer project settings/members. Guest/Reporter cannot push code, and Owner has full administrative control.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A user must be able to push to non-protected branches and create merge requests, but should NOT manage project settings or members. Which default role is appropriate?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which scanner flags third-party libraries declared in your project that have known published vulnerabilities (CVEs)?$tv2$, $tv2$[{"id":"a","text":"Secret Detection"},{"id":"b","text":"Dependency Scanning"},{"id":"c","text":"SAST"},{"id":"d","text":"Container Registry cleanup policy"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Dependency Scanning analyzes your declared dependencies against vulnerability databases to surface known CVEs. Secret Detection finds leaked credentials, SAST inspects your own code, and a registry cleanup policy only prunes old images.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which scanner flags third-party libraries declared in your project that have known published vulnerabilities (CVEs)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which command initializes a brand-new, empty Git repository in the current directory?$tv2$, $tv2$[{"id":"a","text":"git init"},{"id":"b","text":"git start"},{"id":"c","text":"git create"},{"id":"d","text":"git new"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git init` creates a new `.git` directory, turning the current folder into a Git repository. `git start`, `git create`, and `git new` are not Git commands.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command initializes a brand-new, empty Git repository in the current directory?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to apply a single commit from another branch onto your current branch. Which command do you use?$tv2$, $tv2$[{"id":"a","text":"git merge <commit>"},{"id":"b","text":"git cherry-pick <commit>"},{"id":"c","text":"git rebase <commit>"},{"id":"d","text":"git stash <commit>"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git cherry-pick <commit>` applies the changes of one specific commit onto the current branch as a new commit. Merge integrates whole branches, rebase replays a range, and stash is unrelated.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to apply a single commit from another branch onto your current branch. Which command do you use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command stages all modified and new files in the current directory tree?$tv2$, $tv2$[{"id":"a","text":"git add ."},{"id":"b","text":"git stage --commit"},{"id":"c","text":"git commit -all"},{"id":"d","text":"git push ."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git add .` stages changes (including new files) under the current path. `git add -A` stages across the whole repo including deletions. The other forms are not valid Git syntax.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command stages all modified and new files in the current directory tree?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `git clone --branch develop <url>` do?$tv2$, $tv2$[{"id":"a","text":"Clones the repository and checks out the develop branch"},{"id":"b","text":"Deletes the develop branch on the remote"},{"id":"c","text":"Creates a new branch called develop locally only"},{"id":"d","text":"Clones only the develop file"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git clone --branch develop <url>` clones the repo and checks out `develop` instead of the default branch. It does not delete remote branches or clone a single file.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `git clone --branch develop <url>` do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: `git commit` records a snapshot of only the changes that were added to the staging area.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. A commit captures the staged (indexed) content. Modifications not added to the index are not part of the commit (unless `-a` is used to auto-stage tracked files).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: `git commit` records a snapshot of only the changes that were added to the staging area.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You deleted a local branch that had unmerged commits. Which command can help you find those lost commits?$tv2$, $tv2$[{"id":"a","text":"git status"},{"id":"b","text":"git reflog"},{"id":"c","text":"git diff"},{"id":"d","text":"git remote -v"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git reflog` records where HEAD and branch refs have pointed, letting you recover commit SHAs from a deleted branch and recreate it. `status`, `diff`, and `remote -v` do not show ref history.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You deleted a local branch that had unmerged commits. Which command can help you find those lost commits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$In Git, what is HEAD?$tv2$, $tv2$[{"id":"a","text":"The oldest commit in the repository"},{"id":"b","text":"A reference to the current commit/branch you have checked out"},{"id":"c","text":"The remote server name"},{"id":"d","text":"The staging area"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$HEAD is a symbolic reference to the currently checked-out branch (or commit in detached state). It is not the first commit, a remote name, or the index.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In Git, what is HEAD?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all local branches and marks the current one with an asterisk?$tv2$, $tv2$[{"id":"a","text":"git branch"},{"id":"b","text":"git branch -r"},{"id":"c","text":"git log --branches"},{"id":"d","text":"git checkout"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git branch` lists local branches, marking the active one with `*`. `git branch -r` lists remote-tracking branches, and the others do not list local branches that way.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all local branches and marks the current one with an asterisk?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements comparing merge and rebase.$tv2$, $tv2$[{"id":"a","text":"Merge preserves the original branch history and adds a merge commit when histories diverge."},{"id":"b","text":"Rebase rewrites commits onto a new base, producing a linear history."},{"id":"c","text":"Rebasing a shared/published branch is generally discouraged."},{"id":"d","text":"Merge always rewrites commit SHAs of the feature branch."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Merge keeps both histories (often via a merge commit), rebase replays commits for a linear history, and rebasing shared branches is discouraged because it rewrites history. Merge does NOT rewrite the feature branch's commit SHAs.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements comparing merge and rebase.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the source branch of a merge request refer to?$tv2$, $tv2$[{"id":"a","text":"The branch whose changes are proposed to be merged into the target branch"},{"id":"b","text":"The default branch only"},{"id":"c","text":"The branch the changes will be merged into"},{"id":"d","text":"A read-only mirror branch"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$In an MR the source branch contains the changes you want merged; the target branch is where they will land. The source need not be the default branch.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the source branch of a merge request refer to?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A maintainer enabled "Fast-forward merge" only. What must be true for an MR to merge?$tv2$, $tv2$[{"id":"a","text":"The MR can always merge regardless of history"},{"id":"b","text":"The source branch must be rebased on the latest target so a linear fast-forward is possible"},{"id":"c","text":"A merge commit will be created automatically"},{"id":"d","text":"The target branch must be deleted first"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Fast-forward-only merges require the source to be directly ahead of the target (no merge commit). If the target moved, you must rebase/update the source first. No merge commit is created.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"},{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A maintainer enabled "Fast-forward merge" only. What must be true for an MR to merge?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which is a benefit of keeping feature branches short-lived in GitLab Flow?$tv2$, $tv2$[{"id":"a","text":"It guarantees no code review is needed"},{"id":"b","text":"It reduces merge conflicts and integration risk by merging small changes frequently"},{"id":"c","text":"It removes the need for CI/CD"},{"id":"d","text":"It prevents the main branch from being protected"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Short-lived branches integrate small changes often, minimizing divergence and conflicts. Review and CI are still required, and main remains protectable.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which is a benefit of keeping feature branches short-lived in GitLab Flow?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about GitLab groups and subgroups.$tv2$, $tv2$[{"id":"a","text":"A subgroup inherits members and permissions from its parent group."},{"id":"b","text":"Projects can be moved between groups (transferred)."},{"id":"c","text":"A group can contain both projects and subgroups."},{"id":"d","text":"Subgroups cannot have their own members beyond inherited ones."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Subgroups inherit parent membership, projects can be transferred between namespaces, and a group can hold projects and subgroups. Subgroups CAN also have their own additional members, not only inherited ones.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about GitLab groups and subgroups.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the target branch of a typical feature merge request?$tv2$, $tv2$[{"id":"a","text":"Always a tag"},{"id":"b","text":"Usually the default/integration branch (e.g. main) the feature should land in"},{"id":"c","text":"The runner"},{"id":"d","text":"The container registry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A feature MR usually targets the default integration branch (commonly `main`) where reviewed work is integrated. Tags, runners, and the registry are not MR targets.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the target branch of a typical feature merge request?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How can you require that specific people review changes to files in `/infra/` before merge?$tv2$, $tv2$[{"id":"a","text":"Add a label named infra"},{"id":"b","text":"Define CODEOWNERS entries for /infra/ and enable code owner approval on the protected branch"},{"id":"c","text":"Delete the /infra/ directory"},{"id":"d","text":"Disable merge requests"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$CODEOWNERS maps `/infra/` to owners; enabling "Require code owner approval" on the protected target branch forces those owners to approve MRs touching that path. Labels do not enforce reviewers.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How can you require that specific people review changes to files in `/infra/` before merge?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement about forking is correct?$tv2$, $tv2$[{"id":"a","text":"A fork shares the same storage as the upstream project, so changes affect upstream immediately"},{"id":"b","text":"A fork is an independent server-side copy; you push to it and propose changes upstream via merge requests"},{"id":"c","text":"Forking automatically grants you Owner on upstream"},{"id":"d","text":"You cannot open a merge request from a fork"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A fork is a separate copy you control; changes do not affect upstream until merged via an MR from the fork. Forking does not grant upstream roles, and MRs from forks are fully supported.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement about forking is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$In a release-branch GitLab Flow, what is a release branch typically used for?$tv2$, $tv2$[{"id":"a","text":"Daily feature development"},{"id":"b","text":"Stabilizing a specific release and applying only bug fixes/cherry-picks before tagging"},{"id":"c","text":"Storing CI logs"},{"id":"d","text":"Hosting documentation"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Release branches isolate a version for stabilization: only fixes (often cherry-picked from main) go in before tagging the release. Active feature work continues on main, not the release branch.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a release-branch GitLab Flow, what is a release branch typically used for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does "rebase" do to an MR's source branch in GitLab when you click the Rebase button?$tv2$, $tv2$[{"id":"a","text":"Squashes all commits into one"},{"id":"b","text":"Replays the source branch commits on top of the latest target branch"},{"id":"c","text":"Deletes the source branch"},{"id":"d","text":"Merges the MR immediately"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The Rebase action replays the source branch onto the current tip of the target branch, updating it without a merge commit. It does not squash, delete the branch, or merge.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does "rebase" do to an MR's source branch in GitLab when you click the Rebase button?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is a "job" in a GitLab CI/CD pipeline?$tv2$, $tv2$[{"id":"a","text":"A protected branch"},{"id":"b","text":"A defined unit of work (with a script) that a runner executes as part of a stage"},{"id":"c","text":"A merge request"},{"id":"d","text":"A container registry image"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A job is the smallest pipeline unit: it has a script, belongs to a stage, and is run by a runner. It is not a branch, MR, or image.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is a "job" in a GitLab CI/CD pipeline?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$If no `stages` are defined in `.gitlab-ci.yml`, what default stages does GitLab use?$tv2$, $tv2$[{"id":"a","text":"build, test, deploy"},{"id":"b","text":"compile, package, ship"},{"id":"c","text":"init, run, end"},{"id":"d","text":"There are no default stages; the pipeline fails"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$When `stages` is omitted, GitLab uses the default `.pre`, `build`, `test`, `deploy`, `.post` ordering (commonly summarized as build → test → deploy). The pipeline does not fail for omitting `stages`.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$If no `stages` are defined in `.gitlab-ci.yml`, what default stages does GitLab use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword assigns a job to a particular stage?$tv2$, $tv2$[{"id":"a","text":"stage"},{"id":"b","text":"phase"},{"id":"c","text":"step"},{"id":"d","text":"group"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `stage` keyword places a job in a named stage (must exist in `stages` or be a default). `phase`, `step`, and `group` are not GitLab CI keywords for this.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword assigns a job to a particular stage?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a job to run for tag pipelines only. Which rule condition matches?$tv2$, $tv2$[{"id":"a","text":"rules: - if: $CI_COMMIT_TAG"},{"id":"b","text":"rules: - if: $CI_MERGE_REQUEST_IID"},{"id":"c","text":"only: branches"},{"id":"d","text":"when: never"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`$CI_COMMIT_TAG` is set only for tag pipelines, so `rules: - if: $CI_COMMIT_TAG` includes the job for tags. The MR variable matches MR pipelines, `only: branches` excludes tags, and `when: never` disables the job.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a job to run for tag pipelines only. Which rule condition matches?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid values for a job's `when` keyword.$tv2$, $tv2$[{"id":"a","text":"on_success"},{"id":"b","text":"manual"},{"id":"c","text":"always"},{"id":"d","text":"random"}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Valid `when` values include `on_success` (default), `on_failure`, `always`, `manual`, `delayed`, and `never`. `random` is not a valid value.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid values for a job's `when` keyword.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which predefined variable contains the absolute path to the cloned project on the runner?$tv2$, $tv2$[{"id":"a","text":"CI_PROJECT_DIR"},{"id":"b","text":"CI_COMMIT_SHA"},{"id":"c","text":"CI_PIPELINE_ID"},{"id":"d","text":"CI_JOB_NAME"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`CI_PROJECT_DIR` is the full path where the repository is checked out. `CI_COMMIT_SHA` is the commit hash, `CI_PIPELINE_ID` the pipeline ID, and `CI_JOB_NAME` the job name.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which predefined variable contains the absolute path to the cloned project on the runner?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job needs a Postgres database for integration tests. Which keyword attaches it as a linked container?$tv2$, $tv2$[{"id":"a","text":"services"},{"id":"b","text":"image"},{"id":"c","text":"cache"},{"id":"d","text":"needs"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`services` attaches helper containers (e.g. `postgres`) accessible by hostname during the job. `image` is the job's own container, `cache` reuses files, and `needs` builds a DAG.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job needs a Postgres database for integration tests. Which keyword attaches it as a linked container?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What does `parallel: 5` on a job do?$tv2$, $tv2$[{"id":"a","text":"Runs the job 5 times in parallel as separate instances"},{"id":"b","text":"Retries the job 5 times"},{"id":"c","text":"Limits the job to 5 minutes"},{"id":"d","text":"Requires 5 runners to be online before starting"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`parallel: N` creates N parallel instances of the job (each with `CI_NODE_INDEX`/`CI_NODE_TOTAL`), often used to split test suites. It is not retry, timeout, or a runner-count gate.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `parallel: 5` on a job do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword defines per-job or global environment variables directly in `.gitlab-ci.yml`?$tv2$, $tv2$[{"id":"a","text":"variables"},{"id":"b","text":"env"},{"id":"c","text":"export"},{"id":"d","text":"params"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `variables` keyword defines CI/CD variables globally or per job in the YAML. `env`, `export`, and `params` are not GitLab CI keywords for declaring variables.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword defines per-job or global environment variables directly in `.gitlab-ci.yml`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job has `artifacts: paths: [build/]` and `expire_in: 1 week`. What happens after one week?$tv2$, $tv2$[{"id":"a","text":"The job is deleted"},{"id":"b","text":"The stored artifacts for that job are removed automatically"},{"id":"c","text":"The pipeline reruns"},{"id":"d","text":"The cache is cleared"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`expire_in` controls how long artifacts are retained; after the period GitLab deletes those artifacts (unless kept as latest). It does not delete the job, rerun the pipeline, or clear cache.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job has `artifacts: paths: [build/]` and `expire_in: 1 week`. What happens after one week?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword lets a job start before earlier-stage jobs finish, based on an explicit dependency list (DAG)?$tv2$, $tv2$[{"id":"a","text":"needs"},{"id":"b","text":"stage"},{"id":"c","text":"only"},{"id":"d","text":"tags"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`needs` creates a directed acyclic graph so a job runs as soon as its needed jobs complete, ignoring strict stage ordering. `stage` enforces ordering, `only` filters inclusion, and `tags` selects runners.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword lets a job start before earlier-stage jobs finish, based on an explicit dependency list (DAG)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$A pipeline must deploy to staging automatically but require a click for production. How is this typically modeled?$tv2$, $tv2$[{"id":"a","text":"Both jobs use when: always"},{"id":"b","text":"staging deploy uses when: on_success; production deploy uses when: manual with environment: production"},{"id":"c","text":"Both jobs use when: never"},{"id":"d","text":"Use only the build stage"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Automatic staging plus a manual production gate is the standard pattern: staging runs on success, production is a `when: manual` job with `environment: production` so a human approves the release.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A pipeline must deploy to staging automatically but require a click for production. How is this typically modeled?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `interruptible: true` on a job allow GitLab to do?$tv2$, $tv2$[{"id":"a","text":"Automatically cancel the job/pipeline if a newer pipeline starts for the same ref"},{"id":"b","text":"Pause the job for manual approval"},{"id":"c","text":"Retry the job indefinitely"},{"id":"d","text":"Run the job on any runner"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`interruptible: true` marks a job safe to cancel so GitLab can auto-cancel redundant running pipelines when a newer commit is pushed, saving CI minutes. It is not approval, retry, or runner selection.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `interruptible: true` on a job allow GitLab to do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What does mentioning `@username` in an issue or MR comment do?$tv2$, $tv2$[{"id":"a","text":"Assigns the issue to that user permanently"},{"id":"b","text":"Notifies (mentions) that user and creates a link to their profile"},{"id":"c","text":"Deletes that user"},{"id":"d","text":"Grants that user Owner access"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`@username` mentions the user, sending them a notification and linking their profile. It does not assign, delete, or change permissions.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does mentioning `@username` in an issue or MR comment do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which quick action assigns the current issue to a user from a comment?$tv2$, $tv2$[{"id":"a","text":"/assign @user"},{"id":"b","text":"/owner @user"},{"id":"c","text":"/give @user"},{"id":"d","text":"/take @user only"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/assign @user` sets the assignee (and `/assign me` assigns yourself). `/owner`, `/give`, and `/take @user only` are not the assign quick action.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which quick action assigns the current issue to a user from a comment?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is an issue board list most commonly backed by?$tv2$, $tv2$[{"id":"a","text":"A label"},{"id":"b","text":"A commit"},{"id":"c","text":"A runner tag"},{"id":"d","text":"A cache key"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Board lists are typically created from labels (or assignees/milestones); moving a card between label lists updates the issue's labels. Commits, runner tags, and cache keys do not back board lists.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is an issue board list most commonly backed by?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How do epics differ from milestones?$tv2$, $tv2$[{"id":"a","text":"Epics are time-boxed; milestones group unrelated commits"},{"id":"b","text":"Epics group related issues (often across projects) under an initiative; milestones track a time-boxed scope of work"},{"id":"c","text":"They are identical features"},{"id":"d","text":"Milestones are a Git concept"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Epics organize related issues (frequently across projects) toward a larger goal; milestones track a defined, often time-boxed set of issues/MRs with dates and progress. They are distinct, non-Git features.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"},{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How do epics differ from milestones?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about merge request approvals.$tv2$, $tv2$[{"id":"a","text":"You can require a minimum number of approvals before merging."},{"id":"b","text":"Approval rules can require specific users or groups (e.g. code owners)."},{"id":"c","text":"An approval can be configured to be removed when new commits are pushed."},{"id":"d","text":"Approvals are purely cosmetic and never block merging."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Approvals can enforce a minimum count, require specific approvers/groups, and optionally reset on new commits. They are an enforced merge gate, not cosmetic.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about merge request approvals.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Including `Closes #15` in a merge request description has what effect?$tv2$, $tv2$[{"id":"a","text":"It deletes issue #15 immediately"},{"id":"b","text":"It links the MR to issue #15 and closes it automatically when the MR merges to the default branch"},{"id":"c","text":"It assigns issue #15 to you"},{"id":"d","text":"It creates 15 new issues"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Closing keywords like `Closes #15` in an MR description link the issue and auto-close it upon merge to the default branch. It does not delete immediately, assign, or create issues.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Including `Closes #15` in a merge request description has what effect?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which quick action sets a milestone on an issue from a comment?$tv2$, $tv2$[{"id":"a","text":"/milestone %\"2.0 Release\""},{"id":"b","text":"/release 2.0"},{"id":"c","text":"/due 2.0"},{"id":"d","text":"/sprint 2.0"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/milestone %"Milestone Name"` assigns a milestone via quick action. `/release`, `/due`, and `/sprint` are not the milestone quick action (`/due` sets a due date instead).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which quick action sets a milestone on an issue from a comment?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which role is the highest default privilege level for a project or group in GitLab?$tv2$, $tv2$[{"id":"a","text":"Owner"},{"id":"b","text":"Maintainer"},{"id":"c","text":"Developer"},{"id":"d","text":"Reporter"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Owner is the top default role, able to administer the project/group including deletion, visibility, and member/role management. Maintainer is below it; Developer/Reporter are lower still.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which role is the highest default privilege level for a project or group in GitLab?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which scanner inspects your own application source code (not dependencies) for insecure patterns without running it?$tv2$, $tv2$[{"id":"a","text":"Dependency Scanning"},{"id":"b","text":"SAST"},{"id":"c","text":"Secret Detection"},{"id":"d","text":"Container Scanning"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$SAST statically analyzes your source code for vulnerabilities. Dependency Scanning targets third-party libraries, Secret Detection finds credentials, and Container Scanning analyzes image OS/packages.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which scanner inspects your own application source code (not dependencies) for insecure patterns without running it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A team wants every change to the default branch to be reviewed and to leave an auditable trail. Which combination best achieves this?$tv2$, $tv2$[{"id":"a","text":"Allow direct pushes and disable audit events"},{"id":"b","text":"Protect the branch, require MR approvals, and rely on audit events for change tracking"},{"id":"c","text":"Give all users Owner and remove approvals"},{"id":"d","text":"Use only Git stash"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Protecting the branch with required approvals enforces review, while audit events provide the immutable record of who changed what — together forming a strong compliance control. The other options weaken or remove controls.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A team wants every change to the default branch to be reviewed and to leave an auditable trail. Which combination best achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which project visibility level allows any authenticated user on the GitLab instance to view it, but not anonymous users?$tv2$, $tv2$[{"id":"a","text":"Public"},{"id":"b","text":"Internal"},{"id":"c","text":"Private"},{"id":"d","text":"Protected"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Internal visibility lets any signed-in instance user view the project; Public allows anyone (including anonymous), and Private restricts to members. "Protected" is not a visibility level.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which project visibility level allows any authenticated user on the GitLab instance to view it, but not anonymous users?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL good practices for handling secrets in GitLab CI/CD.$tv2$, $tv2$[{"id":"a","text":"Store secrets as masked, protected CI/CD variables instead of in the repo."},{"id":"b","text":"Use the short-lived CI_JOB_TOKEN or scoped tokens where possible."},{"id":"c","text":"Commit production passwords directly in .gitlab-ci.yml for convenience."},{"id":"d","text":"Rotate any credential that is detected as leaked."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Best practice: keep secrets out of the repo (masked/protected variables), prefer short-lived/scoped tokens, and rotate leaked credentials. Committing production passwords into YAML is a serious anti-pattern.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL good practices for handling secrets in GitLab CI/CD.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Where do GitLab security scan results for an MR typically appear so reviewers can gate the merge?$tv2$, $tv2$[{"id":"a","text":"Only in email"},{"id":"b","text":"In the MR security widget / pipeline Security tab listing newly introduced vulnerabilities"},{"id":"c","text":"In the Git stash"},{"id":"d","text":"In the runner logs only"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Scan results surface in the MR security widget and pipeline Security tab, highlighting vulnerabilities introduced by the change so reviewers can require fixes before merging.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Where do GitLab security scan results for an MR typically appear so reviewers can gate the merge?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: The principle of least privilege suggests assigning users the lowest role that still lets them do their job (e.g. Reporter instead of Maintainer when they only need read access).$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Least privilege minimizes risk by granting only the access required; in GitLab that means choosing the lowest sufficient role (Guest/Reporter/Developer/Maintainer/Owner) for each user.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: The principle of least privilege suggests assigning users the lowest role that still lets them do their job (e.g. Reporter instead of Maintainer when they only need read access).$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the working tree status — which files are staged, modified, or untracked?$tv2$, $tv2$[{"id":"a","text":"git log"},{"id":"b","text":"git status"},{"id":"c","text":"git diff --cached"},{"id":"d","text":"git show"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git status` summarizes staged, modified, and untracked files plus branch tracking info. `git log` shows commit history, `git diff --cached` shows only the staged diff, and `git show` displays a single commit.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the working tree status — which files are staged, modified, or untracked?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You committed with a typo in the message and have not pushed yet. Which command edits the most recent commit message?$tv2$, $tv2$[{"id":"a","text":"git commit --amend"},{"id":"b","text":"git rebase --continue"},{"id":"c","text":"git revert HEAD"},{"id":"d","text":"git reset HEAD~1"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git commit --amend` rewrites the latest commit (message and/or staged content). `git revert` creates a new commit that undoes changes, and `git reset HEAD~1` moves the branch pointer back rather than editing the message.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You committed with a typo in the message and have not pushed yet. Which command edits the most recent commit message?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A lightweight Git tag is essentially just a named pointer to a commit, while an annotated tag is a full object storing tagger, date, and a message.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Lightweight tags are simple refs to a commit; annotated tags (`git tag -a`) are stored as full objects with metadata and can be GPG-signed, which is why annotated tags are recommended for releases.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A lightweight Git tag is essentially just a named pointer to a commit, while an annotated tag is a full object storing tagger, date, and a message.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command uploads your local `main` branch commits to the remote named `origin`?$tv2$, $tv2$[{"id":"a","text":"git fetch origin main"},{"id":"b","text":"git push origin main"},{"id":"c","text":"git pull origin main"},{"id":"d","text":"git clone origin main"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git push origin main` sends local commits to the remote branch. `git fetch`/`git pull` download from the remote, and `git clone` creates a new local copy of a repository.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command uploads your local `main` branch commits to the remote named `origin`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is a GitLab project primarily a container for?$tv2$, $tv2$[{"id":"a","text":"Only CI/CD runners"},{"id":"b","text":"A repository plus its issues, merge requests, CI/CD, wiki, and related features"},{"id":"c","text":"Only billing and subscription data"},{"id":"d","text":"A single user account"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A GitLab project bundles the Git repository together with issues, merge requests, pipelines, wiki, registry, and more. It is not limited to runners, billing, or a user account.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is a GitLab project primarily a container for?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A group Owner wants every new project under the group to inherit the same members and permissions automatically. Which structure achieves this?$tv2$, $tv2$[{"id":"a","text":"Create each project as a personal project and add members manually"},{"id":"b","text":"Place the projects in the group (or its subgroups); members and roles cascade down by inheritance"},{"id":"c","text":"Use a protected tag on each project"},{"id":"d","text":"Fork a template project for each new project"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Group and subgroup membership cascades to contained projects, so adding a member at the group level grants inherited access to its projects. Personal projects, tags, and forking do not provide group-wide inherited membership.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A group Owner wants every new project under the group to inherit the same members and permissions automatically. Which structure achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about the GitLab fork-based contribution workflow.$tv2$, $tv2$[{"id":"a","text":"A fork is a server-side copy of a project that you own and can push to."},{"id":"b","text":"You open a merge request from a branch in your fork targeting the upstream project."},{"id":"c","text":"Forking requires Owner access on the upstream project."},{"id":"d","text":"Maintainers of the upstream project can be allowed to edit the MR source branch."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Forks are your own server-side copies; MRs go from your fork branch to upstream; and the "Allow commits from members who can merge to the target branch" option lets maintainers edit the source branch. Forking does NOT require Owner access — read access to a public/visible project is enough.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about the GitLab fork-based contribution workflow.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In GitLab Flow, why is the main branch generally kept deployable at all times?$tv2$, $tv2$[{"id":"a","text":"So that broken code can be released faster"},{"id":"b","text":"Because feature work is integrated only after passing review and CI, keeping main stable and releasable"},{"id":"c","text":"Because main cannot be protected"},{"id":"d","text":"Because GitLab forbids feature branches"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab Flow keeps main releasable by merging only reviewed, CI-passing changes via merge requests. Main can and should be protected, and feature branches are central to the flow — not forbidden.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In GitLab Flow, why is the main branch generally kept deployable at all times?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the role of a GitLab Runner?$tv2$, $tv2$[{"id":"a","text":"It stores the project's Git history"},{"id":"b","text":"It is the agent that picks up CI/CD jobs and executes them"},{"id":"c","text":"It renders the merge request diff"},{"id":"d","text":"It manages user permissions"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A GitLab Runner is the agent that polls GitLab for jobs and runs them (using an executor such as docker or shell). It does not store Git history, render diffs, or manage permissions.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the role of a GitLab Runner?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A pipeline uses a job with `trigger: include: child-pipeline.yml`. This creates which kind of pipeline relationship?$tv2$, $tv2$[{"id":"a","text":"A merge request pipeline"},{"id":"b","text":"A parent-child pipeline, where the parent triggers a separate child pipeline"},{"id":"c","text":"A scheduled pipeline"},{"id":"d","text":"A manual pipeline only"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Using `trigger` to run another configuration creates a parent-child (downstream) pipeline; the child runs as its own pipeline orchestrated by the parent. This is distinct from merge request, scheduled, or manual pipeline types.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/pipelines/downstream_pipelines.html","label":"GitLab Docs — Parent-child pipelines"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A pipeline uses a job with `trigger: include: child-pipeline.yml`. This creates which kind of pipeline relationship?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A `build` job produces a compiled binary that a later `test` job must use. Which keyword should `build` use so the file is passed forward reliably?$tv2$, $tv2$[{"id":"a","text":"cache:"},{"id":"b","text":"artifacts:"},{"id":"c","text":"services:"},{"id":"d","text":"variables:"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Build outputs that must reach later jobs should be declared as `artifacts`, which GitLab stores and passes to downstream jobs by default. `cache` is best-effort reuse between runs and is not a reliable hand-off mechanism.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A `build` job produces a compiled binary that a later `test` job must use. Which keyword should `build` use so the file is passed forward reliably?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about `rules` vs `only`/`except` in GitLab CI/CD.$tv2$, $tv2$[{"id":"a","text":"rules is the recommended, more flexible mechanism and can use rules:if and rules:changes."},{"id":"b","text":"only/except are older keywords and should not be combined with rules in the same job."},{"id":"c","text":"rules can set when and allow_failure per condition."},{"id":"d","text":"only/except can evaluate complex CI/CD variable expressions exactly like rules:if."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$rules is the modern, flexible approach (supports `if`, `changes`, per-rule `when`/`allow_failure`) and must not be mixed with only/except in the same job. only/except are simpler and do NOT support the full expression capability of rules:if.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about `rules` vs `only`/`except` in GitLab CI/CD.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You want a CI/CD job to build and push a Docker image to the project's built-in image storage. Which GitLab feature is that storage?$tv2$, $tv2$[{"id":"a","text":"GitLab Pages"},{"id":"b","text":"The Container Registry"},{"id":"c","text":"The CI/CD cache"},{"id":"d","text":"Job artifacts"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The GitLab Container Registry is the integrated registry for storing/distributing Docker images per project (with predefined `CI_REGISTRY*` variables). Pages hosts static sites; cache/artifacts store build files, not container images.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/packages/container_registry/","label":"GitLab Docs — Container Registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a CI/CD job to build and push a Docker image to the project's built-in image storage. Which GitLab feature is that storage?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job named `pages` publishes the contents of its `public/` directory as a static website. Which GitLab feature does this?$tv2$, $tv2$[{"id":"a","text":"GitLab Pages"},{"id":"b","text":"Container Registry"},{"id":"c","text":"Environments"},{"id":"d","text":"Releases"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab Pages serves a static site from artifacts produced by a job conventionally named `pages` that exposes a `public/` directory. The Registry stores images, Environments track deployments, and Releases publish versioned release notes/assets.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/pages/","label":"GitLab Docs — GitLab Pages"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job named `pages` publishes the contents of its `public/` directory as a static website. Which GitLab feature does this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which merge method results in a single commit on the target branch that combines all of the merge request's commits?$tv2$, $tv2$[{"id":"a","text":"Merge commit"},{"id":"b","text":"Squash and merge (squashing the MR commits into one)"},{"id":"c","text":"Fast-forward only"},{"id":"d","text":"Cherry-pick each commit individually"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Squash combines all MR commits into a single commit on the target branch, keeping history tidy. A plain merge commit preserves individual commits, fast-forward keeps them linearly, and cherry-pick is a separate manual operation.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which merge method results in a single commit on the target branch that combines all of the merge request's commits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want a merge request to merge automatically as soon as its pipeline passes, without watching it. Which feature do you use?$tv2$, $tv2$[{"id":"a","text":"Draft status"},{"id":"b","text":"Merge when pipeline succeeds (auto-merge)"},{"id":"c","text":"Closing the linked issue"},{"id":"d","text":"Adding a milestone"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Auto-merge ("Merge when pipeline succeeds") queues the MR to merge automatically once the pipeline is green and other conditions are met. Draft blocks merging, and issues/milestones do not trigger merges.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/auto_merge.html","label":"GitLab Docs — Merge when pipeline succeeds"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want a merge request to merge automatically as soon as its pipeline passes, without watching it. Which feature do you use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which feature lets you apply colored, named categories to issues and merge requests for filtering and board organization?$tv2$, $tv2$[{"id":"a","text":"Labels"},{"id":"b","text":"Tags"},{"id":"c","text":"Releases"},{"id":"d","text":"Runners"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Labels are colored, named categories applied to issues/MRs/epics, used for filtering and board lists. Git tags mark commits, releases publish versioned artifacts, and runners execute CI jobs.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which feature lets you apply colored, named categories to issues and merge requests for filtering and board organization?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which default role is required to administer project settings, manage members, and configure protected branches (short of full Owner)?$tv2$, $tv2$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Maintainer"}]$tv2$::jsonb, $tv2$["d"]$tv2$::jsonb, $tv2$Maintainer can manage project settings, members, and protected branches. Guest/Reporter are read-oriented, Developer can push to non-protected branches but not administer the project; Owner is the top-level role.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which default role is required to administer project settings, manage members, and configure protected branches (short of full Owner)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: GitLab security scanners such as SAST and Secret Detection are typically run as jobs inside the CI/CD pipeline.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. GitLab security scanning (SAST, Secret Detection, Dependency Scanning, etc.) is delivered as CI/CD jobs (often via includable templates), so results appear in the pipeline and merge request security widget.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: GitLab security scanners such as SAST and Secret Detection are typically run as jobs inside the CI/CD pipeline.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$For compliance, an organization needs an immutable record of who changed group membership and when. Which capability provides this?$tv2$, $tv2$[{"id":"a","text":"CI/CD pipeline logs"},{"id":"b","text":"Audit events / audit logging"},{"id":"c","text":"Issue comments"},{"id":"d","text":"The container registry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Audit events capture security/compliance-relevant changes (membership, permissions, settings) with actor and timestamp for review. Pipeline logs, issue comments, and the registry are not designed as the authoritative audit trail.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"},{"url":"https://docs.gitlab.com/ee/administration/compliance.html","label":"GitLab Docs — Compliance"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$For compliance, an organization needs an immutable record of who changed group membership and when. Which capability provides this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the primary purpose of `git add`?$tv2$, $tv2$[{"id":"a","text":"To create a new branch"},{"id":"b","text":"To stage changes so they are included in the next commit"},{"id":"c","text":"To upload commits to the remote"},{"id":"d","text":"To delete files from history"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git add` moves working-tree changes into the staging area (index) for the next commit. Branching, pushing, and history rewriting use different commands.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the primary purpose of `git add`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command commits all changes to already-tracked files without separately running `git add`?$tv2$, $tv2$[{"id":"a","text":"git commit -a -m \"msg\""},{"id":"b","text":"git commit --new -m \"msg\""},{"id":"c","text":"git add --commit -m \"msg\""},{"id":"d","text":"git push -a -m \"msg\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git commit -a -m "msg"` auto-stages modifications and deletions of tracked files, then commits. It does NOT include brand-new untracked files (those still need `git add`).$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command commits all changes to already-tracked files without separately running `git add`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want to temporarily save uncommitted work including untracked files before switching context. Which command does that?$tv2$, $tv2$[{"id":"a","text":"git stash -u (or --include-untracked)"},{"id":"b","text":"git reset --hard"},{"id":"c","text":"git clean -fd"},{"id":"d","text":"git commit -u"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git stash -u` (`--include-untracked`) stashes modified tracked files plus untracked files, leaving a clean tree to restore later. `reset --hard`/`clean -fd` destroy changes, and `commit -u` is not valid.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to temporarily save uncommitted work including untracked files before switching context. Which command does that?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `git pull --rebase` do differently from a plain `git pull`?$tv2$, $tv2$[{"id":"a","text":"It deletes local commits"},{"id":"b","text":"It fetches and then rebases your local commits on top of the updated remote branch instead of creating a merge commit"},{"id":"c","text":"It pushes instead of pulling"},{"id":"d","text":"It only fetches without integrating"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`git pull --rebase` replays your local commits on top of the fetched remote tip, producing a linear history without a merge commit. Plain `git pull` merges instead. It does not delete commits or push.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `git pull --rebase` do differently from a plain `git pull`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A lightweight tag and a branch are the same thing in Git.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. Both are refs, but a branch is meant to move as you commit, while a tag is intended as a fixed marker on a specific commit (e.g. a release point) and does not advance automatically.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A lightweight tag and a branch are the same thing in Git.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists which commit and author last modified each line of `app.py`?$tv2$, $tv2$[{"id":"a","text":"git blame app.py"},{"id":"b","text":"git log app.py"},{"id":"c","text":"git diff app.py"},{"id":"d","text":"git show app.py"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git blame app.py` annotates each line with the commit, author, and timestamp that last changed it. `git log` shows commit history, `diff` shows changes, and `show` displays a commit.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists which commit and author last modified each line of `app.py`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which command downloads new commits and refs from `origin` without changing your working branch?$tv2$, $tv2$[{"id":"a","text":"git fetch origin"},{"id":"b","text":"git pull origin"},{"id":"c","text":"git merge origin"},{"id":"d","text":"git push origin"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`git fetch origin` updates remote-tracking refs only. `git pull` also integrates them into the current branch, `git merge` combines branches, and `git push` uploads commits.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command downloads new commits and refs from `origin` without changing your working branch?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `git checkout -- file.txt` (or `git restore file.txt`) do?$tv2$, $tv2$[{"id":"a","text":"Stages file.txt"},{"id":"b","text":"Discards unstaged changes in file.txt, restoring it to the last committed version"},{"id":"c","text":"Deletes file.txt from history"},{"id":"d","text":"Creates a branch named file.txt"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$It reverts working-tree changes for that file to the committed state, discarding unstaged edits. It does not stage, rewrite history, or create a branch.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `git checkout -- file.txt` (or `git restore file.txt`) do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Git and GitLab Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Git as a distributed VCS.$tv2$, $tv2$[{"id":"a","text":"Each clone contains the full project history."},{"id":"b","text":"You can commit locally without network access."},{"id":"c","text":"A central server is mandatory for making any commit."},{"id":"d","text":"Branching and merging are core, lightweight operations."}]$tv2$::jsonb, $tv2$["a","b","d"]$tv2$::jsonb, $tv2$Distributed Git gives every clone full history, allows offline local commits, and treats branching/merging as cheap operations. A central server is a convention (e.g. GitLab) but not required to commit.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Git as a distributed VCS.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the recommended way to integrate a finished feature branch into main in GitLab?$tv2$, $tv2$[{"id":"a","text":"Push directly to main"},{"id":"b","text":"Open a merge request from the feature branch to main and merge after review/CI"},{"id":"c","text":"Email the diff to a maintainer"},{"id":"d","text":"Rename main to the feature branch"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Open an MR from the feature branch targeting main; after review and a green pipeline it is merged. Direct pushes bypass review/CI, and emailing/renaming are not GitLab workflows.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the recommended way to integrate a finished feature branch into main in GitLab?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which protected-branch capability requires that the person who pushed/authored a change cannot also be its sole approver?$tv2$, $tv2$[{"id":"a","text":"Prevent approval by the author / separation-of-duties approval settings"},{"id":"b","text":"Squash commits"},{"id":"c","text":"Delete source branch"},{"id":"d","text":"Fast-forward merge"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$GitLab approval settings can prevent authors (and optionally committers) from approving their own MRs, enforcing separation of duties. Squash, delete-source-branch, and fast-forward are merge behaviors, not approval controls.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which protected-branch capability requires that the person who pushed/authored a change cannot also be its sole approver?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the target branch field of a merge request specify?$tv2$, $tv2$[{"id":"a","text":"The branch the source changes will be merged into"},{"id":"b","text":"The branch that contains the proposed changes"},{"id":"c","text":"The runner that builds the MR"},{"id":"d","text":"The label applied to the MR"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The target branch is where the MR's changes will land (often the default branch). The source branch holds the proposed changes; runners and labels are unrelated to this field.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the target branch field of a merge request specify?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about protected branches and merge requests working together.$tv2$, $tv2$[{"id":"a","text":"Setting push to \"No one\" forces changes through merge requests."},{"id":"b","text":"You can require approvals before a protected branch MR can merge."},{"id":"c","text":"Code owner approval can be required for protected branches."},{"id":"d","text":"Protected branches automatically merge all open MRs."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Protecting a branch (no direct push) plus required approvals and optional code-owner approval enforces a reviewed MR workflow. Protected branches do NOT auto-merge open MRs.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about protected branches and merge requests working together.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why might a team choose "Squash and merge" as the default merge method?$tv2$, $tv2$[{"id":"a","text":"To preserve every WIP commit on main"},{"id":"b","text":"To keep the target branch history clean with one tidy commit per merge request"},{"id":"c","text":"To delete the target branch"},{"id":"d","text":"To skip code review"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Squashing condenses an MR's many work-in-progress commits into a single coherent commit on the target branch, keeping history clean. It does not delete branches or bypass review.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why might a team choose "Squash and merge" as the default merge method?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A subgroup `team-a` is under group `engineering`. A user added as Developer on `engineering` has what access to projects in `team-a`?$tv2$, $tv2$[{"id":"a","text":"No access at all"},{"id":"b","text":"Inherited Developer access to projects in team-a via group membership cascade"},{"id":"c","text":"Owner access automatically"},{"id":"d","text":"Read-only regardless of role"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Membership cascades down the namespace: a Developer on `engineering` inherits Developer access to subgroups like `team-a` and their projects (unless further restricted). It is neither no access nor automatic Owner.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A subgroup `team-a` is under group `engineering`. A user added as Developer on `engineering` has what access to projects in `team-a`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In a fork-based contribution, where do you push your changes?$tv2$, $tv2$[{"id":"a","text":"Directly to the upstream default branch"},{"id":"b","text":"To a branch in your own fork, then open a merge request to upstream"},{"id":"c","text":"To the upstream wiki"},{"id":"d","text":"To the container registry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$You push to a branch in your fork (which you own) and open an MR from there to upstream. You cannot push to upstream without access, and the wiki/registry are not contribution paths.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a fork-based contribution, where do you push your changes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which GitLab Flow practice keeps production deployable and traceable?$tv2$, $tv2$[{"id":"a","text":"Committing experimental code straight to the production branch"},{"id":"b","text":"Merging only reviewed, CI-passing changes forward through environment/main branches via merge requests"},{"id":"c","text":"Force-pushing to production nightly"},{"id":"d","text":"Disabling pipelines for production"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$GitLab Flow promotes only reviewed, tested changes forward via MRs, keeping production deployable and changes traceable. Direct/experimental commits or force-pushes to production undermine stability and traceability.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which GitLab Flow practice keeps production deployable and traceable?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Source Code Management and Workflows$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does adding `upstream` as a remote let a fork owner do?$tv2$, $tv2$[{"id":"a","text":"Push directly to the original project"},{"id":"b","text":"Fetch the latest changes from the original project to keep the fork in sync"},{"id":"c","text":"Delete the original project"},{"id":"d","text":"Bypass merge requests"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$An `upstream` remote lets the fork owner fetch and merge/rebase the original project's latest changes to stay current. It does not grant push access or bypass MRs.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does adding `upstream` as a remote let a fork owner do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is a GitLab CI/CD pipeline?$tv2$, $tv2$[{"id":"a","text":"A single Git branch"},{"id":"b","text":"A collection of jobs grouped into stages that automate build, test, and deploy"},{"id":"c","text":"A user role"},{"id":"d","text":"A container image registry"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A pipeline is the top-level CI/CD construct: jobs organized into ordered stages that automate building, testing, and deploying. It is not a branch, role, or registry.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is a GitLab CI/CD pipeline?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Within one stage, if two jobs are defined, how do they execute (given enough runners)?$tv2$, $tv2$[{"id":"a","text":"Sequentially, alphabetically"},{"id":"b","text":"In parallel"},{"id":"c","text":"Only the last one runs"},{"id":"d","text":"They merge into a single job"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Jobs in the same stage run in parallel (subject to runner availability); the pipeline advances only when all of them succeed. They are not serialized or merged.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Within one stage, if two jobs are defined, how do they execute (given enough runners)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword would you use to ensure a job runs even if a previous-stage job failed (e.g. for notifications)?$tv2$, $tv2$[{"id":"a","text":"when: always"},{"id":"b","text":"when: on_success"},{"id":"c","text":"when: never"},{"id":"d","text":"allow_failure: false"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`when: always` runs the job regardless of earlier success/failure, useful for notifications/cleanup. `on_success` (default) skips it on failure, `never` disables it, and `allow_failure` does not control run conditions.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword would you use to ensure a job runs even if a previous-stage job failed (e.g. for notifications)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A job should only run on the default branch. Which rule is correct?$tv2$, $tv2$[{"id":"a","text":"rules: - if: $CI_COMMIT_BRANCH == $CI_DEFAULT_BRANCH"},{"id":"b","text":"rules: - if: $CI_MERGE_REQUEST_IID"},{"id":"c","text":"only: tags"},{"id":"d","text":"when: manual"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Comparing `$CI_COMMIT_BRANCH` to `$CI_DEFAULT_BRANCH` restricts the job to the default branch. The MR variable matches MR pipelines, `only: tags` matches tags, and `when: manual` only changes trigger mode.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A job should only run on the default branch. Which rule is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about artifacts.$tv2$, $tv2$[{"id":"a","text":"Artifacts can be browsed/downloaded from the GitLab UI."},{"id":"b","text":"Artifacts can be passed to jobs in later stages by default."},{"id":"c","text":"expire_in controls how long artifacts are retained."},{"id":"d","text":"Artifacts are the same as cache and have identical guarantees."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Artifacts are stored by GitLab, downloadable, passed downstream by default, and expire via `expire_in`. They are NOT the same as cache — artifacts are reliable hand-offs while cache is best-effort.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about artifacts.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which predefined variable holds the full commit SHA of the pipeline's commit?$tv2$, $tv2$[{"id":"a","text":"CI_COMMIT_SHA"},{"id":"b","text":"CI_PIPELINE_SOURCE"},{"id":"c","text":"CI_JOB_ID"},{"id":"d","text":"CI_PROJECT_NAME"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`CI_COMMIT_SHA` is the commit hash being built. `CI_PIPELINE_SOURCE` is what triggered the pipeline, `CI_JOB_ID` the job ID, and `CI_PROJECT_NAME` the project name.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which predefined variable holds the full commit SHA of the pipeline's commit?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A deploy job uses `environment: name: staging`. Where can you see the deployment history for staging?$tv2$, $tv2$[{"id":"a","text":"In the Git stash"},{"id":"b","text":"On the project's Environments page (Deployments)"},{"id":"c","text":"In the container registry tags"},{"id":"d","text":"In the issue board"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Declaring an environment records deployments visible on the Environments/Deployments page, including history and the ability to re-deploy or roll back. Stash, registry, and boards do not track deployments.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A deploy job uses `environment: name: staging`. Where can you see the deployment history for staging?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword would let a job download artifacts from only a specific named job in an earlier stage?$tv2$, $tv2$[{"id":"a","text":"dependencies: [build_linux]"},{"id":"b","text":"cache: build_linux"},{"id":"c","text":"image: build_linux"},{"id":"d","text":"stage: build_linux"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`dependencies: [build_linux]` restricts artifact downloads to that job. `cache`, `image`, and `stage` serve different purposes and do not scope artifact fetching.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword would let a job download artifacts from only a specific named job in an earlier stage?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 4, $tv2$SINGLE$tv2$::"QType", $tv2$You need build → test → deploy where deploy starts immediately after its specific build job (skip waiting for unrelated test jobs). What do you use?$tv2$, $tv2$[{"id":"a","text":"parallel on deploy"},{"id":"b","text":"needs: [\"build_app\"] on the deploy job to form a DAG"},{"id":"c","text":"allow_failure on test jobs"},{"id":"d","text":"cache:key on deploy"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Adding `needs: ["build_app"]` to deploy creates a DAG so deploy runs as soon as `build_app` completes, regardless of unrelated jobs/stages. `parallel`, `allow_failure`, and `cache:key` do not change ordering this way.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need build → test → deploy where deploy starts immediately after its specific build job (skip waiting for unrelated test jobs). What do you use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `image:` keyword at the top level of `.gitlab-ci.yml` (outside any job) define?$tv2$, $tv2$[{"id":"a","text":"The default container image used by all jobs unless they override it"},{"id":"b","text":"The Git branch to build"},{"id":"c","text":"The runner host"},{"id":"d","text":"The artifact retention"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A top-level `image` sets the default job container; individual jobs can override it with their own `image`. It does not pick branches, runner hosts, or artifact retention.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `image:` keyword at the top level of `.gitlab-ci.yml` (outside any job) define?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which keyword delays a job's start by a configured period after it becomes eligible?$tv2$, $tv2$[{"id":"a","text":"when: delayed (with start_in)"},{"id":"b","text":"timeout"},{"id":"c","text":"retry"},{"id":"d","text":"interruptible"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`when: delayed` with `start_in: <duration>` schedules the job to start after a delay (e.g. delayed rollouts). `timeout` caps runtime, `retry` re-runs failures, and `interruptible` enables auto-cancel.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which keyword delays a job's start by a configured period after it becomes eligible?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How do you reuse a common job definition defined as `.deploy_base` for two deploy jobs?$tv2$, $tv2$[{"id":"a","text":"extends: .deploy_base in each deploy job"},{"id":"b","text":"include: .deploy_base"},{"id":"c","text":"needs: .deploy_base"},{"id":"d","text":"trigger: .deploy_base"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`extends: .deploy_base` inherits and lets each job override the hidden template's configuration. `include` is for external files, `needs` builds a DAG, and `trigger` starts downstream pipelines.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How do you reuse a common job definition defined as `.deploy_base` for two deploy jobs?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$CI/CD Pipelines$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `coverage: '/Total.*?(\d+\.\d+)%/'` in a job do?$tv2$, $tv2$[{"id":"a","text":"Sets the test timeout"},{"id":"b","text":"Extracts a code coverage percentage from job output to display in the UI/MR"},{"id":"c","text":"Defines artifacts"},{"id":"d","text":"Selects a runner"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `coverage` keyword applies a regex to the job log to capture a coverage percentage that GitLab then displays on the pipeline/MR. It is unrelated to timeouts, artifacts, or runner selection.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `coverage: '/Total.*?(\d+\.\d+)%/'` in a job do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What does referencing `#42` in an issue or MR comment create?$tv2$, $tv2$[{"id":"a","text":"A deletion of issue 42"},{"id":"b","text":"A cross-link/reference to issue number 42"},{"id":"c","text":"A new merge request"},{"id":"d","text":"An assignment to user 42"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$In GitLab, `#42` links issue 42 (and `!42` links MR 42). It creates a navigable cross-reference, not a deletion, MR, or assignment.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does referencing `#42` in an issue or MR comment create?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which feature is best for grouping related issues across multiple projects under one initiative?$tv2$, $tv2$[{"id":"a","text":"Epics"},{"id":"b","text":"Labels only"},{"id":"c","text":"Git tags"},{"id":"d","text":"Snippets"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Epics (a group-level feature) collect related issues that may span projects under a single initiative with their own timeline. Labels categorize but do not provide hierarchy; tags/snippets are unrelated.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which feature is best for grouping related issues across multiple projects under one initiative?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A quick action `/spend 2h` on an issue does what?$tv2$, $tv2$[{"id":"a","text":"Records 2 hours of time spent on the issue"},{"id":"b","text":"Sets a 2-hour due date"},{"id":"c","text":"Closes the issue after 2 hours"},{"id":"d","text":"Assigns 2 users"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/spend 2h` logs time spent (paired with `/estimate` for the estimate). It is not a due date, auto-close timer, or assignment action.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A quick action `/spend 2h` on an issue does what?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which capability lets you see remaining vs completed work for a milestone over its timeframe?$tv2$, $tv2$[{"id":"a","text":"Burndown/burnup charts"},{"id":"b","text":"CI/CD cache"},{"id":"c","text":"Container registry"},{"id":"d","text":"Git reflog"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Milestone burndown/burnup charts visualize progress (remaining/completed work) across the milestone period. Cache, registry, and reflog are unrelated to milestone tracking.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which capability lets you see remaining vs completed work for a milestone over its timeframe?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$How does a label-based issue board column relate to issue labels?$tv2$, $tv2$[{"id":"a","text":"Each board list maps to a label; moving a card changes the issue's labels accordingly"},{"id":"b","text":"Board lists ignore labels entirely"},{"id":"c","text":"A board can only have one list"},{"id":"d","text":"Boards delete labels when used"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Label-based board lists correspond to labels; dragging a card between lists updates the issue's labels to match the destination list. Boards support many lists and do not delete labels.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How does a label-based issue board column relate to issue labels?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about GitLab issues.$tv2$, $tv2$[{"id":"a","text":"Issues can have assignees, labels, milestones, and a due date."},{"id":"b","text":"Issues support threaded discussion and mentions."},{"id":"c","text":"Closing keywords in a merged MR can auto-close linked issues."},{"id":"d","text":"Issues are stored as Git tags in the repository."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Issues support assignees, labels, milestones, due dates, threaded discussion/mentions, and auto-close via MR keywords. They are stored in GitLab's database, NOT as Git tags in the repo.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about GitLab issues.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Project Management and Collaboration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `/label ~bug` quick action do in an issue?$tv2$, $tv2$[{"id":"a","text":"Adds the bug label to the issue"},{"id":"b","text":"Deletes all labels"},{"id":"c","text":"Closes the issue"},{"id":"d","text":"Creates a label called issue"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`/label ~bug` applies the `bug` label (`/unlabel` removes labels). It does not delete all labels, close the issue, or create a label named "issue".$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `/label ~bug` quick action do in an issue?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which default role can push to non-protected branches but cannot manage project members or settings?$tv2$, $tv2$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Owner"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Developer can push to non-protected branches and open MRs but cannot administer members/settings/protected branches (that needs Maintainer/Owner). Guest/Reporter cannot push code.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which default role can push to non-protected branches but cannot manage project members or settings?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which scanner is specifically aimed at finding committed credentials such as tokens and keys?$tv2$, $tv2$[{"id":"a","text":"SAST"},{"id":"b","text":"Secret Detection"},{"id":"c","text":"Dependency Scanning"},{"id":"d","text":"Container Scanning"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Secret Detection scans code and history for leaked credentials. SAST analyzes code logic, Dependency Scanning checks libraries, and Container Scanning inspects image packages.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which scanner is specifically aimed at finding committed credentials such as tokens and keys?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$An organization needs to prove that every production change was reviewed by someone other than the author. Which combination supports this audit requirement?$tv2$, $tv2$[{"id":"a","text":"Allow self-approval and disable logging"},{"id":"b","text":"Require MR approvals with author self-approval prevented, plus audit events"},{"id":"c","text":"Give all users Owner"},{"id":"d","text":"Use only Git tags"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Requiring approvals while preventing the author from approving enforces independent review (separation of duties), and audit events provide the immutable proof. Self-approval or universal Owner undermines the control.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An organization needs to prove that every production change was reviewed by someone other than the author. Which combination supports this audit requirement?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which project visibility allows anyone, including users who are not signed in, to view the project?$tv2$, $tv2$[{"id":"a","text":"Private"},{"id":"b","text":"Internal"},{"id":"c","text":"Public"},{"id":"d","text":"Restricted"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Public visibility lets anyone (including anonymous visitors) view the project. Internal requires sign-in, Private restricts to members, and "Restricted" is not a visibility level.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which project visibility allows anyone, including users who are not signed in, to view the project?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about GitLab security scanning.$tv2$, $tv2$[{"id":"a","text":"Scanners typically run as CI/CD jobs, often added via include templates."},{"id":"b","text":"Findings appear in the pipeline Security tab and the MR security widget."},{"id":"c","text":"SAST analyzes source code without executing it."},{"id":"d","text":"Security scanners replace the need for code review."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$GitLab scanners run as CI jobs (added via templates), surface results in the pipeline/MR, and SAST is static analysis. They complement — but do NOT replace — human code review and approvals.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about GitLab security scanning.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A live token was leaked in a commit. Beyond removing it from code, what is essential?$tv2$, $tv2$[{"id":"a","text":"Nothing else is needed"},{"id":"b","text":"Revoke/rotate the token because it remains recoverable in Git history"},{"id":"c","text":"Make the project public"},{"id":"d","text":"Add it to .gitignore"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Because Git history retains the secret, deleting it from the latest code is insufficient — the token must be revoked/rotated. `.gitignore` only affects future tracking, not existing history.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A live token was leaked in a commit. Beyond removing it from code, what is essential?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Security and Compliance Basics$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Storing a deploy key or token as a masked, protected CI/CD variable is more secure than committing it to the repository.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Masked/protected variables keep secrets out of Git history, hide them in logs, and limit exposure to protected branches/tags — far safer than committing them into the repository.$tv2$, $tv2$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:gitlab-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$gitlab-certified-associate-p3$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Storing a deploy key or token as a masked, protected CI/CD variable is more secure than committing it to the repository.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement BEST describes the core idea of Infrastructure as Code (IaC)?$tv2$, $tv2$[{"id":"a","text":"Provisioning infrastructure by manually clicking through a cloud console and recording the steps in a wiki."},{"id":"b","text":"Defining and managing infrastructure through machine-readable configuration files that can be versioned, reviewed, and reused."},{"id":"c","text":"Running operating-system patches automatically on a fixed schedule."},{"id":"d","text":"Storing application source code in a version control system."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$IaC means infrastructure is described in declarative/configuration files that can be version-controlled and reused. Manual console clicks and OS patching are not IaC, and storing app source code alone is just source control.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement BEST describes the core idea of Infrastructure as Code (IaC)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A team adopts IaC and commits all Terraform configuration to Git. Which benefit is MOST directly enabled by this practice?$tv2$, $tv2$[{"id":"a","text":"Infrastructure changes can be peer-reviewed and rolled back like application code."},{"id":"b","text":"Terraform no longer needs to track state."},{"id":"c","text":"Cloud provider credentials are no longer required."},{"id":"d","text":"Resources are provisioned without any API calls."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Version-controlling configuration enables code review, history, and rollback of infrastructure changes. State is still required, credentials are still needed, and Terraform still calls provider APIs.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A team adopts IaC and commits all Terraform configuration to Git. Which benefit is MOST directly enabled by this practice?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which characteristic distinguishes Terraform as a provisioning tool from configuration-management tools like Ansible, Chef, or Puppet?$tv2$, $tv2$[{"id":"a","text":"Terraform focuses on provisioning and managing the lifecycle of infrastructure resources, not on configuring software inside existing servers."},{"id":"b","text":"Terraform can only manage a single cloud provider at a time."},{"id":"c","text":"Terraform requires an agent installed on every managed machine."},{"id":"d","text":"Terraform cannot create or destroy infrastructure resources."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Terraform is primarily a provisioning tool that manages the full lifecycle of infrastructure across many providers, while config-management tools specialize in configuring software on already-provisioned machines. Terraform is multi-cloud and agentless.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which characteristic distinguishes Terraform as a provisioning tool from configuration-management tools like Ansible, Chef, or Puppet?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why is Terraform considered "cloud-agnostic" / multi-cloud?$tv2$, $tv2$[{"id":"a","text":"It only works with HashiCorp Cloud Platform."},{"id":"b","text":"It uses a provider plugin model so the same workflow can manage AWS, Azure, GCP, Kubernetes, and many other platforms."},{"id":"c","text":"It translates configuration into CloudFormation under the hood."},{"id":"d","text":"It requires a different binary for each cloud provider."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Terraform uses a plugin-based provider architecture, so one consistent workflow and language manage resources across many platforms with a single binary. It does not delegate to CloudFormation.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is Terraform considered "cloud-agnostic" / multi-cloud?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which Terraform command must be run FIRST in a new configuration directory to download provider plugins and prepare the backend?$tv2$, $tv2$[{"id":"a","text":"terraform plan"},{"id":"b","text":"terraform apply"},{"id":"c","text":"terraform init"},{"id":"d","text":"terraform validate"}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$`terraform init` initializes the working directory: it downloads provider plugins, installs modules, and configures the backend. Plan, apply, and validate all require an initialized directory.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which Terraform command must be run FIRST in a new configuration directory to download provider plugins and prepare the backend?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In a Terraform configuration, which block is used to declare and constrain the provider plugins a configuration depends on?$tv2$, $tv2$[{"id":"a","text":"The `terraform { required_providers { ... } }` block."},{"id":"b","text":"The `resource` block."},{"id":"c","text":"The `output` block."},{"id":"d","text":"The `data` block."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`required_providers` inside the `terraform` settings block declares each provider's source address and version constraints. Resource/data blocks define infrastructure and outputs expose values.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In a Terraform configuration, which block is used to declare and constrain the provider plugins a configuration depends on?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about the Terraform configuration language (HCL).$tv2$, $tv2$[{"id":"a","text":"HCL is declarative — you describe the desired end state, not step-by-step instructions."},{"id":"b","text":"Resources are addressed as `<resource_type>.<name>` within the configuration."},{"id":"c","text":"Terraform configuration files must use a `.tf` (or `.tf.json`) extension to be loaded."},{"id":"d","text":"Terraform executes resource blocks strictly in the order they appear in the file."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$HCL is declarative, resources are referenced as type.name, and config files use `.tf`/`.tf.json`. Terraform builds a dependency graph and does NOT rely on textual order of blocks.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language","label":"Terraform Docs — Configuration Language"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about the Terraform configuration language (HCL).$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the canonical Terraform core workflow?$tv2$, $tv2$[{"id":"a","text":"Write → Plan → Apply"},{"id":"b","text":"Build → Test → Deploy"},{"id":"c","text":"Init → Destroy → Apply"},{"id":"d","text":"Plan → Validate → Format"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The Terraform core workflow is Write (author config), Plan (preview changes), and Apply (execute). The other sequences are not the documented core workflow.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/tutorials/aws-get-started","label":"Terraform Tutorials — Get Started"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the canonical Terraform core workflow?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `terraform plan` do?$tv2$, $tv2$[{"id":"a","text":"Permanently provisions all resources defined in the configuration."},{"id":"b","text":"Creates an execution plan describing the actions Terraform would take to reach the desired state, without changing real infrastructure."},{"id":"c","text":"Deletes all resources tracked in state."},{"id":"d","text":"Uploads the state file to a remote backend."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform plan` is a read-only preview: it compares desired config to current state and shows additions/changes/deletions without modifying infrastructure. Apply performs changes; destroy removes resources.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `terraform plan` do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You run `terraform apply` and Terraform prompts "Do you want to perform these actions?". Which flag would skip this interactive approval (e.g. in CI)?$tv2$, $tv2$[{"id":"a","text":"-auto-approve"},{"id":"b","text":"-force"},{"id":"c","text":"-no-prompt"},{"id":"d","text":"-yes"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform apply -auto-approve` skips the interactive confirmation. There is no `-force`, `-no-prompt`, or `-yes` flag for this purpose on apply.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You run `terraform apply` and Terraform prompts "Do you want to perform these actions?". Which flag would skip this interactive approval (e.g. in CI)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$In Terraform, what is a module?$tv2$, $tv2$[{"id":"a","text":"A container for multiple resources that are used together, callable from other configurations."},{"id":"b","text":"A single resource block."},{"id":"c","text":"A cloud provider plugin binary."},{"id":"d","text":"A state file stored in a remote backend."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A module is a reusable container of resources (and variables/outputs) that can be called from other configurations via a `module` block. It is not a single resource, a provider, or a state file.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In Terraform, what is a module?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which `module` block argument specifies WHERE the module code comes from?$tv2$, $tv2$[{"id":"a","text":"version"},{"id":"b","text":"source"},{"id":"c","text":"providers"},{"id":"d","text":"depends_on"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The `source` argument is mandatory and tells Terraform where to load the module (local path, registry, Git, etc.). `version` constrains registry module versions; the others have different roles.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `module` block argument specifies WHERE the module code comes from?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A root module needs a value produced inside a child module `network` (e.g. a VPC ID). How is that value exposed and consumed?$tv2$, $tv2$[{"id":"a","text":"The child module declares an `output`; the root module references it as `module.network.<output_name>`."},{"id":"b","text":"The root module reads the child module's state file directly."},{"id":"c","text":"The child module declares a `variable`; the root references `var.network`."},{"id":"d","text":"Child module values are global and need no declaration."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Child modules expose values via `output` blocks, consumed by the caller as `module.<name>.<output>`. Variables are inputs INTO a module, not outputs, and module internals are otherwise encapsulated.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A root module needs a value produced inside a child module `network` (e.g. a VPC ID). How is that value exposed and consumed?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$An EC2 instance was created manually in the AWS console and you want Terraform to manage it going forward. Which command brings the existing resource under Terraform management?$tv2$, $tv2$[{"id":"a","text":"terraform refresh"},{"id":"b","text":"terraform import"},{"id":"c","text":"terraform apply -replace"},{"id":"d","text":"terraform state rm"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform import` associates an existing real-world resource with a Terraform resource address in state. `refresh` only updates state from reality, `-replace` recreates, and `state rm` removes tracking.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/import","label":"Terraform Docs — terraform import"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$An EC2 instance was created manually in the AWS console and you want Terraform to manage it going forward. Which command brings the existing resource under Terraform management?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lets you interactively evaluate Terraform expressions and inspect values such as `var.region` or function results?$tv2$, $tv2$[{"id":"a","text":"terraform show"},{"id":"b","text":"terraform console"},{"id":"c","text":"terraform graph"},{"id":"d","text":"terraform output"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform console` opens an interactive REPL to evaluate expressions, functions, and state data. `show` prints state/plan, `graph` emits the dependency graph, and `output` prints root output values.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/console","label":"Terraform Docs — terraform console"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lets you interactively evaluate Terraform expressions and inspect values such as `var.region` or function results?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the primary purpose of the Terraform state file?$tv2$, $tv2$[{"id":"a","text":"To store provider plugin binaries."},{"id":"b","text":"To map resources defined in configuration to real-world infrastructure objects and track metadata."},{"id":"c","text":"To store the user's cloud credentials."},{"id":"d","text":"To cache the output of `terraform fmt`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$State maps configuration to real resources and stores metadata Terraform needs to plan changes. It is not a credential store, plugin cache, or formatting cache.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the primary purpose of the Terraform state file?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why is a remote backend (e.g. S3, HCP Terraform) recommended over the default local backend for team use?$tv2$, $tv2$[{"id":"a","text":"It makes Terraform run faster on a laptop."},{"id":"b","text":"It provides shared state, optional state locking, and keeps sensitive state off individual workstations."},{"id":"c","text":"It removes the need for provider plugins."},{"id":"d","text":"It disables the need for `terraform init`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Remote backends enable shared, centralized state with locking and reduce the risk of conflicting concurrent applies. They do not affect speed materially, providers, or init requirements.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is a remote backend (e.g. S3, HCP Terraform) recommended over the default local backend for team use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: State locking prevents two users from running operations that write to the same state at the same time, helping avoid state corruption.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. When supported by the backend, Terraform locks state during write operations so concurrent applies cannot corrupt it. Not all backends support locking, but the statement describes its purpose correctly.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: State locking prevents two users from running operations that write to the same state at the same time, helping avoid state corruption.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You want to provide a configurable instance type without hard-coding it. Which construct should you use?$tv2$, $tv2$[{"id":"a","text":"An input variable declared with a `variable` block, referenced as `var.instance_type`."},{"id":"b","text":"An `output` block."},{"id":"c","text":"A `provider` block alias."},{"id":"d","text":"A `terraform` settings block."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Input variables (`variable` blocks, referenced via `var.<name>`) parameterize configuration. Outputs expose values, provider aliases configure multiple provider instances, and the terraform block holds settings.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to provide a configurable instance type without hard-coding it. Which construct should you use?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which construct lets you assign a name to an expression so it can be reused multiple times within a module without re-computing it?$tv2$, $tv2$[{"id":"a","text":"A local value (`locals` block), referenced as `local.<name>`."},{"id":"b","text":"An input variable."},{"id":"c","text":"A data source."},{"id":"d","text":"A provisioner."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Local values defined in a `locals` block name a computed expression for reuse via `local.<name>`. Variables are external inputs, data sources read external data, and provisioners run scripts.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/locals","label":"Terraform Docs — Local Values"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which construct lets you assign a name to an expression so it can be reused multiple times within a module without re-computing it?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which of the following is a benefit of provisioning infrastructure with IaC rather than manual processes?$tv2$, $tv2$[{"id":"a","text":"It removes the need to authenticate to cloud providers."},{"id":"b","text":"It improves consistency and repeatability while reducing human error from manual steps."},{"id":"c","text":"It guarantees infrastructure can never be changed."},{"id":"d","text":"It eliminates the need for any state tracking."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Codifying infrastructure makes provisioning consistent and repeatable and reduces manual mistakes. It does not remove authentication, freeze infrastructure, or eliminate state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which of the following is a benefit of provisioning infrastructure with IaC rather than manual processes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which approach BEST exemplifies "immutable infrastructure" supported by IaC?$tv2$, $tv2$[{"id":"a","text":"Patching running servers in place over SSH for every change."},{"id":"b","text":"Building a new image/resource for each change and replacing the old one rather than mutating it."},{"id":"c","text":"Editing configuration directly in the cloud console."},{"id":"d","text":"Keeping a single long-lived server forever and never replacing it."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Immutable infrastructure replaces resources with newly built ones instead of mutating existing servers in place, improving predictability. In-place patching and console edits are mutable, ad-hoc practices.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which approach BEST exemplifies "immutable infrastructure" supported by IaC?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 1, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Because IaC configuration is stored in version control, infrastructure changes can use the same pull-request review process as application code.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Storing IaC in version control enables code review, history, and collaboration workflows (pull requests) for infrastructure, just like application code.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Because IaC configuration is stored in version control, infrastructure changes can use the same pull-request review process as application code.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL outcomes that IaC tools like Terraform help achieve.$tv2$, $tv2$[{"id":"a","text":"Reproducible environments across dev, staging, and prod."},{"id":"b","text":"A documented, reviewable history of infrastructure changes."},{"id":"c","text":"The ability to preview changes before applying them."},{"id":"d","text":"Guaranteed elimination of all cloud costs."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$IaC delivers reproducibility, an auditable change history, and (with Terraform) plan previews. It does not eliminate cloud costs — you still pay for provisioned resources.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL outcomes that IaC tools like Terraform help achieve.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Terraform is described as "provider-agnostic." What does the provider plugin model primarily enable?$tv2$, $tv2$[{"id":"a","text":"Managing resources across many platforms with one consistent workflow and language."},{"id":"b","text":"Running Terraform without any binary installed."},{"id":"c","text":"Avoiding the need to ever declare resources."},{"id":"d","text":"Storing state only on local disk."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Providers are plugins that let Terraform manage many platforms (clouds, SaaS, Kubernetes) through one consistent HCL workflow. It does not remove the binary, resources, or state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Terraform is described as "provider-agnostic." What does the provider plugin model primarily enable?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why does Terraform build a resource dependency graph?$tv2$, $tv2$[{"id":"a","text":"To bill resources by dependency count."},{"id":"b","text":"To determine the correct order to create, update, or destroy resources and parallelize where safe."},{"id":"c","text":"To replace the need for a state file."},{"id":"d","text":"To encrypt the configuration."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The dependency graph lets Terraform order operations correctly and run independent changes in parallel. It does not affect billing, replace state, or encrypt config.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/resources/behavior","label":"Terraform Docs — Resource Dependencies"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why does Terraform build a resource dependency graph?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A team wants one tool to provision a load balancer in AWS, a DNS record in Cloudflare, and a database in a managed provider — all in one config. Why is Terraform well suited?$tv2$, $tv2$[{"id":"a","text":"It only supports AWS so it is simpler."},{"id":"b","text":"A single configuration can use multiple providers and wire their resources together with references."},{"id":"c","text":"It requires a separate state file per provider by design."},{"id":"d","text":"It cannot reference one provider's resource from another."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Terraform configurations can declare multiple providers and reference resources across them in one plan/apply, which is a core multi-cloud strength. References across providers are fully supported.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A team wants one tool to provision a load balancer in AWS, a DNS record in Cloudflare, and a database in a managed provider — all in one config. Why is Terraform well suited?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Terraform is agentless for the platforms it manages — it talks to provider APIs and does not require software pre-installed on target infrastructure.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Terraform invokes provider APIs directly and does not need an agent on managed infrastructure, unlike some configuration-management tools.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Terraform is agentless for the platforms it manages — it talks to provider APIs and does not require software pre-installed on target infrastructure.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which block type actually creates and manages an infrastructure object?$tv2$, $tv2$[{"id":"a","text":"resource"},{"id":"b","text":"data"},{"id":"c","text":"output"},{"id":"d","text":"variable"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A `resource` block declares an infrastructure object Terraform creates/manages. `data` reads existing objects, `output` exposes values, and `variable` declares inputs.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/resources","label":"Terraform Docs — Resources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which block type actually creates and manages an infrastructure object?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Where does Terraform install provider plugins by default during `terraform init`?$tv2$, $tv2$[{"id":"a","text":"Into the system PATH."},{"id":"b","text":"Into the `.terraform` directory within the working directory."},{"id":"c","text":"Into the remote state backend."},{"id":"d","text":"Into the dependency lock file."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Provider plugins and modules are installed under the `.terraform` directory in the working directory during init. The lock file records selections but does not hold the binaries.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Where does Terraform install provider plugins by default during `terraform init`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which environment variable enables detailed Terraform debug logging?$tv2$, $tv2$[{"id":"a","text":"TF_DEBUG"},{"id":"b","text":"TF_LOG"},{"id":"c","text":"TF_VERBOSE"},{"id":"d","text":"TF_TRACE_ONLY"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Setting `TF_LOG` (e.g. to `TRACE` or `DEBUG`) enables verbose logging; `TF_LOG_PATH` writes it to a file. The other variables do not exist.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which environment variable enables detailed Terraform debug logging?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$How do you set an input variable named `region` from the command line for a single run?$tv2$, $tv2$[{"id":"a","text":"terraform apply -var=\"region=us-east-1\""},{"id":"b","text":"terraform apply --set region=us-east-1"},{"id":"c","text":"terraform apply -region us-east-1"},{"id":"d","text":"terraform apply region=us-east-1"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`-var="name=value"` (or `-var-file`) sets input variables on the command line. Terraform also reads `TF_VAR_region` and `*.tfvars` files; the other syntaxes are invalid.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How do you set an input variable named `region` from the command line for a single run?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which file name is automatically loaded for variable values without any extra flag?$tv2$, $tv2$[{"id":"a","text":"terraform.tfvars"},{"id":"b","text":"variables.tf"},{"id":"c","text":"vars.json"},{"id":"d","text":"terraform.config"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Terraform automatically loads `terraform.tfvars` and `*.auto.tfvars`. `variables.tf` typically declares variables (not values), and the other names are not auto-loaded.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which file name is automatically loaded for variable values without any extra flag?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid ways to assign a value to an input variable.$tv2$, $tv2$[{"id":"a","text":"A `-var` flag on the command line."},{"id":"b","text":"A `*.tfvars` / `*.auto.tfvars` file."},{"id":"c","text":"A `TF_VAR_<name>` environment variable."},{"id":"d","text":"Defining it inside an `output` block."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Variables can be set via `-var`, `.tfvars` files, and `TF_VAR_` environment variables (plus interactive prompt for root). `output` blocks expose values; they do not assign variables.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid ways to assign a value to an input variable.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does the `terraform { required_version = ">= 1.5.0" }` setting do?$tv2$, $tv2$[{"id":"a","text":"Pins the AWS provider to 1.5.0."},{"id":"b","text":"Constrains which Terraform CLI versions may run this configuration."},{"id":"c","text":"Sets the state schema version."},{"id":"d","text":"Forces a specific module version."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`required_version` constrains the Terraform CLI version allowed to run the configuration. Provider versions use `required_providers`; module versions use the module block `version`.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does the `terraform { required_version = ">= 1.5.0" }` setting do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In `terraform plan` output, what does a leading `+` next to a resource mean?$tv2$, $tv2$[{"id":"a","text":"The resource will be updated in place."},{"id":"b","text":"The resource will be created."},{"id":"c","text":"The resource will be destroyed."},{"id":"d","text":"The resource will be replaced."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$A `+` indicates creation, `~` update in place, `-` destroy, and `-/+` replacement. So `+` means Terraform will create the resource.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `terraform plan` output, what does a leading `+` next to a resource mean?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Running `terraform apply` with no saved plan file does what?$tv2$, $tv2$[{"id":"a","text":"Applies immediately with no preview."},{"id":"b","text":"Generates a plan, shows it, and prompts for approval before making changes."},{"id":"c","text":"Only formats the configuration."},{"id":"d","text":"Refuses to run without `-out`."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform apply` without a plan file first runs a plan, displays it, and asks for confirmation (unless `-auto-approve`). It does not skip the preview or require `-out`.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Running `terraform apply` with no saved plan file does what?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which command would you use to remove all managed infrastructure at the end of a temporary environment's life?$tv2$, $tv2$[{"id":"a","text":"terraform plan"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform validate"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform destroy` tears down all resources tracked in state for the configuration. plan previews, fmt formats, and validate checks syntax.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command would you use to remove all managed infrastructure at the end of a temporary environment's life?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You ran `terraform plan -out=tfplan` and want to inspect the saved plan in human-readable form. Which command does that?$tv2$, $tv2$[{"id":"a","text":"terraform show tfplan"},{"id":"b","text":"terraform output tfplan"},{"id":"c","text":"terraform console tfplan"},{"id":"d","text":"terraform validate tfplan"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform show tfplan` renders a saved plan (or state) in readable form; `terraform show -json tfplan` emits JSON. The other commands do not read plan files.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You ran `terraform plan -out=tfplan` and want to inspect the saved plan in human-readable form. Which command does that?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command refreshes state and shows what would change but is guaranteed not to modify infrastructure?$tv2$, $tv2$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform destroy"},{"id":"d","text":"terraform import"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform plan` is read-only: it computes and displays the diff without applying changes. apply/destroy modify infra; import mutates state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command refreshes state and shows what would change but is guaranteed not to modify infrastructure?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about the core write → plan → apply workflow.$tv2$, $tv2$[{"id":"a","text":"`plan` does not change real infrastructure."},{"id":"b","text":"`apply` requires approval unless `-auto-approve` is given or a saved plan file is supplied."},{"id":"c","text":"A saved plan file applied with `terraform apply tfplan` is executed without an additional prompt."},{"id":"d","text":"`apply` always ignores the configuration and only reads state."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$plan is read-only; apply prompts unless auto-approved or given a saved plan; applying a saved plan skips the extra prompt. apply uses configuration plus state — it does not ignore configuration.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about the core write → plan → apply workflow.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: `terraform apply` can be run safely before `terraform init` in a brand-new configuration directory.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$False. `terraform init` must run first to install providers/modules and configure the backend; apply errors in an uninitialized directory.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: `terraform apply` can be run safely before `terraform init` in a brand-new configuration directory.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the "root module" in a Terraform configuration?$tv2$, $tv2$[{"id":"a","text":"The set of `.tf` files in the directory where Terraform is run."},{"id":"b","text":"The first module published to the registry."},{"id":"c","text":"The state file."},{"id":"d","text":"The provider plugin directory."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The root module is the working directory configuration where Terraform is invoked; it may call child modules. It is not the registry, state, or plugin directory.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the "root module" in a Terraform configuration?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A registry module source is written as `hashicorp/consul/aws`. What do the three parts represent?$tv2$, $tv2$[{"id":"a","text":"Region / account / resource."},{"id":"b","text":"Namespace / name / target provider."},{"id":"c","text":"Version / hash / source."},{"id":"d","text":"Bucket / key / region."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Public registry module addresses use `<NAMESPACE>/<NAME>/<PROVIDER>` (e.g. `hashicorp/consul/aws`). It is unrelated to regions, hashes, or buckets.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A registry module source is written as `hashicorp/consul/aws`. What do the three parts represent?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$To use a Git branch as a module source, which form is valid?$tv2$, $tv2$[{"id":"a","text":"source = \"git::https://example.com/vpc.git?ref=dev\""},{"id":"b","text":"source = \"branch://dev/vpc\""},{"id":"c","text":"source = \"vpc.git@dev\""},{"id":"d","text":"source = \"https://example.com/vpc#dev\""}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Git module sources use the `git::` prefix and a `?ref=` query for a branch/tag/commit. The other syntaxes are not valid Terraform module source forms.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$To use a Git branch as a module source, which form is valid?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A module is called with `count = 3`. How do you reference an output `id` of the second instance from the caller?$tv2$, $tv2$[{"id":"a","text":"module.thing[1].id"},{"id":"b","text":"module.thing.id[1]"},{"id":"c","text":"module.thing.1.id"},{"id":"d","text":"count.module.thing.id"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$With `count`, module instances are indexed: `module.<name>[<index>].<output>`, so the second is `module.thing[1].id`. The other forms are invalid address syntax.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/count","label":"Terraform Docs — count"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A module is called with `count = 3`. How do you reference an output `id` of the second instance from the caller?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why is pinning a registry module `version` (e.g. `version = "~> 4.0"`) considered a best practice?$tv2$, $tv2$[{"id":"a","text":"It makes `terraform init` skip downloading the module."},{"id":"b","text":"It prevents unexpected breaking changes by controlling which module releases are used."},{"id":"c","text":"It encrypts the module source."},{"id":"d","text":"It is required for local path modules."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Version constraints protect you from unexpected breaking updates by bounding which module releases Terraform may select. Local path modules are not versioned, and version does not skip downloads or encrypt anything.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why is pinning a registry module `version` (e.g. `version = "~> 4.0"`) considered a best practice?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about Terraform modules.$tv2$, $tv2$[{"id":"a","text":"Input variables pass values into a module."},{"id":"b","text":"Output values expose data from a module to its caller."},{"id":"c","text":"A module can call other (child) modules."},{"id":"d","text":"A module's internal resources are directly addressable from the caller without outputs."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Modules take inputs via variables, expose data via outputs, and can nest child modules. Internal resources are encapsulated — the caller must use outputs, not reach inside.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about Terraform modules.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which `module` block meta-argument explicitly orders a module after another resource/module is created?$tv2$, $tv2$[{"id":"a","text":"depends_on"},{"id":"b","text":"source"},{"id":"c","text":"version"},{"id":"d","text":"sensitive"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`depends_on` on a module block creates an explicit ordering dependency. `source`/`version` locate the module; `sensitive` is not a module-block meta-argument.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/depends_on","label":"Terraform Docs — Meta-Arguments"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which `module` block meta-argument explicitly orders a module after another resource/module is created?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command prints a human-readable representation of the current state?$tv2$, $tv2$[{"id":"a","text":"terraform show"},{"id":"b","text":"terraform plan -state"},{"id":"c","text":"terraform fmt -state"},{"id":"d","text":"terraform init -show"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform show` (with no arguments) renders the current state in readable form; it can also render a saved plan file. The other invocations are not valid.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command prints a human-readable representation of the current state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$When importing an existing resource, what must already exist in your configuration for `terraform import aws_instance.web i-123` to succeed?$tv2$, $tv2$[{"id":"a","text":"A matching `resource \"aws_instance\" \"web\"` block."},{"id":"b","text":"A saved plan file."},{"id":"c","text":"An output block named web."},{"id":"d","text":"A workspace named web."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Classic `terraform import` requires the target resource block to exist in configuration so the imported object can be bound to that address. It does not need a plan file, output, or workspace.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/import","label":"Terraform Docs — terraform import"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$When importing an existing resource, what must already exist in your configuration for `terraform import aws_instance.web i-123` to succeed?$tv2$);
