INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the default backend Terraform uses if none is configured?$tv2$, $tv2$[{"id":"a","text":"The S3 backend."},{"id":"b","text":"The local backend (a `terraform.tfstate` file on disk)."},{"id":"c","text":"HCP Terraform."},{"id":"d","text":"No state is kept at all."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Without a configured backend, Terraform uses the local backend, writing `terraform.tfstate` to the working directory. State is always kept; it is just stored locally.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the default backend Terraform uses if none is configured?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command shows the attributes of a single resource recorded in state?$tv2$, $tv2$[{"id":"a","text":"terraform state show ADDR"},{"id":"b","text":"terraform output ADDR"},{"id":"c","text":"terraform plan ADDR"},{"id":"d","text":"terraform fmt ADDR"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform state show <address>` prints the stored attributes of one resource. `output` reads outputs, `plan` previews changes, and `fmt` formats files.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command shows the attributes of a single resource recorded in state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command creates a new CLI workspace named "staging"?$tv2$, $tv2$[{"id":"a","text":"terraform workspace new staging"},{"id":"b","text":"terraform workspace create staging"},{"id":"c","text":"terraform new workspace staging"},{"id":"d","text":"terraform workspace add staging"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform workspace new <name>` creates and switches to a new workspace; `terraform workspace select` switches to an existing one. The other forms are invalid.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command creates a new CLI workspace named "staging"?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Within configuration, how do you reference the name of the currently selected CLI workspace?$tv2$, $tv2$[{"id":"a","text":"terraform.workspace"},{"id":"b","text":"var.workspace"},{"id":"c","text":"local.workspace"},{"id":"d","text":"workspace.current"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `terraform.workspace` expression returns the current workspace name, often used to vary naming/sizing per environment. The other references are not built-in.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Within configuration, how do you reference the name of the currently selected CLI workspace?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Why should the state file generally NOT be committed to a public Git repository?$tv2$, $tv2$[{"id":"a","text":"It is too large for Git."},{"id":"b","text":"It may contain sensitive values (secrets, IPs) and can cause conflicts/corruption with concurrent edits."},{"id":"c","text":"Git cannot store JSON."},{"id":"d","text":"Terraform refuses to read state from Git."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$State can hold secrets and is prone to merge conflicts/corruption if shared via Git; a locking remote backend is recommended instead. Size and JSON support are not the issues.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Why should the state file generally NOT be committed to a public Git repository?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A backend supports locking. What is the main risk if locking were unavailable and two engineers ran `apply` simultaneously?$tv2$, $tv2$[{"id":"a","text":"Slightly slower applies."},{"id":"b","text":"State corruption or lost updates from concurrent writes."},{"id":"c","text":"Provider plugins would be deleted."},{"id":"d","text":"The configuration would be reformatted."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Concurrent writes to the same state without locking can corrupt it or lose updates. Locking serializes write operations to prevent this; it is unrelated to formatting or plugins.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A backend supports locking. What is the main risk if locking were unavailable and two engineers ran `apply` simultaneously?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid uses of the `terraform state` command family.$tv2$, $tv2$[{"id":"a","text":"Listing tracked resource addresses (`state list`)."},{"id":"b","text":"Moving a resource to a new address (`state mv`)."},{"id":"c","text":"Removing a resource from state without destroying it (`state rm`)."},{"id":"d","text":"Downloading provider plugins (`state init`)."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$`state list`, `state mv`, and `state rm` are real subcommands. There is no `state init`; provider plugins are installed by `terraform init`.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid uses of the `terraform state` command family.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You want to iterate over a map to create one resource per key with stable addresses. Which meta-argument is best?$tv2$, $tv2$[{"id":"a","text":"for_each"},{"id":"b","text":"count"},{"id":"c","text":"depends_on"},{"id":"d","text":"lifecycle"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`for_each` over a map/set keys instances by key, giving stable addresses when the collection changes (unlike `count`, which uses positional indexes). depends_on and lifecycle do not iterate.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to iterate over a map to create one resource per key with stable addresses. Which meta-argument is best?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which declaration prevents an output value from being shown in CLI plan/apply output?$tv2$, $tv2$[{"id":"a","text":"Adding `sensitive = true` to the `output` block."},{"id":"b","text":"Adding `hidden = true` to the `output` block."},{"id":"c","text":"Wrapping the value in `nonsensitive()`."},{"id":"d","text":"Setting `count = 0` on the output."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Marking an output `sensitive = true` redacts it from CLI output (it is still stored in state). `nonsensitive()` does the opposite; `hidden` and `count` on outputs are not how this works.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which declaration prevents an output value from being shown in CLI plan/apply output?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which expression accesses the `id` attribute of a resource declared as `resource "aws_vpc" "main"`?$tv2$, $tv2$[{"id":"a","text":"aws_vpc.main.id"},{"id":"b","text":"var.aws_vpc.main.id"},{"id":"c","text":"resource.aws_vpc.main.id"},{"id":"d","text":"module.aws_vpc.main.id"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Managed resource attributes are referenced as `<type>.<name>.<attr>` — here `aws_vpc.main.id`. The `var.`/`module.`/`resource.` prefixes are wrong for a managed resource attribute reference.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/expressions","label":"Terraform Docs — Expressions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which expression accesses the `id` attribute of a resource declared as `resource "aws_vpc" "main"`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which function returns the first non-null argument and is useful for variable defaulting?$tv2$, $tv2$[{"id":"a","text":"coalesce"},{"id":"b","text":"lookup"},{"id":"c","text":"flatten"},{"id":"d","text":"try"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`coalesce` returns the first non-null/non-empty argument, handy for defaults. `lookup` reads a map key, `flatten` flattens nested lists, and `try` swallows evaluation errors.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/functions","label":"Terraform Docs — Built-in Functions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which function returns the first non-null argument and is useful for variable defaulting?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: A `validation` block inside a `variable` declaration can enforce custom rules (e.g. allowed values) and fail the run with a message if violated.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Variable `validation` blocks define a `condition` and `error_message`, rejecting invalid input early with a clear message.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p1$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: A `validation` block inside a `variable` declaration can enforce custom rules (e.g. allowed values) and fail the run with a message if violated.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which of the following is an advantage of declarative IaC (like Terraform) over an imperative scripting approach?$tv2$, $tv2$[{"id":"a","text":"You must specify every API call in the exact order to execute."},{"id":"b","text":"You describe the desired end state and the tool determines the operations needed to reach it."},{"id":"c","text":"It cannot detect drift from the desired state."},{"id":"d","text":"It always requires an agent on the target machine."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Declarative IaC lets you state the desired end result; the engine computes the required changes and can detect drift. Imperative scripting requires ordering every step manually.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which of the following is an advantage of declarative IaC (like Terraform) over an imperative scripting approach?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Treating infrastructure as code allows the same configuration to be reliably reproduced across multiple environments (dev, staging, prod).$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Reproducibility across environments is a key IaC benefit — the same versioned configuration (parameterized by variables) recreates consistent infrastructure.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Treating infrastructure as code allows the same configuration to be reliably reproduced across multiple environments (dev, staging, prod).$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$How does Terraform state help Terraform achieve its purpose of safe, predictable changes?$tv2$, $tv2$[{"id":"a","text":"It stores the desired configuration so Git is unnecessary."},{"id":"b","text":"It records what Terraform manages so plans can show an accurate diff between desired config and real infrastructure."},{"id":"c","text":"It encrypts all provider API traffic."},{"id":"d","text":"It eliminates the need for provider plugins."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$State lets Terraform compare desired configuration with the last-known real infrastructure to produce an accurate execution plan. It does not replace version control, encrypt API traffic, or remove providers.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How does Terraform state help Terraform achieve its purpose of safe, predictable changes?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL benefits Terraform provides as an infrastructure provisioning tool.$tv2$, $tv2$[{"id":"a","text":"A consistent workflow across many providers."},{"id":"b","text":"An execution plan that previews changes before they are applied."},{"id":"c","text":"Tracking of resource relationships via a dependency graph."},{"id":"d","text":"Automatic configuration of application software inside running VMs without any provisioner."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Terraform offers a uniform multi-provider workflow, plan previews, and graph-based dependency ordering. It does NOT inherently configure in-VM software — that is the domain of configuration-management tools (or explicit provisioners).$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL benefits Terraform provides as an infrastructure provisioning tool.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which source address format correctly identifies the official AWS provider in `required_providers`?$tv2$, $tv2$[{"id":"a","text":"source = \"aws\""},{"id":"b","text":"source = \"hashicorp/aws\""},{"id":"c","text":"source = \"terraform-provider-aws\""},{"id":"d","text":"source = \"registry/aws/latest\""}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Provider source addresses use `<NAMESPACE>/<TYPE>` (here `hashicorp/aws`), optionally with a host prefix. The bare name and the other forms are not valid source addresses.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which source address format correctly identifies the official AWS provider in `required_providers`?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In `version = "~> 1.2.0"` inside `required_providers`, what does the `~>` operator mean?$tv2$, $tv2$[{"id":"a","text":"Exactly version 1.2.0 only."},{"id":"b","text":"Allow the rightmost version component to increment — here >= 1.2.0 and < 1.3.0."},{"id":"c","text":"Any version greater than 1.2.0 with no upper bound."},{"id":"d","text":"Any version less than 1.2.0."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The pessimistic constraint `~>` allows the last specified component to increase. `~> 1.2.0` permits 1.2.x but not 1.3.0. Exact pinning uses `= 1.2.0`.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In `version = "~> 1.2.0"` inside `required_providers`, what does the `~>` operator mean?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What is the role of the dependency lock file (`.terraform.lock.hcl`)?$tv2$, $tv2$[{"id":"a","text":"It stores the Terraform state."},{"id":"b","text":"It records the selected provider versions and hashes so the same versions are used on subsequent runs."},{"id":"c","text":"It locks the state during apply."},{"id":"d","text":"It contains the cloud credentials."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The lock file pins provider selections (versions + hashes) for reproducible installs across machines. It is unrelated to state storage, state locking, or credentials.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the role of the dependency lock file (`.terraform.lock.hcl`)?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You want to save a plan to a file and apply exactly that plan later. Which commands do this?$tv2$, $tv2$[{"id":"a","text":"terraform plan -out=tfplan, then terraform apply tfplan"},{"id":"b","text":"terraform plan > tfplan, then terraform apply < tfplan"},{"id":"c","text":"terraform save tfplan, then terraform run tfplan"},{"id":"d","text":"terraform plan --export tfplan, then terraform deploy tfplan"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform plan -out=tfplan` writes a binary plan file; `terraform apply tfplan` applies exactly that saved plan with no further prompt. Shell redirection or invented flags do not work.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want to save a plan to a file and apply exactly that plan later. Which commands do this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command destroys all remote objects managed by the current configuration?$tv2$, $tv2$[{"id":"a","text":"terraform delete"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform apply -remove"},{"id":"d","text":"terraform state rm"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform destroy` removes all infrastructure tracked in state for the configuration. `state rm` only stops tracking a resource without destroying it; the other commands do not exist.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command destroys all remote objects managed by the current configuration?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A single resource is misbehaving and you want Terraform to destroy and recreate ONLY that resource on the next apply (current recommended approach).$tv2$, $tv2$[{"id":"a","text":"terraform apply -replace=\"aws_instance.web\""},{"id":"b","text":"terraform taint aws_instance.web only"},{"id":"c","text":"terraform destroy -target then re-apply manually each time"},{"id":"d","text":"terraform refresh aws_instance.web"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform apply -replace=ADDR` is the current recommended way to force replacement of a specific resource. `terraform taint` is deprecated in favor of `-replace`; refresh only syncs state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/taint","label":"Terraform Docs — terraform taint"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A single resource is misbehaving and you want Terraform to destroy and recreate ONLY that resource on the next apply (current recommended approach).$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$When you reference a module from the public Terraform Registry, which arguments are typically required in the `module` block?$tv2$, $tv2$[{"id":"a","text":"source and (recommended) version"},{"id":"b","text":"count and for_each"},{"id":"c","text":"provider and backend"},{"id":"d","text":"depends_on and lifecycle"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Registry modules need a `source` address; specifying `version` is strongly recommended to pin a known release. The other pairs are unrelated meta-arguments/blocks.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$When you reference a module from the public Terraform Registry, which arguments are typically required in the `module` block?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$How do you pass values INTO a child module?$tv2$, $tv2$[{"id":"a","text":"By setting the module's declared input variables as arguments in the `module` block."},{"id":"b","text":"By editing the child module's state file."},{"id":"c","text":"Through the child module's `output` blocks."},{"id":"d","text":"Through environment variables only."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A module's input variables are set as arguments within the calling `module` block. Outputs send values back to the caller; you do not edit state to pass inputs.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How do you pass values INTO a child module?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid Terraform module source types.$tv2$, $tv2$[{"id":"a","text":"A local path such as \"./modules/network\"."},{"id":"b","text":"A Terraform Registry address such as \"terraform-aws-modules/vpc/aws\"."},{"id":"c","text":"A Git repository such as \"git::https://example.com/vpc.git\"."},{"id":"d","text":"A raw state file URL such as \"state://prod.tfstate\"."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Local paths, registry addresses, and Git (and other VCS/HTTP/bucket) sources are supported module source types. There is no `state://` module source.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid Terraform module source types.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command produces a visual representation (DOT graph) of the resource dependency graph?$tv2$, $tv2$[{"id":"a","text":"terraform graph"},{"id":"b","text":"terraform show -graph"},{"id":"c","text":"terraform plan -graph"},{"id":"d","text":"terraform console -graph"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform graph` outputs the dependency graph in DOT format for visualization. The other commands do not have a `-graph` mode.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command produces a visual representation (DOT graph) of the resource dependency graph?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Use Terraform Outside the Core Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You suspect the real infrastructure has drifted from state (someone changed a resource manually). Which command updates state to match real-world resources without modifying infrastructure?$tv2$, $tv2$[{"id":"a","text":"terraform apply -refresh-only"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform import"},{"id":"d","text":"terraform fmt"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform apply -refresh-only` reconciles state with the actual remote objects without changing infrastructure. Import adds a new resource to state; destroy removes infra; fmt only formats files.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You suspect the real infrastructure has drifted from state (someone changed a resource manually). Which command updates state to match real-world resources without modifying infrastructure?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command lists all resource addresses currently tracked in the Terraform state?$tv2$, $tv2$[{"id":"a","text":"terraform state list"},{"id":"b","text":"terraform show list"},{"id":"c","text":"terraform list state"},{"id":"d","text":"terraform get state"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`terraform state list` prints the resource addresses in state. The other forms are not valid Terraform subcommands.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command lists all resource addresses currently tracked in the Terraform state?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A resource was removed from configuration but you want Terraform to STOP managing it WITHOUT destroying the real resource. Which command achieves this?$tv2$, $tv2$[{"id":"a","text":"terraform destroy -target=ADDR"},{"id":"b","text":"terraform state rm ADDR"},{"id":"c","text":"terraform taint ADDR"},{"id":"d","text":"terraform apply -replace=ADDR"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform state rm` removes the resource from state so Terraform no longer manages it, leaving the real object intact. Destroy deletes it; taint/replace force recreation.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A resource was removed from configuration but you want Terraform to STOP managing it WITHOUT destroying the real resource. Which command achieves this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Implement and Maintain State$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$When using an S3 remote backend, which additional mechanism is commonly configured to provide state locking?$tv2$, $tv2$[{"id":"a","text":"A DynamoDB table (or S3-native locking) referenced by the backend configuration."},{"id":"b","text":"A second S3 bucket for backups only."},{"id":"c","text":"An EC2 instance acting as a lock server."},{"id":"d","text":"A local file on each engineer's laptop."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The S3 backend traditionally uses a DynamoDB table (newer versions also support S3-native lockfiles) to coordinate state locking and prevent concurrent writes. A backup bucket or local file does not provide locking.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$When using an S3 remote backend, which additional mechanism is commonly configured to provide state locking?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$You need to read attributes of an EXISTING resource that Terraform does not manage (e.g. an existing AMI) for use in configuration. Which construct fits?$tv2$, $tv2$[{"id":"a","text":"A `data` source block."},{"id":"b","text":"A `resource` block."},{"id":"c","text":"An `output` block."},{"id":"d","text":"A `provisioner` block."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Data sources let configuration read information about existing/external objects without managing them. Resource blocks create/manage objects; outputs export values; provisioners run scripts.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/data-sources","label":"Terraform Docs — Data Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You need to read attributes of an EXISTING resource that Terraform does not manage (e.g. an existing AMI) for use in configuration. Which construct fits?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Read, Generate, and Modify Configuration$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Which built-in function would you use to join a list of strings into a single string with a comma separator?$tv2$, $tv2$[{"id":"a","text":"concat(\",\", list)"},{"id":"b","text":"join(\",\", list)"},{"id":"c","text":"merge(\",\", list)"},{"id":"d","text":"format(\",\", list)"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`join(separator, list)` concatenates list elements into a string using the separator. `concat` joins lists into a list, `merge` combines maps, and `format` does printf-style formatting.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/functions","label":"Terraform Docs — Built-in Functions"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which built-in function would you use to join a list of strings into a single string with a comma separator?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which of the following is NOT a goal of Infrastructure as Code?$tv2$, $tv2$[{"id":"a","text":"Reproducible, automated provisioning."},{"id":"b","text":"Version-controlled, reviewable infrastructure changes."},{"id":"c","text":"Ad-hoc, undocumented manual changes directly in the cloud console."},{"id":"d","text":"Consistent environments across dev, staging, and prod."}]$tv2$::jsonb, $tv2$["c"]$tv2$::jsonb, $tv2$Ad-hoc, undocumented manual console changes are exactly what IaC seeks to eliminate. Reproducibility, versioning, and environment consistency are core IaC goals.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which of the following is NOT a goal of Infrastructure as Code?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A company uses IaC and wants to know exactly what changed and who approved it for an audit. Which IaC practice provides this?$tv2$, $tv2$[{"id":"a","text":"Storing configuration in version control with peer-reviewed pull requests."},{"id":"b","text":"Editing resources by hand and emailing screenshots."},{"id":"c","text":"Disabling state to avoid records."},{"id":"d","text":"Granting everyone console admin rights."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Versioned configuration plus reviewed pull requests yields a clear, attributable audit trail of infrastructure changes. The other options remove or undermine traceability.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A company uses IaC and wants to know exactly what changed and who approved it for an audit. Which IaC practice provides this?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$How does IaC help with disaster recovery?$tv2$, $tv2$[{"id":"a","text":"It backs up running VM disks automatically."},{"id":"b","text":"The codified configuration can recreate infrastructure consistently in a new region or account."},{"id":"c","text":"It prevents all outages from ever happening."},{"id":"d","text":"It stores customer data redundantly."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Because infrastructure is codified, the same configuration can rebuild environments reliably elsewhere, aiding disaster recovery. IaC does not back up disks or guarantee zero outages.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$How does IaC help with disaster recovery?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Infrastructure as Code (IaC) Concepts$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: With declarative IaC you specify the desired end state and the tool figures out the operations required to reach it.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Declarative IaC tools like Terraform take a desired-state description and compute the create/update/delete actions needed to converge to it.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: With declarative IaC you specify the desired end state and the tool figures out the operations required to reach it.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which is a primary reason teams choose Terraform over writing custom cloud SDK scripts?$tv2$, $tv2$[{"id":"a","text":"Terraform tracks state and produces a reviewable plan, removing the need to hand-code create/update/delete logic."},{"id":"b","text":"Terraform requires no provider credentials."},{"id":"c","text":"Terraform is the only tool that can call cloud APIs."},{"id":"d","text":"Terraform forbids the use of variables."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Terraform manages state and computes plans automatically, sparing teams from hand-writing idempotent create/update/delete logic. It still needs credentials and supports variables.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which is a primary reason teams choose Terraform over writing custom cloud SDK scripts?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$What problem does Terraform's execution plan specifically solve?$tv2$, $tv2$[{"id":"a","text":"It encrypts the state file at rest."},{"id":"b","text":"It lets you review proposed changes before they are applied, reducing surprise destructive actions."},{"id":"c","text":"It installs provider plugins."},{"id":"d","text":"It rotates cloud credentials."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$The plan previews exactly what will be created, changed, or destroyed so risky actions can be caught before apply. Plugin install and credential handling are separate concerns.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What problem does Terraform's execution plan specifically solve?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Compared with click-ops in a console, what does Terraform add for repeatable infrastructure?$tv2$, $tv2$[{"id":"a","text":"A codified, versionable definition plus a consistent plan/apply workflow."},{"id":"b","text":"Free cloud compute."},{"id":"c","text":"Automatic application code deployment."},{"id":"d","text":"Elimination of the need for any cloud account."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Terraform turns infrastructure into versioned code with a consistent workflow, unlike manual console operations. It does not provide free compute or deploy application code by itself.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Compared with click-ops in a console, what does Terraform add for repeatable infrastructure?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Purpose of Terraform (vs other IaC)$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL statements that correctly describe Terraform's purpose and design.$tv2$, $tv2$[{"id":"a","text":"It is primarily an infrastructure provisioning tool."},{"id":"b","text":"It uses providers to support many platforms."},{"id":"c","text":"It produces an execution plan before changing infrastructure."},{"id":"d","text":"It is mainly a configuration-management tool for installing software inside servers."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Terraform is a provisioning tool that uses providers and produces a plan before applying. In-server software configuration is the domain of config-management tools.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"},{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL statements that correctly describe Terraform's purpose and design.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which command would you run after adding a new provider to `required_providers` so it is downloaded?$tv2$, $tv2$[{"id":"a","text":"terraform init"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform output"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Adding or changing required providers requires re-running `terraform init` to install them. plan/fmt/output do not install providers.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which command would you run after adding a new provider to `required_providers` so it is downloaded?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What does `terraform init -upgrade` do?$tv2$, $tv2$[{"id":"a","text":"Upgrades the Terraform CLI binary."},{"id":"b","text":"Allows providers/modules to be upgraded to the newest versions allowed by constraints, updating the lock file."},{"id":"c","text":"Upgrades the remote state schema."},{"id":"d","text":"Reinstalls the operating system packages."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform init -upgrade` re-selects the newest provider/module versions permitted by constraints and updates `.terraform.lock.hcl`. It does not upgrade the CLI itself.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What does `terraform init -upgrade` do?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$Precedence: a variable `region` is set by a `terraform.tfvars` file AND by a `-var` flag on the command line. Which value wins?$tv2$, $tv2$[{"id":"a","text":"The `.tfvars` file value."},{"id":"b","text":"The `-var` command-line value."},{"id":"c","text":"Terraform errors on conflict."},{"id":"d","text":"The environment variable always wins."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Command-line `-var`/`-var-file` flags have higher precedence than `.tfvars`/`.auto.tfvars` files and `TF_VAR_` environment variables, so the `-var` value wins.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Precedence: a variable `region` is set by a `terraform.tfvars` file AND by a `-var` flag on the command line. Which value wins?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which type constraint declares a variable that must be a map of strings?$tv2$, $tv2$[{"id":"a","text":"type = map(string)"},{"id":"b","text":"type = list(string)"},{"id":"c","text":"type = string(map)"},{"id":"d","text":"type = object"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`map(string)` constrains the variable to a map whose values are strings. `list(string)` is a list, and the other forms are not valid type syntax.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which type constraint declares a variable that must be a map of strings?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which block configures authentication and endpoints for a platform such as AWS?$tv2$, $tv2$[{"id":"a","text":"The `provider` block."},{"id":"b","text":"The `output` block."},{"id":"c","text":"The `variable` block."},{"id":"d","text":"The `locals` block."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The `provider` block configures provider-specific settings like region/credentials/endpoints. outputs expose values, variables declare inputs, locals name expressions.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which block configures authentication and endpoints for a platform such as AWS?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 3, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL true statements about the `terraform` settings block.$tv2$, $tv2$[{"id":"a","text":"It can declare `required_version` for the CLI."},{"id":"b","text":"It can declare `required_providers` with source and version."},{"id":"c","text":"It can declare a `backend` for state storage."},{"id":"d","text":"It is where you define resources to create."}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$The `terraform` block holds `required_version`, `required_providers`, and `backend` settings. Resources are declared in `resource` blocks, not the terraform block.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL true statements about the `terraform` settings block.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Fundamentals$tv2$, 2, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Terraform automatically loads every file ending in `.tf` in the working directory regardless of file name.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. Terraform loads all `.tf` (and `.tf.json`) files in the directory; the split into main.tf/variables.tf/outputs.tf is convention, not a requirement.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language","label":"Terraform Docs — Configuration Language"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Terraform automatically loads every file ending in `.tf` in the working directory regardless of file name.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$In plan output, what does a `~` prefix on a resource mean?$tv2$, $tv2$[{"id":"a","text":"Create"},{"id":"b","text":"Update in place"},{"id":"c","text":"Destroy"},{"id":"d","text":"No change"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`~` indicates an in-place update; `+` is create, `-` is destroy, and `-/+` is replacement. Unchanged resources are not listed by default.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$In plan output, what does a `~` prefix on a resource mean?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$What is the recommended way to skip the approval prompt during automated `terraform destroy` in CI?$tv2$, $tv2$[{"id":"a","text":"terraform destroy -auto-approve"},{"id":"b","text":"terraform destroy -force"},{"id":"c","text":"terraform destroy -y"},{"id":"d","text":"terraform destroy --no-confirm"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`-auto-approve` skips the interactive confirmation for both apply and destroy. The legacy `-force` flag was removed; `-y`/`--no-confirm` do not exist.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the recommended way to skip the approval prompt during automated `terraform destroy` in CI?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$You want plan/apply to refresh state from real infrastructure but you are confident nothing drifted and want a faster run. Which flag skips the refresh?$tv2$, $tv2$[{"id":"a","text":"terraform plan -refresh=false"},{"id":"b","text":"terraform plan -no-state"},{"id":"c","text":"terraform plan -skip"},{"id":"d","text":"terraform plan -fast"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$`-refresh=false` tells Terraform to skip the state refresh against real resources. The other flags are not valid Terraform options.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$You want plan/apply to refresh state from real infrastructure but you are confident nothing drifted and want a faster run. Which flag skips the refresh?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$Which is the FIRST step in the Terraform core workflow?$tv2$, $tv2$[{"id":"a","text":"Write the configuration."},{"id":"b","text":"Apply the configuration."},{"id":"c","text":"Destroy the configuration."},{"id":"d","text":"Import existing resources."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The core workflow is Write → Plan → Apply, so authoring (writing) the configuration comes first. Apply/destroy/import come later or are outside the core loop.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/tutorials/aws-get-started","label":"Terraform Tutorials — Get Started"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which is the FIRST step in the Terraform core workflow?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A teammate asks how to see proposed changes without risk of modifying anything. What do you tell them to run?$tv2$, $tv2$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform destroy"},{"id":"d","text":"terraform state rm"}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$`terraform plan` previews changes read-only. apply and destroy mutate infrastructure; `state rm` mutates state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A teammate asks how to see proposed changes without risk of modifying anything. What do you tell them to run?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$After `terraform apply tfplan` using a previously saved plan, why is there no second confirmation prompt?$tv2$, $tv2$[{"id":"a","text":"Saved plan files are encrypted."},{"id":"b","text":"A saved plan already represents an approved set of actions, so Terraform executes it directly."},{"id":"c","text":"`-auto-approve` is always implied by `init`."},{"id":"d","text":"Plan files disable all output."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Applying a saved plan executes exactly the previously reviewed actions, so no further approval is requested. This is unrelated to encryption or init.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$After `terraform apply tfplan` using a previously saved plan, why is there no second confirmation prompt?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$The Terraform Workflow$tv2$, 2, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL commands that can change real infrastructure.$tv2$, $tv2$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform plan"},{"id":"d","text":"terraform validate"}]$tv2$::jsonb, $tv2$["a","b"]$tv2$::jsonb, $tv2$apply and destroy mutate real infrastructure. plan only previews and validate only checks configuration syntax/consistency.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"},{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL commands that can change real infrastructure.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Which statement about module input variables is correct?$tv2$, $tv2$[{"id":"a","text":"They are declared in the child module and assigned by the calling module block."},{"id":"b","text":"They are declared in the calling module and read by the child via output."},{"id":"c","text":"They are global and require no declaration."},{"id":"d","text":"They are stored in the state file as the only way to pass values."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$A child module declares its inputs with `variable` blocks; the caller supplies values as arguments in the `module` block. Outputs flow data back to the caller.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Which statement about module input variables is correct?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 1, $tv2$SINGLE$tv2$::"QType", $tv2$What is the main motivation for using modules?$tv2$, $tv2$[{"id":"a","text":"To encrypt configuration."},{"id":"b","text":"To package and reuse a set of resources with a clean input/output interface (DRY)."},{"id":"c","text":"To avoid using providers."},{"id":"d","text":"To bypass the need for state."}]$tv2$::jsonb, $tv2$["b"]$tv2$::jsonb, $tv2$Modules promote reuse and abstraction by bundling related resources behind a defined interface (inputs/outputs), keeping configuration DRY. They do not replace providers or state.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$What is the main motivation for using modules?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$A local module is referenced with `source = "../modules/vpc"`. What is true of local path sources?$tv2$, $tv2$[{"id":"a","text":"They are not versioned; they track whatever is at that path."},{"id":"b","text":"They require a `version` argument."},{"id":"c","text":"They are downloaded from the registry."},{"id":"d","text":"They must use the `git::` prefix."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$Local path modules are not versioned — Terraform uses the code at that relative path directly. The `version` argument applies only to registry modules.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A local module is referenced with `source = "../modules/vpc"`. What is true of local path sources?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$SINGLE$tv2$::"QType", $tv2$A module is called with `for_each = toset(["a","b"])`. How is the "b" instance's output `arn` referenced from the caller?$tv2$, $tv2$[{"id":"a","text":"module.thing[\"b\"].arn"},{"id":"b","text":"module.thing.b.arn"},{"id":"c","text":"module.thing[1].arn"},{"id":"d","text":"module.thing.arn[\"b\"]"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$With `for_each`, instances are keyed by the set/map key: `module.<name>["<key>"].<output>`, so `module.thing["b"].arn`. Numeric indexing is for `count`, not `for_each`.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$A module is called with `for_each = toset(["a","b"])`. How is the "b" instance's output `arn` referenced from the caller?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$SINGLE$tv2$::"QType", $tv2$Where can you discover community and verified modules to reuse?$tv2$, $tv2$[{"id":"a","text":"The Terraform Registry (registry.terraform.io)."},{"id":"b","text":"The local backend."},{"id":"c","text":"The state file."},{"id":"d","text":"The `.terraform.lock.hcl` file."}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$The public Terraform Registry hosts published (including verified) modules and providers for reuse. State, backends, and the lock file are unrelated to module discovery.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Where can you discover community and verified modules to reuse?$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 3, $tv2$TRUE_FALSE$tv2$::"QType", $tv2$True or False: Adding or changing a `module` block requires running `terraform init` (or `terraform get`) before the next plan.$tv2$, $tv2$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tv2$::jsonb, $tv2$["a"]$tv2$::jsonb, $tv2$True. New or changed module sources must be installed via `terraform init` (or `terraform get`) before Terraform can plan with them.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$True or False: Adding or changing a `module` block requires running `terraform init` (or `terraform get`) before the next plan.$tv2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tv2$Terraform Modules$tv2$, 2, $tv2$MULTI$tv2$::"QType", $tv2$Select ALL valid module `source` values.$tv2$, $tv2$[{"id":"a","text":"\"./modules/app\""},{"id":"b","text":"\"terraform-aws-modules/vpc/aws\""},{"id":"c","text":"\"git::https://github.com/org/repo.git//subdir?ref=v1.0.0\""},{"id":"d","text":"\"backend://prod\""}]$tv2$::jsonb, $tv2$["a","b","c"]$tv2$::jsonb, $tv2$Local paths, registry addresses, and Git URLs (including subdir and ref) are valid module sources. There is no `backend://` source scheme.$tv2$, $tv2$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tv2$::jsonb, $tv2$PUBLISHED$tv2$::"QStatus", $tv2$manual:terraform-seed$tv2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $tv2$hashicorp-terraform-associate-p2$tv2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tv2$Select ALL valid module `source` values.$tv2$);
